struct TS3KeyboardShortcutSummary: Identifiable {
    let id = UUID()
    let group: String
    let action: String
    let keys: String
}

struct TS3KeyboardShortcutDescriptor {
    let key: KeyEquivalent
    let modifiers: EventModifiers
    let normalizedKeyName: String

    init?(_ rawValue: String) {
        let parts = rawValue
            .split(separator: "-")
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        guard let keyName = parts.last else { return nil }

        var modifiers: EventModifiers = []
        for modifier in parts.dropLast() {
            switch modifier.lowercased() {
            case "command", "cmd", "⌘":
                modifiers.insert(.command)
            case "shift", "⇧":
                modifiers.insert(.shift)
            case "option", "alt", "⌥":
                modifiers.insert(.option)
            case "control", "ctrl", "⌃":
                modifiers.insert(.control)
            default:
                return nil
            }
        }

        guard let key = Self.keyEquivalent(for: keyName) else { return nil }
        self.key = key
        self.modifiers = modifiers
        self.normalizedKeyName = Self.normalizedKeyName(for: keyName)
    }

    private static func keyEquivalent(for keyName: String) -> KeyEquivalent? {
        switch normalizedKeyName(for: keyName) {
        case "return", "enter":
            return .return
        case "escape", "esc":
            return .escape
        case "space":
            return .space
        case "tab":
            return .tab
        case "delete", "backspace":
            return .delete
        default:
            guard keyName.count == 1, let character = keyName.first else { return nil }
            return KeyEquivalent(character)
        }
    }

    private static func normalizedKeyName(for keyName: String) -> String {
        keyName.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }
}

#if canImport(UIKit)
private extension TS3KeyboardShortcutDescriptor {
    func matches(_ key: UIKey) -> Bool {
        guard matchesModifiers(key.modifierFlags) else { return false }
        let characters = key.charactersIgnoringModifiers.lowercased()
        switch normalizedKeyName {
        case "return", "enter":
            return characters == "\r" || characters == "\n"
        case "escape", "esc":
            return characters == "\u{1B}"
        case "space":
            return characters == " "
        case "tab":
            return characters == "\t"
        case "delete", "backspace":
            return characters == "\u{8}" || characters == "\u{7F}"
        default:
            return characters == normalizedKeyName
        }
    }

    private func matchesModifiers(_ flags: UIKeyModifierFlags) -> Bool {
        var expected: UIKeyModifierFlags = []
        if modifiers.contains(.command) {
            expected.insert(.command)
        }
        if modifiers.contains(.shift) {
            expected.insert(.shift)
        }
        if modifiers.contains(.option) {
            expected.insert(.alternate)
        }
        if modifiers.contains(.control) {
            expected.insert(.control)
        }
        let relevant: UIKeyModifierFlags = [.command, .shift, .alternate, .control]
        return flags.intersection(relevant) == expected
    }
}

private struct TS3WhisperShortcutCaptureView: UIViewRepresentable {
    @ObservedObject var model: TS3AppModel

    func makeUIView(context: Context) -> TS3WhisperShortcutCaptureUIView {
        let view = TS3WhisperShortcutCaptureUIView()
        view.model = model
        DispatchQueue.main.async {
            view.becomeFirstResponder()
        }
        return view
    }

    func updateUIView(_ uiView: TS3WhisperShortcutCaptureUIView, context: Context) {
        uiView.model = model
    }
}

private final class TS3WhisperShortcutCaptureUIView: UIView {
    weak var model: TS3AppModel?
    private var isHoldingWhisperShortcut = false

    override var canBecomeFirstResponder: Bool { true }

    override func didMoveToWindow() {
        super.didMoveToWindow()
        if window != nil {
            becomeFirstResponder()
        }
    }

    override func pressesBegan(_ presses: Set<UIPress>, with event: UIPressesEvent?) {
        guard let model,
              model.whisperActivationMode == .holdToWhisper,
              model.state == .connected,
              model.whisperRoute != .none,
              !model.isWhisperActivationActive,
              containsWhisperStartShortcut(in: presses) else {
            super.pressesBegan(presses, with: event)
            return
        }
        isHoldingWhisperShortcut = true
        model.beginCurrentWhisperActivation()
    }

    override func pressesEnded(_ presses: Set<UIPress>, with event: UIPressesEvent?) {
        if isHoldingWhisperShortcut, containsWhisperStartShortcut(in: presses) {
            isHoldingWhisperShortcut = false
            model?.endWhisperActivation()
            return
        }
        super.pressesEnded(presses, with: event)
    }

    override func pressesCancelled(_ presses: Set<UIPress>, with event: UIPressesEvent?) {
        if isHoldingWhisperShortcut, containsWhisperStartShortcut(in: presses) {
            isHoldingWhisperShortcut = false
            model?.endWhisperActivation()
            return
        }
        super.pressesCancelled(presses, with: event)
    }

    private func containsWhisperStartShortcut(in presses: Set<UIPress>) -> Bool {
        guard let shortcut = model?.keyboardShortcuts.first(where: { $0.actionId == "start-whisper-activation" }),
              shortcut.isEnabled,
              let descriptor = TS3KeyboardShortcutDescriptor(shortcut.keys) else {
            return false
        }
        return presses.contains { press in
            guard let key = press.key else { return false }
            return descriptor.matches(key)
        }
    }
}
#else
private struct TS3WhisperShortcutCaptureView: View {
    let model: TS3AppModel

    var body: some View {
        EmptyView()
    }
}
#endif

extension View {
    @ViewBuilder
    func ts3KeyboardShortcut(_ actionId: String, in model: TS3AppModel) -> some View {
        if let shortcut = model.keyboardShortcuts.first(where: { $0.actionId == actionId }),
           shortcut.isEnabled,
           let descriptor = TS3KeyboardShortcutDescriptor(shortcut.keys) {
            self.keyboardShortcut(descriptor.key, modifiers: descriptor.modifiers)
        } else {
            self
        }
    }
}

struct KeyboardShortcutsSheet: View {
    private enum ShortcutConfirmation: Identifiable {
        case enableAll
        case disableAll
        case resetDisabled
        case resetAll

        var id: String {
            switch self {
            case .enableAll: return "enableAll"
            case .disableAll: return "disableAll"
            case .resetDisabled: return "resetDisabled"
            case .resetAll: return "resetAll"
            }
        }
    }

    private struct ShortcutImportConfirmation: Identifiable {
        let id = UUID()
        let data: Data
        let preview: TS3KeyboardShortcutImportPreview
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var isExportingShortcuts = false
    @State private var isExportingShortcutBackup = false
    @State private var isImportingShortcutBackup = false
    @State private var confirmation: ShortcutConfirmation?
    @State private var pendingShortcutImport: ShortcutImportConfirmation?
    @State private var captureShortcut: TS3KeyboardShortcutBinding?
    @State private var shortcutsDocument = TS3TextFileDocument()
    @State private var shortcutBackupDocument = TS3BookmarkFileDocument()

    var body: some View {
        NavigationView {
            List {
                Section(header: Text("shortcuts.capability")) {
                    let summary = shortcutCapabilitySummary
                    ServerInfoDetailRow(
                        label: NSLocalizedString("shortcuts.capability.enabled", comment: ""),
                        value: String(
                            format: NSLocalizedString("shortcuts.capability.enabledFormat", comment: ""),
                            summary.validEnabledCount,
                            summary.totalCount
                        )
                    )
                    Text(shortcutCapabilityText(summary))
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button("shortcuts.copyCapabilitySummary") {
                        TS3PlatformSupport.copyToPasteboard(summary.clipboardSummary)
                    }
                }

                Section(header: Text("shortcuts.actions")) {
                    ForEach(model.keyboardShortcuts) { shortcut in
                        VStack(alignment: .leading, spacing: 8) {
                            HStack {
                                VStack(alignment: .leading, spacing: 2) {
                                    Text(shortcut.action)
                                        .font(.subheadline.weight(.semibold))
                                    Text(shortcut.group)
                                        .font(.caption)
                                        .foregroundColor(.secondary)
                                    Text(currentShortcut(for: shortcut).displaySummary)
                                        .font(.caption2)
                                        .foregroundColor(.secondary)
                                }
                                Spacer()
                                Toggle("", isOn: shortcutEnabledBinding(shortcut))
                                    .labelsHidden()
                            }
                            HStack {
                                TextField("shortcuts.keys", text: shortcutKeysBinding(shortcut))
                                    .font(.system(.body, design: .monospaced))
                                    .ts3PlainTextField()
                                Button("shortcuts.record") {
                                    captureShortcut = currentShortcut(for: shortcut)
                                }
                                .buttonStyle(.borderless)
                            }
                            let current = currentShortcut(for: shortcut)
                            if current.isEnabled && TS3KeyboardShortcutDescriptor(current.keys) == nil {
                                Text("shortcuts.invalidFormat")
                                    .font(.caption)
                                    .foregroundColor(.red)
                            }
                            if let duplicateText = duplicateShortcutText(for: shortcut) {
                                Text(duplicateText)
                                    .font(.caption)
                                    .foregroundColor(.orange)
                            }
                            if shortcut.keys != shortcut.defaultKeys {
                                Button(String(format: NSLocalizedString("shortcuts.resetToFormat", comment: ""), shortcut.defaultKeys)) {
                                    model.updateKeyboardShortcut(
                                        shortcut,
                                        keys: shortcut.defaultKeys,
                                        isEnabled: shortcut.isEnabled
                                    )
                                }
                            }
                            Button("shortcuts.copySummary") {
                                TS3PlatformSupport.copyToPasteboard(currentShortcut(for: shortcut).clipboardSummary)
                            }
                            .font(.caption)
                        }
                        .accessibilityElement(children: .combine)
                        .accessibilityLabel(shortcut.action)
                        .accessibilityValue(currentShortcut(for: shortcut).accessibilityValue)
                        .accessibilityAction(named: NSLocalizedString("shortcuts.copySummary", comment: "")) {
                            TS3PlatformSupport.copyToPasteboard(currentShortcut(for: shortcut).clipboardSummary)
                        }
                    }
                }

                Section(header: Text("shortcuts.export")) {
                    Button("shortcuts.copyShortcuts") {
                        TS3PlatformSupport.copyToPasteboard(shortcutsSnapshot)
                    }
                    Button("shortcuts.exportShortcuts") {
                        shortcutsDocument = TS3TextFileDocument(data: Data(shortcutsSnapshot.utf8))
                        isExportingShortcuts = true
                    }
                    Button("shortcuts.exportBackup") {
                        exportShortcutBackup()
                    }
                    Button("shortcuts.importBackup") {
                        isImportingShortcutBackup = true
                    }
                }

                Section(header: Text("shortcuts.manage")) {
                    Button("shortcuts.enableAll") {
                        confirmation = .enableAll
                    }
                    Button("shortcuts.disableAll") {
                        confirmation = .disableAll
                    }
                    Button("shortcuts.resetDisabled") {
                        confirmation = .resetDisabled
                    }
                    Button("shortcuts.resetAll") {
                        confirmation = .resetAll
                    }
                }
            }
            .navigationTitle("shortcuts.title")
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button("common.done") {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .fileExporter(
                isPresented: $isExportingShortcuts,
                document: shortcutsDocument,
                contentType: .plainText,
                defaultFilename: "ts3-keyboard-shortcuts"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingShortcutBackup,
                document: shortcutBackupDocument,
                contentType: .json,
                defaultFilename: "ts3-keyboard-shortcuts"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingShortcutBackup,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareShortcutBackupImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .sheet(item: $pendingShortcutImport) { confirmation in
                ShortcutImportPreviewSheet(
                    preview: confirmation.preview,
                    importBackup: { selectedActionIds in
                        importShortcutBackup(data: confirmation.data, selectedActionIds: selectedActionIds)
                        pendingShortcutImport = nil
                    },
                    cancel: {
                        pendingShortcutImport = nil
                    }
                )
            }
            .sheet(item: $captureShortcut) { shortcut in
                ShortcutCaptureSheet(shortcut: currentShortcut(for: shortcut)) { updatedKeys, isEnabled in
                    model.updateKeyboardShortcut(shortcut, keys: updatedKeys, isEnabled: isEnabled)
                }
            }
            .alert(item: $confirmation) { confirmation in
                switch confirmation {
                case .enableAll:
                    return Alert(
                        title: Text("shortcuts.enableAllAlert.title"),
                        message: Text("shortcuts.enableAllAlert.message"),
                        primaryButton: .default(Text("shortcuts.enable")) {
                            model.setAllKeyboardShortcutsEnabled(true)
                        },
                        secondaryButton: .cancel()
                    )
                case .disableAll:
                    return Alert(
                        title: Text("shortcuts.disableAllAlert.title"),
                        message: Text("shortcuts.disableAllAlert.message"),
                        primaryButton: .destructive(Text("shortcuts.disable")) {
                            model.setAllKeyboardShortcutsEnabled(false)
                        },
                        secondaryButton: .cancel()
                    )
                case .resetDisabled:
                    return Alert(
                        title: Text("shortcuts.resetDisabledAlert.title"),
                        message: Text("shortcuts.resetDisabledAlert.message"),
                        primaryButton: .destructive(Text("shortcuts.reset")) {
                            model.resetDisabledKeyboardShortcuts()
                        },
                        secondaryButton: .cancel()
                    )
                case .resetAll:
                    return Alert(
                        title: Text("shortcuts.resetAllAlert.title"),
                        message: Text("shortcuts.resetAllAlert.message"),
                        primaryButton: .destructive(Text("shortcuts.reset")) {
                            model.resetKeyboardShortcuts()
                        },
                        secondaryButton: .cancel()
                    )
                }
            }
        }
    }

    private var shortcutsSnapshot: String {
        model.keyboardShortcuts.map { shortcut in
            shortcut.clipboardSummary
        }.joined(separator: "\n")
    }

    private var shortcutCapabilitySummary: TS3KeyboardShortcutCapabilitySummary {
        TS3KeyboardShortcutCapabilitySummary(shortcuts: model.keyboardShortcuts)
    }

    private func shortcutCapabilityText(_ summary: TS3KeyboardShortcutCapabilitySummary) -> String {
        [
            String(format: NSLocalizedString("shortcuts.capability.catalystFormat", comment: ""), summary.catalystMenuCount),
            String(format: NSLocalizedString("shortcuts.capability.whisperFormat", comment: ""), summary.whisperShortcutCount),
            String(format: NSLocalizedString("shortcuts.capability.issueFormat", comment: ""), summary.invalidEnabledCount, summary.duplicateEnabledCount),
            NSLocalizedString("shortcuts.capability.iosLimit", comment: "")
        ].joined(separator: " · ")
    }

    private func shortcutKeysBinding(_ shortcut: TS3KeyboardShortcutBinding) -> Binding<String> {
        Binding(
            get: { model.keyboardShortcuts.first { $0.actionId == shortcut.actionId }?.keys ?? shortcut.keys },
            set: { model.updateKeyboardShortcut(shortcut, keys: $0, isEnabled: shortcut.isEnabled) }
        )
    }

    private func shortcutEnabledBinding(_ shortcut: TS3KeyboardShortcutBinding) -> Binding<Bool> {
        Binding(
            get: { model.keyboardShortcuts.first { $0.actionId == shortcut.actionId }?.isEnabled ?? shortcut.isEnabled },
            set: { model.updateKeyboardShortcut(shortcut, keys: shortcut.keys, isEnabled: $0) }
        )
    }

    private func currentShortcut(for shortcut: TS3KeyboardShortcutBinding) -> TS3KeyboardShortcutBinding {
        model.keyboardShortcuts.first { $0.actionId == shortcut.actionId } ?? shortcut
    }

    private func duplicateShortcutText(for shortcut: TS3KeyboardShortcutBinding) -> String? {
        let current = currentShortcut(for: shortcut)
        guard current.isEnabled, TS3KeyboardShortcutDescriptor(current.keys) != nil else { return nil }
        let normalizedKeys = current.keys.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
        let duplicates = model.keyboardShortcuts.filter {
            $0.actionId != current.actionId
                && $0.isEnabled
                && $0.keys.trimmingCharacters(in: .whitespacesAndNewlines).lowercased() == normalizedKeys
        }
        guard !duplicates.isEmpty else { return nil }
        return String(format: NSLocalizedString("shortcuts.duplicateFormat", comment: ""), duplicates.map(\.action).joined(separator: ", "))
    }

    private func exportShortcutBackup() {
        do {
            shortcutBackupDocument = TS3BookmarkFileDocument(data: try model.keyboardShortcutsExportData())
            isExportingShortcutBackup = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareShortcutBackupImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.keyboardShortcutsImportPreview(from: data)
            pendingShortcutImport = ShortcutImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importShortcutBackup(data: Data, selectedActionIds: Set<String>) {
        do {
            try model.importKeyboardShortcuts(from: data, selectedActionIds: selectedActionIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }
}

private struct ShortcutImportPreviewSheet: View {
    let preview: TS3KeyboardShortcutImportPreview
    let importBackup: (Set<String>) -> Void
    let cancel: () -> Void
    @State private var selectedActionIds: Set<String>

    init(
        preview: TS3KeyboardShortcutImportPreview,
        importBackup: @escaping (Set<String>) -> Void,
        cancel: @escaping () -> Void
    ) {
        self.preview = preview
        self.importBackup = importBackup
        self.cancel = cancel
        _selectedActionIds = State(initialValue: Set(preview.candidates.map(\.id)))
    }

    private var restoreImpactSummary: TS3KeyboardShortcutRestoreImpactSummary {
        TS3KeyboardShortcutRestoreImpactSummary(preview: preview, selectedActionIds: selectedActionIds)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text("shortcuts.importPreview")) {
                    Text(preview.clipboardSummary)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button("shortcuts.copyImportSummary") {
                        TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                    }
                }

                if !preview.candidates.isEmpty {
                    Section(header: Text("shortcuts.restoreEntries")) {
                        Toggle("shortcuts.selectAll", isOn: Binding(
                            get: { selectedActionIds.count == preview.candidates.count },
                            set: { isSelected in
                                selectedActionIds = isSelected ? Set(preview.candidates.map(\.id)) : []
                            }
                        ))
                        ServerInfoDetailRow(
                            label: NSLocalizedString("shortcuts.restoreImpact", comment: ""),
                            value: String(
                                format: NSLocalizedString("shortcuts.restoreImpactFormat", comment: ""),
                                restoreImpactSummary.selectedShortcutCount,
                                restoreImpactSummary.changedShortcutCount,
                                restoreImpactSummary.disabledShortcutCount
                            )
                        )
                        Text(shortcutRestoreImpactText(restoreImpactSummary))
                            .font(.caption2)
                            .foregroundColor(restoreImpactSummary.needsAttention ? .orange : .secondary)
                        Button("shortcuts.copyRestoreImpact") {
                            TS3PlatformSupport.copyToPasteboard(restoreImpactSummary.clipboardSummary)
                        }
                        .disabled(!restoreImpactSummary.hasSelection)
                        ForEach(preview.candidates) { candidate in
                            Toggle(isOn: Binding(
                                get: { selectedActionIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedActionIds.insert(candidate.id)
                                    } else {
                                        selectedActionIds.remove(candidate.id)
                                    }
                                }
                            )) {
                                VStack(alignment: .leading, spacing: 2) {
                                    Text(candidate.action)
                                        .font(.caption.weight(.semibold))
                                    Text(candidate.keys)
                                        .font(.caption2)
                                        .foregroundColor(.secondary)
                                    Text(shortcutCandidateDetail(candidate))
                                        .font(.caption2)
                                        .foregroundColor(candidate.isInvalid || candidate.isDuplicate ? .orange : .secondary)
                                }
                            }
                        }
                    }
                }

                if !preview.changedSummaries.isEmpty {
                    Section(header: Text("shortcuts.changedShortcuts")) {
                        ForEach(Array(preview.changedSummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .lineLimit(2)
                                .truncationMode(.middle)
                        }
                    }
                }

                if !preview.invalidSummaries.isEmpty || !preview.duplicateSummaries.isEmpty {
                    Section(header: Text("shortcuts.warnings")) {
                        ForEach(Array((preview.invalidSummaries + preview.duplicateSummaries).enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.orange)
                                .lineLimit(2)
                                .truncationMode(.middle)
                        }
                    }
                }

                if !preview.unknownSummaries.isEmpty {
                    Section(header: Text("shortcuts.ignoredEntries")) {
                        ForEach(Array(preview.unknownSummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                                .lineLimit(1)
                                .truncationMode(.middle)
                        }
                    }
                }

                Section(header: Text("shortcuts.importBehavior")) {
                    Text("shortcuts.importBehavior.summary")
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle("shortcuts.importTitle")
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button("common.cancel") {
                        cancel()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button("shortcuts.import") {
                        importBackup(selectedActionIds)
                    }
                    .disabled(selectedActionIds.isEmpty)
                }
            }
        }
    }

    private func shortcutCandidateDetail(_ candidate: TS3KeyboardShortcutImportPreview.Candidate) -> String {
        [
            candidate.group,
            candidate.isEnabled ? NSLocalizedString("shortcuts.enabled", comment: "") : NSLocalizedString("shortcuts.disabled", comment: ""),
            candidate.isChanged ? NSLocalizedString("shortcuts.changed", comment: "") : NSLocalizedString("shortcuts.unchanged", comment: ""),
            candidate.isInvalid ? NSLocalizedString("shortcuts.invalid", comment: "") : nil,
            candidate.isDuplicate ? NSLocalizedString("shortcuts.duplicate", comment: "") : nil
        ]
        .compactMap { $0 }
        .joined(separator: " · ")
    }

    private func shortcutRestoreImpactText(_ summary: TS3KeyboardShortcutRestoreImpactSummary) -> String {
        [
            String(
                format: NSLocalizedString("shortcuts.restoreImpactIssuesFormat", comment: ""),
                summary.invalidShortcutCount,
                summary.duplicateShortcutCount,
                summary.unknownShortcutCount
            ),
            String(
                format: NSLocalizedString("shortcuts.restoreImpactPlatformFormat", comment: ""),
                summary.catalystMenuShortcutCount,
                summary.whisperShortcutCount
            ),
            NSLocalizedString("shortcuts.restoreImpactIOSGlobalHotkeys", comment: "")
        ].joined(separator: " | ")
    }
}

struct ShortcutCaptureSheet: View {
    @Environment(\.presentationMode) private var presentationMode
    let shortcut: TS3KeyboardShortcutBinding
    let save: (String, Bool) -> Void

    @State private var isEnabled: Bool
    @State private var usesCommand: Bool
    @State private var usesShift: Bool
    @State private var usesOption: Bool
    @State private var usesControl: Bool
    @State private var selectedKey: String
    @State private var customKey: String

    private static let customKeyToken = "Custom"
    private static let keyOptions = [
        "A", "B", "C", "D", "E", "F", "G", "I", "K", "L", "M", "P", "R", "S", "T", "W",
        "1", "2", "3", "4", "5", "6", "7", "8", "9", "0",
        "/", ".", ",", ";", "'", "[", "]", "-", "=",
        "Return", "Space", "Tab", "Escape", "Delete",
        customKeyToken
    ]

    init(shortcut: TS3KeyboardShortcutBinding, save: @escaping (String, Bool) -> Void) {
        self.shortcut = shortcut
        self.save = save
        let parsed = Self.parse(shortcut.keys)
        _isEnabled = State(initialValue: shortcut.isEnabled)
        _usesCommand = State(initialValue: parsed.modifiers.contains("Command"))
        _usesShift = State(initialValue: parsed.modifiers.contains("Shift"))
        _usesOption = State(initialValue: parsed.modifiers.contains("Option"))
        _usesControl = State(initialValue: parsed.modifiers.contains("Control"))
        let key = parsed.key.isEmpty ? "T" : parsed.key
        if Self.keyOptions.contains(key) {
            _selectedKey = State(initialValue: key)
            _customKey = State(initialValue: "")
        } else {
            _selectedKey = State(initialValue: Self.customKeyToken)
            _customKey = State(initialValue: key)
        }
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(shortcut.action)) {
                    Toggle("shortcuts.enabled", isOn: $isEnabled)
                    Toggle("Command", isOn: $usesCommand)
                    Toggle("Shift", isOn: $usesShift)
                    Toggle("Option", isOn: $usesOption)
                    Toggle("Control", isOn: $usesControl)
                }

                Section(header: Text("shortcuts.key")) {
                    Picker("shortcuts.key", selection: $selectedKey) {
                        ForEach(Self.keyOptions, id: \.self) { key in
                            Text(key).tag(key)
                        }
                    }
                    if selectedKey == Self.customKeyToken {
                        TextField("shortcuts.singleKeyPlaceholder", text: $customKey)
                            .font(.system(.body, design: .monospaced))
                            .ts3PlainTextField()
                    }
                }

                Section(header: Text("shortcuts.preview")) {
                    Text(capturedKeys)
                        .font(.system(.body, design: .monospaced))
                    if TS3KeyboardShortcutDescriptor(capturedKeys) == nil {
                        Text("shortcuts.chooseSupportedKey")
                            .font(.caption)
                            .foregroundColor(.red)
                    }
                    if !hasModifier {
                        Text("shortcuts.noModifierWarning")
                            .font(.caption)
                            .foregroundColor(.orange)
                    }
                }

                Section {
                    Button("shortcuts.saveShortcut") {
                        save(capturedKeys, isEnabled)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(TS3KeyboardShortcutDescriptor(capturedKeys) == nil)
                    Button("shortcuts.useDefault") {
                        save(shortcut.defaultKeys, isEnabled)
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .navigationTitle("shortcuts.recordTitle")
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button("common.cancel") {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }

    private var capturedKeys: String {
        var parts: [String] = []
        if usesCommand { parts.append("Command") }
        if usesShift { parts.append("Shift") }
        if usesOption { parts.append("Option") }
        if usesControl { parts.append("Control") }
        parts.append(capturedKey)
        return parts.joined(separator: "-")
    }

    private var capturedKey: String {
        if selectedKey == Self.customKeyToken {
            return customKey.trimmingCharacters(in: .whitespacesAndNewlines)
        }
        return selectedKey
    }

    private var hasModifier: Bool {
        usesCommand || usesShift || usesOption || usesControl
    }

    private static func parse(_ keys: String) -> (modifiers: Set<String>, key: String) {
        let parts = keys
            .split(separator: "-")
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
        guard let key = parts.last else { return ([], "") }
        var modifiers: Set<String> = []
        for modifier in parts.dropLast() {
            switch modifier.lowercased() {
            case "command", "cmd", "⌘":
                modifiers.insert("Command")
            case "shift", "⇧":
                modifiers.insert("Shift")
            case "option", "alt", "⌥":
                modifiers.insert("Option")
            case "control", "ctrl", "⌃":
                modifiers.insert("Control")
            default:
                break
            }
        }
        return (modifiers, normalizedKey(key))
    }

    private static func normalizedKey(_ key: String) -> String {
        switch key.lowercased() {
        case "return", "enter":
            return "Return"
        case "escape", "esc":
            return "Escape"
        case "space":
            return "Space"
        case "tab":
            return "Tab"
        case "delete", "backspace":
            return "Delete"
        default:
            return key.count == 1 ? key.uppercased() : key
        }
    }
}

struct ConnectingView: View {
