}

struct ChannelRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let channel: TS3ChannelSummary
    let members: [TS3UserSummary]
    var hasChildChannels = false
    var isCollapsed = false
    var toggleCollapsed: (() -> Void)?
    @State private var joinPassword = ""
    @State private var defaultChannelPassword = ""
    @State private var fullInviteChannelPassword = ""
    @State private var isShowingJoinPassword = false
    @State private var isShowingDefaultChannelPassword = false
    @State private var isShowingFullInvitePassword = false
    @State private var isShowingInfo = false
    @State private var isShowingChannelMessage = false
    @State private var isShowingEdit = false
    @State private var isShowingMove = false
    @State private var isShowingPermissions = false
    @State private var isShowingFiles = false
    @State private var isShowingPrivilegeKeys = false
    @State private var isConfirmingDelete = false
    @State private var isConfirmingForcedDelete = false

    private var channelPath: String {
        model.channelPath(for: channel)
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, locale: Locale.current, arguments: arguments)
    }

    private var channelClipboardSummary: String {
        var parts = [
            "channelId=\(channel.id)",
            "name=\(channel.name)",
            "path=\(channelPath)"
        ]
        if let topic = channel.topic, !topic.isEmpty {
            parts.append("topic=\(topic)")
        }
        if let description = channel.description, !description.isEmpty {
            parts.append("description=\(description)")
        }
        if let iconId = channel.iconId, iconId != 0 {
            parts.append("iconId=\(iconId)")
        }
        parts.append("members=\(members.count)")
        return parts.joined(separator: " | ")
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 12) {
            HStack(spacing: 12) {
                if hasChildChannels {
                    Button {
                        toggleCollapsed?()
                    } label: {
                        Image(systemName: isCollapsed ? "chevron.right" : "chevron.down")
                            .frame(width: 18, height: 18)
                    }
                    .buttonStyle(.borderless)
                    .accessibilityLabel(isCollapsed ? localized("channelActions.expandChannel") : localized("channelActions.collapseChannel"))
                }
                VStack(alignment: .leading, spacing: 4) {
                    HStack(spacing: 8) {
                        Text(channel.name)
                            .fontWeight(channel.isCurrent ? .semibold : .regular)
                        if channel.isCurrent {
                            Text(localized("channelActions.current"))
                                .font(.caption.weight(.semibold))
                                .foregroundColor(.accentColor)
                                .padding(.horizontal, 8)
                                .padding(.vertical, 4)
                                .background(Color.accentColor.opacity(0.12))
                                .clipShape(Capsule())
                        }
                        if channel.isDefault {
                            Image(systemName: "house.fill")
                                .foregroundColor(.secondary)
                        }
                        if let iconId = channel.iconId, iconId != 0 {
                            ChannelIconView(channel: channel)
                        }
                        if channel.isPasswordProtected {
                            Image(systemName: "lock.fill")
                                .foregroundColor(.secondary)
                        }
                        if channel.isSubscribed == false {
                            Image(systemName: "bell.slash")
                                .foregroundColor(.secondary)
                        }
                    }
                    HStack(spacing: 6) {
                        Text(localized("channelActions.userCountFormat", members.count))
                            .font(.caption)
                            .foregroundColor(.secondary)
                        if let power = channel.neededTalkPower {
                            Text(localized("channelActions.talkPowerFormat", power))
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                        if let codecQuality = channel.codecQuality {
                            Text(localized("channelActions.qualityFormat", codecQuality))
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                        if let limitText = channelLimitText {
                            Text(limitText)
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                    }
                    if let topic = channel.topic, !topic.isEmpty {
                        Text(topic)
                            .font(.footnote)
                            .foregroundColor(.secondary)
                    }
                }
                Spacer()
                if channel.isCurrent {
                    Image(systemName: "checkmark.circle.fill")
                        .foregroundColor(.accentColor)
                } else {
                    Button(localized("channelActions.join")) {
                        if channel.isPasswordProtected {
                            isShowingJoinPassword = true
                        } else {
                            model.joinChannel(channel)
                        }
                    }
                    .buttonStyle(TS3BorderedButtonStyle())
                }
                Menu {
                    Button(localized("channelActions.channelInfo")) {
                        isShowingInfo = true
                    }
                    Button(localized("channelActions.copyChannelSummary")) {
                        TS3PlatformSupport.copyToPasteboard(channelClipboardSummary)
                    }
                    Button(localized("channelActions.copyChannelName")) {
                        TS3PlatformSupport.copyToPasteboard(channel.name)
                    }
                    Button(localized("channelActions.copyChannelPath")) {
                        TS3PlatformSupport.copyToPasteboard(channelPath)
                    }
                    Button(localized("channelActions.copyChannelInviteLink")) {
                        model.copyInviteLink(for: channel)
                    }
                    Button(localized("channelActions.copyFullChannelInviteLink")) {
                        if channel.isPasswordProtected {
                            fullInviteChannelPassword = ""
                            isShowingFullInvitePassword = true
                        } else {
                            model.copyFullInviteLink(for: channel)
                        }
                    }
                    Button(localized("channelActions.copyChannelId")) {
                        TS3PlatformSupport.copyToPasteboard("\(channel.id)")
                    }
                    Button(localized("channelActions.sendChannelMessage")) {
                        isShowingChannelMessage = true
                    }
                    if let isSubscribed = channel.isSubscribed {
                        Button(isSubscribed ? localized("channelActions.unsubscribeChannel") : localized("channelActions.subscribeChannel")) {
                            model.setChannelSubscribed(channel, isSubscribed: !isSubscribed)
                        }
                    } else {
                        Button(localized("channelActions.subscribeChannel")) {
                            model.setChannelSubscribed(channel, isSubscribed: true)
                        }
                    }
                    Button(localized("channelActions.editChannel")) {
                        isShowingEdit = true
                    }
                    Button(localized("channelActions.editChannelPermissions")) {
                        model.selectChannelPermissions(channel)
                        isShowingPermissions = true
                    }
                    Button(localized("channelActions.browseChannelFiles")) {
                        model.openFileBrowser(channel: channel)
                        isShowingFiles = true
                    }
                    if !model.channelGroups.isEmpty {
                        Button(localized("channelActions.createChannelPrivilegeKey")) {
                            isShowingPrivilegeKeys = true
                        }
                    }
                    Button(localized("channelActions.moveChannel")) {
                        isShowingMove = true
                    }
                    Button(localized("channelActions.setAsDefaultChannel")) {
                        if channel.isPasswordProtected {
                            defaultChannelPassword = ""
                            isShowingDefaultChannelPassword = true
                        } else {
                            model.setDefaultChannel(channel)
                        }
                    }
                    Button(localized("channelActions.whisperToChannel")) {
                        model.enableWhisperToChannel(id: channel.id)
                    }
                    Button(localized("channelActions.deleteChannel")) {
                        isConfirmingDelete = true
                    }
                    Button(localized("channelActions.forceDeleteChannel")) {
                        isConfirmingForcedDelete = true
                    }
                } label: {
                    Image(systemName: "ellipsis.circle")
                }
            }

            if members.isEmpty {
                Text(localized("channelActions.noUsers"))
                    .font(.footnote)
                    .foregroundColor(.secondary)
            } else {
                VStack(alignment: .leading, spacing: 8) {
                    ForEach(members) { member in
                        ChannelMemberRow(member: member)
                    }
                }
            }
        }
        .padding(.vertical, 4)
        .sheet(isPresented: $isShowingJoinPassword) {
            JoinChannelPasswordSheet(channel: channel, password: $joinPassword)
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingDefaultChannelPassword) {
            DefaultChannelPasswordSheet(channel: channel, password: $defaultChannelPassword)
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingFullInvitePassword) {
            FullChannelInvitePasswordSheet(channel: channel, password: $fullInviteChannelPassword)
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingInfo) {
            ChannelInformationSheet(channel: channel, memberCount: members.count)
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingChannelMessage) {
            ChannelMessageSheet(channel: channel)
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingEdit) {
            ChannelEditorSheet(mode: .edit(channel))
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingMove) {
            MoveChannelSheet(channel: channel)
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingPermissions) {
            PermissionsSheet()
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingFiles) {
            FileBrowserSheet()
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingPrivilegeKeys) {
            PrivilegeKeysSheet(
                initialTargetType: .channelGroup,
                initialChannelGroupId: model.channelGroups.first?.id,
                initialChannelId: channel.id
            )
            .environmentObject(model)
        }
        .alert(isPresented: $isConfirmingDelete) {
            Alert(
                title: Text(localized("channelActions.deleteChannel")),
                message: Text(channel.name),
                primaryButton: .destructive(Text(NSLocalizedString("common.delete", comment: ""))) {
                    model.deleteChannel(channel, force: false)
                },
                secondaryButton: .cancel()
            )
        }
        .background(
            EmptyView().alert(isPresented: $isConfirmingForcedDelete) {
                Alert(
                    title: Text(localized("channelActions.forceDeleteChannel")),
                    message: Text(channel.name),
                    primaryButton: .destructive(Text(localized("channelActions.forceDelete"))) {
                        model.deleteChannel(channel, force: true)
                    },
                    secondaryButton: .cancel()
                )
            }
        )
    }

    private var channelLimitText: String? {
        if channel.maxClientsUnlimited == true {
            return nil
        }
        if let maxClients = channel.maxClients, maxClients >= 0 {
            return localized("channelActions.limitFormat", maxClients)
        }
        if channel.maxFamilyClientsInherited == true || channel.maxFamilyClientsUnlimited == true {
            return nil
        }
        if let maxFamilyClients = channel.maxFamilyClients, maxFamilyClients >= 0 {
            return localized("channelActions.familyLimitFormat", maxFamilyClients)
        }
        return nil
    }
}

struct MoveChannelSheet: View {
    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    let channel: TS3ChannelSummary
    @State private var selectedParentId: Int?
    @State private var selectedOrderId: Int?

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(channel.name)) {
                    Picker(localized("moveChannel.parent"), selection: $selectedParentId) {
                        Text(localized("moveChannel.root")).tag(Optional<Int>.none)
                        ForEach(parentOptions) { parent in
                            Text(parent.name).tag(Optional(parent.id))
                        }
                    }
                    Picker(localized("moveChannel.position"), selection: $selectedOrderId) {
                        Text(localized("moveChannel.first")).tag(Optional<Int>.none)
                        ForEach(siblingOptions) { sibling in
                            Text(localized("moveChannel.afterFormat", sibling.name)).tag(Optional(sibling.id))
                        }
                    }
                }
                Section(header: Text(localized("moveChannel.preview"))) {
                    if let warning = moveWarning {
                        Text(warning)
                            .foregroundColor(.red)
                    } else {
                        Text(movePreview)
                            .font(.caption)
                            .foregroundColor(.secondary)
                        if !targetSiblingsPreview.isEmpty {
                            ForEach(targetSiblingsPreview, id: \.self) { line in
                                Text(line)
                                    .font(.caption2)
                                    .foregroundColor(.secondary)
                            }
                        }
                    }
                }
                Section {
                    Button(localized("moveChannel.move")) {
                        model.moveChannel(channel, toParentId: selectedParentId, order: selectedOrderId)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canSubmit)
                }
            }
            .navigationTitle(localized("moveChannel.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                selectedParentId = normalizedParentId(channel.parentId)
                selectedOrderId = normalizedOrderId(channel.order)
            }
            .onChange(of: selectedParentId) { _ in
                selectedOrderId = nil
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(NSLocalizedString("common.cancel", comment: "")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }

    private var parentOptions: [TS3ChannelSummary] {
        ChannelTreeItem.flatten(channels: model.channels)
            .map(\.channel)
            .filter { candidate in
                candidate.id != channel.id && !isDescendant(candidate, of: channel)
            }
    }

    private var siblingOptions: [TS3ChannelSummary] {
        orderedSiblings(
            model.channels.filter { candidate in
                candidate.id != channel.id
                    && normalizedParentId(candidate.parentId) == selectedParentId
            }
        )
    }

    private var canSubmit: Bool {
        moveWarning == nil && !isUnchangedMove
    }

    private var isUnchangedMove: Bool {
        selectedParentId == normalizedParentId(channel.parentId)
            && selectedOrderId == normalizedOrderId(channel.order)
    }

    private var moveWarning: String? {
        if let selectedParentId, !parentOptions.contains(where: { $0.id == selectedParentId }) {
            return localized("moveChannel.invalidParent")
        }
        if isUnchangedMove {
            return localized("moveChannel.unchangedPosition")
        }
        return nil
    }

    private var movePreview: String {
        let parentName = selectedParentId.flatMap { id in
            model.channels.first { $0.id == id }?.name
        } ?? localized("moveChannel.root")
        let position = selectedOrderId.flatMap { id in
            model.channels.first { $0.id == id }?.name
        }.map { localized("moveChannel.afterLowerFormat", $0) } ?? localized("moveChannel.firstLower")
        return localized("moveChannel.previewFormat", channel.name, parentName, position)
    }

    private var targetSiblingsPreview: [String] {
        var lines: [String] = []
        let siblings = siblingOptions
        if siblings.isEmpty {
            lines.append(localized("moveChannel.noVisibleSiblings"))
        } else {
            let names = siblings.prefix(5).map(\.name).joined(separator: ", ")
            lines.append(localized("moveChannel.visibleSiblingsFormat", names))
            if siblings.count > 5 {
                lines.append(localized("moveChannel.moreSiblingsFormat", siblings.count - 5))
            }
        }
        return lines
    }

    private func isDescendant(_ candidate: TS3ChannelSummary, of channel: TS3ChannelSummary) -> Bool {
        var parent = normalizedParentId(candidate.parentId)
        while let parentId = parent {
            if parentId == channel.id {
                return true
            }
            parent = normalizedParentId(model.channels.first { $0.id == parentId }?.parentId)
        }
        return false
    }

    private func normalizedParentId(_ parentId: Int?) -> Int? {
        guard let parentId, parentId > 0 else { return nil }
        return parentId
    }

    private func normalizedOrderId(_ orderId: Int?) -> Int? {
        guard let orderId, orderId > 0 else { return nil }
        return orderId
    }

    private func orderedSiblings(_ channels: [TS3ChannelSummary]) -> [TS3ChannelSummary] {
        let ids = Set(channels.map(\.id))
        let byPreviousId = Dictionary(grouping: channels) { channel -> Int? in
            guard let previousId = channel.order, ids.contains(previousId) else { return nil }
            return previousId
        }
        var visited: Set<Int> = []
        var result: [TS3ChannelSummary] = []

        func stableSort(_ lhs: TS3ChannelSummary, _ rhs: TS3ChannelSummary) -> Bool {
            if lhs.order != rhs.order {
                return (lhs.order ?? Int.min) < (rhs.order ?? Int.min)
            }
            if lhs.name != rhs.name {
                return lhs.name.localizedCaseInsensitiveCompare(rhs.name) == .orderedAscending
            }
            return lhs.id < rhs.id
        }

        func appendChain(startingAt channel: TS3ChannelSummary) {
            var current: TS3ChannelSummary? = channel
            while let channel = current, !visited.contains(channel.id) {
                visited.insert(channel.id)
                result.append(channel)
                current = byPreviousId[channel.id]?.sorted(by: stableSort).first {
                    !visited.contains($0.id)
                }
            }
        }

        for channel in (byPreviousId[nil] ?? []).sorted(by: stableSort) {
            appendChain(startingAt: channel)
        }
        for channel in channels.sorted(by: stableSort) where !visited.contains(channel.id) {
            appendChain(startingAt: channel)
        }
        return result
    }
}

struct ChannelInformationSheet: View {
    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    let channel: TS3ChannelSummary
    let memberCount: Int
    @State private var isExportingSnapshot = false
    @State private var snapshotDocument = TS3TextFileDocument()

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("channelInfo.snapshot"))) {
                    Button(localized("channelInfo.copy")) {
                        TS3PlatformSupport.copyToPasteboard(informationSnapshot)
                    }
                    .disabled(informationSnapshot.isEmpty)
                    Button(localized("channelInfo.export")) {
                        snapshotDocument = TS3TextFileDocument(data: Data(informationSnapshot.utf8))
                        isExportingSnapshot = true
                    }
                    .disabled(informationSnapshot.isEmpty)
                }

                Section(header: Text(channel.name)) {
                    ServerInfoDetailRow(label: localized("channelInfo.channelId"), value: String(channel.id))
                    ServerInfoDetailRow(label: localized("channelInfo.uniqueId"), value: channel.uniqueIdentifier, monospaced: true)
                    ServerInfoDetailRow(label: localized("channelInfo.parent"), value: parentName)
                    ServerInfoDetailRow(label: localized("channelInfo.orderAfter"), value: orderName)
                    ServerInfoDetailRow(label: localized("channelInfo.type"), value: channelTypeText)
                    ServerInfoDetailRow(label: localized("channelInfo.defaultChannel"), value: yesNo(channel.isDefault))
                    ServerInfoDetailRow(label: localized("channelInfo.password"), value: channel.isPasswordProtected ? localized("channelInfo.protected") : localized("channelInfo.notProtected"))
                    ServerInfoDetailRow(label: localized("channelInfo.subscribed"), value: channel.isSubscribed.map(yesNo))
                    ServerInfoDetailRow(label: localized("channelInfo.iconId"), value: channel.iconId.map(String.init))
                    ServerInfoDetailRow(label: localized("channelInfo.members"), value: String(memberCount))
                    ServerInfoDetailRow(label: localized("channelInfo.directClients"), value: channel.totalClients.map(String.init))
                    ServerInfoDetailRow(label: localized("channelInfo.familyClients"), value: channel.totalClientsFamily.map(String.init))
                }

                Section(header: Text(localized("channelInfo.text"))) {
                    ServerInfoDetailRow(label: localized("channelInfo.phoneticName"), value: channel.phoneticName)
                    ServerInfoDetailRow(label: localized("channelInfo.topic"), value: channel.topic)
                    ServerInfoDetailRow(label: localized("channelInfo.description"), value: channel.description)
                    ServerInfoDetailRow(label: localized("channelInfo.filePath"), value: channel.filePath)
                    ServerInfoDetailRow(label: localized("channelInfo.bannerGraphic"), value: channel.bannerGraphicsURL)
                    ServerInfoDetailRow(label: localized("channelInfo.bannerMode"), value: channel.bannerMode.map(bannerModeText))
                }

                Section(header: Text(localized("channelInfo.audio"))) {
                    ServerInfoDetailRow(label: localized("channelInfo.codecProfile"), value: codecConfigurationProfileText)
                    ServerInfoDetailRow(label: localized("channelInfo.codec"), value: codecText)
                    ServerInfoDetailRow(label: localized("channelInfo.codecQuality"), value: codecQualityText)
                    ServerInfoDetailRow(label: localized("channelInfo.codecLatencyFactor"), value: channel.codecLatencyFactor.map(String.init))
                    ServerInfoDetailRow(label: localized("channelInfo.unencryptedVoice"), value: channel.isCodecUnencrypted.map(yesNo))
                    if !codecConfigurationMessages.isEmpty {
                        ForEach(codecConfigurationMessages, id: \.self) { message in
                            Text(message)
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                    }
                    Button(localized("channelInfo.copyCodecSummary")) {
                        TS3PlatformSupport.copyToPasteboard(codecConfiguration.clipboardSummary)
                    }
                    ServerInfoDetailRow(label: localized("channelInfo.forcedSilence"), value: channel.isForcedSilence.map(yesNo))
                    ServerInfoDetailRow(label: localized("channelInfo.neededTalkPower"), value: channel.neededTalkPower.map(String.init))
                    ServerInfoDetailRow(label: localized("channelInfo.neededJoinPower"), value: channel.neededJoinPower.map(String.init))
                    ServerInfoDetailRow(label: localized("channelInfo.neededSubscribePower"), value: channel.neededSubscribePower.map(String.init))
                    ServerInfoDetailRow(label: localized("channelInfo.neededModifyPower"), value: channel.neededModifyPower.map(String.init))
                    ServerInfoDetailRow(label: localized("channelInfo.neededDeletePower"), value: channel.neededDeletePower.map(String.init))
                    ServerInfoDetailRow(label: localized("channelInfo.neededDescriptionViewPower"), value: channel.neededDescriptionViewPower.map(String.init))
                }

                Section(header: Text(localized("channelInfo.limits"))) {
                    ServerInfoDetailRow(label: localized("channelInfo.limitState"), value: limitStateText)
                    ServerInfoDetailRow(label: localized("channelInfo.maxClients"), value: maxClientsText)
                    ServerInfoDetailRow(label: localized("channelInfo.maxFamilyClients"), value: maxFamilyClientsText)
                    ServerInfoDetailRow(label: localized("channelInfo.deleteDelay"), value: channel.deleteDelaySeconds.map { localized("channelInfo.secondsFormat", $0) })
                    ServerInfoDetailRow(label: localized("channelInfo.secondsEmpty"), value: channel.secondsEmpty.map { localized("channelInfo.secondsFormat", $0) })
                    Button(localized("channelInfo.copyLimitSummary")) {
                        TS3PlatformSupport.copyToPasteboard(limitSummary.clipboardSummary)
                    }
                }
            }
            .fileExporter(
                isPresented: $isExportingSnapshot,
                document: snapshotDocument,
                contentType: .plainText,
                defaultFilename: "ts3-channel-\(channel.id)"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .navigationTitle(localized("channelInfo.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(NSLocalizedString("common.done", comment: "")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }

    private var parentName: String {
        guard let parentId = normalizedId(channel.parentId) else { return localized("channelInfo.root") }
        return model.channels.first { $0.id == parentId }?.name ?? localized("channelInfo.channelWithIdFormat", parentId)
    }

    private var orderName: String? {
        guard let orderId = normalizedId(channel.order) else { return localized("channelInfo.first") }
        return model.channels.first { $0.id == orderId }?.name ?? localized("channelInfo.channelWithIdFormat", orderId)
    }

    private var channelTypeText: String {
        if channel.isPermanent {
            return localized("channelInfo.channelType.permanent")
        }
        if channel.isSemiPermanent == true {
            return localized("channelInfo.channelType.semiPermanent")
        }
        return localized("channelInfo.channelType.temporary")
    }

    private var codecText: String? {
        guard let codec = channel.codec else { return nil }
        let title: String
        switch TS3ChannelCodec(rawValue: codec) {
        case .some(.speexNarrowband):
            title = localized("channelInfo.codec.speexNarrowband")
        case .some(.speexWideband):
            title = localized("channelInfo.codec.speexWideband")
        case .some(.speexUltraWideband):
            title = localized("channelInfo.codec.speexUltraWideband")
        case .some(.celtMono):
            title = localized("channelInfo.codec.celtMono")
        case .some(.opusVoice):
            title = localized("channelInfo.codec.opusVoice")
        case .some(.opusMusic):
            title = localized("channelInfo.codec.opusMusic")
        case nil:
            return localized("channelInfo.unknownValueFormat", codec)
        }
        return localized("channelInfo.valueWithNumberFormat", title, codec)
    }

    private var codecQualityText: String? {
        guard let quality = channel.codecQuality else { return nil }
        return TS3ChannelCodecConstraints.qualityRange.contains(quality)
            ? localized("channelInfo.qualityFormat", quality)
            : localized("channelInfo.unknownValueFormat", quality)
    }

    private var maxClientsText: String? {
        if channel.maxClientsUnlimited == true { return localized("channelInfo.unlimited") }
        return channel.maxClients.map(String.init)
    }

    private var maxFamilyClientsText: String? {
        if channel.maxFamilyClientsInherited == true { return localized("channelInfo.inherited") }
        if channel.maxFamilyClientsUnlimited == true { return localized("channelInfo.unlimited") }
        return channel.maxFamilyClients.map(String.init)
    }

    private var limitSummary: TS3ChannelLimitSummary {
        TS3ChannelLimitSummary(channel: channel)
    }

    private var limitStateText: String {
        [
            localized("channelInfo.directLimitStateFormat", limitStateTitle(limitSummary.directState)),
            localized("channelInfo.familyLimitStateFormat", limitStateTitle(limitSummary.familyState))
        ].joined(separator: ", ")
    }

    private func limitStateTitle(_ state: TS3ChannelLimitSummary.LimitState) -> String {
        switch state {
        case .unknown:
            return localized("channelInfo.limitState.unknown")
        case .unlimited:
            return localized("channelInfo.limitState.unlimited")
        case .available:
            return localized("channelInfo.limitState.available")
        case .nearLimit:
            return localized("channelInfo.limitState.nearLimit")
        case .full:
            return localized("channelInfo.limitState.full")
        case .overLimit:
            return localized("channelInfo.limitState.overLimit")
        }
    }

    private func normalizedId(_ id: Int?) -> Int? {
        guard let id, id > 0 else { return nil }
        return id
    }

    private func yesNo(_ value: Bool) -> String {
        value ? localized("channelInfo.yes") : localized("channelInfo.no")
    }

    private var informationSnapshot: String {
        let rows: [(String, String?)] = [
            (localized("channelInfo.channelId"), String(channel.id)),
            (localized("channelInfo.uniqueId"), channel.uniqueIdentifier),
            (localized("channelInfo.name"), channel.name),
            (localized("channelInfo.path"), model.channelPath(for: channel)),
            (localized("channelInfo.parent"), parentName),
            (localized("channelInfo.orderAfter"), orderName),
            (localized("channelInfo.type"), channelTypeText),
            (localized("channelInfo.defaultChannel"), yesNo(channel.isDefault)),
            (localized("channelInfo.password"), channel.isPasswordProtected ? localized("channelInfo.protected") : localized("channelInfo.notProtected")),
            (localized("channelInfo.subscribed"), channel.isSubscribed.map(yesNo)),
            (localized("channelInfo.iconId"), channel.iconId.map(String.init)),
            (localized("channelInfo.members"), String(memberCount)),
            (localized("channelInfo.directClients"), channel.totalClients.map(String.init)),
            (localized("channelInfo.familyClients"), channel.totalClientsFamily.map(String.init)),
            (localized("channelInfo.phoneticName"), channel.phoneticName),
            (localized("channelInfo.topic"), channel.topic),
            (localized("channelInfo.description"), channel.description),
            (localized("channelInfo.filePath"), channel.filePath),
            (localized("channelInfo.bannerGraphic"), channel.bannerGraphicsURL),
            (localized("channelInfo.bannerMode"), channel.bannerMode.map(bannerModeText)),
            (localized("channelInfo.codecProfile"), codecConfigurationProfileText),
            (localized("channelInfo.codec"), codecText),
            (localized("channelInfo.codecQuality"), codecQualityText),
            (localized("channelInfo.codecLatencyFactor"), channel.codecLatencyFactor.map(String.init)),
            (localized("channelInfo.unencryptedVoice"), channel.isCodecUnencrypted.map(yesNo)),
            (localized("channelInfo.codecDiagnostics"), codecConfigurationMessages.joined(separator: "; ")),
            (localized("channelInfo.forcedSilence"), channel.isForcedSilence.map(yesNo)),
            (localized("channelInfo.neededTalkPower"), channel.neededTalkPower.map(String.init)),
            (localized("channelInfo.neededJoinPower"), channel.neededJoinPower.map(String.init)),
            (localized("channelInfo.neededSubscribePower"), channel.neededSubscribePower.map(String.init)),
            (localized("channelInfo.neededModifyPower"), channel.neededModifyPower.map(String.init)),
            (localized("channelInfo.neededDeletePower"), channel.neededDeletePower.map(String.init)),
            (localized("channelInfo.neededDescriptionViewPower"), channel.neededDescriptionViewPower.map(String.init)),
            (localized("channelInfo.limitState"), limitStateText),
            (localized("channelInfo.limitSummary"), limitSummary.clipboardSummary),
            (localized("channelInfo.maxClients"), maxClientsText),
            (localized("channelInfo.maxFamilyClients"), maxFamilyClientsText),
            (localized("channelInfo.deleteDelay"), channel.deleteDelaySeconds.map { localized("channelInfo.secondsFormat", $0) }),
            (localized("channelInfo.secondsEmpty"), channel.secondsEmpty.map { localized("channelInfo.secondsFormat", $0) })
        ]
        return rows
            .compactMap { label, value in
                guard let value, !value.isEmpty else { return nil }
                return "\(label): \(value)"
            }
            .joined(separator: "\n")
    }

    private func bannerModeText(_ value: Int) -> String {
        let title: String
        switch TS3HostBannerMode(rawValue: value) {
        case .some(.noAdjust):
            title = localized("channelInfo.bannerMode.noAdjustment")
        case .some(.ignoreAspect):
            title = localized("channelInfo.bannerMode.ignoreAspect")
        case .some(.keepAspect):
            title = localized("channelInfo.bannerMode.keepAspect")
        case nil:
            return localized("channelInfo.unknownValueFormat", value)
        }
        return localized("channelInfo.valueWithNumberFormat", title, value)
    }

    private var codecConfiguration: TS3ChannelCodecConfigurationSummary {
        TS3ChannelCodecConfigurationSummary(
            codec: channel.codec,
            codecQuality: channel.codecQuality,
            codecLatencyFactor: channel.codecLatencyFactor,
            isCodecUnencrypted: channel.isCodecUnencrypted
        )
    }

    private var codecConfigurationProfileText: String {
        codecConfigurationProfileText(codecConfiguration.profile)
    }

    private func codecConfigurationProfileText(_ profile: TS3ChannelCodecConfigurationSummary.Profile) -> String {
        switch profile {
        case .unchanged:
            return localized("channelInfo.codecProfile.unchanged")
        case .voice:
            return localized("channelInfo.codecProfile.voice")
        case .music:
            return localized("channelInfo.codecProfile.music")
        case .compatibility:
            return localized("channelInfo.codecProfile.compatibility")
        case .highQuality:
            return localized("channelInfo.codecProfile.highQuality")
        case .lowLatency:
            return localized("channelInfo.codecProfile.lowLatency")
        case .custom:
            return localized("channelInfo.codecProfile.custom")
        }
    }

    private var codecConfigurationMessages: [String] {
        var messages: [String] = []
        if codecConfiguration.hasInvalidQuality {
            messages.append(localized("channelInfo.codecQualityRangeWarning"))
        }
        if codecConfiguration.hasInvalidLatencyFactor {
            messages.append(localized("channelInfo.codecLatencyRangeWarning"))
        }
        if codecConfiguration.usesLegacyCodec {
            messages.append(localized("channelInfo.legacyCodecWarning"))
        }
        if codecConfiguration.disablesVoiceEncryption {
            messages.append(localized("channelInfo.voiceEncryptionDisabledWarning"))
        }
        return messages
    }
}

struct ChannelIconView: View {
    let channel: TS3ChannelSummary

    var body: some View {
        Group {
            if let image = platformImage {
                Image(ts3PlatformImage: image)
                    .resizable()
                    .scaledToFit()
            } else {
                Image(systemName: "seal.fill")
                    .resizable()
                    .scaledToFit()
                    .foregroundColor(.secondary)
            }
        }
        .frame(width: 16, height: 16)
        .accessibilityLabel("Icon \(channel.iconId ?? 0)")
    }

    private var platformImage: TS3PlatformImage? {
        guard let iconURL = channel.iconURL else { return nil }
        return TS3PlatformImage(contentsOfFile: iconURL.path)
    }
}

enum UserActionMode: Identifiable {
    case info
    case privateMessage
    case offlineMessage
    case poke
    case editDescription
    case contactNote
    case complain
    case kickChannel
    case kickServer
    case ban

    var id: String {
        switch self {
        case .info: return "info"
        case .privateMessage: return "privateMessage"
        case .offlineMessage: return "offlineMessage"
        case .poke: return "poke"
        case .editDescription: return "editDescription"
        case .contactNote: return "contactNote"
        case .complain: return "complain"
        case .kickChannel: return "kickChannel"
        case .kickServer: return "kickServer"
        case .ban: return "ban"
        }
    }
}

enum DatabaseClientActionMode: Identifiable {
    case offlineMessage
    case contactNote
    case complain
    case ban

    var id: String {
        switch self {
        case .offlineMessage:
            return "offlineMessage"
        case .contactNote:
            return "contactNote"
        case .complain:
            return "complain"
        case .ban:
            return "ban"
        }
    }
}

struct ChannelMemberRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let member: TS3UserSummary
    @State private var actionMode: UserActionMode?
    @State private var isShowingPlaybackSettings = false
    @State private var isShowingPermissions = false
    @State private var isShowingDatabaseClient = false
    @State private var passwordMoveChannel: TS3ChannelSummary?
    @State private var movePassword = ""

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, locale: Locale.current, arguments: arguments)
    }

    private var memberClipboardSummary: String {
        var parts = [
            "clientId=\(member.id)",
            "nickname=\(member.nickname)",
            "channelId=\(member.channelId)"
        ]
        if let databaseId = member.databaseId {
            parts.append("databaseId=\(databaseId)")
        }
        if let uniqueIdentifier = member.uniqueIdentifier, !uniqueIdentifier.isEmpty {
            parts.append("uid=\(uniqueIdentifier)")
        }
        if let ipAddress = member.ipAddress, !ipAddress.isEmpty {
            parts.append("ip=\(ipAddress)")
        }
        if let country = member.country, !country.isEmpty {
            parts.append("country=\(country)")
        }
        if let platform = member.platform, !platform.isEmpty {
            parts.append("platform=\(platform)")
        }
        if let version = member.version, !version.isEmpty {
            parts.append("version=\(version)")
        }
        return parts.joined(separator: " | ")
    }

    var body: some View {
        HStack(spacing: 10) {
            UserAvatarView(user: member)
            VStack(alignment: .leading, spacing: 2) {
                HStack(spacing: 4) {
                    Text(member.nickname)
                        .font(.subheadline)
                        .foregroundColor(.primary)
                    UserIconView(user: member)
                }
                HStack(spacing: 8) {
                    if contactStatus == .friend {
                        Text(localized("contacts.status.friend"))
                    }
                    if contactStatus == .blocked {
                        Text(localized("contacts.status.blocked"))
                    }
                    if member.isAway {
                        Text(member.awayMessage?.isEmpty == false ? localized("clientActions.awayMessageFormat", member.awayMessage!) : localized("selfStatus.away"))
                    }
                    if member.isInputMuted {
                        Text(localized("clientActions.micMuted"))
                    }
                    if member.isOutputMuted {
                        Text(localized("clientActions.soundMuted"))
                    }
                    if isPlaybackMuted {
                        Text(localized("clientActions.locallyMuted"))
                    } else if playbackPreference.volume != 1 {
                        Text(localized("clientActions.volumeFormat", model.playbackVolumePercentText(for: member)))
                    }
                    if member.isChannelCommander {
                        Text(localized("clientActions.commander"))
                    }
                    if member.isPrioritySpeaker {
                        Text(localized("clientActions.priority"))
                    }
                    if member.isTalker {
                        Text(localized("clientActions.talker"))
                    }
                    if member.isRequestingTalkPower {
                        Text(localized("clientActions.wantsTalk"))
                    }
                    if let talkRequestMessage = member.talkRequestMessage, !talkRequestMessage.isEmpty {
                        Text(localized("clientActions.requestFormat", talkRequestMessage))
                            .lineLimit(2)
                    }
                    if let power = member.talkPower {
                        Text(localized("channelActions.talkPowerFormat", power))
                    }
                    if let channelGroupId = member.channelGroupId {
                        Text(localized("clientActions.channelGroupFormat", TS3GroupSummary.name(for: channelGroupId, in: model.channelGroups)))
                    }
                }
                .font(.caption)
                .foregroundColor(.secondary)
                if !member.serverGroups.isEmpty {
                    Text(localized("clientActions.serverGroupsFormat", serverGroupNames))
                        .font(.caption)
                        .foregroundColor(.secondary)
                        .lineLimit(1)
                }
                if let description = member.description, !description.isEmpty {
                    Text(description)
                        .font(.caption)
                        .foregroundColor(.secondary)
                        .lineLimit(2)
                }
                if let note = model.contactNote(for: member) {
                    Text(localized("clientActions.noteFormat", note))
                        .font(.caption)
                        .foregroundColor(.secondary)
                        .lineLimit(2)
                }
            }
            if member.isCurrentUser {
                Text(localized("clientActions.you"))
                    .font(.caption.weight(.semibold))
                    .foregroundColor(.accentColor)
                    .padding(.horizontal, 8)
                    .padding(.vertical, 4)
                    .background(Color.accentColor.opacity(0.12))
                    .clipShape(Capsule())
            }
            Spacer()
            Menu {
                Button(localized("contacts.row.clientInfo")) {
                    actionMode = .info
                }
                Button(localized("clientActions.copyClientSummary")) {
                    TS3PlatformSupport.copyToPasteboard(memberClipboardSummary)
                }
                Button(localized("contacts.row.copyNickname")) {
                    TS3PlatformSupport.copyToPasteboard(member.nickname)
                }
                Button(localized("selfStatus.copyClientId")) {
                    TS3PlatformSupport.copyToPasteboard("\(member.id)")
                }
                if let databaseId = member.databaseId {
                    Button(localized("selfStatus.copyDatabaseId")) {
                        TS3PlatformSupport.copyToPasteboard("\(databaseId)")
                    }
                }
                if let uniqueIdentifier = member.uniqueIdentifier, !uniqueIdentifier.isEmpty {
                    Button(localized("contacts.row.copyUniqueId")) {
                        TS3PlatformSupport.copyToPasteboard(uniqueIdentifier)
                    }
                }
                if let ipAddress = member.ipAddress, !ipAddress.isEmpty {
                    Button(localized("clientActions.copyIpAddress")) {
                        TS3PlatformSupport.copyToPasteboard(ipAddress)
                    }
                }
                Button(localized("contacts.row.sendPrivateMessage")) {
                    actionMode = .privateMessage
                }
                Button(localized("clientActions.sendOfflineMessage")) {
                    actionMode = .offlineMessage
                }
                Button(localized("contacts.row.poke")) {
                    actionMode = .poke
                }
                if !member.isCurrentUser {
                    Button(localized("clientActions.complain")) {
                        actionMode = .complain
                    }
                    Button(localized("database.viewComplaints")) {
                        model.showComplaints(for: member)
                    }
                }
                Button(localized("clientActions.whisperToUser")) {
                    model.enableWhisperToClient(member)
                }
                if !member.isCurrentUser {
                    Menu(localized("clientActions.localPlayback")) {
                        Button(isPlaybackMuted ? localized("clientActions.unmuteLocally") : localized("clientActions.muteLocally")) {
                            model.setPlaybackMuted(!isPlaybackMuted, for: member)
                        }
                        .disabled(contactStatus == .blocked)
                        Button(localized("clientActions.adjustVolume")) {
                            isShowingPlaybackSettings = true
                        }
                        Button(localized("clientActions.resetVolume")) {
                            model.updatePlaybackVolume(1, for: member)
                            model.setPlaybackMuted(false, for: member)
                        }
                        .disabled(!playbackPreference.isMuted && playbackPreference.volume == 1)
                    }
                }
                Button(localized("clientActions.refreshDetails")) {
                    model.refreshUserDetails(member)
                }
                Button(localized("clientActions.viewDatabaseClient")) {
                    if let record = TS3DatabaseClientSummary(user: member) {
                        model.loadDatabaseClientDetails(record)
                        isShowingDatabaseClient = true
                    }
                }
                .disabled(member.databaseId == nil)
                Button(localized("selfStatus.downloadAvatar")) {
                    model.refreshUserAvatar(member)
                }
                Button(localized("database.editDescription")) {
                    actionMode = .editDescription
                }
                Button(localized("clientActions.editChannelClientPermissions")) {
                    model.selectChannelClientPermissions(member)
                    isShowingPermissions = member.databaseId != nil
                }
                .disabled(member.databaseId == nil)
                if member.uniqueIdentifier != nil {
                    Menu(localized("clientActions.contact")) {
                        Button(localized("clientActions.openContactManager")) {
                            model.showContacts(for: member)
                        }
                        Button(localized("clientActions.markAsFriend")) {
                            model.setContactStatus(.friend, for: member)
                        }
                        .disabled(contactStatus == .friend)
                        Button(localized("clientActions.blockContact")) {
                            model.setContactStatus(.blocked, for: member)
                        }
                        .disabled(contactStatus == .blocked)
                        Button(localized("clientActions.ignoreContact")) {
                            model.setContactStatus(.ignored, for: member)
                        }
                        .disabled(contactStatus == .ignored)
                        Button(localized("clientActions.setNeutral")) {
                            model.setContactStatus(.neutral, for: member)
                        }
                        .disabled(contactStatus == .neutral && model.contactNote(for: member) == nil)
                        Button(localized("clientActions.editNote")) {
                            actionMode = .contactNote
                        }
                    }
                }
                if member.isPrioritySpeaker {
                    Button(localized("selfStatus.removePrioritySpeaker")) {
                        model.setPrioritySpeaker(false, for: member)
                    }
                } else {
                    Button(localized("selfStatus.grantPrioritySpeaker")) {
                        model.setPrioritySpeaker(true, for: member)
                    }
                }
                if member.isTalker {
                    Button(localized("clientActions.removeTalkPower")) {
                        model.setTalker(false, for: member)
                    }
                } else {
                    Button(member.isRequestingTalkPower ? localized("clientActions.grantTalkPower") : localized("selfStatus.markAsTalker")) {
                        model.setTalker(true, for: member)
                    }
                    if member.isRequestingTalkPower {
                        Button(localized("clientActions.denyTalkRequest")) {
                            model.denyTalkRequest(for: member)
                        }
                    }
                }
                Menu(localized("clientActions.moveTo")) {
                    ForEach(model.channels) { channel in
                        Button(channel.name) {
                            if channel.isPasswordProtected {
                                movePassword = ""
                                passwordMoveChannel = channel
                            } else {
                                model.moveUser(member, to: channel)
                            }
                        }
                    }
                }
                if !member.isCurrentUser {
                    Button(localized("clientActions.kickFromChannel")) {
                        actionMode = .kickChannel
                    }
                    Button(localized("clientActions.kickFromServer")) {
                        actionMode = .kickServer
                    }
                    Button(localized("clientActions.ban")) {
                        actionMode = .ban
                    }
                }
                if !availableServerGroups.isEmpty {
                    Menu(localized("clientActions.addServerGroup")) {
                        ForEach(availableServerGroups) { group in
                            Button(group.name) {
                                model.addServerGroup(group, to: member)
                            }
                        }
                    }
                }
                if !assignedServerGroups.isEmpty {
                    Menu(localized("clientActions.removeServerGroup")) {
                        ForEach(assignedServerGroups) { group in
                            Button(group.name) {
                                model.removeServerGroup(group, from: member)
                            }
                        }
                    }
                }
                if !model.channelGroups.isEmpty, let channel = model.channels.first(where: { $0.id == member.channelId }) {
                    Menu(localized("clientActions.setChannelGroup")) {
                        ForEach(model.channelGroups) { group in
                            Button(group.name) {
                                model.setChannelGroup(group, for: member, in: channel)
                            }
                        }
                    }
                }
            } label: {
                Image(systemName: "ellipsis.circle")
            }
        }
        .sheet(item: $actionMode) { mode in
            UserActionSheet(mode: mode, user: member)
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingPlaybackSettings) {
            UserPlaybackSheet(user: member)
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingPermissions) {
            PermissionsSheet()
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingDatabaseClient) {
            ClientDatabaseSheet()
                .environmentObject(model)
        }
        .sheet(item: $passwordMoveChannel) { channel in
            MoveUserPasswordSheet(user: member, channel: channel, password: $movePassword)
                .environmentObject(model)
        }
    }

    private var assignedServerGroups: [TS3GroupSummary] {
        model.serverGroups.filter { member.serverGroups.contains($0.id) }
    }

    private var availableServerGroups: [TS3GroupSummary] {
        model.serverGroups.filter { !member.serverGroups.contains($0.id) }
    }

    private var serverGroupNames: String {
        member.serverGroups
            .map { TS3GroupSummary.name(for: $0, in: model.serverGroups) }
            .joined(separator: ", ")
    }

    private var contactStatus: TS3ContactStatus {
        model.contactStatus(for: member)
    }

    private var playbackPreference: TS3UserPlaybackPreference {
        model.userPlaybackPreference(for: member)
    }

    private var isPlaybackMuted: Bool {
        model.isPlaybackMuted(for: member)
    }
}

struct UserActionSheet: View {
    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    let mode: UserActionMode
    let user: TS3UserSummary
    @State private var subject = ""
    @State private var text = ""
    @State private var banDuration: TS3BanDuration = .permanent
    @State private var customBanMinutes = "60"
    @State private var isExportingInfo = false
    @State private var infoExportDocument = TS3TextFileDocument()

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, locale: Locale.current, arguments: arguments)
    }

    var title: String {
        switch mode {
        case .info: return localized("contacts.row.clientInfo")
        case .privateMessage: return localized("clientActions.privateMessage")
        case .offlineMessage: return localized("clientActions.offlineMessage")
        case .poke: return localized("contacts.row.poke")
        case .editDescription: return localized("database.editDescription")
        case .contactNote: return localized("clientActions.contactNote")
        case .complain: return localized("clientActions.complain")
        case .kickChannel: return localized("clientActions.kickFromChannel")
        case .kickServer: return localized("clientActions.kickFromServer")
        case .ban: return localized("clientActions.banUser")
        }
    }

    var fieldTitle: String {
        switch mode {
        case .info: return localized("clientActions.details")
        case .privateMessage: return localized("clientActions.message")
        case .offlineMessage: return localized("clientActions.message")
        case .poke: return localized("clientActions.pokeMessage")
        case .editDescription: return localized("temporaryPasswords.description")
        case .contactNote: return localized("clientActions.note")
        case .complain: return localized("complaints.complaint")
        case .kickChannel, .kickServer, .ban: return localized("clientActions.reason")
        }
    }

    var actionTitle: String {
        switch mode {
        case .info: return localized("clientActions.refresh")
        case .privateMessage: return localized("clientActions.send")
        case .offlineMessage: return localized("clientActions.send")
        case .poke: return localized("contacts.row.poke")
        case .editDescription: return localized("common.save")
        case .contactNote: return localized("common.save")
        case .complain: return localized("clientActions.submitComplaint")
        case .kickChannel, .kickServer: return localized("clientActions.kick")
        case .ban: return localized("clientActions.ban")
        }
    }

    var body: some View {
        NavigationView {
            Form {
                if mode == .info {
                    Section(header: Text(localized("selfStatus.snapshot"))) {
                        Button(localized("clientActions.copyClientInformation")) {
                            TS3PlatformSupport.copyToPasteboard(infoSnapshot)
                        }
                        .disabled(infoSnapshot.isEmpty)
                        Button(localized("clientActions.exportClientInformation")) {
                            infoExportDocument = TS3TextFileDocument(data: Data(infoSnapshot.utf8))
                            isExportingInfo = true
                        }
                        .disabled(infoSnapshot.isEmpty)
                    }

                    UserInfoRows(user: currentUser)
                } else {
                    Section(header: Text(user.nickname)) {
                        if mode == .offlineMessage {
                            TextField(localized("clientActions.subject"), text: $subject)
                                .ts3PlainTextField()
                        }
                        TextField(fieldTitle, text: $text)
                            .ts3PlainTextField()
                        if mode == .offlineMessage {
                            ServerInfoDetailRow(
                                label: localized("clientActions.offlineDraftCoverage"),
                                value: localized(
                                    "clientActions.offlineDraftCoverageFormat",
                                    offlineMessageDraftCoverageSummary.recipientFieldCount,
                                    offlineMessageDraftCoverageSummary.requiredContentFieldCount,
                                    offlineMessageDraftCoverageSummary.validationIssueCount
                                )
                            )
                            Text(offlineMessageDraftCoverageText(offlineMessageDraftCoverageSummary))
                                .font(.caption)
                                .foregroundColor(offlineMessageDraftCoverageSummary.needsAttention ? .orange : .secondary)
                            Button(localized("clientActions.copyOfflineDraftCoverage")) {
                                TS3PlatformSupport.copyToPasteboard(offlineMessageDraftCoverageSummary.clipboardSummary)
                            }
                            Text(offlineMessageDraftSummary)
                                .font(.caption)
                                .foregroundColor(.secondary)
                            Button(localized("clientActions.copyOfflineMessageSummary")) {
                                TS3PlatformSupport.copyToPasteboard(offlineMessageDraftSummary)
                            }
                            ForEach(offlineMessageDraftValidationMessages, id: \.self) { message in
                                Text(message)
                                    .font(.caption)
                                    .foregroundColor(.red)
                            }
                        }
                        if mode == .poke {
                            ServerInfoDetailRow(
                                label: localized("clientActions.pokeDraftCoverage"),
                                value: localized(
                                    "clientActions.pokeDraftCoverageFormat",
                                    pokeDraftCoverageSummary.targetFieldCount,
                                    pokeDraftCoverageSummary.validationIssueCount
                                )
                            )
                            Text(pokeDraftCoverageText(pokeDraftCoverageSummary))
                                .font(.caption)
                                .foregroundColor(pokeDraftCoverageSummary.needsAttention ? .orange : .secondary)
                            Button(localized("clientActions.copyPokeDraftCoverage")) {
                                TS3PlatformSupport.copyToPasteboard(pokeDraftCoverageSummary.clipboardSummary)
                            }
                            Text(pokeDraftSummary)
                                .font(.caption)
                                .foregroundColor(.secondary)
                            Button(localized("clientActions.copyPokeSummary")) {
                                TS3PlatformSupport.copyToPasteboard(pokeDraftSummary)
                            }
                            ForEach(pokeDraftValidationMessages, id: \.self) { message in
                                Text(message)
                                    .font(.caption)
                                    .foregroundColor(.red)
                            }
                        }
                    }
                    if mode == .ban {
                        Section(header: Text(localized("ban.duration"))) {
                            Picker(localized("ban.duration"), selection: $banDuration) {
                                ForEach(TS3BanDuration.allCases) { duration in
                                    Text(duration.title).tag(duration)
                                }
                            }
                            if banDuration == .custom {
                                TextField(localized("temporaryPasswords.minutes"), text: $customBanMinutes)
                                    .ts3PlainTextField()
                            }
                        }
                    }
                    if mode != .info {
                        Section {
                            Button(actionTitle) {
                                switch mode {
                                case .info:
                                    break
                                case .privateMessage:
                                    model.sendPrivateMessage(text, to: user)
                                case .offlineMessage:
                                    model.sendOfflineMessage(to: user, subject: subject, message: text) {
                                        model.clearOfflineMessageDraft(id: offlineDraftId)
                                    }
                                case .poke:
                                    model.pokeUser(user, message: text)
                                case .editDescription:
                                    model.editUserDescription(user, description: text)
                                case .contactNote:
                                    model.setContactNote(text, for: user)
                                case .complain:
                                    model.complainAboutUser(user, message: text)
                                case .kickChannel:
                                    model.kickUserFromChannel(user, message: text.isEmpty ? nil : text)
                                case .kickServer:
                                    model.kickUserFromServer(user, message: text.isEmpty ? nil : text)
                                case .ban:
                                    model.banUser(
                                        user,
                                        durationSeconds: banDuration.seconds(customMinutes: customBanMinutes),
                                        message: text.isEmpty ? nil : text
                                    )
                                }
                                presentationMode.wrappedValue.dismiss()
                            }
                            .disabled(isActionDisabled)
                        }
                    }
                }
            }
            .fileExporter(
                isPresented: $isExportingInfo,
                document: infoExportDocument,
                contentType: .plainText,
                defaultFilename: "ts3-client-\(currentUser.id)"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .navigationTitle(title)
            .ts3InlineNavigationTitle()
            .onAppear {
                if mode == .editDescription {
                    text = user.description ?? ""
                }
                if mode == .contactNote {
                    text = model.contactNote(for: user) ?? ""
                }
                if mode == .offlineMessage {
                    loadOfflineDraft()
                }
                if mode == .info {
                    model.refreshUserDetails(user)
                }
            }
            .onChange(of: subject) { _ in
                saveOfflineDraftIfNeeded()
            }
            .onChange(of: text) { _ in
                saveOfflineDraftIfNeeded()
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.cancel")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }

    private var isActionDisabled: Bool {
        let textIsEmpty = text.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        switch mode {
        case .info:
            return true
        case .privateMessage, .complain:
            return textIsEmpty
        case .poke:
            return !pokeDraftValidationMessages.isEmpty
        case .offlineMessage:
            return !offlineMessageDraftValidationMessages.isEmpty
        case .editDescription, .contactNote, .kickChannel, .kickServer:
            return false
        case .ban:
            return banDuration == .custom && TS3BanDuration.customSeconds(from: customBanMinutes) == nil
        }
    }

    private var offlineDraftId: String {
        if let uniqueIdentifier = user.uniqueIdentifier, !uniqueIdentifier.isEmpty {
            return "uid:\(uniqueIdentifier)"
        }
        if let databaseId = user.databaseId {
            return "db:\(databaseId)"
        }
        return "client:\(user.id)"
    }

    private func loadOfflineDraft() {
        guard let draft = model.offlineMessageDraft(for: offlineDraftId) else { return }
        subject = draft.subject
        text = draft.message
    }

    private func saveOfflineDraftIfNeeded() {
        guard mode == .offlineMessage else { return }
        model.saveOfflineMessageDraft(
            id: offlineDraftId,
            recipientName: user.nickname,
            subject: subject,
            message: text
        )
    }

    private var offlineMessageDraftValidationMessages: [String] {
        TS3OfflineMessageDraftValidator.validationMessages(
            recipientName: user.nickname,
            recipientUniqueIdentifier: user.uniqueIdentifier,
            subject: subject,
            message: text,
            allowsRecipientLookup: true
        )
    }

    private var offlineMessageDraftSummary: String {
        TS3OfflineMessageDraftValidator.creationSummary(
            recipientName: user.nickname,
            recipientUniqueIdentifier: user.uniqueIdentifier,
            subject: subject,
            message: text,
            allowsRecipientLookup: true
        )
    }

    private var offlineMessageDraftCoverageSummary: TS3OfflineMessageDraftCoverageSummary {
        TS3OfflineMessageDraftCoverageSummary(
            recipientName: user.nickname,
            recipientUniqueIdentifier: user.uniqueIdentifier,
            subject: subject,
            message: text,
            allowsRecipientLookup: true,
            validationMessages: offlineMessageDraftValidationMessages
        )
    }

    private func offlineMessageDraftCoverageText(_ summary: TS3OfflineMessageDraftCoverageSummary) -> String {
        [
            localized("clientActions.offlineDraftCoverageRecipientNameFormat", summary.hasRecipientName ? 1 : 0),
            localized("clientActions.offlineDraftCoverageRecipientUidFormat", summary.hasRecipientUniqueIdentifier ? 1 : 0),
            localized("clientActions.offlineDraftCoverageLookupFormat", summary.allowsRecipientLookup ? 1 : 0),
            localized("clientActions.offlineDraftCoverageSubjectFormat", summary.hasSubject ? 1 : 0),
            localized("clientActions.offlineDraftCoverageBodyFormat", summary.hasBody ? 1 : 0)
        ].joined(separator: " | ")
    }

    private var pokeDraftValidationMessages: [String] {
        TS3PokeDraftValidator.validationMessages(
            targetName: user.nickname,
            targetClientId: user.id,
            message: text
        )
    }

    private var pokeDraftSummary: String {
        TS3PokeDraftValidator.creationSummary(
            targetName: user.nickname,
            targetClientId: user.id,
            message: text
        )
    }

    private var pokeDraftCoverageSummary: TS3PokeDraftCoverageSummary {
        TS3PokeDraftCoverageSummary(
            targetName: user.nickname,
            targetClientId: user.id,
            message: text,
            validationMessages: pokeDraftValidationMessages
        )
    }

    private func pokeDraftCoverageText(_ summary: TS3PokeDraftCoverageSummary) -> String {
        [
            localized("clientActions.pokeDraftCoverageTargetNameFormat", summary.hasTargetName ? 1 : 0),
            localized("clientActions.pokeDraftCoverageClientIdFormat", summary.hasTargetClientId ? 1 : 0),
            localized("clientActions.pokeDraftCoverageCustomMessageFormat", summary.hasCustomMessage ? 1 : 0)
        ].joined(separator: " | ")
    }

    private var infoSnapshot: String {
        UserInfoRows.snapshot(for: currentUser, model: model)
    }

    private var currentUser: TS3UserSummary {
        model.clients.first(where: { $0.id == user.id }) ?? user
    }
}

struct UserInfoRows: View {
    @EnvironmentObject private var model: TS3AppModel
    let user: TS3UserSummary

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, locale: Locale.current, arguments: arguments)
    }

    private func yesNo(_ value: Bool) -> String {
        localized(value ? "common.yes" : "common.no")
    }

    var body: some View {
        Section(header: Text(user.nickname)) {
            ServerInfoDetailRow(label: localized("clientActions.clientId"), value: String(user.id))
            ServerInfoDetailRow(label: localized("database.databaseId"), value: user.databaseId.map(String.init))
            ServerInfoDetailRow(label: localized("clientActions.uniqueId"), value: user.uniqueIdentifier, monospaced: true)
            ServerInfoDetailRow(label: localized("selfStatus.iconId"), value: user.iconId.map(String.init))
            ServerInfoDetailRow(label: localized("clientActions.avatarHash"), value: user.avatarHash, monospaced: true)
            ServerInfoDetailRow(label: localized("clientActions.avatarPath"), value: user.avatarURL?.path, monospaced: true)
            ServerInfoDetailRow(label: localized("channelEditor.channel"), value: String(user.channelId))
            ServerInfoDetailRow(label: localized("clientActions.country"), value: user.country)
            ServerInfoDetailRow(label: localized("clientActions.ipAddress"), value: user.ipAddress)
        }

        Section(header: Text(localized("clientActions.contact"))) {
            ServerInfoDetailRow(label: localized("serverInfo.status"), value: localizedContactStatus)
            ServerInfoDetailRow(label: localized("clientActions.note"), value: model.contactNote(for: user))
        }

        Section(header: Text(localized("clientActions.localPlayback"))) {
            ServerInfoDetailRow(label: localized("clientActions.muted"), value: yesNo(model.isPlaybackMuted(for: user)))
            ServerInfoDetailRow(label: localized("clientActions.volume"), value: model.playbackVolumePercentText(for: user))
        }

        Section(header: Text(localized("clientActions.application"))) {
            ServerInfoDetailRow(label: localized("serverInfo.platform"), value: user.platform)
            ServerInfoDetailRow(label: localized("serverInfo.version"), value: user.version)
        }

        Section(header: Text(localized("serverInfo.status"))) {
            ServerInfoDetailRow(label: localized("selfStatus.channelCommander"), value: yesNo(user.isChannelCommander))
            ServerInfoDetailRow(label: localized("clientActions.prioritySpeaker"), value: yesNo(user.isPrioritySpeaker))
            ServerInfoDetailRow(label: localized("clientActions.talker"), value: yesNo(user.isTalker))
            ServerInfoDetailRow(label: localized("clientActions.requestsTalkPower"), value: yesNo(user.isRequestingTalkPower))
            ServerInfoDetailRow(label: localized("clientActions.talkRequest"), value: user.talkRequestMessage?.isEmpty == false ? user.talkRequestMessage : nil)
            ServerInfoDetailRow(label: localized("selfStatus.talkPower"), value: user.talkPower.map(String.init))
        }

        Section(header: Text(localized("clientActions.activity"))) {
            ServerInfoDetailRow(label: localized("serverInfo.connected"), value: durationText(user.connectedSeconds))
            ServerInfoDetailRow(label: localized("serverInfo.idle"), value: durationText(user.idleTimeSeconds))
            ServerInfoDetailRow(label: localized("clientActions.totalConnections"), value: user.totalConnections.map(String.init))
            ServerInfoDetailRow(label: localized("serverInfo.created"), value: dateText(user.createdAt))
            ServerInfoDetailRow(label: localized("clientActions.lastConnected"), value: dateText(user.lastConnectedAt))
        }

        Section(header: Text(localized("serverInfo.status"))) {
            ServerInfoDetailRow(label: localized("selfStatus.away"), value: user.isAway ? (user.awayMessage?.isEmpty == false ? user.awayMessage : localized("common.yes")) : localized("common.no"))
            ServerInfoDetailRow(label: localized("clientActions.inputMuted"), value: yesNo(user.isInputMuted))
            ServerInfoDetailRow(label: localized("clientActions.outputMuted"), value: yesNo(user.isOutputMuted))
        }
    }

    private var localizedContactStatus: String {
        switch model.contactStatus(for: user) {
        case .neutral: return localized("contacts.status.neutral")
        case .friend: return localized("contacts.status.friend")
        case .ignored: return localized("contacts.status.ignored")
        case .blocked: return localized("contacts.status.blocked")
        }
    }

    private func dateText(_ date: Date?) -> String? {
        guard let date else { return nil }
        return DateFormatter.localizedString(from: date, dateStyle: .medium, timeStyle: .short)
    }

    private func durationText(_ seconds: Int?) -> String? {
        guard let seconds else { return nil }
        if seconds < 60 { return "\(seconds)s" }
        let minutes = seconds / 60
        if minutes < 60 { return "\(minutes)m \(seconds % 60)s" }
        let hours = minutes / 60
        if hours < 24 { return "\(hours)h \(minutes % 60)m" }
        let days = hours / 24
        return "\(days)d \(hours % 24)h"
    }

    static func snapshot(for user: TS3UserSummary, model: TS3AppModel) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short

        func dateText(_ date: Date?) -> String? {
            guard let date else { return nil }
            return formatter.string(from: date)
        }

        func durationText(_ seconds: Int?) -> String? {
            guard let seconds else { return nil }
            if seconds < 60 { return "\(seconds)s" }
            let minutes = seconds / 60
            if minutes < 60 { return "\(minutes)m \(seconds % 60)s" }
            let hours = minutes / 60
            if hours < 24 { return "\(hours)h \(minutes % 60)m" }
            let days = hours / 24
            return "\(days)d \(hours % 24)h"
        }

        let rows: [(String, String?)] = [
            ("Nickname", user.nickname),
            ("Client ID", String(user.id)),
            ("Database ID", user.databaseId.map(String.init)),
            ("Unique ID", user.uniqueIdentifier),
            ("Icon ID", user.iconId.map(String.init)),
            ("Avatar Hash", user.avatarHash),
            ("Avatar Path", user.avatarURL?.path),
            ("Channel", String(user.channelId)),
            ("Country", user.country),
            ("IP Address", user.ipAddress),
            ("Contact Status", model.contactStatus(for: user).title),
            ("Note", model.contactNote(for: user)),
            ("Locally Muted", model.isPlaybackMuted(for: user) ? "Yes" : "No"),
            ("Playback Volume", model.playbackVolumePercentText(for: user)),
            ("Platform", user.platform),
            ("Version", user.version),
            ("Channel Commander", user.isChannelCommander ? "Yes" : "No"),
            ("Priority Speaker", user.isPrioritySpeaker ? "Yes" : "No"),
            ("Talker", user.isTalker ? "Yes" : "No"),
            ("Requests Talk Power", user.isRequestingTalkPower ? "Yes" : "No"),
            ("Talk Request", user.talkRequestMessage?.isEmpty == false ? user.talkRequestMessage : nil),
            ("Talk Power", user.talkPower.map(String.init)),
            ("Connected", durationText(user.connectedSeconds)),
            ("Idle", durationText(user.idleTimeSeconds)),
            ("Total Connections", user.totalConnections.map(String.init)),
            ("Created", dateText(user.createdAt)),
            ("Last Connected", dateText(user.lastConnectedAt)),
            ("Away", user.isAway ? (user.awayMessage?.isEmpty == false ? user.awayMessage : "Yes") : "No"),
            ("Input Muted", user.isInputMuted ? "Yes" : "No"),
            ("Output Muted", user.isOutputMuted ? "Yes" : "No")
        ]

        return rows
            .compactMap { label, value in
                guard let value, !value.isEmpty else { return nil }
                return "\(label): \(value)"
            }
            .joined(separator: "\n")
    }
}

struct UserIconView: View {
    let user: TS3UserSummary

    @ViewBuilder
    var body: some View {
        if let image = platformImage {
            Image(ts3PlatformImage: image)
                .resizable()
                .scaledToFit()
                .frame(width: 14, height: 14)
                .accessibilityLabel("Client icon")
        } else if user.iconId != nil && user.iconId != 0 {
            Image(systemName: "seal")
                .resizable()
                .scaledToFit()
                .foregroundColor(.secondary)
                .frame(width: 14, height: 14)
                .accessibilityLabel("Client icon")
        }
    }

    private var platformImage: TS3PlatformImage? {
        guard let iconURL = user.iconURL else { return nil }
        return TS3PlatformImage(contentsOfFile: iconURL.path)
    }
}

struct ContactsSheet: View {
    private struct ContactImportConfirmation: Identifiable {
        let url: URL
        let preview: TS3ContactImportPreview
        let id = UUID()
    }

    private struct ContactFilterPresetImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3ContactFilterPresetImportPreview
        let id = UUID()
    }

    private enum ContactSortMode: String, CaseIterable, Identifiable {
        case nickname
        case status
        case updated
        case note

        var id: String { rawValue }

        var titleKey: String {
            switch self {
            case .nickname: return "contacts.sort.nickname"
            case .status: return "contacts.sort.status"
            case .updated: return "contacts.sort.updated"
            case .note: return "contacts.sort.note"
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var searchText = ""
    @State private var sortMode: ContactSortMode = .nickname
    @State private var sortAscending = true
    @State private var presetName = ""
    @State private var isShowingNewContact = false
    @State private var isExportingContacts = false
    @State private var isImportingContacts = false
    @State private var isExportingPresets = false
    @State private var isImportingPresets = false
    @State private var isConfirmingDeletePresets = false
    @State private var isConfirmingDeleteVisibleContacts = false
    @State private var isShowingVisibleNoteSheet = false
    @State private var pendingContactImport: ContactImportConfirmation?
    @State private var pendingPresetImport: ContactFilterPresetImportConfirmation?
    @State private var contactsDocument = TS3TextFileDocument()
    @State private var presetsDocument = TS3BookmarkFileDocument()

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    private func localizedStatusTitle(_ status: TS3ContactStatus) -> String {
        switch status {
        case .neutral:
            return localized("contacts.status.neutral")
        case .friend:
            return localized("contacts.status.friend")
        case .ignored:
            return localized("contacts.status.ignored")
        case .blocked:
            return localized("contacts.status.blocked")
        }
    }

    private var notedContacts: [TS3ContactEntry] {
        model.contacts
            .filter { !$0.note.isEmpty && $0.status == .neutral }
    }

    private var normalizedSearchText: String {
        searchText.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    private var isSearching: Bool {
        !normalizedSearchText.isEmpty
    }

    private var filteredFriends: [TS3ContactEntry] {
        filterContacts(model.friendContacts)
    }

    private var filteredBlocked: [TS3ContactEntry] {
        filterContacts(model.blockedContacts)
    }

    private var filteredIgnored: [TS3ContactEntry] {
        filterContacts(model.ignoredContacts)
    }

    private var filteredNotes: [TS3ContactEntry] {
        filterContacts(notedContacts)
    }

    private var visibleContacts: [TS3ContactEntry] {
        var seen = Set<String>()
        return (filteredFriends + filteredBlocked + filteredIgnored + filteredNotes).filter { contact in
            seen.insert(contact.uniqueIdentifier).inserted
        }
    }

    private var visibleContactSummary: TS3ContactListSummary {
        TS3ContactListSummary(
            contacts: visibleContacts,
            onlineUniqueIdentifiers: Set(model.clients.compactMap(\.uniqueIdentifier))
        )
    }

    private var contactBulkActionSummary: TS3ContactBulkActionSummary {
        TS3ContactBulkActionSummary(contacts: visibleContacts)
    }

    private var contactOfficialAuditSummary: TS3ContactOfficialManagementAuditSummary {
        TS3ContactOfficialManagementAuditSummary(
            visibleSummary: visibleContactSummary,
            bulkActionSummary: contactBulkActionSummary,
            hasFilterPresets: !model.contactFilterPresets.isEmpty,
            hasVisibleExport: !visibleContacts.isEmpty,
            hasOnlineContextActions: !model.onlineContactCandidates.isEmpty
        )
    }

    private var canMarkVisibleFriends: Bool {
        visibleContacts.contains { $0.status != .friend }
    }

    private var canBlockVisibleContacts: Bool {
        visibleContacts.contains { $0.status != .blocked }
    }

    private var canIgnoreVisibleContacts: Bool {
        visibleContacts.contains { $0.status != .ignored }
    }

    private var canSetVisibleNeutral: Bool {
        visibleContacts.contains { $0.status != .neutral }
    }

    private func contactStatusDraft(_ status: TS3ContactStatus) -> TS3ContactStatusDraft {
        TS3ContactStatusDraft(contacts: visibleContacts, status: status)
    }

    private func applyVisibleContactStatus(_ status: TS3ContactStatus) {
        let draft = contactStatusDraft(status)
        guard draft.validationMessages.isEmpty else {
            model.lastError = draft.validationMessages.joined(separator: "\n")
            return
        }
        model.updateContacts(draft.uniqueContacts, status: status)
    }

    private func copyVisibleContactStatusDraft(_ status: TS3ContactStatus) {
        TS3PlatformSupport.copyToPasteboard(contactStatusDraft(status).clipboardSummary)
    }

    var body: some View {
        NavigationView {
            List {
                Section(header: Text(localized("contacts.section.add"))) {
                    Button(localized("contacts.newContact")) {
                        isShowingNewContact = true
                    }
                }

                Section(header: Text(localized("contacts.section.filters"))) {
                    Picker(localized("contacts.sortBy"), selection: $sortMode) {
                        ForEach(ContactSortMode.allCases) { mode in
                            Text(localized(mode.titleKey)).tag(mode)
                        }
                    }
                    Toggle(localized("contacts.ascending"), isOn: $sortAscending)
                    TextField(localized("contacts.search"), text: $searchText)
                        .ts3PlainTextField()
                    Menu {
                        TextField(localized("contacts.presetName"), text: $presetName)
                        Button(localized("contacts.saveCurrentFilters")) {
                            model.saveContactFilterPreset(
                                name: presetName,
                                sortMode: sortMode.rawValue,
                                sortAscending: sortAscending,
                                searchText: searchText
                            )
                            presetName = ""
                        }
                        .disabled(presetName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                        if model.contactFilterPresets.isEmpty {
                            Text(localized("contacts.noSavedFilterPresets"))
                        } else {
                            ForEach(model.contactFilterPresets) { preset in
                                Menu {
                                    Button(localized("contacts.applyPreset")) {
                                        applyPreset(preset)
                                    }
                                    Button(localized("contacts.useName")) {
                                        presetName = preset.name
                                    }
                                    Button(localized("contacts.deletePreset")) {
                                        model.deleteContactFilterPreset(preset)
                                    }
                                } label: {
                                    VStack(alignment: .leading) {
                                        Text(preset.name)
                                        Text(presetSummary(preset))
                                    }
                                }
                            }
                        }
                        Divider()
                        Button(localized("contacts.exportPresets")) {
                            exportPresets()
                        }
                        .disabled(model.contactFilterPresets.isEmpty)
                        Button(localized("contacts.importPresets")) {
                            isImportingPresets = true
                        }
                        Button(localized("contacts.deleteAllPresets")) {
                            isConfirmingDeletePresets = true
                        }
                        .disabled(model.contactFilterPresets.isEmpty)
                    } label: {
                        Label(localized("contacts.filterPresets"), systemImage: "line.3.horizontal.decrease.circle")
                    }
                    if hasLocalFilters {
                        Button(localized("contacts.clearFilters")) {
                            sortMode = .nickname
                            sortAscending = true
                            searchText = ""
                        }
                    }
                    if !visibleContacts.isEmpty {
                        ServerInfoDetailRow(
                            label: localized("contacts.visibleSummary"),
                            value: localized(
                                "contacts.visibleSummaryFormat",
                                visibleContactSummary.totalCount,
                                visibleContactSummary.onlineCount
                            )
                        )
                        Text(contactListSummaryText(visibleContactSummary))
                            .font(.caption)
                            .foregroundColor(.secondary)
                        ServerInfoDetailRow(
                            label: localized("contacts.bulkSummary"),
                            value: localized(
                                "contacts.bulkSummaryFormat",
                                contactBulkActionSummary.visibleCount,
                                contactBulkActionSummary.effectiveActionCount
                            )
                        )
                        Text(contactBulkActionSummaryText(contactBulkActionSummary))
                            .font(.caption)
                            .foregroundColor(contactBulkActionSummary.needsAttention ? .orange : .secondary)
                        Button(localized("contacts.copyBulkSummary")) {
                            TS3PlatformSupport.copyToPasteboard(contactBulkActionSummary.clipboardSummary)
                        }
                        ServerInfoDetailRow(
                            label: localized("contacts.officialAudit"),
                            value: localized(
                                "contacts.officialAuditFormat",
                                contactOfficialAuditSummary.coveredOfficialAreaCount,
                                contactOfficialAuditSummary.officialAreaTotal,
                                contactOfficialAuditSummary.missingOfficialAreaCount
                            )
                        )
                        Text(contactOfficialAuditText(contactOfficialAuditSummary))
                            .font(.caption)
                            .foregroundColor(contactOfficialAuditSummary.needsAttention ? .orange : .secondary)
                        Button(localized("contacts.copyOfficialAudit")) {
                            TS3PlatformSupport.copyToPasteboard(contactOfficialAuditSummary.clipboardSummary)
                        }
                    }
                }

                contactSection(title: localized("contacts.section.friends"), contacts: filteredFriends)
                contactSection(title: localized("contacts.section.blocked"), contacts: filteredBlocked)
                contactSection(title: localized("contacts.section.ignored"), contacts: filteredIgnored)
                contactSection(title: localized("contacts.section.notes"), contacts: filteredNotes)
            }
            .navigationTitle(localized("contacts.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Menu {
                        Button(localized("contacts.copySnapshot")) {
                            TS3PlatformSupport.copyToPasteboard(contactSnapshot)
                        }
                        .disabled(model.contacts.isEmpty)
                        Button(localized("contacts.copyVisibleSummary")) {
                            TS3PlatformSupport.copyToPasteboard(visibleContactSummary.clipboardSummary)
                        }
                        .disabled(visibleContacts.isEmpty)
                        Button(localized("contacts.exportSnapshot")) {
                            contactsDocument = TS3TextFileDocument(data: Data(contactSnapshot.utf8))
                            isExportingContacts = true
                        }
                        .disabled(model.contacts.isEmpty)
                        Button(localized("contacts.exportBackup")) {
                            exportContacts()
                        }
                        .disabled(model.contacts.isEmpty)
                        Button(localized("contacts.exportVisibleBackup")) {
                            exportVisibleContacts()
                        }
                        .disabled(visibleContacts.isEmpty)
                        Button(localized("contacts.importBackup")) {
                            isImportingContacts = true
                        }
                        Divider()
                        Button(localized("contacts.markOnlineFriends")) {
                            model.updateOnlineContacts(status: .friend)
                        }
                        .disabled(model.onlineContactCandidates.isEmpty)
                        Button(localized("contacts.blockOnlineUsers")) {
                            model.updateOnlineContacts(status: .blocked)
                        }
                        .disabled(model.onlineContactCandidates.isEmpty)
                        Button(localized("contacts.ignoreOnlineUsers")) {
                            model.updateOnlineContacts(status: .ignored)
                        }
                        .disabled(model.onlineContactCandidates.isEmpty)
                        Divider()
                        Button(localized("contacts.markVisibleFriends")) {
                            applyVisibleContactStatus(.friend)
                        }
                        .disabled(!canMarkVisibleFriends)
                        Button(localized("contacts.copyMarkFriendsDraft")) {
                            copyVisibleContactStatusDraft(.friend)
                        }
                        .disabled(visibleContacts.isEmpty)
                        Button(localized("contacts.blockVisibleContacts")) {
                            applyVisibleContactStatus(.blocked)
                        }
                        .disabled(!canBlockVisibleContacts)
                        Button(localized("contacts.copyBlockDraft")) {
                            copyVisibleContactStatusDraft(.blocked)
                        }
                        .disabled(visibleContacts.isEmpty)
                        Button(localized("contacts.ignoreVisibleContacts")) {
                            applyVisibleContactStatus(.ignored)
                        }
                        .disabled(!canIgnoreVisibleContacts)
                        Button(localized("contacts.copyIgnoreDraft")) {
                            copyVisibleContactStatusDraft(.ignored)
                        }
                        .disabled(visibleContacts.isEmpty)
                        Button(localized("contacts.setVisibleNeutral")) {
                            applyVisibleContactStatus(.neutral)
                        }
                        .disabled(!canSetVisibleNeutral)
                        Button(localized("contacts.copyNeutralDraft")) {
                            copyVisibleContactStatusDraft(.neutral)
                        }
                        .disabled(visibleContacts.isEmpty)
                        Button(localized("contacts.appendNoteVisible")) {
                            isShowingVisibleNoteSheet = true
                        }
                        .disabled(visibleContacts.isEmpty)
                        Button(localized("contacts.deleteVisible")) {
                            isConfirmingDeleteVisibleContacts = true
                        }
                        .disabled(visibleContacts.isEmpty)
                        .foregroundColor(.red)
                    } label: {
                        Label(localized("contacts.title"), systemImage: "ellipsis.circle")
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(NSLocalizedString("common.done", comment: "")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .fileExporter(
                isPresented: $isExportingContacts,
                document: contactsDocument,
                contentType: .plainText,
                defaultFilename: "ts3-contacts"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingContacts,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareContactImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPresets,
                document: presetsDocument,
                contentType: .json,
                defaultFilename: "ts3-contact-filter-presets"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPresets,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    preparePresetImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .alert(isPresented: $isConfirmingDeletePresets) {
                Alert(
                    title: Text(localized("contacts.deleteAllPresetsAlert.title")),
                    message: Text(localized("contacts.deleteAllPresetsAlert.messageFormat", model.contactFilterPresets.count)),
                    primaryButton: .destructive(Text(localized("contacts.delete"))) {
                        model.deleteAllContactFilterPresets()
                    },
                    secondaryButton: .cancel()
                )
            }
            .alert(isPresented: $isConfirmingDeleteVisibleContacts) {
                Alert(
                    title: Text(localized("contacts.deleteVisibleAlert.title")),
                    message: Text(localized("contacts.deleteVisibleAlert.messageFormat", visibleContacts.count)),
                    primaryButton: .destructive(Text(localized("contacts.delete"))) {
                        model.deleteContacts(visibleContacts)
                    },
                    secondaryButton: .cancel()
                )
            }
            .sheet(item: $pendingContactImport) { confirmation in
                ContactImportSheet(
                    preview: confirmation.preview,
                    previewMessage: contactImportPreviewMessage(confirmation.preview),
                    importContacts: { options in
                        importContacts(from: confirmation.url, options: options)
                        pendingContactImport = nil
                    },
                    cancel: {
                        pendingContactImport = nil
                    }
                )
            }
            .sheet(item: $pendingPresetImport) { confirmation in
                ContactFilterPresetImportSheet(
                    preview: confirmation.preview,
                    importPresets: { selectedPresetIds in
                        importPresets(data: confirmation.data, selectedPresetIds: selectedPresetIds)
                        pendingPresetImport = nil
                    },
                    cancel: {
                        pendingPresetImport = nil
                    }
                )
            }
            .sheet(isPresented: $isShowingNewContact) {
                ContactEditorSheet(
                    uniqueIdentifier: "",
                    nickname: "",
                    initialStatus: .neutral,
                    initialNote: "",
                    submit: { uniqueIdentifier, nickname, status, note in
                        model.addContact(
                            uniqueIdentifier: uniqueIdentifier,
                            nickname: nickname,
                            status: status,
                            note: note
                        )
                    }
                )
                .environmentObject(model)
            }
            .sheet(isPresented: $isShowingVisibleNoteSheet) {
                ContactBatchNoteSheet(
                    contacts: visibleContacts,
                    submit: { draft in
                        model.appendNote(draft)
                    }
                )
            }
        }
    }

    private func filterContacts(_ contacts: [TS3ContactEntry]) -> [TS3ContactEntry] {
        let entries = contacts.filter { contact in
            !isSearching
                || containsSearch(contact.nickname)
                || containsSearch(contact.uniqueIdentifier)
                || containsSearch(contact.note)
                || containsSearch(localizedStatusTitle(contact.status))
        }
        return sortedContacts(entries)
    }

    private func containsSearch(_ value: String) -> Bool {
        value.lowercased().contains(normalizedSearchText)
    }

    private var hasLocalFilters: Bool {
        isSearching || sortMode != .nickname || !sortAscending
    }

    private func sortedContacts(_ contacts: [TS3ContactEntry]) -> [TS3ContactEntry] {
        contacts.sorted { lhs, rhs in
            if lhs.id == rhs.id {
                return false
            }

            let comparison: ComparisonResult
            switch sortMode {
            case .nickname:
                comparison = lhs.nickname.localizedCaseInsensitiveCompare(rhs.nickname)
            case .status:
                comparison = localizedStatusTitle(lhs.status).localizedCaseInsensitiveCompare(localizedStatusTitle(rhs.status))
            case .updated:
                comparison = lhs.updatedAt.compare(rhs.updatedAt)
            case .note:
                comparison = lhs.note.localizedCaseInsensitiveCompare(rhs.note)
            }

            if comparison == .orderedSame {
                return lhs.nickname.localizedCaseInsensitiveCompare(rhs.nickname) == .orderedAscending
            }
            return sortAscending ? comparison == .orderedAscending : comparison == .orderedDescending
        }
    }

    private func exportContacts() {
        do {
            contactsDocument = TS3TextFileDocument(data: try model.contactsExportData())
            isExportingContacts = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func exportVisibleContacts() {
        do {
            contactsDocument = TS3TextFileDocument(data: try model.contactsExportData(visibleContacts))
            isExportingContacts = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareContactImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let preview = try model.contactImportPreview(from: Data(contentsOf: url))
            pendingContactImport = ContactImportConfirmation(url: url, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importContacts(from url: URL, options: TS3ContactImportOptions) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            _ = try model.importContacts(from: Data(contentsOf: url), options: options)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func contactImportPreviewMessage(_ preview: TS3ContactImportPreview) -> String {
        var lines = [
            localized("contacts.import.backupContactsFormat", preview.importedCount),
            localized("contacts.import.validContactsFormat", preview.validCount)
        ]
        if preview.invalidCount > 0 {
            lines.append(localized("contacts.import.invalidEntriesFormat", preview.invalidCount))
        }
        if preview.duplicateCount > 0 {
            lines.append(localized("contacts.import.duplicateUniqueIdsFormat", preview.duplicateCount))
        }
        lines.append(localized("contacts.import.actionSummaryFormat", preview.newCount, preview.updatedCount, preview.unchangedCount))
        if !preview.statusSummaries.isEmpty {
            lines.append(localized("contacts.import.statusesFormat", preview.statusSummaries.joined(separator: " | ")))
        }
        if !preview.newContactNames.isEmpty {
            lines.append(localized("contacts.import.addingFormat", contactNameSummary(preview.newContactNames)))
        }
        if !preview.updatedContactNames.isEmpty {
            lines.append(localized("contacts.import.updatingFormat", contactNameSummary(preview.updatedContactNames)))
        }
        if !preview.unchangedContactNames.isEmpty {
            lines.append(localized("contacts.import.unchangedFormat", contactNameSummary(preview.unchangedContactNames)))
        }
        return lines.joined(separator: "\n")
    }

    private func contactNameSummary(_ names: [String]) -> String {
        let visible = names.prefix(6).joined(separator: ", ")
        let remainingCount = names.count - min(names.count, 6)
        guard remainingCount > 0 else { return visible }
        return localized("contacts.moreNamesFormat", visible, remainingCount)
    }

    private func contactListSummaryText(_ summary: TS3ContactListSummary) -> String {
        var parts = [
            localized("contacts.summary.friendsFormat", summary.friendCount),
            localized("contacts.summary.blockedFormat", summary.blockedCount),
            localized("contacts.summary.ignoredFormat", summary.ignoredCount),
            localized("contacts.summary.neutralFormat", summary.neutralCount),
            localized("contacts.summary.notesFormat", summary.notedCount)
        ]
        if let latestUpdate = summary.latestUpdate {
            let formatter = DateFormatter()
            formatter.dateStyle = .medium
            formatter.timeStyle = .short
            parts.append(localized("contacts.summary.updatedFormat", formatter.string(from: latestUpdate)))
        }
        return parts.joined(separator: " · ")
    }

    private func contactBulkActionSummaryText(_ summary: TS3ContactBulkActionSummary) -> String {
        [
            localized("contacts.bulkFriendFormat", summary.markFriendCount),
            localized("contacts.bulkBlockFormat", summary.blockCount),
            localized("contacts.bulkIgnoreFormat", summary.ignoreCount),
            localized("contacts.bulkNeutralFormat", summary.neutralCount),
            localized("contacts.bulkNoteFormat", summary.appendNoteCount),
            localized("contacts.bulkDeleteFormat", summary.deleteVisibleCount)
        ].joined(separator: " · ")
    }

    private func contactOfficialAuditText(_ summary: TS3ContactOfficialManagementAuditSummary) -> String {
        [
            localized("contacts.officialAuditActionsFormat", summary.officialActionCount),
            localized("contacts.officialAuditVisibleFormat", summary.visibleSummary.totalCount),
            localized("contacts.officialAuditOnlineFormat", summary.visibleSummary.onlineCount),
            localized("contacts.officialAuditBulkFormat", summary.bulkActionSummary.effectiveActionCount),
            localized("contacts.officialAuditAttentionFormat", summary.needsAttention ? 1 : 0)
        ].joined(separator: " · ")
    }

    private func applyPreset(_ preset: TS3ContactFilterPreset) {
        sortMode = ContactSortMode(rawValue: preset.sortMode) ?? .nickname
        sortAscending = preset.sortAscending
        searchText = preset.searchText
        presetName = preset.name
    }

    private func presetSummary(_ preset: TS3ContactFilterPreset) -> String {
        var parts = [
            localized(
                "contacts.presetSummary.sortFormat",
                localized((ContactSortMode(rawValue: preset.sortMode) ?? .nickname).titleKey)
            )
        ]
        if !preset.sortAscending {
            parts.append(localized("contacts.presetSummary.descending"))
        }
        if !preset.searchText.isEmpty {
            parts.append(localized("contacts.presetSummary.searchFormat", preset.searchText))
        }
        return parts.joined(separator: " · ")
    }

    private func exportPresets() {
        do {
            presetsDocument = TS3BookmarkFileDocument(data: try model.contactFilterPresetsExportData())
            isExportingPresets = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func preparePresetImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.contactFilterPresetsImportPreview(from: data)
            pendingPresetImport = ContactFilterPresetImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPresets(data: Data, selectedPresetIds: Set<UUID>) {
        do {
            _ = try model.importContactFilterPresets(from: data, selectedPresetIds: selectedPresetIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private var contactSnapshot: String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short

        func dateText(_ date: Date) -> String {
            formatter.string(from: date)
        }

        return model.contacts
            .sorted { lhs, rhs in
                if lhs.status != rhs.status {
                    return localizedStatusTitle(lhs.status) < localizedStatusTitle(rhs.status)
                }
                return lhs.nickname.localizedCaseInsensitiveCompare(rhs.nickname) == .orderedAscending
            }
            .map { contact in
                [
                    localized("contacts.snapshot.nicknameFormat", contact.nickname),
                    localized("contacts.snapshot.uniqueIdFormat", contact.uniqueIdentifier),
                    localized("contacts.snapshot.statusFormat", localizedStatusTitle(contact.status)),
                    localized("contacts.snapshot.noteFormat", contact.note.isEmpty ? "-" : contact.note),
                    localized("contacts.snapshot.updatedFormat", dateText(contact.updatedAt))
                ]
                .joined(separator: "\n")
            }
            .joined(separator: "\n\n")
    }

    @ViewBuilder
    private func contactSection(title: String, contacts: [TS3ContactEntry]) -> some View {
        Section(header: Text(title)) {
            if contacts.isEmpty {
                Text(isSearching ? localized("contacts.noMatchingContacts") : localized("contacts.noContacts"))
                    .foregroundColor(.secondary)
            } else {
                ForEach(contacts) { contact in
                    ContactRow(contact: contact)
                        .environmentObject(model)
                }
            }
        }
    }
}

private struct ContactImportSheet: View {
    let preview: TS3ContactImportPreview
    let previewMessage: String
    let importContacts: (TS3ContactImportOptions) -> Void
    let cancel: () -> Void

    @State private var options = TS3ContactImportOptions.all

    private var selectedCount: Int {
        (options.newContacts ? preview.newCount : 0)
            + (options.updatedContacts ? preview.updatedCount : 0)
    }

    private var canImport: Bool {
        options.hasSelectedEntries && selectedCount > 0
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("contacts.import.preview"))) {
                    Text(previewMessage)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Text(localized("contacts.import.selectedEntriesFormat", selectedCount))
                        .font(.caption.weight(.semibold))
                    ForEach(preview.statusSummaries, id: \.self) { summary in
                        Text(summary)
                            .font(.caption2)
                            .foregroundColor(.secondary)
                    }
                }

                Section(header: Text(localized("contacts.import.entries"))) {
                    Toggle(localized("contacts.import.newContacts"), isOn: $options.newContacts)
                        .disabled(preview.newCount == 0)
                    Toggle(localized("contacts.import.updatedContacts"), isOn: $options.updatedContacts)
                        .disabled(preview.updatedCount == 0)
                    if preview.unchangedCount > 0 {
                        Text(localized("contacts.import.unchangedSkippedFormat", preview.unchangedCount))
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                }
            }
            .navigationTitle(localized("contacts.import.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(NSLocalizedString("common.cancel", comment: "")) {
                        cancel()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("contacts.import.action")) {
                        importContacts(options)
                    }
                    .disabled(!canImport)
                }
            }
        }
    }
}

private struct ContactFilterPresetImportSheet: View {
    @Environment(\.presentationMode) private var presentationMode

    let preview: TS3ContactFilterPresetImportPreview
    let importPresets: (Set<UUID>) -> Void
    let cancel: () -> Void
    @State private var selectedPresetIds: Set<UUID>

    init(
        preview: TS3ContactFilterPresetImportPreview,
        importPresets: @escaping (Set<UUID>) -> Void,
        cancel: @escaping () -> Void
    ) {
        self.preview = preview
        self.importPresets = importPresets
        self.cancel = cancel
        _selectedPresetIds = State(initialValue: Set(preview.candidates.map(\.id)))
    }

    private var canImport: Bool {
        preview.candidates.contains { selectedPresetIds.contains($0.id) }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("contacts.filterImport.preview"))) {
                    Text(localized("contacts.filterImport.importedPresetsFormat", preview.importedPresetCount))
                    Text(localized("contacts.filterImport.usablePresetsFormat", preview.usablePresetCount))
                    Text(localized("contacts.filterImport.newPresetsFormat", preview.newPresetCount))
                    Text(localized("contacts.filterImport.replacingPresetsFormat", preview.replacedPresetCount))
                    Text(localized("contacts.filterImport.skippedPresetsFormat", preview.skippedPresetCount))
                    Button(localized("contacts.filterImport.copyPreview")) {
                        TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                    }
                }

                Section(header: Text(localized("contacts.filterImport.restore"))) {
                    HStack {
                        Button(localized("contacts.filterImport.selectAll")) {
                            selectedPresetIds = Set(preview.candidates.map(\.id))
                        }
                        Spacer()
                        Button(localized("contacts.filterImport.clear")) {
                            selectedPresetIds.removeAll()
                        }
                    }
                    ForEach(preview.candidates) { candidate in
                        Toggle(
                            candidate.summary,
                            isOn: Binding(
                                get: { selectedPresetIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedPresetIds.insert(candidate.id)
                                    } else {
                                        selectedPresetIds.remove(candidate.id)
                                    }
                                }
                            )
                        )
                    }
                }

                Section {
                    Text(localized("contacts.filterImport.behavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("contacts.filterImport.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(NSLocalizedString("common.cancel", comment: "")) {
                        cancel()
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("contacts.import.action")) {
                        importPresets(selectedPresetIds)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canImport)
                }
            }
        }
    }
}

struct ContactRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let contact: TS3ContactEntry
    @State private var isEditing = false
    @State private var isShowingOfflineMessage = false
    @State private var isShowingBanContact = false
    @State private var isShowingClientDatabase = false
    @State private var onlineActionMode: UserActionMode?

    private var onlineUser: TS3UserSummary? {
        model.onlineUser(for: contact)
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    private func localizedStatusTitle(_ status: TS3ContactStatus) -> String {
        switch status {
        case .neutral:
            return localized("contacts.status.neutral")
        case .friend:
            return localized("contacts.status.friend")
        case .ignored:
            return localized("contacts.status.ignored")
        case .blocked:
            return localized("contacts.status.blocked")
        }
    }

    var body: some View {
        HStack(alignment: .top, spacing: 10) {
            VStack(alignment: .leading, spacing: 4) {
                HStack(spacing: 6) {
                    Text(contact.nickname)
                        .font(.subheadline.weight(.semibold))
                    Text(localizedStatusTitle(contact.status))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                Text(contact.uniqueIdentifier)
                    .font(.caption)
                    .foregroundColor(.secondary)
                    .lineLimit(1)
                if !contact.note.isEmpty {
                    Text(contact.note)
                        .font(.caption)
                        .foregroundColor(.secondary)
                        .lineLimit(2)
                }
                if let onlineUser {
                    Text(localized("contacts.row.onlineAsFormat", onlineUser.nickname))
                        .font(.caption)
                        .foregroundColor(.accentColor)
                        .lineLimit(1)
                }
            }
            Spacer()
            Menu {
                if onlineUser != nil {
                    Button(localized("contacts.row.sendPrivateMessage")) {
                        onlineActionMode = .privateMessage
                    }
                    Button(localized("contacts.row.poke")) {
                        onlineActionMode = .poke
                    }
                    Button(localized("contacts.row.clientInfo")) {
                        onlineActionMode = .info
                    }
                    Divider()
                }
                Button(localized("clientActions.sendOfflineMessage")) {
                    isShowingOfflineMessage = true
                }
                Button(localized("contacts.row.banUniqueId")) {
                    isShowingBanContact = true
                }
                Button(localized("contacts.row.editContact")) {
                    isEditing = true
                }
                Button(localized("contacts.row.findDatabaseClient")) {
                    model.findDatabaseClient(for: contact)
                    isShowingClientDatabase = true
                }
                Button(localized("contacts.row.saveContactBookmark")) {
                    model.saveContactBookmark(for: contact)
                }
                .disabled(model.serverHost.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                Button(localized("contacts.row.copyContactBookmark")) {
                    TS3PlatformSupport.copyToPasteboard(model.contactBookmarkSummary(for: contact))
                }
                Button(localized("contacts.row.copyNickname")) {
                    TS3PlatformSupport.copyToPasteboard(contact.nickname)
                }
                Button(localized("contacts.row.copyUniqueId")) {
                    TS3PlatformSupport.copyToPasteboard(contact.uniqueIdentifier)
                }
                Button(localized("contacts.row.copySummary")) {
                    TS3PlatformSupport.copyToPasteboard(clipboardSummary)
                }
                ForEach(TS3ContactStatus.allCases) { status in
                    Button(localized("contacts.row.setStatusFormat", localizedStatusTitle(status))) {
                        model.updateContact(contact, status: status, note: contact.note)
                    }
                    .disabled(contact.status == status)
                }
                Button(localized("contacts.row.deleteContact")) {
                    model.deleteContact(contact)
                }
            } label: {
                Image(systemName: "ellipsis.circle")
            }
            .buttonStyle(.borderless)
        }
        .sheet(isPresented: $isEditing) {
            ContactEditorSheet(
                uniqueIdentifier: contact.uniqueIdentifier,
                nickname: contact.nickname,
                initialStatus: contact.status,
                initialNote: contact.note,
                submit: { uniqueIdentifier, nickname, status, note in
                    model.addContact(
                        uniqueIdentifier: uniqueIdentifier,
                        nickname: nickname.isEmpty ? contact.nickname : nickname,
                        status: status,
                        note: note
                    )
                }
            )
        }
        .sheet(item: $onlineActionMode) { mode in
            if let onlineUser {
                UserActionSheet(mode: mode, user: onlineUser)
                    .environmentObject(model)
            }
        }
        .sheet(isPresented: $isShowingOfflineMessage) {
            ContactOfflineMessageSheet(contact: contact)
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingBanContact) {
            ContactBanSheet(contact: contact)
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingClientDatabase) {
            ClientDatabaseSheet()
                .environmentObject(model)
        }
        .contextMenu {
            if onlineUser != nil {
                Button(localized("contacts.row.sendPrivateMessage")) {
                    onlineActionMode = .privateMessage
                }
                Button(localized("contacts.row.poke")) {
                    onlineActionMode = .poke
                }
            }
            Button(localized("clientActions.sendOfflineMessage")) {
                isShowingOfflineMessage = true
            }
            Button(localized("contacts.row.banUniqueId")) {
                isShowingBanContact = true
            }
            Button(localized("contacts.row.copyNickname")) {
                TS3PlatformSupport.copyToPasteboard(contact.nickname)
            }
            Button(localized("contacts.row.copyUniqueId")) {
                TS3PlatformSupport.copyToPasteboard(contact.uniqueIdentifier)
            }
            Button(localized("contacts.row.copySummary")) {
                TS3PlatformSupport.copyToPasteboard(clipboardSummary)
            }
            Button(localized("contacts.row.editContact")) {
                isEditing = true
            }
            Button(localized("contacts.row.findDatabaseClient")) {
                model.findDatabaseClient(for: contact)
                isShowingClientDatabase = true
            }
            Button(localized("contacts.row.saveContactBookmark")) {
                model.saveContactBookmark(for: contact)
            }
            .disabled(model.serverHost.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
            Button(localized("contacts.row.copyContactBookmark")) {
                TS3PlatformSupport.copyToPasteboard(model.contactBookmarkSummary(for: contact))
            }
            Button(localized("contacts.row.deleteContact")) {
                model.deleteContact(contact)
            }
        }
        .accessibilityElement(children: .ignore)
        .accessibilityLabel(contact.nickname)
        .accessibilityValue(contact.accessibilityValue(onlineNickname: onlineUser?.nickname))
        .accessibilityAction(named: localized("contacts.row.copySummary")) {
            TS3PlatformSupport.copyToPasteboard(clipboardSummary)
        }
        .accessibilityAction(named: localized("contacts.row.editContact")) {
            isEditing = true
        }
        .accessibilityAction(named: localized("contacts.row.findDatabaseClient")) {
            model.findDatabaseClient(for: contact)
            isShowingClientDatabase = true
        }
        .accessibilityAction(named: localized("contacts.row.saveContactBookmark")) {
            model.saveContactBookmark(for: contact)
        }
        .accessibilityAction(named: localized("contacts.row.copyContactBookmark")) {
            TS3PlatformSupport.copyToPasteboard(model.contactBookmarkSummary(for: contact))
        }
        .accessibilityAction(named: localized("clientActions.sendOfflineMessage")) {
            isShowingOfflineMessage = true
        }
        .accessibilityAction(named: localized("contacts.row.banUniqueId")) {
            isShowingBanContact = true
        }
        .accessibilityAction(named: localized("contacts.row.deleteContact")) {
            model.deleteContact(contact)
        }
    }

    private var clipboardSummary: String {
        contact.clipboardSummary(onlineNickname: onlineUser?.nickname)
    }
}

struct ContactOfflineMessageSheet: View {
    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    let contact: TS3ContactEntry
    @State private var subject = ""
    @State private var message = ""

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(contact.nickname)) {
                    Text(contact.uniqueIdentifier)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    TextField(localized("clientActions.subject"), text: $subject)
                        .ts3PlainTextField()
                    TextField(localized("clientActions.message"), text: $message)
                        .ts3PlainTextField()
                    Text(offlineMessageDraftSummary)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("clientActions.copyOfflineMessageSummary")) {
                        TS3PlatformSupport.copyToPasteboard(offlineMessageDraftSummary)
                    }
                    ForEach(offlineMessageDraftValidationMessages, id: \.self) { message in
                        Text(message)
                            .font(.caption)
                            .foregroundColor(.red)
                    }
                }
            }
            .navigationTitle(localized("clientActions.offlineMessage"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(NSLocalizedString("common.cancel", comment: "")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("clientActions.send")) {
                        model.sendOfflineMessage(
                            toUniqueIdentifier: contact.uniqueIdentifier,
                            subject: subject,
                            message: message
                        ) {
                            model.clearOfflineMessageDraft(id: offlineDraftId)
                        }
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(isSendDisabled)
                }
            }
            .onAppear {
                loadOfflineDraft()
            }
            .onChange(of: subject) { _ in
                saveOfflineDraft()
            }
            .onChange(of: message) { _ in
                saveOfflineDraft()
            }
        }
    }

    private var offlineDraftId: String {
        "uid:\(contact.uniqueIdentifier)"
    }

    private func loadOfflineDraft() {
        guard let draft = model.offlineMessageDraft(for: offlineDraftId) else { return }
        subject = draft.subject
        message = draft.message
    }

    private func saveOfflineDraft() {
        model.saveOfflineMessageDraft(
            id: offlineDraftId,
            recipientName: contact.nickname,
            subject: subject,
            message: message
        )
    }

    private var isSendDisabled: Bool {
        !offlineMessageDraftValidationMessages.isEmpty
    }

    private var offlineMessageDraftValidationMessages: [String] {
        TS3OfflineMessageDraftValidator.validationMessages(
            recipientName: contact.nickname,
            recipientUniqueIdentifier: contact.uniqueIdentifier,
            subject: subject,
            message: message
        )
    }

    private var offlineMessageDraftSummary: String {
        TS3OfflineMessageDraftValidator.creationSummary(
            recipientName: contact.nickname,
            recipientUniqueIdentifier: contact.uniqueIdentifier,
            subject: subject,
            message: message
        )
    }
}

struct ContactBanSheet: View {
    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    let contact: TS3ContactEntry
    @State private var reason = ""
    @State private var duration: TS3BanDuration = .permanent
    @State private var customBanMinutes = "60"

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(contact.nickname)) {
                    Text(contact.uniqueIdentifier)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Picker(localized("ban.duration"), selection: $duration) {
                        ForEach(TS3BanDuration.allCases) { duration in
                            Text(duration.title).tag(duration)
                        }
                    }
                    if duration == .custom {
                        TextField(localized("ban.minutes"), text: $customBanMinutes)
                            .ts3PlainTextField()
                            .ts3NumericKeyboard()
                    }
                    TextField(localized("ban.reason"), text: $reason)
                        .ts3PlainTextField()
                    Text(banDraftSummary)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("ban.copyRuleSummary")) {
                        TS3PlatformSupport.copyToPasteboard(banDraftSummary)
                    }
                    ForEach(banDraftValidationMessages, id: \.self) { message in
                        Text(message)
                            .font(.caption)
                            .foregroundColor(.red)
                    }
                }
            }
            .navigationTitle(localized("contacts.row.banUniqueId"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(NSLocalizedString("common.cancel", comment: "")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("clientActions.ban")) {
                        model.banContact(
                            contact,
                            durationSeconds: duration.seconds(customMinutes: customBanMinutes),
                            reason: reason,
                            isCustomDuration: duration == .custom
                        )
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(isBanDisabled)
                }
            }
        }
    }

    private var isBanDisabled: Bool {
        !banDraftValidationMessages.isEmpty
    }

    private var banDraftValidationMessages: [String] {
        TS3BanDraftValidator.validationMessages(
            ip: "",
            name: "",
            uniqueIdentifier: contact.uniqueIdentifier,
            myTeamSpeakId: "",
            lastNickname: contact.nickname,
            durationSeconds: duration.seconds(customMinutes: customBanMinutes),
            isCustomDuration: duration == .custom,
            reason: reason
        )
    }

    private var banDraftSummary: String {
        TS3BanDraftValidator.creationSummary(
            ip: "",
            name: "",
            uniqueIdentifier: contact.uniqueIdentifier,
            myTeamSpeakId: "",
            lastNickname: contact.nickname,
            durationSeconds: duration.seconds(customMinutes: customBanMinutes),
            isPermanent: duration == .permanent,
            reason: reason
        )
    }
}

struct ContactEditorSheet: View {
    @Environment(\.presentationMode) private var presentationMode
    let uniqueIdentifier: String
    let nickname: String
    let submit: (String, String, TS3ContactStatus, String) -> Void
    @State private var status: TS3ContactStatus
    @State private var note: String
    @State private var identifier: String
    @State private var displayName: String

    init(
        uniqueIdentifier: String,
        nickname: String,
        initialStatus: TS3ContactStatus,
        initialNote: String,
        submit: @escaping (String, String, TS3ContactStatus, String) -> Void
    ) {
        self.uniqueIdentifier = uniqueIdentifier
        self.nickname = nickname
        self.submit = submit
        _status = State(initialValue: initialStatus)
        _note = State(initialValue: initialNote)
        _identifier = State(initialValue: uniqueIdentifier)
        _displayName = State(initialValue: nickname)
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    private func localizedStatusTitle(_ status: TS3ContactStatus) -> String {
        switch status {
        case .neutral:
            return localized("contacts.status.neutral")
        case .friend:
            return localized("contacts.status.friend")
        case .ignored:
            return localized("contacts.status.ignored")
        case .blocked:
            return localized("contacts.status.blocked")
        }
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(displayName.isEmpty ? localized("contacts.editor.contact") : displayName)) {
                    TextField(localized("contacts.editor.uniqueId"), text: $identifier)
                        .ts3PlainTextField()
                    TextField(localized("contacts.editor.nickname"), text: $displayName)
                        .ts3PlainTextField()
                    Picker(localized("contacts.editor.status"), selection: $status) {
                        ForEach(TS3ContactStatus.allCases) { status in
                            Text(localizedStatusTitle(status)).tag(status)
                        }
                    }
                    TextField(localized("contacts.editor.note"), text: $note)
                        .ts3PlainTextField()
                }
                Section {
                    Button(localized("contacts.editor.save")) {
                        submit(identifier, displayName, status, note)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(identifier.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                }
            }
            .navigationTitle(uniqueIdentifier.isEmpty ? localized("contacts.editor.newTitle") : localized("contacts.editor.editTitle"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(NSLocalizedString("common.cancel", comment: "")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }
}

