enum TS3BanDuration: String, CaseIterable, Identifiable {
    case tenMinutes
    case oneHour
    case oneDay
    case oneWeek
    case permanent
    case custom

    var id: String { rawValue }

    var title: String {
        switch self {
        case .tenMinutes: return NSLocalizedString("ban.duration.tenMinutes", comment: "")
        case .oneHour: return NSLocalizedString("ban.duration.oneHour", comment: "")
        case .oneDay: return NSLocalizedString("ban.duration.oneDay", comment: "")
        case .oneWeek: return NSLocalizedString("ban.duration.oneWeek", comment: "")
        case .permanent: return NSLocalizedString("ban.duration.permanent", comment: "")
        case .custom: return NSLocalizedString("ban.duration.custom", comment: "")
        }
    }

    func seconds(customMinutes: String) -> Int? {
        switch self {
        case .tenMinutes: return 10 * 60
        case .oneHour: return 60 * 60
        case .oneDay: return 24 * 60 * 60
        case .oneWeek: return 7 * 24 * 60 * 60
        case .permanent: return nil
        case .custom: return Self.customSeconds(from: customMinutes)
        }
    }

    static func customSeconds(from minutesText: String) -> Int? {
        let trimmed = minutesText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let minutes = Int(trimmed), minutes > 0 else {
            return nil
        }
        return minutes * 60
    }

    static func draftSelection(for durationSeconds: Int?) -> (duration: TS3BanDuration, customMinutes: String) {
        guard let durationSeconds, durationSeconds > 0 else {
            return (.permanent, "60")
        }
        switch durationSeconds {
        case 10 * 60:
            return (.tenMinutes, "10")
        case 60 * 60:
            return (.oneHour, "60")
        case 24 * 60 * 60:
            return (.oneDay, "1440")
        case 7 * 24 * 60 * 60:
            return (.oneWeek, "10080")
        default:
            let minutes = max(1, Int((Double(durationSeconds) / 60.0).rounded(.up)))
            return (.custom, String(minutes))
        }
    }
}

enum TS3TemporaryPasswordDuration: String, CaseIterable, Identifiable {
    case tenMinutes
    case oneHour
    case oneDay
    case oneWeek
    case custom

    var id: String { rawValue }

    var title: String {
        switch self {
        case .tenMinutes: return "10 Minutes"
        case .oneHour: return "1 Hour"
        case .oneDay: return "1 Day"
        case .oneWeek: return "1 Week"
        case .custom: return "Custom"
