    func seconds(customMinutes: String) -> Int? {
        switch self {
        case .tenMinutes: return 10 * 60
        case .oneHour: return 60 * 60
        case .oneDay: return 24 * 60 * 60
        case .oneWeek: return 7 * 24 * 60 * 60
        case .custom: return Self.customSeconds(from: customMinutes)
        }
    }

    static func customSeconds(from minutesText: String) -> Int? {
        let trimmed = minutesText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let minutes = Int(trimmed), minutes > 0 else {
            return nil
        }
        return minutes * 60
    }
}

struct ChatSheet: View {
    private struct ChatFilterPresetImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3ChatFilterPresetImportPreview
        let id = UUID()
    }

    private struct ChatConversationFilter: Identifiable, Hashable {
        enum Scope: Hashable {
            case all
            case server
            case channel(Int?)
            case client(Int?)
        }

        let scope: Scope
        let title: String
        let messageCount: Int

        var id: String {
            switch scope {
            case .all:
                return "all"
            case .server:
                return "server"
            case .channel(let id):
                return "channel:\(id.map(String.init) ?? "unknown")"
            case .client(let id):
                return "client:\(id.map(String.init) ?? "unknown")"
            }
        }

        func includes(_ message: TS3ChatMessageSummary) -> Bool {
            switch scope {
            case .all:
                return true
            case .server:
                return message.targetMode == .server
            case .channel(let id):
                return message.targetMode == .channel && message.targetId == id
            case .client(let id):
                guard message.targetMode == .client else { return false }
                let peerId = message.isOwnMessage ? message.targetId : message.senderId
                return peerId == id
            }
        }
    }

    private enum ChatSenderFilter: String, CaseIterable, Identifiable {
        case all
        case own
        case others

        var id: String { rawValue }

        var title: String {
            switch self {
            case .all: return NSLocalizedString("chat.sender.all", comment: "")
            case .own: return NSLocalizedString("chat.sender.own", comment: "")
            case .others: return NSLocalizedString("chat.sender.others", comment: "")
            }
        }

        func includes(_ message: TS3ChatMessageSummary) -> Bool {
            switch self {
            case .all:
                return true
            case .own:
                return message.isOwnMessage
            case .others:
                return !message.isOwnMessage
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var message = ""
    @State private var target: TS3TextMessageTargetMode = .channel
    @State private var selectedPrivateClientId = 0
    @State private var selectedConversationId = "all"
    @State private var filter: ChatMessageFilter = .all
    @State private var senderFilter: ChatSenderFilter = .all
    @State private var newestFirst = false
    @State private var searchText = ""
    @State private var presetName = ""
    @State private var isShowingOfflineMessages = false
    @State private var isConfirmingClearHistory = false
    @State private var isConfirmingClearVisibleHistory = false
    @State private var isExportingTranscript = false
    @State private var isImportingChatHistory = false
    @State private var isExportingChatHistory = false
    @State private var isImportingPresets = false
    @State private var isExportingPresets = false
    @State private var isConfirmingDeletePresets = false
    @State private var isShowingHistorySettings = false
    @State private var pendingPresetImport: ChatFilterPresetImportConfirmation?
    @State private var transcriptDocument = TS3TextFileDocument()
    @State private var chatHistoryDocument = TS3BookmarkFileDocument()
    @State private var presetsDocument = TS3BookmarkFileDocument()

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            VStack(spacing: 0) {
                VStack(spacing: 8) {
                    Picker(localized("chat.target"), selection: $target) {
                        Text("chat.mode.channel").tag(TS3TextMessageTargetMode.channel)
                        Text("chat.mode.server").tag(TS3TextMessageTargetMode.server)
                        Text("chat.mode.private").tag(TS3TextMessageTargetMode.client)
                    }
                    .pickerStyle(.segmented)

                    if target == .client {
                        if privateMessageTargets.isEmpty {
                            Text(localized("chat.noOtherUsers"))
                                .font(.caption)
                                .foregroundColor(.secondary)
                                .frame(maxWidth: .infinity, alignment: .leading)
                        } else {
                            Picker(localized("chat.user"), selection: $selectedPrivateClientId) {
                                ForEach(privateMessageTargets) { user in
                                    Text(user.nickname).tag(user.id)
                                }
                            }
                        }
                    }

                    Picker(localized("chat.filter"), selection: $filter) {
                        ForEach(ChatMessageFilter.allCases) { item in
                            Text(item.title).tag(item)
                        }
                    }
                    .pickerStyle(.segmented)

                    Picker(localized("chat.conversation"), selection: $selectedConversationId) {
                        ForEach(chatConversationOptions) { conversation in
                            Text(conversationPickerTitle(conversation)).tag(conversation.id)
                        }
                    }

                    Picker(localized("chat.sender"), selection: $senderFilter) {
                        ForEach(ChatSenderFilter.allCases) { item in
                            Text(item.title).tag(item)
                        }
                    }

                    Toggle(localized("chat.newestFirst"), isOn: $newestFirst)

                    TextField(localized("chat.searchPlaceholder"), text: $searchText)
                        .textFieldStyle(.roundedBorder)

                    Menu {
                        TextField(localized("chat.presetName"), text: $presetName)
                        Button(localized("chat.saveCurrentFilters")) {
                            model.saveChatFilterPreset(
                                name: presetName,
                                messageFilter: filter.rawValue,
                                senderFilter: senderFilter.rawValue,
                                newestFirst: newestFirst,
                                searchText: searchText
                            )
                            presetName = ""
                        }
                        .disabled(presetName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                        if model.chatFilterPresets.isEmpty {
                            Text(localized("chat.noSavedFilterPresets"))
                        } else {
                            ForEach(model.chatFilterPresets) { preset in
                                Menu {
                                    Button(localized("chat.applyPreset")) {
                                        applyPreset(preset)
                                    }
                                    Button(localized("chat.useName")) {
                                        presetName = preset.name
                                    }
                                    Button(localized("chat.deletePreset")) {
                                        model.deleteChatFilterPreset(preset)
                                    }
                                } label: {
                                    VStack(alignment: .leading) {
                                        Text(preset.name)
                                        Text(presetSummary(preset))
                                    }
                                }
                            }
                        }
                        Divider()
                        Button(localized("chat.exportPresets")) {
                            exportPresets()
                        }
                        .disabled(model.chatFilterPresets.isEmpty)
                        Button(localized("chat.importPresets")) {
                            isImportingPresets = true
                        }
                        Button(localized("chat.deleteAllPresets")) {
                            isConfirmingDeletePresets = true
                        }
                        .disabled(model.chatFilterPresets.isEmpty)
                    } label: {
                        Label(localized("chat.filterPresets"), systemImage: "line.3.horizontal.decrease.circle")
                    }

                    if hasChatFilters {
                        Button(localized("chat.clearFilters")) {
                            filter = .all
                            senderFilter = .all
                            selectedConversationId = "all"
                            newestFirst = false
                            searchText = ""
                        }
                    }
                }
                .padding()

                List {
                    if filteredMessages.isEmpty {
                        Text(emptyMessageText)
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(filteredMessages) { item in
                            ChatMessageRow(item: item, replyUser: replyUser(for: item))
                                .environmentObject(model)
                                .listRowBackground(item.isOwnMessage ? Color.accentColor.opacity(0.08) : Color.clear)
                        }
                    }
                }

                HStack(spacing: 8) {
                    TextField(localized("chat.message"), text: $message)
                        .textFieldStyle(.roundedBorder)
                    Button(localized("chat.send")) {
                        switch target {
                        case .server:
                            model.sendServerMessage(message)
                        case .channel:
                            model.sendChannelMessage(message)
                        case .client:
                            if let user = selectedPrivateClient {
                                model.sendPrivateMessage(message, to: user)
                            }
                        }
                        message = ""
                    }
                    .buttonStyle(TS3BorderedButtonStyle(isProminent: true))
                    .disabled(!canSendMessage)
                }
                .padding()
            }
            .navigationTitle(localized("chat.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItemGroup(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("chat.inbox")) {
                        model.refreshOfflineMessages()
                        isShowingOfflineMessages = true
                    }
                    .disabled(model.state != .connected)
                    Button(localized("chat.clear")) {
                        isConfirmingClearHistory = true
                    }
                    .disabled(model.chatMessages.isEmpty)
                    Menu {
                        Button(localized("chat.exportTranscript")) {
                            transcriptDocument = TS3TextFileDocument(data: model.chatTranscriptData(
                                messages: filteredMessages,
                                title: selectedConversation.title,
                                filterSummary: transcriptFilterSummary
                            ))
                            isExportingTranscript = true
                        }
                        .disabled(filteredMessages.isEmpty)
                        Button(localized("chat.exportHistoryBackup")) {
                            exportChatHistory()
                        }
                        .disabled(model.chatMessages.isEmpty)
                        Button(localized("chat.importHistoryBackup")) {
                            isImportingChatHistory = true
                        }
                        Button(localized("chat.historySettings")) {
                            isShowingHistorySettings = true
                        }
                        Divider()
                        Button(localized("chat.clearVisibleHistory")) {
                            isConfirmingClearVisibleHistory = true
                        }
                        .disabled(filteredMessages.isEmpty)
                    } label: {
                        Label(localized("chat.history"), systemImage: "ellipsis.circle")
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.done")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .sheet(isPresented: $isShowingOfflineMessages) {
                OfflineMessagesSheet()
                    .environmentObject(model)
            }
            .sheet(isPresented: $isShowingHistorySettings) {
                ChatHistorySettingsSheet()
                    .environmentObject(model)
            }
            .fileExporter(
                isPresented: $isExportingTranscript,
                document: transcriptDocument,
                contentType: .plainText,
                defaultFilename: "ts3-chat-transcript"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPresets,
                document: presetsDocument,
                contentType: .json,
                defaultFilename: "ts3-chat-filter-presets"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingChatHistory,
                document: chatHistoryDocument,
                contentType: .json,
                defaultFilename: "ts3-chat-history"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPresets,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    preparePresetImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .sheet(item: $pendingPresetImport) { confirmation in
                ChatFilterPresetImportSheet(
                    preview: confirmation.preview,
                    importPresets: { selectedPresetIds in
                        importPresets(data: confirmation.data, selectedPresetIds: selectedPresetIds)
                        pendingPresetImport = nil
                    },
                    cancel: {
                        pendingPresetImport = nil
                    }
                )
            }
            .fileImporter(
                isPresented: $isImportingChatHistory,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    importChatHistory(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .onAppear {
                model.beginViewingChat()
                selectDefaultPrivateClientIfNeeded()
            }
            .onChange(of: target) { _ in
                selectDefaultPrivateClientIfNeeded()
            }
            .onChange(of: model.clients.map(\.id)) { _ in
                selectDefaultPrivateClientIfNeeded()
            }
            .onChange(of: model.chatMessages.map(\.id)) { _ in
                resetSelectedConversationIfNeeded()
            }
            .onDisappear {
                model.endViewingChat()
            }
            .alert(isPresented: $isConfirmingClearHistory) {
                Alert(
                    title: Text(localized("chat.clearHistoryAlert.title")),
                    message: Text(localized("chat.clearHistoryAlert.message")),
                    primaryButton: .destructive(Text(localized("chat.clearHistory"))) {
                        model.clearChatHistory()
                    },
                    secondaryButton: .cancel()
                )
            }
            .alert(isPresented: $isConfirmingClearVisibleHistory) {
                Alert(
                    title: Text(localized("chat.clearVisibleHistoryAlert.title")),
                    message: Text(localized("chat.clearVisibleHistoryAlert.message", filteredMessages.count)),
                    primaryButton: .destructive(Text(localized("chat.clearVisible"))) {
                        model.clearChatMessages(filteredMessages)
                    },
                    secondaryButton: .cancel()
                )
            }
            .alert(isPresented: $isConfirmingDeletePresets) {
                Alert(
                    title: Text(localized("chat.deleteAllPresetsAlert.title")),
                    message: Text(localized("chat.deleteAllPresetsAlert.message", model.chatFilterPresets.count)),
                    primaryButton: .destructive(Text(localized("connect.delete"))) {
                        model.deleteAllChatFilterPresets()
                    },
                    secondaryButton: .cancel()
                )
            }
        }
    }

    private var privateMessageTargets: [TS3UserSummary] {
        model.clients.filter { !$0.isCurrentUser }
    }

    private var selectedPrivateClient: TS3UserSummary? {
        privateMessageTargets.first { $0.id == selectedPrivateClientId }
    }

    private var canSendMessage: Bool {
        !message.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            && model.state == .connected
            && (target != .client || selectedPrivateClient != nil)
    }

    private var selectedConversation: ChatConversationFilter {
        chatConversationOptions.first { $0.id == selectedConversationId } ?? chatConversationOptions[0]
    }

    private var chatConversationOptions: [ChatConversationFilter] {
        let messages = model.chatMessages
        let serverMessages = messages.filter { $0.targetMode == .server }
        let channelIds = Set(messages.compactMap { message -> Int?? in
            guard message.targetMode == .channel else { return nil }
            return .some(message.targetId)
        })
        let clientIds = Set(messages.compactMap { message -> Int?? in
            guard message.targetMode == .client else { return nil }
            return .some(message.isOwnMessage ? message.targetId : message.senderId)
        })

        var options = [
            ChatConversationFilter(scope: .all, title: localized("chat.allConversations"), messageCount: messages.count)
        ]

        if !serverMessages.isEmpty {
            options.append(ChatConversationFilter(scope: .server, title: localized("chat.mode.server"), messageCount: serverMessages.count))
        }

        let channelOptions = channelIds.map { id in
            ChatConversationFilter(
                scope: .channel(id),
                title: channelTitle(for: id),
                messageCount: messages.filter { $0.targetMode == .channel && $0.targetId == id }.count
            )
        }
        .sorted { lhs, rhs in
            lhs.title.localizedCaseInsensitiveCompare(rhs.title) == .orderedAscending
        }

        let clientOptions = clientIds.map { id in
            ChatConversationFilter(
                scope: .client(id),
                title: clientTitle(for: id, in: messages),
                messageCount: messages.filter { message in
                    guard message.targetMode == .client else { return false }
                    return (message.isOwnMessage ? message.targetId : message.senderId) == id
                }.count
            )
        }
        .sorted { lhs, rhs in
            lhs.title.localizedCaseInsensitiveCompare(rhs.title) == .orderedAscending
        }

        options.append(contentsOf: channelOptions)
        options.append(contentsOf: clientOptions)
        return options
    }

    private var filteredMessages: [TS3ChatMessageSummary] {
        let query = searchText.trimmingCharacters(in: .whitespacesAndNewlines)
        let conversation = selectedConversation
        let messages = model.chatMessages.filter { item in
            conversation.includes(item)
                && filter.includes(item.targetMode)
                && senderFilter.includes(item)
                && (query.isEmpty
                    || item.senderName.localizedCaseInsensitiveContains(query)
                    || item.message.localizedCaseInsensitiveContains(query))
        }
        if newestFirst {
            return messages.sorted { $0.timestamp > $1.timestamp }
        }
        return messages.sorted { $0.timestamp < $1.timestamp }
    }

    private var emptyMessageText: String {
        model.chatMessages.isEmpty ? localized("chat.noMessages") : localized("chat.noMatchingMessages")
    }

    private var hasChatFilters: Bool {
        filter != .all
            || senderFilter != .all
            || selectedConversationId != "all"
            || newestFirst
            || !searchText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
    }

    private var transcriptFilterSummary: String {
        var parts = [
            filter.title,
            senderFilter.title,
            newestFirst ? localized("chat.newestFirstSummary") : localized("chat.oldestFirstSummary")
        ]
        let query = searchText.trimmingCharacters(in: .whitespacesAndNewlines)
        if !query.isEmpty {
            parts.append(localized("chat.searchSummary", query))
        }
        return parts.joined(separator: " | ")
    }

    private func replyUser(for item: TS3ChatMessageSummary) -> TS3UserSummary? {
        guard item.targetMode == .client else {
            return nil
        }
        return model.onlineUser(for: item)
    }

    private func selectDefaultPrivateClientIfNeeded() {
        guard target == .client else { return }
        if !privateMessageTargets.contains(where: { $0.id == selectedPrivateClientId }) {
            selectedPrivateClientId = privateMessageTargets.first?.id ?? 0
        }
    }

    private func resetSelectedConversationIfNeeded() {
        if !chatConversationOptions.contains(where: { $0.id == selectedConversationId }) {
            selectedConversationId = "all"
        }
    }

    private func conversationPickerTitle(_ conversation: ChatConversationFilter) -> String {
        "\(conversation.title) (\(conversation.messageCount))"
    }

    private func channelTitle(for id: Int?) -> String {
        guard let id else { return localized("chat.unknownChannel") }
        return model.channels.first { $0.id == id }?.name ?? localized("chat.channelFormat", id)
    }

    private func clientTitle(for id: Int?, in messages: [TS3ChatMessageSummary]) -> String {
        guard let id else { return localized("chat.unknownUser") }
        if let nickname = model.clients.first(where: { $0.id == id })?.nickname {
            return nickname
        }
        if let message = messages.last(where: { !$0.isOwnMessage && $0.senderId == id }) {
            return message.senderName
        }
        return localized("chat.clientFormat", id)
    }

    private func exportChatHistory() {
        do {
            chatHistoryDocument = TS3BookmarkFileDocument(data: try model.chatHistoryBackupData())
            isExportingChatHistory = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importChatHistory(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            _ = try model.importChatHistoryBackup(from: Data(contentsOf: url))
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func applyPreset(_ preset: TS3ChatFilterPreset) {
        filter = ChatMessageFilter(rawValue: preset.messageFilter) ?? .all
        senderFilter = ChatSenderFilter(rawValue: preset.senderFilter) ?? .all
        newestFirst = preset.newestFirst
        searchText = preset.searchText
        presetName = preset.name
    }

    private func presetSummary(_ preset: TS3ChatFilterPreset) -> String {
        var parts = [
            (ChatMessageFilter(rawValue: preset.messageFilter) ?? .all).title,
            (ChatSenderFilter(rawValue: preset.senderFilter) ?? .all).title,
            preset.newestFirst ? localized("chat.newest") : localized("chat.oldest")
        ]
        if !preset.searchText.isEmpty {
            parts.append(localized("chat.searchPresetSummary", preset.searchText))
        }
        return parts.joined(separator: " · ")
    }

    private func exportPresets() {
        do {
            presetsDocument = TS3BookmarkFileDocument(data: try model.chatFilterPresetsExportData())
            isExportingPresets = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func preparePresetImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.chatFilterPresetsImportPreview(from: data)
            pendingPresetImport = ChatFilterPresetImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPresets(data: Data, selectedPresetIds: Set<UUID>) {
        do {
            _ = try model.importChatFilterPresets(from: data, selectedPresetIds: selectedPresetIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }
}

private struct ChatFilterPresetImportSheet: View {
    @Environment(\.presentationMode) private var presentationMode

    let preview: TS3ChatFilterPresetImportPreview
    let importPresets: (Set<UUID>) -> Void
    let cancel: () -> Void
    @State private var selectedPresetIds: Set<UUID>

    init(
        preview: TS3ChatFilterPresetImportPreview,
        importPresets: @escaping (Set<UUID>) -> Void,
        cancel: @escaping () -> Void
    ) {
        self.preview = preview
        self.importPresets = importPresets
        self.cancel = cancel
        _selectedPresetIds = State(initialValue: Set(preview.candidates.map(\.id)))
    }

    private var canImport: Bool {
        preview.candidates.contains { selectedPresetIds.contains($0.id) }
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text("chat.importPreview")) {
                    Text(String(format: NSLocalizedString("chat.importedPresetsFormat", comment: ""), preview.importedPresetCount))
                    Text(String(format: NSLocalizedString("chat.usablePresetsFormat", comment: ""), preview.usablePresetCount))
                    Text(String(format: NSLocalizedString("chat.newPresetsFormat", comment: ""), preview.newPresetCount))
                    Text(String(format: NSLocalizedString("chat.replacingPresetsFormat", comment: ""), preview.replacedPresetCount))
                    Text(String(format: NSLocalizedString("chat.skippedPresetsFormat", comment: ""), preview.skippedPresetCount))
                    Button("chat.copyBackupPreview") {
                        TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                    }
                }

                Section(header: Text("chat.restore")) {
                    HStack {
                        Button("chat.selectAll") {
                            selectedPresetIds = Set(preview.candidates.map(\.id))
                        }
                        Spacer()
                        Button("connect.clear") {
                            selectedPresetIds.removeAll()
                        }
                    }
                    ForEach(preview.candidates) { candidate in
                        Toggle(
                            candidate.summary,
                            isOn: Binding(
                                get: { selectedPresetIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedPresetIds.insert(candidate.id)
                                    } else {
                                        selectedPresetIds.remove(candidate.id)
                                    }
                                }
                            )
                        )
                    }
                }

                Section {
                    Text("chat.importBehavior.summary")
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(Text("chat.importFilters"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button("common.cancel") {
                        cancel()
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button("chat.import") {
                        importPresets(selectedPresetIds)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canImport)
                }
            }
        }
    }
}

struct ChatMessageRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let item: TS3ChatMessageSummary
    let replyUser: TS3UserSummary?
    @State private var replyTarget: TS3UserSummary?

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            HStack {
                Text(item.senderName)
                    .font(.subheadline.weight(.semibold))
                Spacer()
                Text(Self.dateText(item.timestamp))
                    .font(.caption)
                    .foregroundColor(.secondary)
                Text(targetModeText(item.targetMode))
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
            Text(item.message)
                .font(.body)
            if let replyUser {
                Button("chat.reply") {
                    replyTarget = replyUser
                }
                .buttonStyle(.borderless)
                .font(.caption)
                .accessibilityLabel(String(format: NSLocalizedString("chat.replyToFormat", comment: ""), replyUser.nickname))
            }
        }
        .contextMenu {
            Button("chat.copyMessage") {
                TS3PlatformSupport.copyToPasteboard(item.message)
            }
            Button("chat.copySender") {
                TS3PlatformSupport.copyToPasteboard(item.senderName)
            }
            if let replyUser, replyUser.uniqueIdentifier?.isEmpty == false {
                Button("chat.addSenderToContacts") {
                    model.addContact(from: item)
                }
            }
            Button("chat.copyEntry") {
                TS3PlatformSupport.copyToPasteboard(clipboardText)
            }
        }
        .sheet(item: $replyTarget) { user in
            ChatPrivateReplySheet(user: user)
                .environmentObject(model)
        }
    }

    private func targetModeText(_ mode: TS3TextMessageTargetMode) -> String {
        switch mode {
        case .server:
            return NSLocalizedString("chat.mode.server", comment: "")
        case .channel:
            return NSLocalizedString("chat.mode.channel", comment: "")
        case .client:
            return NSLocalizedString("chat.mode.private", comment: "")
        }
    }

    private var clipboardText: String {
        "\(Self.dateText(item.timestamp)) [\(targetModeText(item.targetMode))] \(item.senderName): \(item.message)"
    }

    private static func dateText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .short
        formatter.timeStyle = .short
        return formatter.string(from: date)
    }
}

struct ChatHistorySettingsSheet: View {
    private struct ChatHistorySettingsImportConfirmation: Identifiable {
        let url: URL
        let id = UUID()
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var messageLimitText = ""
    @State private var isExportingSettings = false
    @State private var isImportingSettings = false
    @State private var isConfirmingReset = false
    @State private var pendingImport: ChatHistorySettingsImportConfirmation?
    @State private var settingsDocument = TS3TextFileDocument()

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text("chat.retention")) {
                    TextField(NSLocalizedString("chat.messageLimit", comment: ""), text: $messageLimitText)
                        .ts3PlainTextField()
                    Text("chat.historyLimitHelp")
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button("chat.applyLimit") {
                        applyLimit()
                    }
                    .disabled(parsedLimit == nil)
                    Menu("chat.presets") {
                        Button(String(format: NSLocalizedString("chat.keepMessagesFormat", comment: ""), 100)) {
                            setLimit(100)
                        }
                        Button(String(format: NSLocalizedString("chat.keepMessagesFormat", comment: ""), 500)) {
                            setLimit(500)
                        }
                        Button(String(format: NSLocalizedString("chat.keepMessagesFormat", comment: ""), 1000)) {
                            setLimit(1000)
                        }
                        Button(String(format: NSLocalizedString("chat.keepMessagesFormat", comment: ""), 5000)) {
                            setLimit(5000)
                        }
                    }
                }

                Section(header: Text("chat.backup")) {
                    Button("chat.exportHistorySettings") {
                        exportSettings()
                    }
                    Button("chat.importHistorySettings") {
                        isImportingSettings = true
                    }
                    Button("chat.resetHistorySettings") {
                        isConfirmingReset = true
                    }
                    .foregroundColor(.red)
                }
            }
            .navigationTitle(Text("chat.historySettings"))
            .ts3InlineNavigationTitle()
            .onAppear {
                messageLimitText = "\(model.chatHistoryMessageLimit)"
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button("common.done") {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .fileExporter(
                isPresented: $isExportingSettings,
                document: settingsDocument,
                contentType: .json,
                defaultFilename: "ts3-chat-history-settings"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingSettings,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    pendingImport = ChatHistorySettingsImportConfirmation(url: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .alert(isPresented: $isConfirmingReset) {
                Alert(
                    title: Text("chat.resetHistorySettingsAlert.title"),
                    message: Text("chat.resetHistorySettingsAlert.message"),
                    primaryButton: .destructive(Text("shortcuts.reset")) {
                        model.resetChatHistorySettings()
                        messageLimitText = "\(model.chatHistoryMessageLimit)"
                    },
                    secondaryButton: .cancel()
                )
            }
            .alert(item: $pendingImport) { confirmation in
                Alert(
                    title: Text("chat.importHistorySettingsAlert.title"),
                    message: Text("chat.importHistorySettingsAlert.message"),
                    primaryButton: .destructive(Text("chat.import")) {
                        importSettings(from: confirmation.url)
                    },
                    secondaryButton: .cancel()
                )
            }
        }
    }

    private var parsedLimit: Int? {
        let trimmed = messageLimitText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let value = Int(trimmed), value > 0 else { return nil }
        return value
    }

    private func setLimit(_ limit: Int) {
        model.updateChatHistoryMessageLimit(limit)
        messageLimitText = "\(model.chatHistoryMessageLimit)"
    }

    private func applyLimit() {
        guard let parsedLimit else { return }
        setLimit(parsedLimit)
    }

    private func exportSettings() {
        do {
            settingsDocument = TS3TextFileDocument(data: try model.chatHistorySettingsExportData())
            isExportingSettings = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importSettings(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            try model.importChatHistorySettings(from: Data(contentsOf: url))
            messageLimitText = "\(model.chatHistoryMessageLimit)"
        } catch {
            model.lastError = error.localizedDescription
        }
    }
}

