enum ChatMessageFilter: String, CaseIterable, Identifiable {
    case all
    case channel
    case server
    case privateMessage

    var id: String { rawValue }

    var title: String {
        switch self {
        case .all:
            return NSLocalizedString("chat.filter.all", comment: "")
        case .channel:
            return NSLocalizedString("chat.mode.channel", comment: "")
        case .server:
            return NSLocalizedString("chat.mode.server", comment: "")
        case .privateMessage:
            return NSLocalizedString("chat.mode.private", comment: "")
        }
    }

    func includes(_ mode: TS3TextMessageTargetMode) -> Bool {
        switch self {
        case .all:
            return true
        case .channel:
            return mode == .channel
        case .server:
            return mode == .server
        case .privateMessage:
            return mode == .client
        }
    }
}

struct EventsSheet: View {
    private struct EventArchiveImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3EventHistoryArchivePreview
        let id = UUID()
    }

    private struct EventFilterPresetImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3EventFilterPresetImportPreview
        let id = UUID()
    }

    private enum EventCleanupConfirmation: Identifiable {
        case all
        case activity
        case pokes

        var id: String {
            switch self {
            case .all: return "all"
            case .activity: return "activity"
            case .pokes: return "pokes"
            }
        }

        var title: String {
            switch self {
            case .all: return NSLocalizedString("events.clearAllAlert.title", comment: "")
            case .activity: return NSLocalizedString("events.clearActivityAlert.title", comment: "")
            case .pokes: return NSLocalizedString("events.clearPokesAlert.title", comment: "")
            }
        }

        func message(activityCount: Int, pokeCount: Int) -> String {
            switch self {
            case .all:
                return String(format: NSLocalizedString("events.clearAllAlert.messageFormat", comment: ""), activityCount, pokeCount)
            case .activity:
                return String(format: NSLocalizedString("events.clearActivityAlert.messageFormat", comment: ""), activityCount)
            case .pokes:
                return String(format: NSLocalizedString("events.clearPokesAlert.messageFormat", comment: ""), pokeCount)
            }
        }
    }

    private enum EventSourceFilter: String, CaseIterable, Identifiable {
        case all
        case own
        case others

        var id: String { rawValue }

        var title: String {
            switch self {
            case .all: return NSLocalizedString("events.source.all", comment: "")
            case .own: return NSLocalizedString("events.source.own", comment: "")
            case .others: return NSLocalizedString("events.source.others", comment: "")
            }
        }

        func includes(_ event: TS3ActivitySummary) -> Bool {
            switch self {
            case .all:
                return true
            case .own:
                return event.isOwnClient
            case .others:
                return !event.isOwnClient
            }
        }

        func includes(_ poke: TS3PokeSummary) -> Bool {
            switch self {
            case .all:
                return true
            case .own:
                return poke.isOwnPoke
            case .others:
                return !poke.isOwnPoke
            }
        }
    }

    private enum EventFilter: String, CaseIterable, Identifiable {
        case all
        case activity
        case pokes
        case clientMovement
        case channelChanges

        var id: String { rawValue }

        var title: String {
            switch self {
            case .all: return NSLocalizedString("events.filter.all", comment: "")
            case .activity: return NSLocalizedString("events.activity", comment: "")
            case .pokes: return NSLocalizedString("events.pokes", comment: "")
            case .clientMovement: return NSLocalizedString("events.filter.clientMovement", comment: "")
            case .channelChanges: return NSLocalizedString("events.filter.channelChanges", comment: "")
            }
        }

        var includesPokes: Bool {
            self == .all || self == .pokes
        }

        func includes(_ event: TS3ActivitySummary) -> Bool {
            switch self {
            case .all, .activity:
                return true
            case .pokes:
                return false
            case .clientMovement:
                switch event.kind {
                case .clientEntered, .clientLeft, .clientMoved:
                    return true
                case .channelCreated, .channelEdited, .channelDeleted, .channelMoved, .channelPasswordChanged, .channelDescriptionChanged:
                    return false
                }
            case .channelChanges:
                switch event.kind {
                case .clientEntered, .clientLeft, .clientMoved:
                    return false
                case .channelCreated, .channelEdited, .channelDeleted, .channelMoved, .channelPasswordChanged, .channelDescriptionChanged:
                    return true
                }
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var eventFilter: EventFilter = .all
    @State private var sourceFilter: EventSourceFilter = .all
    @State private var newestFirst = true
    @State private var searchText = ""
    @State private var presetName = ""
    @State private var isExportingEvents = false
    @State private var isExportingEventArchive = false
    @State private var isImportingEventArchive = false
    @State private var isExportingPresets = false
    @State private var isImportingPresets = false
    @State private var isConfirmingDeletePresets = false
    @State private var cleanupConfirmation: EventCleanupConfirmation?
    @State private var pendingEventArchiveImport: EventArchiveImportConfirmation?
    @State private var pendingPresetImport: EventFilterPresetImportConfirmation?
    @State private var eventsDocument = TS3TextFileDocument()
    @State private var eventArchiveDocument = TS3BookmarkFileDocument()
    @State private var presetsDocument = TS3BookmarkFileDocument()

    private var visibleActivityEvents: [TS3ActivitySummary] {
        let events = model.activityEvents.filter { event in
            eventFilter.includes(event) && sourceFilter.includes(event) && (
                !isSearching
                    || containsSearch(event.clientName)
                    || containsSearch(event.invokerName)
                    || containsSearch(event.channelName)
                    || containsSearch(event.reasonMessage)
                    || containsSearch(ActivityEventRow.snapshotMessage(for: event, in: model))
            )
        }
        return sortedActivityEvents(events)
    }

    private var visiblePokeEvents: [TS3PokeSummary] {
        guard eventFilter.includesPokes else { return [] }
        let pokes = model.pokeEvents.filter { poke in
            sourceFilter.includes(poke) && (
                !isSearching
                    || containsSearch(poke.senderName)
                    || containsSearch(poke.senderUniqueIdentifier)
                    || containsSearch(poke.message)
            )
        }
        return sortedPokeEvents(pokes)
    }

    private var hasVisibleEvents: Bool {
        !visibleActivityEvents.isEmpty || !visiblePokeEvents.isEmpty
    }

    private var visiblePokeSummary: TS3PokeListSummary {
        TS3PokeListSummary(pokes: visiblePokeEvents)
    }

    private var visiblePokeClearImpact: TS3PokeClearImpactSummary {
        TS3PokeClearImpactSummary(pokes: visiblePokeEvents)
    }

    private var visibleEventsSnapshot: String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short

        func dateText(_ date: Date) -> String {
            formatter.string(from: date)
        }

        var lines: [String] = []
        if eventFilter != .all {
            lines.append("Type Filter: \(eventFilter.title)")
        }
        if sourceFilter != .all {
            lines.append("Source Filter: \(sourceFilter.title)")
        }
        lines.append("Sort: \(newestFirst ? "Newest First" : "Oldest First")")
        if isSearching {
            lines.append("Search: \(searchText.trimmingCharacters(in: .whitespacesAndNewlines))")
        }
        if !lines.isEmpty {
            lines.append("")
        }
        if !visibleActivityEvents.isEmpty {
            lines.append("Activity")
            for event in visibleActivityEvents {
                lines.append("[\(dateText(event.timestamp))] \(event.clientName): \(ActivityEventRow.snapshotMessage(for: event, in: model))")
                if let reason = event.reasonMessage, !reason.isEmpty {
                    lines.append("  Reason: \(reason)")
                }
            }
        }
        if !visiblePokeEvents.isEmpty {
            if !lines.isEmpty { lines.append("") }
            lines.append("Pokes")
            for poke in visiblePokeEvents {
                lines.append("[\(dateText(poke.timestamp))] \(poke.isOwnPoke ? "Sent to" : "Received from") \(poke.senderName): \(poke.message.isEmpty ? "Poke" : poke.message)")
            }
        }
        return lines.joined(separator: "\n")
    }

    var body: some View {
        NavigationView {
            List {
                Section(header: Text(localized("events.filters"))) {
                    Picker(localized("groups.type"), selection: $eventFilter) {
                        ForEach(EventFilter.allCases) { filter in
                            Text(filter.title).tag(filter)
                        }
                    }
                    Picker(localized("events.source"), selection: $sourceFilter) {
                        ForEach(EventSourceFilter.allCases) { filter in
                            Text(filter.title).tag(filter)
                        }
                    }
                    Toggle(localized("events.newestFirst"), isOn: $newestFirst)
                    TextField(localized("events.searchEvents"), text: $searchText)
                        .ts3PlainTextField()
                    if hasLocalFilters {
                        Button(localized("events.clearFilters")) {
                            eventFilter = .all
                            sourceFilter = .all
                            newestFirst = true
                            searchText = ""
                        }
                    }
                    ServerInfoDetailRow(
                        label: localized("events.visiblePokeSummary"),
                        value: localized("events.visiblePokeSummaryFormat", visiblePokeSummary.totalCount)
                    )
                    Text(pokeSummaryText(visiblePokeSummary))
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("events.copyVisiblePokeSummary")) {
                        TS3PlatformSupport.copyToPasteboard(visiblePokeSummary.clipboardSummary)
                    }
                    .disabled(visiblePokeEvents.isEmpty)
                }

                Section(header: Text(localized("groups.filterPresets"))) {
                    TextField(localized("groups.presetName"), text: $presetName)
                        .ts3PlainTextField()
                    Button(localized("groups.saveCurrentFilters")) {
                        model.saveEventFilterPreset(
                            name: presetName,
                            eventFilter: eventFilter.rawValue,
                            sourceFilter: sourceFilter.rawValue,
                            newestFirst: newestFirst,
                            searchText: searchText
                        )
                        presetName = ""
                    }
                    .disabled(presetName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                    if model.eventFilterPresets.isEmpty {
                        Text(localized("events.noSavedFilterPresets"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(model.eventFilterPresets) { preset in
                            HStack {
                                VStack(alignment: .leading, spacing: 2) {
                                    Text(preset.name)
                                        .font(.subheadline.weight(.semibold))
                                    Text(presetSummary(preset))
                                        .font(.caption)
                                        .foregroundColor(.secondary)
                                }
                                Spacer()
                                Menu {
                                    Button(localized("groups.applyPreset")) {
                                        applyPreset(preset)
                                    }
                                    Button(localized("groups.useName")) {
                                        presetName = preset.name
                                    }
                                    Button(localized("groups.deletePreset")) {
                                        model.deleteEventFilterPreset(preset)
                                    }
                                } label: {
                                    Image(systemName: "ellipsis.circle")
                                }
                            }
                        }
                    }
                    Button(localized("groups.exportPresets")) {
                        exportPresets()
                    }
                    .disabled(model.eventFilterPresets.isEmpty)
                    Button(localized("groups.importPresets")) {
                        isImportingPresets = true
                    }
                    Button(localized("groups.deleteAllPresets")) {
                        isConfirmingDeletePresets = true
                    }
                    .disabled(model.eventFilterPresets.isEmpty)
                }

                Section(header: Text(localized("events.activity"))) {
                    if model.activityEvents.isEmpty {
                        Text(localized("events.noActivity"))
                            .foregroundColor(.secondary)
                    } else if visibleActivityEvents.isEmpty {
                        Text(localized("events.noMatchingActivity"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(visibleActivityEvents) { event in
                            ActivityEventRow(event: event)
                                .environmentObject(model)
                        }
                    }
                }
                Section(header: Text(localized("events.pokes"))) {
                    if model.pokeEvents.isEmpty {
                        Text(localized("events.noPokes"))
                            .foregroundColor(.secondary)
                    } else if visiblePokeEvents.isEmpty {
                        Text(localized("events.noMatchingPokes"))
                            .foregroundColor(.secondary)
                    } else {
                        ServerInfoDetailRow(
                            label: localized("events.pokeClearImpact"),
                            value: localized("events.pokeClearImpactFormat", visiblePokeClearImpact.clearingCount)
                        )
                        Text(pokeClearImpactText(visiblePokeClearImpact))
                            .font(.caption)
                            .foregroundColor(.secondary)
                        Button(localized("events.copyPokeClearImpact")) {
                            TS3PlatformSupport.copyToPasteboard(visiblePokeClearImpact.clipboardSummary)
                        }
                        .disabled(visiblePokeEvents.isEmpty)
                        ForEach(visiblePokeEvents) { poke in
                            PokeEventRow(poke: poke)
                                .environmentObject(model)
                        }
                    }
                }
            }
            .navigationTitle(localized("events.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                model.markEventsRead()
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("groups.refresh")) {
                        model.markEventsRead()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Menu {
                        Button(localized("events.copySnapshot")) {
                            TS3PlatformSupport.copyToPasteboard(visibleEventsSnapshot)
                        }
                        .disabled(!hasVisibleEvents)
                        Button(localized("events.exportSnapshot")) {
                            eventsDocument = TS3TextFileDocument(data: Data(visibleEventsSnapshot.utf8))
                            isExportingEvents = true
                        }
                        .disabled(!hasVisibleEvents)
                        Button(localized("events.exportArchive")) {
                            exportEventArchive()
                        }
                        .disabled(model.activityEvents.isEmpty && model.pokeEvents.isEmpty)
                        Button(localized("events.importArchive")) {
                            isImportingEventArchive = true
                        }
                        Button(localized("events.clearEvents")) {
                            cleanupConfirmation = .all
                        }
                        .disabled(model.activityEvents.isEmpty && model.pokeEvents.isEmpty)
                        Button(localized("events.clearActivity")) {
                            cleanupConfirmation = .activity
                        }
                        .disabled(model.activityEvents.isEmpty)
                        Button(localized("events.clearPokes")) {
                            cleanupConfirmation = .pokes
                        }
                        .disabled(model.pokeEvents.isEmpty)
                        Button(localized("events.exportFilterPresets")) {
                            exportPresets()
                        }
                        .disabled(model.eventFilterPresets.isEmpty)
                    } label: {
                        Image(systemName: "ellipsis.circle")
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.done")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .fileExporter(
                isPresented: $isExportingEvents,
                document: eventsDocument,
                contentType: .plainText,
                defaultFilename: "ts3-events"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingEventArchive,
                document: eventArchiveDocument,
                contentType: .json,
                defaultFilename: "ts3-event-archive"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPresets,
                document: presetsDocument,
                contentType: .json,
                defaultFilename: "ts3-event-filter-presets"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingEventArchive,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareEventArchiveImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPresets,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    preparePresetImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .alert(isPresented: $isConfirmingDeletePresets) {
                Alert(
                    title: Text(localized("events.deleteAllPresetsAlert.title")),
                    message: Text(localized("groups.deleteAllPresetsAlert.messageFormat", model.eventFilterPresets.count)),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deleteAllEventFilterPresets()
                    },
                    secondaryButton: .cancel()
                )
            }
            .alert(item: $cleanupConfirmation) { confirmation in
                Alert(
                    title: Text(confirmation.title),
                    message: Text(confirmation.message(activityCount: model.activityEvents.count, pokeCount: model.pokeEvents.count)),
                    primaryButton: .destructive(Text(localized("events.clear"))) {
                        switch confirmation {
                        case .all:
                            model.clearEventHistory()
                        case .activity:
                            model.clearActivityEvents()
                        case .pokes:
                            model.clearPokeEvents()
                        }
                    },
                    secondaryButton: .cancel()
                )
            }
            .sheet(item: $pendingEventArchiveImport) { confirmation in
                EventArchiveImportSheet(
                    preview: confirmation.preview,
                    previewMessage: eventArchivePreviewMessage(confirmation.preview),
                    restoreArchive: { selectedEventIds in
                        importEventArchive(data: confirmation.data, selectedEventIds: selectedEventIds)
                        pendingEventArchiveImport = nil
                    },
                    cancel: {
                        pendingEventArchiveImport = nil
                    }
                )
            }
            .sheet(item: $pendingPresetImport) { confirmation in
                EventFilterPresetImportSheet(
                    preview: confirmation.preview,
                    importPresets: { selectedPresetIds in
                        importPresets(data: confirmation.data, selectedPresetIds: selectedPresetIds)
                        pendingPresetImport = nil
                    },
                    cancel: {
                        pendingPresetImport = nil
                    }
                )
            }
        }
    }

    private var normalizedSearchText: String {
        searchText.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    private var isSearching: Bool {
        !normalizedSearchText.isEmpty
    }

    private var hasLocalFilters: Bool {
        isSearching || eventFilter != .all || sourceFilter != .all || !newestFirst
    }

    private func containsSearch(_ value: String?) -> Bool {
        guard let value, !normalizedSearchText.isEmpty else { return false }
        return value.lowercased().contains(normalizedSearchText)
    }

    private func sortedActivityEvents(_ events: [TS3ActivitySummary]) -> [TS3ActivitySummary] {
        events.sorted { lhs, rhs in
            if lhs.id == rhs.id {
                return false
            }
            if lhs.timestamp == rhs.timestamp {
                return lhs.clientName.localizedCaseInsensitiveCompare(rhs.clientName) == .orderedAscending
            }
            return newestFirst ? lhs.timestamp > rhs.timestamp : lhs.timestamp < rhs.timestamp
        }
    }

    private func sortedPokeEvents(_ pokes: [TS3PokeSummary]) -> [TS3PokeSummary] {
        pokes.sorted { lhs, rhs in
            if lhs.id == rhs.id {
                return false
            }
            if lhs.timestamp == rhs.timestamp {
                return lhs.senderName.localizedCaseInsensitiveCompare(rhs.senderName) == .orderedAscending
            }
            return newestFirst ? lhs.timestamp > rhs.timestamp : lhs.timestamp < rhs.timestamp
        }
    }

    private func applyPreset(_ preset: TS3EventFilterPreset) {
        eventFilter = EventFilter(rawValue: preset.eventFilter) ?? .all
        sourceFilter = EventSourceFilter(rawValue: preset.sourceFilter) ?? .all
        newestFirst = preset.newestFirst
        searchText = preset.searchText
        presetName = preset.name
    }

    private func presetSummary(_ preset: TS3EventFilterPreset) -> String {
        var parts = [
            (EventFilter(rawValue: preset.eventFilter) ?? .all).title,
            (EventSourceFilter(rawValue: preset.sourceFilter) ?? .all).title,
            preset.newestFirst ? localized("events.newest") : localized("events.oldest")
        ]
        if !preset.searchText.isEmpty {
            parts.append(localized("events.searchPresetSummaryFormat", preset.searchText))
        }
        return parts.joined(separator: " · ")
    }

    private func pokeSummaryText(_ summary: TS3PokeListSummary) -> String {
        [
            localized("events.pokeSummaryIncomingFormat", summary.incomingCount),
            localized("events.pokeSummaryOutgoingFormat", summary.outgoingCount),
            localized("events.pokeSummaryWithUidFormat", summary.withUniqueIdCount),
            localized("events.pokeSummaryWithoutUidFormat", summary.withoutUniqueIdCount),
            localized("events.pokeSummaryDefaultMessageFormat", summary.defaultMessageCount),
            localized("events.pokeSummaryCustomMessageFormat", summary.customMessageCount),
            localized("events.pokeSummaryParticipantsFormat", summary.distinctParticipantCount)
        ].joined(separator: " · ")
    }

    private func pokeClearImpactText(_ impact: TS3PokeClearImpactSummary) -> String {
        [
            localized("events.pokeSummaryIncomingFormat", impact.incomingCount),
            localized("events.pokeSummaryOutgoingFormat", impact.outgoingCount),
            localized("events.pokeSummaryWithoutUidFormat", impact.withoutUniqueIdCount),
            localized("events.pokeSummaryCustomMessageFormat", impact.customMessageCount),
            localized("events.pokeClearImpactAttentionFormat", impact.needsAttention ? localized("common.yes") : localized("common.no"))
        ].joined(separator: " · ")
    }

    private func exportPresets() {
        do {
            presetsDocument = TS3BookmarkFileDocument(data: try model.eventFilterPresetsExportData())
            isExportingPresets = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func exportEventArchive() {
        do {
            eventArchiveDocument = TS3BookmarkFileDocument(data: try model.eventHistoryArchiveData())
            isExportingEventArchive = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareEventArchiveImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.eventHistoryArchivePreview(from: data)
            pendingEventArchiveImport = EventArchiveImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func eventArchivePreviewMessage(_ preview: TS3EventHistoryArchivePreview) -> String {
        [
            localized("events.archivePreview.eventsFormat", preview.totalCount),
            localized("events.archivePreview.activityFormat", preview.activityCount),
            localized("events.archivePreview.pokesFormat", preview.pokeCount),
            localized("events.archivePreview.currentEventsFormat", preview.currentTotalCount),
            localized("events.archivePreview.currentActivityFormat", preview.currentActivityCount),
            localized("events.archivePreview.currentPokesFormat", preview.currentPokeCount),
            localized("events.archivePreview.restoreBehavior")
        ].joined(separator: "\n")
    }

    private func importEventArchive(data: Data, selectedEventIds: Set<String>) {
        do {
            try model.restoreEventHistoryArchive(from: data, selectedEventIds: selectedEventIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func preparePresetImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.eventFilterPresetsImportPreview(from: data)
            pendingPresetImport = EventFilterPresetImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPresets(data: Data, selectedPresetIds: Set<UUID>) {
        do {
            _ = try model.importEventFilterPresets(from: data, selectedPresetIds: selectedPresetIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

private struct EventArchiveImportSheet: View {
    let preview: TS3EventHistoryArchivePreview
    let previewMessage: String
    let restoreArchive: (Set<String>) -> Void
    let cancel: () -> Void
    @State private var selectedEventIds: Set<String> = []

    private var validSelectedEventIds: Set<String> {
        Set(selectedEventIds.filter(preview.containsEvent))
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("events.import.preview"))) {
                    Text(previewMessage)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    if preview.hasEvents {
                        Button(localized("events.import.copyEventSummary")) {
                            TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                        }
                        HStack {
                            Button(localized("events.import.selectAll")) {
                                selectedEventIds = Set(preview.candidates.map(\.id))
                            }
                            Button(localized("events.import.clear")) {
                                selectedEventIds = []
                            }
                            .disabled(selectedEventIds.isEmpty)
                        }
                    }
                }

                if !preview.activitySummaries.isEmpty {
                    Section(header: Text(localized("events.activity"))) {
                        ForEach(Array(preview.activityKindSummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                                .lineLimit(1)
                                .truncationMode(.middle)
                        }
                        ForEach(preview.candidates.filter { $0.kind == .activity }) { candidate in
                            Toggle(isOn: Binding(
                                get: { selectedEventIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedEventIds.insert(candidate.id)
                                    } else {
                                        selectedEventIds.remove(candidate.id)
                                    }
                                }
                            )) {
                                Text(candidate.summary)
                                    .font(.caption2)
                                    .lineLimit(2)
                                    .truncationMode(.middle)
                            }
                        }
                    }
                }

                if !preview.pokeSummaries.isEmpty {
                    Section(header: Text(localized("events.pokes"))) {
                        ForEach(Array(preview.pokeDirectionSummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                                .lineLimit(1)
                                .truncationMode(.middle)
                        }
                        ForEach(preview.candidates.filter { $0.kind == .poke }) { candidate in
                            Toggle(isOn: Binding(
                                get: { selectedEventIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedEventIds.insert(candidate.id)
                                    } else {
                                        selectedEventIds.remove(candidate.id)
                                    }
                                }
                            )) {
                                Text(candidate.summary)
                                    .font(.caption2)
                                    .lineLimit(2)
                                    .truncationMode(.middle)
                            }
                        }
                    }
                }

                Section(header: Text(localized("events.import.restoreBehavior"))) {
                    Text(localized("events.import.restoreBehaviorSummary"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("events.import.restoreEventsTitle"))
            .ts3InlineNavigationTitle()
            .onAppear {
                if selectedEventIds.isEmpty {
                    selectedEventIds = Set(preview.candidates.map(\.id))
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("events.import.restore")) {
                        restoreArchive(validSelectedEventIds)
                    }
                    .disabled(!preview.hasEvents || validSelectedEventIds.isEmpty)
                }
            }
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

private struct EventFilterPresetImportSheet: View {
    @Environment(\.presentationMode) private var presentationMode

    let preview: TS3EventFilterPresetImportPreview
    let importPresets: (Set<UUID>) -> Void
    let cancel: () -> Void
    @State private var selectedPresetIds: Set<UUID>

    init(
        preview: TS3EventFilterPresetImportPreview,
        importPresets: @escaping (Set<UUID>) -> Void,
        cancel: @escaping () -> Void
    ) {
        self.preview = preview
        self.importPresets = importPresets
        self.cancel = cancel
        _selectedPresetIds = State(initialValue: Set(preview.candidates.map(\.id)))
    }

    private var canImport: Bool {
        preview.candidates.contains { selectedPresetIds.contains($0.id) }
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("events.import.preview"))) {
                    Text(localized("events.filterImport.importedPresetsFormat", preview.importedPresetCount))
                    Text(localized("events.filterImport.usablePresetsFormat", preview.usablePresetCount))
                    Text(localized("events.filterImport.newPresetsFormat", preview.newPresetCount))
                    Text(localized("events.filterImport.replacingPresetsFormat", preview.replacedPresetCount))
                    Text(localized("events.filterImport.skippedPresetsFormat", preview.skippedPresetCount))
                    Button(localized("events.filterImport.copyBackupPreview")) {
                        TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                    }
                }

                Section(header: Text(localized("events.import.restore"))) {
                    HStack {
                        Button(localized("events.import.selectAll")) {
                            selectedPresetIds = Set(preview.candidates.map(\.id))
                        }
                        Spacer()
                        Button(localized("events.import.clear")) {
                            selectedPresetIds.removeAll()
                        }
                    }
                    ForEach(preview.candidates) { candidate in
                        Toggle(
                            candidate.summary,
                            isOn: Binding(
                                get: { selectedPresetIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedPresetIds.insert(candidate.id)
                                    } else {
                                        selectedPresetIds.remove(candidate.id)
                                    }
                                }
                            )
                        )
                    }
                }

                Section {
                    Text(localized("events.filterImport.behavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("events.filterImport.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("events.filterImport.import")) {
                        importPresets(selectedPresetIds)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canImport)
                }
            }
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

struct ActivityEventRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let event: TS3ActivitySummary

    var body: some View {
        VStack(alignment: .leading, spacing: 4) {
            HStack {
                Text(titleText)
                    .font(.subheadline.weight(.semibold))
                Spacer()
                Text(Self.dateText(event.timestamp))
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
            Text(messageText)
                .font(.body)
            if let detailText {
                Text(detailText)
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
        }
        .padding(.vertical, 4)
        .contextMenu {
            Button("Copy Summary") {
                TS3PlatformSupport.copyToPasteboard(event.clipboardSummary)
            }
            Button("Copy Message") {
                TS3PlatformSupport.copyToPasteboard(messageText)
            }
        }
        .accessibilityElement(children: .ignore)
        .accessibilityLabel(titleText)
        .accessibilityValue(accessibilityValue)
        .accessibilityAction(named: "Copy Summary") {
            TS3PlatformSupport.copyToPasteboard(event.clipboardSummary)
        }
        .accessibilityAction(named: "Copy Message") {
            TS3PlatformSupport.copyToPasteboard(messageText)
        }
    }

    private var messageText: String {
        Self.snapshotMessage(for: event, in: model)
    }

    private var titleText: String {
        switch event.kind {
        case .clientEntered, .clientLeft, .clientMoved:
            return event.clientName
        case .channelCreated, .channelEdited, .channelDeleted, .channelMoved, .channelPasswordChanged, .channelDescriptionChanged:
            return event.invokerName?.isEmpty == false ? event.invokerName! : "Server"
        }
    }

    private var detailText: String? {
        if let reason = event.reasonMessage, !reason.isEmpty {
            return reason
        }
        if let invoker = event.invokerName, !invoker.isEmpty, isClientEvent {
            return "by \(invoker)"
        }
        return nil
    }

    private var accessibilityValue: String {
        event.rowAccessibilityValue(messageText: messageText, detailText: detailText)
    }

    private var isClientEvent: Bool {
        switch event.kind {
        case .clientEntered, .clientLeft, .clientMoved:
            return true
        case .channelCreated, .channelEdited, .channelDeleted, .channelMoved, .channelPasswordChanged, .channelDescriptionChanged:
            return false
        }
    }

    private var affectedChannelText: String {
        if let name = event.channelName, !name.isEmpty {
            return name
        }
        return channelText(event.channelId)
    }

    private func channelText(_ channelId: Int?) -> String {
        model.channelName(for: channelId) ?? "the server"
    }

    static func snapshotMessage(for event: TS3ActivitySummary, in model: TS3AppModel) -> String {
        switch event.kind {
        case .clientEntered:
            return "joined \(model.channelName(for: event.toChannelId) ?? "the server")"
        case .clientLeft:
            return "left \(model.channelName(for: event.fromChannelId) ?? "the server")"
        case .clientMoved:
            return "moved from \(model.channelName(for: event.fromChannelId) ?? "the server") to \(model.channelName(for: event.toChannelId) ?? "the server")"
        case .channelCreated:
            return "created \(event.channelName ?? model.channelName(for: event.channelId) ?? "a channel")"
        case .channelEdited:
            return "edited \(event.channelName ?? model.channelName(for: event.channelId) ?? "a channel")"
        case .channelDeleted:
            return "deleted \(event.channelName ?? model.channelName(for: event.channelId) ?? "a channel")"
        case .channelMoved:
            return "moved \(event.channelName ?? model.channelName(for: event.channelId) ?? "a channel") to \(model.channelName(for: event.toChannelId) ?? "the server")"
        case .channelPasswordChanged:
            return "changed the password for \(event.channelName ?? model.channelName(for: event.channelId) ?? "a channel")"
        case .channelDescriptionChanged:
            return "changed the description for \(event.channelName ?? model.channelName(for: event.channelId) ?? "a channel")"
        }
    }

    private static func dateText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .short
        formatter.timeStyle = .medium
        return formatter.string(from: date)
    }
}

struct PokeEventRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let poke: TS3PokeSummary
    @State private var replyTarget: TS3UserSummary?
    @State private var isShowingOfflineReply = false

    var body: some View {
        VStack(alignment: .leading, spacing: 4) {
            HStack {
                Text(poke.displayTitle)
                    .font(.subheadline.weight(.semibold))
                Spacer()
                Text(Self.dateText(poke.timestamp))
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
            Text(poke.messageText)
                .font(.body)
            if onlineSender != nil || poke.senderUniqueIdentifier?.isEmpty == false {
                HStack(spacing: 12) {
                    if let onlineSender {
                        Button("Private Message") {
                            replyTarget = onlineSender
                        }
                        .buttonStyle(.borderless)
                        Button("Poke Back") {
                            model.pokeUser(onlineSender, message: "Poke")
                        }
                        .buttonStyle(.borderless)
                    }
                    if poke.senderUniqueIdentifier?.isEmpty == false {
                        Button("Offline Reply") {
                            isShowingOfflineReply = true
                        }
                        .buttonStyle(.borderless)
                        Button("Add Contact") {
                            model.addContact(from: poke)
                        }
                        .buttonStyle(.borderless)
                    }
                }
                .font(.caption)
            }
        }
        .padding(.vertical, 4)
        .contextMenu {
            if let onlineSender {
                Button("Private Message") {
                    replyTarget = onlineSender
                }
                Button("Poke Back") {
                    model.pokeUser(onlineSender, message: "Poke")
                }
            }
            if poke.senderUniqueIdentifier?.isEmpty == false {
                Button("Offline Reply") {
                    isShowingOfflineReply = true
                }
                Button("Add Contact") {
                    model.addContact(from: poke)
                }
            }
            Button("Copy Poke") {
                TS3PlatformSupport.copyToPasteboard(poke.clipboardSummary)
            }
            Button("Copy Message") {
                TS3PlatformSupport.copyToPasteboard(poke.messageText)
            }
            Button("Copy User") {
                TS3PlatformSupport.copyToPasteboard(poke.senderName)
            }
            if let uniqueIdentifier = poke.senderUniqueIdentifier, !uniqueIdentifier.isEmpty {
                Button("Copy Unique ID") {
                    TS3PlatformSupport.copyToPasteboard(uniqueIdentifier)
                }
            }
        }
        .accessibilityElement(children: .ignore)
        .accessibilityLabel(poke.displayTitle)
        .accessibilityValue(poke.accessibilityValue)
        .accessibilityAction(named: "Copy Poke") {
            TS3PlatformSupport.copyToPasteboard(poke.clipboardSummary)
        }
        .accessibilityAction(named: "Private Message") {
            guard let onlineSender else { return }
            replyTarget = onlineSender
        }
        .accessibilityAction(named: "Poke Back") {
            guard let onlineSender else { return }
            model.pokeUser(onlineSender, message: "Poke")
        }
        .accessibilityAction(named: "Offline Reply") {
            guard poke.senderUniqueIdentifier?.isEmpty == false else { return }
            isShowingOfflineReply = true
        }
        .accessibilityAction(named: "Add Contact") {
            guard poke.senderUniqueIdentifier?.isEmpty == false else { return }
            model.addContact(from: poke)
        }
        .sheet(item: $replyTarget) { user in
            ChatPrivateReplySheet(user: user)
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingOfflineReply) {
            PokeOfflineReplySheet(poke: poke)
                .environmentObject(model)
        }
    }

    private var onlineSender: TS3UserSummary? {
        model.onlineUser(for: poke)
    }

    private static func dateText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .short
        formatter.timeStyle = .medium
        return formatter.string(from: date)
    }
}

struct PokeOfflineReplySheet: View {
    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    let poke: TS3PokeSummary
    @State private var subject = "Re: Poke"
    @State private var message = ""

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(poke.senderName)) {
                    TextField("Subject", text: $subject)
                        .ts3PlainTextField()
                    TextField("Message", text: $message)
                        .ts3PlainTextField()
                    Text(offlineMessageDraftSummary)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button("Copy Offline Reply Summary") {
                        TS3PlatformSupport.copyToPasteboard(offlineMessageDraftSummary)
                    }
                    ForEach(offlineMessageDraftValidationMessages, id: \.self) { message in
                        Text(message)
                            .font(.caption)
                            .foregroundColor(.red)
                    }
                }
            }
            .navigationTitle("Offline Reply")
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button("Cancel") {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button("Send") {
                        if let uniqueIdentifier = poke.senderUniqueIdentifier {
                            model.sendOfflineMessage(
                                toUniqueIdentifier: uniqueIdentifier,
                                subject: subject,
                                message: message
                            ) {
                                model.clearOfflineMessageDraft(id: offlineDraftId)
                            }
                        }
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(isSendDisabled)
                }
            }
            .onAppear {
                loadOfflineDraft()
            }
            .onChange(of: subject) { _ in
                saveOfflineDraft()
            }
            .onChange(of: message) { _ in
                saveOfflineDraft()
            }
        }
    }

    private var offlineDraftId: String {
        if let uniqueIdentifier = poke.senderUniqueIdentifier, !uniqueIdentifier.isEmpty {
            return "uid:\(uniqueIdentifier)"
        }
        if let senderId = poke.senderId {
            return "client:\(senderId)"
        }
        return "poke:\(poke.id)"
    }

    private func loadOfflineDraft() {
        guard let draft = model.offlineMessageDraft(for: offlineDraftId) else { return }
        subject = draft.subject
        message = draft.message
    }

    private func saveOfflineDraft() {
        model.saveOfflineMessageDraft(
            id: offlineDraftId,
            recipientName: poke.senderName,
            subject: subject,
            message: message
        )
    }

    private var isSendDisabled: Bool {
        !offlineMessageDraftValidationMessages.isEmpty
    }

    private var offlineMessageDraftValidationMessages: [String] {
        TS3OfflineMessageDraftValidator.validationMessages(
            recipientName: poke.senderName,
            recipientUniqueIdentifier: poke.senderUniqueIdentifier,
            subject: subject,
            message: message
        )
    }

    private var offlineMessageDraftSummary: String {
        TS3OfflineMessageDraftValidator.creationSummary(
            recipientName: poke.senderName,
            recipientUniqueIdentifier: poke.senderUniqueIdentifier,
            subject: subject,
            message: message
        )
    }
}

struct OfflineMessagesSheet: View {
    private struct OfflineMessageArchiveImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3OfflineMessageArchivePreview
        let id = UUID()
    }

    private struct OfflineMessageFilterPresetImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3OfflineMessageFilterPresetImportPreview
        let id = UUID()
    }

    private enum OfflineContentFilter: String, CaseIterable, Identifiable {
        case all
        case withBody
        case bodyNotLoaded
        case canReply
        case unknownSender

        var id: String { rawValue }

        var titleKey: String {
            switch self {
            case .all: return "offline.contentFilter.all"
            case .withBody: return "offline.contentFilter.withBody"
            case .bodyNotLoaded: return "offline.contentFilter.bodyNotLoaded"
            case .canReply: return "offline.contentFilter.canReply"
            case .unknownSender: return "offline.contentFilter.unknownSender"
            }
        }

        func matches(_ message: TS3OfflineMessageSummary) -> Bool {
            switch self {
            case .all:
                return true
            case .withBody:
                return message.message?.isEmpty == false
            case .bodyNotLoaded:
                return message.message?.isEmpty != false
            case .canReply:
                return message.senderUniqueIdentifier?.isEmpty == false
            case .unknownSender:
                return message.senderName?.isEmpty != false && message.senderUniqueIdentifier?.isEmpty != false
            }
        }
    }

    private enum OfflineSortMode: String, CaseIterable, Identifiable {
        case timestamp
        case sender
        case subject
        case id

        var id: String { rawValue }

        var titleKey: String {
            switch self {
            case .timestamp: return "offline.sort.timestamp"
            case .sender: return "offline.sort.sender"
            case .subject: return "offline.sort.subject"
            case .id: return "offline.sort.messageId"
            }
        }
    }

    private enum ReadFilter: String, CaseIterable, Identifiable {
        case all
        case unread
        case read

        var id: String { rawValue }

        var titleKey: String {
            switch self {
            case .all: return "offline.readFilter.all"
            case .unread: return "offline.readFilter.unread"
            case .read: return "offline.readFilter.read"
            }
        }

        func matches(_ message: TS3OfflineMessageSummary) -> Bool {
            switch self {
            case .all: return true
            case .unread: return !message.isRead
            case .read: return message.isRead
            }
        }
    }

    private enum DeleteConfirmation: Identifiable {
        case visible
        case read
        case localHistory
        case deleteAllFilterPresets

        var id: String {
            switch self {
            case .visible: return "visible"
            case .read: return "read"
            case .localHistory: return "localHistory"
            case .deleteAllFilterPresets: return "deleteAllFilterPresets"
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var searchText = ""
    @State private var readFilter: ReadFilter = .all
    @State private var contentFilter: OfflineContentFilter = .all
    @State private var sortMode: OfflineSortMode = .timestamp
    @State private var sortAscending = false
    @State private var presetName = ""
    @State private var isExportingInbox = false
    @State private var isExportingInboxArchive = false
    @State private var isImportingInboxArchive = false
    @State private var isExportingPresets = false
    @State private var isImportingPresets = false
    @State private var deleteConfirmation: DeleteConfirmation?
    @State private var inboxDocument = TS3TextFileDocument()
    @State private var inboxArchiveDocument = TS3TextFileDocument()
    @State private var presetsDocument = TS3BookmarkFileDocument()
    @State private var pendingInboxArchiveImport: OfflineMessageArchiveImportConfirmation?
    @State private var pendingPresetImport: OfflineMessageFilterPresetImportConfirmation?

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    private var canUseServerInboxActions: Bool {
        model.state == .connected
    }

    private var filteredMessages: [TS3OfflineMessageSummary] {
        let messages = model.offlineMessages.filter { message in
            readFilter.matches(message) && contentFilter.matches(message) && (
                !isSearching
                    || containsSearch(message.subject)
                    || containsSearch(message.senderName)
                    || containsSearch(message.senderUniqueIdentifier)
                    || containsSearch(message.message)
                    || containsSearch(localized(message.isRead ? "offline.readFilter.read" : "offline.readFilter.unread"))
            )
        }
        return sortedMessages(messages)
    }

    private var visibleInboxSnapshot: String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short

        func dateText(_ date: Date?) -> String? {
            guard let date else { return nil }
            return formatter.string(from: date)
        }

        return filteredMessages.map { message in
            var rows = [
                localized("offline.snapshot.messageIdFormat", message.id),
                localized("offline.snapshot.readFormat", message.isRead ? localized("offline.yes") : localized("offline.no")),
                localized("offline.snapshot.senderFormat", message.senderName ?? message.senderUniqueIdentifier ?? localized("offline.unknownSender")),
                localized("offline.snapshot.subjectFormat", message.subject)
            ]
            if let senderUniqueIdentifier = message.senderUniqueIdentifier, !senderUniqueIdentifier.isEmpty {
                rows.append(localized("offline.snapshot.senderUidFormat", senderUniqueIdentifier))
            }
            if let timestamp = dateText(message.timestamp) {
                rows.append(localized("offline.snapshot.timestampFormat", timestamp))
            }
            if let body = message.message, !body.isEmpty {
                rows.append(localized("offline.snapshot.messageFormat", body))
            }
            return rows.joined(separator: "\n")
        }
        .joined(separator: "\n\n")
    }

    private var visibleInboxSummary: TS3OfflineMessageListSummary {
        TS3OfflineMessageListSummary(messages: filteredMessages)
    }

    private var bulkActionSummary: TS3OfflineMessageBulkActionSummary {
        TS3OfflineMessageBulkActionSummary(
            visibleMessages: filteredMessages,
            allMessages: model.offlineMessages
        )
    }

    var body: some View {
        NavigationView {
            List {
                Section(header: Text(localized("offline.section.search"))) {
                    Picker(localized("offline.status"), selection: $readFilter) {
                        ForEach(ReadFilter.allCases) { filter in
                            Text(localized(filter.titleKey)).tag(filter)
                        }
                    }
                    Picker(localized("offline.content"), selection: $contentFilter) {
                        ForEach(OfflineContentFilter.allCases) { filter in
                            Text(localized(filter.titleKey)).tag(filter)
                        }
                    }
                    Picker(localized("offline.sortBy"), selection: $sortMode) {
                        ForEach(OfflineSortMode.allCases) { mode in
                            Text(localized(mode.titleKey)).tag(mode)
                        }
                    }
                    Toggle(localized("offline.ascending"), isOn: $sortAscending)
                    TextField(localized("offline.searchInbox"), text: $searchText)
                        .ts3PlainTextField()
                    Menu {
                        TextField(localized("offline.presetName"), text: $presetName)
                        Button(localized("offline.saveCurrentFilters")) {
                            model.saveOfflineMessageFilterPreset(
                                name: presetName,
                                readFilter: readFilter.rawValue,
                                contentFilter: contentFilter.rawValue,
                                sortMode: sortMode.rawValue,
                                sortAscending: sortAscending,
                                searchText: searchText
                            )
                            presetName = ""
                        }
                        .disabled(presetName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                        if model.offlineMessageFilterPresets.isEmpty {
                            Text(localized("offline.noSavedFilterPresets"))
                        } else {
                            ForEach(model.offlineMessageFilterPresets) { preset in
                                Menu {
                                    Button(localized("offline.applyPreset")) {
                                        applyPreset(preset)
                                    }
                                    Button(localized("offline.useName")) {
                                        presetName = preset.name
                                    }
                                    Button(localized("offline.deletePreset")) {
                                        model.deleteOfflineMessageFilterPreset(preset)
                                    }
                                } label: {
                                    VStack(alignment: .leading) {
                                        Text(preset.name)
                                        Text(presetSummary(preset))
                                    }
                                }
                            }
                        }
                        Divider()
                        Button(localized("offline.exportPresets")) {
                            exportPresets()
                        }
                        .disabled(model.offlineMessageFilterPresets.isEmpty)
                        Button(localized("offline.importPresets")) {
                            isImportingPresets = true
                        }
                        Button(localized("offline.deleteAllPresets")) {
                            deleteConfirmation = .deleteAllFilterPresets
                        }
                        .disabled(model.offlineMessageFilterPresets.isEmpty)
                    } label: {
                        Label(localized("offline.filterPresets"), systemImage: "line.3.horizontal.decrease.circle")
                    }
                    if hasLocalFilters {
                        Button(localized("offline.clearFilters")) {
                            readFilter = .all
                            contentFilter = .all
                            sortMode = .timestamp
                            sortAscending = false
                            searchText = ""
                        }
                    }
                    ServerInfoDetailRow(
                        label: localized("offline.visibleSummary"),
                        value: localized("offline.visibleSummaryFormat", visibleInboxSummary.totalCount)
                    )
                    Text(inboxSummaryText(visibleInboxSummary))
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("offline.copyVisibleSummary")) {
                        TS3PlatformSupport.copyToPasteboard(visibleInboxSummary.clipboardSummary)
                    }
                    .disabled(filteredMessages.isEmpty)
                    ServerInfoDetailRow(
                        label: localized("offline.bulkSummary"),
                        value: localized(
                            "offline.bulkSummaryFormat",
                            bulkActionSummary.visibleCount,
                            bulkActionSummary.requiresServerCount
                        )
                    )
                    Text(bulkActionSummaryText(bulkActionSummary))
                        .font(.caption)
                        .foregroundColor(bulkActionSummary.needsAttention ? .orange : .secondary)
                    Button(localized("offline.copyBulkSummary")) {
                        TS3PlatformSupport.copyToPasteboard(bulkActionSummary.clipboardSummary)
                    }
                    .disabled(filteredMessages.isEmpty && model.offlineMessages.isEmpty)
                }

                if !canUseServerInboxActions {
                    Section {
                        Text(localized("offline.cachedOnlyNotice"))
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                }

                if model.offlineMessages.isEmpty {
                    Text(localized("offline.noMessages"))
                        .foregroundColor(.secondary)
                } else if filteredMessages.isEmpty {
                    Text(localized("offline.noMatchingMessages"))
                        .foregroundColor(.secondary)
                } else {
                    ForEach(filteredMessages) { message in
                        OfflineMessageRow(message: message)
                            .environmentObject(model)
                    }
                }
            }
            .navigationTitle(localized("offline.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                if canUseServerInboxActions {
                    model.refreshOfflineMessages()
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("offline.refresh")) {
                        model.refreshOfflineMessages()
                    }
                    .disabled(!canUseServerInboxActions)
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Menu {
                        Button(localized("offline.copySnapshot")) {
                            TS3PlatformSupport.copyToPasteboard(visibleInboxSnapshot)
                        }
                        .disabled(filteredMessages.isEmpty)
                        Button(localized("offline.exportSnapshot")) {
                            inboxDocument = TS3TextFileDocument(data: Data(visibleInboxSnapshot.utf8))
                            isExportingInbox = true
                        }
                        .disabled(filteredMessages.isEmpty)
                        Button(localized("offline.exportArchive")) {
                            exportInboxArchive()
                        }
                        .disabled(model.offlineMessages.isEmpty)
                        Button(localized("offline.importArchive")) {
                            isImportingInboxArchive = true
                        }
                        Divider()
                        Button(localized("offline.loadVisibleBodies")) {
                            model.loadOfflineMessageBodies(filteredMessages)
                        }
                        .disabled(!canUseServerInboxActions || !hasBodyPlaceholders)
                        Button(localized("offline.markAllRead")) {
                            model.markAllOfflineMessagesRead()
                        }
                        .disabled(!canUseServerInboxActions || filteredMessages.allSatisfy(\.isRead))
                        Button(localized("offline.markVisibleRead")) {
                            model.markOfflineMessages(filteredMessages, read: true)
                        }
                        .disabled(!canUseServerInboxActions || !filteredMessages.contains { !$0.isRead })
                        Button(localized("offline.markVisibleUnread")) {
                            model.markOfflineMessages(filteredMessages, read: false)
                        }
                        .disabled(!canUseServerInboxActions || !filteredMessages.contains { $0.isRead })
                        Button(localized("offline.deleteVisibleMessages")) {
                            deleteConfirmation = .visible
                        }
                        .disabled(!canUseServerInboxActions || filteredMessages.isEmpty)
                        Button(localized("offline.deleteReadMessages")) {
                            deleteConfirmation = .read
                        }
                        .disabled(!canUseServerInboxActions || readMessages.isEmpty)
                        Button(localized("offline.clearLocalHistory")) {
                            deleteConfirmation = .localHistory
                        }
                        .disabled(model.offlineMessages.isEmpty)
                        Button(localized("offline.exportFilterPresets")) {
                            exportPresets()
                        }
                        .disabled(model.offlineMessageFilterPresets.isEmpty)
                        Button(localized("offline.deleteAllFilterPresets")) {
                            deleteConfirmation = .deleteAllFilterPresets
                        }
                        .disabled(model.offlineMessageFilterPresets.isEmpty)
                    } label: {
                        Image(systemName: "ellipsis.circle")
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(NSLocalizedString("common.done", comment: "")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .fileExporter(
                isPresented: $isExportingInbox,
                document: inboxDocument,
                contentType: .plainText,
                defaultFilename: "ts3-offline-inbox"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingInboxArchive,
                document: inboxArchiveDocument,
                contentType: .json,
                defaultFilename: "ts3-offline-inbox-archive"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPresets,
                document: presetsDocument,
                contentType: .json,
                defaultFilename: "ts3-offline-message-filter-presets"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingInboxArchive,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareInboxArchiveImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPresets,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    preparePresetImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .sheet(item: $pendingInboxArchiveImport) { confirmation in
                OfflineMessageArchiveImportSheet(
                    preview: confirmation.preview,
                    previewMessage: inboxArchivePreviewMessage(confirmation.preview),
                    importArchive: { selectedMessageIds in
                        importInboxArchive(data: confirmation.data, selectedMessageIds: selectedMessageIds)
                        pendingInboxArchiveImport = nil
                    },
                    cancel: {
                        pendingInboxArchiveImport = nil
                    }
                )
            }
            .sheet(item: $pendingPresetImport) { confirmation in
                OfflineMessageFilterPresetImportSheet(
                    preview: confirmation.preview,
                    importPresets: { selectedPresetIds in
                        importPresets(data: confirmation.data, selectedPresetIds: selectedPresetIds)
                        pendingPresetImport = nil
                    },
                    cancel: {
                        pendingPresetImport = nil
                    }
                )
            }
            .alert(item: $deleteConfirmation) { confirmation in
                switch confirmation {
                case .visible:
                    return Alert(
                        title: Text(localized("offline.deleteVisibleAlert.title")),
                        message: Text(localized("offline.deleteVisibleAlert.messageFormat", filteredMessages.count)),
                        primaryButton: .destructive(Text(localized("offline.delete"))) {
                            model.deleteOfflineMessages(filteredMessages)
                        },
                        secondaryButton: .cancel()
                    )
                case .read:
                    return Alert(
                        title: Text(localized("offline.deleteReadAlert.title")),
                        message: Text(localized("offline.deleteReadAlert.messageFormat", readMessages.count)),
                        primaryButton: .destructive(Text(localized("offline.delete"))) {
                            model.deleteOfflineMessages(readMessages)
                        },
                        secondaryButton: .cancel()
                    )
                case .localHistory:
                    return Alert(
                        title: Text(localized("offline.clearLocalHistoryAlert.title")),
                        message: Text(localized("offline.clearLocalHistoryAlert.message")),
                        primaryButton: .destructive(Text(localized("offline.clear"))) {
                            model.clearOfflineMessageHistory()
                        },
                        secondaryButton: .cancel()
                    )
                case .deleteAllFilterPresets:
                    return Alert(
                        title: Text(localized("offline.deleteAllPresetsAlert.title")),
                        message: Text(localized("offline.deleteAllPresetsAlert.messageFormat", model.offlineMessageFilterPresets.count)),
                        primaryButton: .destructive(Text(localized("offline.delete"))) {
                            model.deleteAllOfflineMessageFilterPresets()
                        },
                        secondaryButton: .cancel()
                    )
                }
            }
        }
    }

    private var normalizedSearchText: String {
        searchText.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    private var isSearching: Bool {
        !normalizedSearchText.isEmpty
    }

    private var hasLocalFilters: Bool {
        isSearching || readFilter != .all || contentFilter != .all || sortMode != .timestamp || sortAscending
    }

    private var hasBodyPlaceholders: Bool {
        filteredMessages.contains { $0.message?.isEmpty != false }
    }

    private var readMessages: [TS3OfflineMessageSummary] {
        model.offlineMessages.filter(\.isRead)
    }

    private func containsSearch(_ value: String?) -> Bool {
        guard let value, !normalizedSearchText.isEmpty else { return false }
        return value.lowercased().contains(normalizedSearchText)
    }

    private func sortedMessages(_ messages: [TS3OfflineMessageSummary]) -> [TS3OfflineMessageSummary] {
        messages.sorted { lhs, rhs in
            if lhs.id == rhs.id {
                return false
            }

            let comparison: ComparisonResult
            switch sortMode {
            case .timestamp:
                comparison = compareDates(lhs.timestamp, rhs.timestamp)
            case .sender:
                comparison = senderText(lhs).localizedCaseInsensitiveCompare(senderText(rhs))
            case .subject:
                comparison = lhs.subject.localizedCaseInsensitiveCompare(rhs.subject)
            case .id:
                comparison = compareInts(lhs.id, rhs.id)
            }

            if comparison == .orderedSame {
                return lhs.id < rhs.id
            }
            return sortAscending ? comparison == .orderedAscending : comparison == .orderedDescending
        }
    }

    private func compareDates(_ lhs: Date?, _ rhs: Date?) -> ComparisonResult {
        switch (lhs, rhs) {
        case let (lhs?, rhs?):
            return lhs.compare(rhs)
        case (nil, nil):
            return .orderedSame
        case (nil, _):
            return .orderedAscending
        case (_, nil):
            return .orderedDescending
        }
    }

    private func compareInts(_ lhs: Int, _ rhs: Int) -> ComparisonResult {
        if lhs == rhs {
            return .orderedSame
        }
        return lhs < rhs ? .orderedAscending : .orderedDescending
    }

    private func senderText(_ message: TS3OfflineMessageSummary) -> String {
        message.senderName ?? message.senderUniqueIdentifier ?? ""
    }

    private func applyPreset(_ preset: TS3OfflineMessageFilterPreset) {
        readFilter = ReadFilter(rawValue: preset.readFilter) ?? .all
        contentFilter = OfflineContentFilter(rawValue: preset.contentFilter) ?? .all
        sortMode = OfflineSortMode(rawValue: preset.sortMode) ?? .timestamp
        sortAscending = preset.sortAscending
        searchText = preset.searchText
        presetName = preset.name
    }

    private func presetSummary(_ preset: TS3OfflineMessageFilterPreset) -> String {
        var parts = [
            localized((ReadFilter(rawValue: preset.readFilter) ?? .all).titleKey),
            localized((OfflineContentFilter(rawValue: preset.contentFilter) ?? .all).titleKey),
            localized((OfflineSortMode(rawValue: preset.sortMode) ?? .timestamp).titleKey),
            localized(preset.sortAscending ? "offline.ascending" : "offline.descending")
        ]
        if !preset.searchText.isEmpty {
            parts.append(localized("offline.presetSummary.searchFormat", preset.searchText))
        }
        return parts.joined(separator: " · ")
    }

    private func inboxSummaryText(_ summary: TS3OfflineMessageListSummary) -> String {
        [
            localized("offline.summaryUnreadFormat", summary.unreadCount),
            localized("offline.summaryReadFormat", summary.readCount),
            localized("offline.summaryWithBodyFormat", summary.withBodyCount),
            localized("offline.summaryBodyNotLoadedFormat", summary.bodyNotLoadedCount),
            localized("offline.summaryReplyableFormat", summary.replyableCount),
            localized("offline.summaryUnknownSenderFormat", summary.unknownSenderCount),
            localized("offline.summaryDistinctSendersFormat", summary.distinctSenderCount),
            localized(
                "offline.summaryMessageRangeFormat",
                summary.lowestMessageId.map(String.init) ?? localized("common.none"),
                summary.highestMessageId.map(String.init) ?? localized("common.none")
            )
        ].joined(separator: " · ")
    }

    private func bulkActionSummaryText(_ summary: TS3OfflineMessageBulkActionSummary) -> String {
        [
            localized("offline.bulkLoadBodiesFormat", summary.loadBodyCount),
            localized("offline.bulkMarkReadFormat", summary.markReadCount),
            localized("offline.bulkMarkUnreadFormat", summary.markUnreadCount),
            localized("offline.bulkDeleteVisibleFormat", summary.deleteVisibleCount),
            localized("offline.bulkDeleteReadFormat", summary.deleteReadCount)
        ].joined(separator: " · ")
    }

    private func exportPresets() {
        do {
            presetsDocument = TS3BookmarkFileDocument(data: try model.offlineMessageFilterPresetsExportData())
            isExportingPresets = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func preparePresetImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.offlineMessageFilterPresetsImportPreview(from: data)
            pendingPresetImport = OfflineMessageFilterPresetImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPresets(data: Data, selectedPresetIds: Set<UUID>) {
        do {
            _ = try model.importOfflineMessageFilterPresets(from: data, selectedPresetIds: selectedPresetIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func exportInboxArchive() {
        do {
            inboxArchiveDocument = TS3TextFileDocument(data: try model.offlineMessageArchiveData())
            isExportingInboxArchive = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareInboxArchiveImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.offlineMessageArchivePreview(from: data)
            pendingInboxArchiveImport = OfflineMessageArchiveImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importInboxArchive(data: Data, selectedMessageIds: Set<Int>) {
        do {
            try model.importOfflineMessageArchive(from: data, selectedMessageIds: selectedMessageIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func inboxArchivePreviewMessage(_ preview: TS3OfflineMessageArchivePreview) -> String {
        var lines = [
            localized("offline.archive.messagesFormat", preview.messageCount),
            localized("offline.archive.unreadFormat", preview.unreadCount),
            localized("offline.archive.withBodyFormat", preview.withBodyCount),
            localized("offline.archive.replyableFormat", preview.replyableCount),
            localized("offline.archive.unknownSenderFormat", preview.unknownSenderCount)
        ]
        if preview.skippedMessageCount > 0 {
            lines.append(localized("offline.archive.skippedFormat", preview.skippedMessageCount))
        }
        if !preview.readStateSummaries.isEmpty {
            lines.append(localized("offline.archive.readStatesFormat", preview.readStateSummaries.joined(separator: " | ")))
        }
        if !preview.senderSummaries.isEmpty {
            lines.append(localized("offline.archive.sendersFormat", preview.senderSummaries.joined(separator: " | ")))
        }
        if let senderName = preview.firstSenderName {
            lines.append(localized("offline.archive.firstSenderFormat", senderName))
        } else if let senderUniqueIdentifier = preview.firstSenderUniqueIdentifier {
            lines.append(localized("offline.archive.firstSenderUidFormat", senderUniqueIdentifier))
        }
        if let firstSubject = preview.firstSubject {
            lines.append(localized("offline.archive.firstSubjectFormat", firstSubject))
        }
        if let firstTimestamp = preview.firstTimestamp {
            lines.append(localized("offline.archive.firstDateFormat", OfflineMessageRow.dateText(firstTimestamp)))
        }
        lines.append(preview.hasMessages ? localized("offline.archive.importBehavior") : localized("offline.archive.noUsableMessages"))
        return lines.joined(separator: "\n")
    }
}

private struct OfflineMessageArchiveImportSheet: View {
    let preview: TS3OfflineMessageArchivePreview
    let previewMessage: String
    let importArchive: (Set<Int>) -> Void
    let cancel: () -> Void
    @State private var selectedMessageIds: Set<Int> = []

    private var validSelectedMessageIds: Set<Int> {
        Set(selectedMessageIds.filter(preview.containsMessage))
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("offline.import.preview"))) {
                    Text(previewMessage)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    if preview.hasMessages {
                        Button(localized("offline.import.copyMessageSummary")) {
                            TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                        }
                        HStack {
                            Button(localized("offline.import.selectAll")) {
                                selectedMessageIds = Set(preview.candidates.map(\.id))
                            }
                            Button(localized("offline.import.clear")) {
                                selectedMessageIds = []
                            }
                            .disabled(selectedMessageIds.isEmpty)
                        }
                        ForEach(preview.readStateSummaries, id: \.self) { summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                        }
                        ForEach(preview.senderSummaries, id: \.self) { summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                        }
                        ForEach(Array(preview.messageSummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .lineLimit(2)
                                .truncationMode(.middle)
                        }
                        ForEach(preview.candidates) { candidate in
                            Toggle(isOn: Binding(
                                get: { selectedMessageIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedMessageIds.insert(candidate.id)
                                    } else {
                                        selectedMessageIds.remove(candidate.id)
                                    }
                                }
                            )) {
                                Text(candidate.summary)
                                    .font(.caption2)
                                    .lineLimit(2)
                                    .truncationMode(.middle)
                            }
                        }
                    }
                }

                Section(header: Text(localized("offline.import.behaviorTitle"))) {
                    Text(localized("offline.import.behavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("offline.import.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                if selectedMessageIds.isEmpty {
                    selectedMessageIds = Set(preview.candidates.map(\.id))
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(NSLocalizedString("common.cancel", comment: "")) {
                        cancel()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("offline.import.action")) {
                        importArchive(validSelectedMessageIds)
                    }
                    .disabled(!preview.hasMessages || validSelectedMessageIds.isEmpty)
                }
            }
        }
    }
}

private struct OfflineMessageFilterPresetImportSheet: View {
    @Environment(\.presentationMode) private var presentationMode

    let preview: TS3OfflineMessageFilterPresetImportPreview
    let importPresets: (Set<UUID>) -> Void
    let cancel: () -> Void
    @State private var selectedPresetIds: Set<UUID>

    init(
        preview: TS3OfflineMessageFilterPresetImportPreview,
        importPresets: @escaping (Set<UUID>) -> Void,
        cancel: @escaping () -> Void
    ) {
        self.preview = preview
        self.importPresets = importPresets
        self.cancel = cancel
        _selectedPresetIds = State(initialValue: Set(preview.candidates.map(\.id)))
    }

    private var canImport: Bool {
        preview.candidates.contains { selectedPresetIds.contains($0.id) }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("offline.filterImport.preview"))) {
                    Text(localized("offline.filterImport.importedPresetsFormat", preview.importedPresetCount))
                    Text(localized("offline.filterImport.usablePresetsFormat", preview.usablePresetCount))
                    Text(localized("offline.filterImport.newPresetsFormat", preview.newPresetCount))
                    Text(localized("offline.filterImport.replacingPresetsFormat", preview.replacedPresetCount))
                    Text(localized("offline.filterImport.skippedPresetsFormat", preview.skippedPresetCount))
                    Button(localized("offline.filterImport.copyPreview")) {
                        TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                    }
                }

                Section(header: Text(localized("offline.filterImport.restore"))) {
                    HStack {
                        Button(localized("offline.filterImport.selectAll")) {
                            selectedPresetIds = Set(preview.candidates.map(\.id))
                        }
                        Spacer()
                        Button(localized("offline.filterImport.clear")) {
                            selectedPresetIds.removeAll()
                        }
                    }
                    ForEach(preview.candidates) { candidate in
                        Toggle(
                            candidate.summary,
                            isOn: Binding(
                                get: { selectedPresetIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedPresetIds.insert(candidate.id)
                                    } else {
                                        selectedPresetIds.remove(candidate.id)
                                    }
                                }
                            )
                        )
                    }
                }

                Section {
                    Text(localized("offline.filterImport.behavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("offline.filterImport.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(NSLocalizedString("common.cancel", comment: "")) {
                        cancel()
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("offline.import.action")) {
                        importPresets(selectedPresetIds)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canImport)
                }
            }
        }
    }
}

struct OfflineMessageRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let message: TS3OfflineMessageSummary
    @State private var isShowingReply = false

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack(alignment: .top) {
                VStack(alignment: .leading, spacing: 3) {
                    HStack(spacing: 6) {
                        Text(message.subject)
                            .font(.subheadline.weight(message.isRead ? .regular : .semibold))
                        if !message.isRead {
                            Text(localized("offline.readFilter.unread"))
                                .font(.caption.weight(.semibold))
                                .foregroundColor(.accentColor)
                        }
                    }
                    Text(message.senderDisplayName)
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                Spacer()
                if let timestamp = message.timestamp {
                    Text(Self.dateText(timestamp))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }

            if let body = message.message, !body.isEmpty {
                Text(body)
                    .font(.body)
            } else {
                Button(localized("offline.row.openMessage")) {
                    model.openOfflineMessage(message)
                }
                .buttonStyle(TS3BorderedButtonStyle())
                .disabled(!canUseServerActions)
            }

            HStack {
                if canReply {
                    Button(localized("offline.row.reply")) {
                        isShowingReply = true
                    }
                    .buttonStyle(.borderless)
                    .disabled(!canUseServerActions)
                    Button(localized("offline.row.addContact")) {
                        model.addContact(from: message)
                    }
                    .buttonStyle(.borderless)
                }
                Button(localized(message.isRead ? "offline.row.markUnread" : "offline.row.markRead")) {
                    model.markOfflineMessage(message, read: !message.isRead)
                }
                .buttonStyle(.borderless)
                .disabled(!canUseServerActions)
                if canCopyBody {
                    Button(localized("offline.row.copy")) {
                        TS3PlatformSupport.copyToPasteboard(message.message ?? "")
                    }
                    .buttonStyle(.borderless)
                }
                Spacer()
                Button(localized("offline.delete")) {
                    model.deleteOfflineMessage(message)
                }
                .buttonStyle(.borderless)
                .foregroundColor(.red)
                .disabled(!canUseServerActions)
            }
            .font(.caption)
        }
        .padding(.vertical, 4)
        .sheet(isPresented: $isShowingReply) {
            OfflineMessageReplySheet(message: message)
                .environmentObject(model)
        }
        .contextMenu {
            Button(localized("offline.row.copySubject")) {
                TS3PlatformSupport.copyToPasteboard(message.subject)
            }
            if let body = message.message, !body.isEmpty {
                Button(localized("offline.row.copyMessage")) {
                    TS3PlatformSupport.copyToPasteboard(body)
                }
            }
            if let sender = message.senderName ?? message.senderUniqueIdentifier, !sender.isEmpty {
                Button(localized("offline.row.copySender")) {
                    TS3PlatformSupport.copyToPasteboard(sender)
                }
            }
            if canReply {
                Button(localized("offline.row.addContact")) {
                    model.addContact(from: message)
                }
            }
            Button(localized("offline.row.copySummary")) {
                TS3PlatformSupport.copyToPasteboard(message.clipboardSummary)
            }
        }
        .accessibilityElement(children: .ignore)
        .accessibilityLabel(message.subject)
        .accessibilityValue(message.accessibilityValue)
        .accessibilityAction(named: localized("offline.row.copySummary")) {
            TS3PlatformSupport.copyToPasteboard(message.clipboardSummary)
        }
        .accessibilityAction(named: localized(message.isRead ? "offline.row.markUnread" : "offline.row.markRead")) {
            guard canUseServerActions else { return }
            model.markOfflineMessage(message, read: !message.isRead)
        }
        .accessibilityAction(named: localized("offline.row.deleteMessage")) {
            guard canUseServerActions else { return }
            model.deleteOfflineMessage(message)
        }
        .accessibilityAction(named: localized("offline.row.addContact")) {
            guard canReply else { return }
            model.addContact(from: message)
        }
    }

    private var canReply: Bool {
        message.senderUniqueIdentifier?.isEmpty == false
    }

    private var canUseServerActions: Bool {
        model.state == .connected
    }

    private var canCopyBody: Bool {
        message.message?.isEmpty == false
    }

    fileprivate static func dateText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .short
        formatter.timeStyle = .short
        return formatter.string(from: date)
    }
}

struct OfflineMessageReplySheet: View {
