                                toUniqueIdentifier: uniqueIdentifier,
                                subject: subject,
                                message: replyText
                            ) {
                                model.clearOfflineMessageDraft(id: offlineDraftId)
                            }
                        }
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(isSendDisabled)
                }
            }
            .onAppear {
                loadOfflineDraft()
            }
            .onChange(of: subject) { _ in
                saveOfflineDraft()
            }
            .onChange(of: replyText) { _ in
                saveOfflineDraft()
            }
        }
    }

    private var offlineDraftId: String {
        if let uniqueIdentifier = message.senderUniqueIdentifier, !uniqueIdentifier.isEmpty {
            return "uid:\(uniqueIdentifier)"
        }
        return "offline-message:\(message.id)"
    }

    private func loadOfflineDraft() {
        guard let draft = model.offlineMessageDraft(for: offlineDraftId) else { return }
        subject = draft.subject
        replyText = draft.message
    }

    private func saveOfflineDraft() {
        model.saveOfflineMessageDraft(
            id: offlineDraftId,
            recipientName: message.senderName ?? message.senderUniqueIdentifier ?? localized("offline.reply.recipient"),
            subject: subject,
            message: replyText
        )
    }

    private var isSendDisabled: Bool {
        !offlineMessageDraftValidationMessages.isEmpty
    }

    private var offlineMessageDraftValidationMessages: [String] {
        TS3OfflineMessageDraftValidator.validationMessages(
            recipientName: message.senderName,
            recipientUniqueIdentifier: message.senderUniqueIdentifier,
            subject: subject,
            message: replyText
        )
    }

    private var offlineMessageDraftSummary: String {
        TS3OfflineMessageDraftValidator.creationSummary(
            recipientName: message.senderName,
            recipientUniqueIdentifier: message.senderUniqueIdentifier,
            subject: subject,
            message: replyText
        )
    }

    private static func replySubject(for subject: String) -> String {
        let trimmed = subject.trimmingCharacters(in: .whitespacesAndNewlines)
        if trimmed.lowercased().hasPrefix("re:") {
            return trimmed
        }
        return trimmed.isEmpty ? "Re:" : "Re: \(trimmed)"
    }
}

