                ServerInformationSheet()
                    .environmentObject(model)
            }
            .sheet(isPresented: $isShowingComplaints) {
                ComplaintListSheet()
                    .environmentObject(model)
            }
            .sheet(isPresented: $isShowingClientDatabase) {
                ClientDatabaseSheet()
                    .environmentObject(model)
            }
            .sheet(isPresented: $isShowingContacts) {
                ContactsSheet()
                    .environmentObject(model)
            }
            .sheet(isPresented: $isShowingServerLogs) {
                ServerLogsSheet()
                    .environmentObject(model)
            }
            .fileImporter(
                isPresented: $isImportingNotificationSettings,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareNotificationSettingsImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingNotificationSettings,
                document: notificationSettingsDocument,
                contentType: .json,
                defaultFilename: "ts3-notification-settings"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .alert(isPresented: $isConfirmingResetNotificationSettings) {
                Alert(
                    title: Text(localized("notifications.resetAlert.title")),
                    message: Text(localized("notifications.resetAlert.message")),
                    primaryButton: .destructive(Text(localized("notifications.reset"))) {
                        model.resetNotificationSettings()
                    },
                    secondaryButton: .cancel()
                )
            }
            .sheet(
                item: $pendingNotificationSettingsImport,
                onDismiss: {
                    pendingNotificationSettingsImport = nil
                }
            ) { confirmation in
                NotificationSettingsImportSheet(
                    preview: confirmation.preview,
                    importSettings: { selectedSettingIds in
                        importNotificationSettings(
                            from: confirmation.url,
                            selectedSettingIds: selectedSettingIds
                        )
                        pendingNotificationSettingsImport = nil
                    },
                    cancel: {
                        pendingNotificationSettingsImport = nil
                    }
                )
            }
        }
    }

    private func exportNotificationSettings() {
        do {
            notificationSettingsDocument = TS3TextFileDocument(data: try model.notificationSettingsExportData())
            isExportingNotificationSettings = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareNotificationSettingsImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.notificationSettingsPreview(from: data)
            pendingNotificationSettingsImport = NotificationSettingsImportConfirmation(
                url: url,
                preview: preview
            )
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importNotificationSettings(from url: URL, selectedSettingIds: Set<String>) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            try model.importNotificationSettings(
                from: Data(contentsOf: url),
                options: TS3NotificationSettingsImportOptions(
                    baseSettings: selectedSettingIds.contains("base"),
                    mutedRules: selectedSettingIds.contains("muted-rules"),
                    quietHours: selectedSettingIds.contains("quiet-hours")
                )
            )
        } catch {
            model.lastError = error.localizedDescription
        }
    }
}

private struct NotificationSettingsImportSheet: View {
    @Environment(\.presentationMode) private var presentationMode

    let preview: TS3NotificationSettingsPreview
    let importSettings: (Set<String>) -> Void
    let cancel: () -> Void
    @State private var selectedSettingIds: Set<String>

    init(
        preview: TS3NotificationSettingsPreview,
        importSettings: @escaping (Set<String>) -> Void,
        cancel: @escaping () -> Void
    ) {
        self.preview = preview
        self.importSettings = importSettings
        self.cancel = cancel
        _selectedSettingIds = State(initialValue: Set(preview.candidates.map(\.id)))
    }

    private var previewSummary: String {
        preview.lines.joined(separator: "\n")
    }

    private var canImport: Bool {
        preview.candidates.contains { selectedSettingIds.contains($0.id) }
    }

    private var restoreImpactSummary: TS3NotificationSettingsRestoreImpactSummary {
        TS3NotificationSettingsRestoreImpactSummary(preview: preview, selectedSettingIds: selectedSettingIds)
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("notifications.import.preview"))) {
                    ForEach(preview.lines, id: \.self) { line in
                        Text(line)
                    }
                    Button(localized("notifications.import.copySummary")) {
                        TS3PlatformSupport.copyToPasteboard(previewSummary)
                    }
                }

                Section(header: Text(localized("notifications.import.restore"))) {
                    HStack {
                        Button(localized("notifications.import.selectAll")) {
                            selectedSettingIds = Set(preview.candidates.map(\.id))
                        }
                        Spacer()
                        Button(localized("notifications.import.clear")) {
                            selectedSettingIds.removeAll()
                        }
                    }
                    ServerInfoDetailRow(
                        label: localized("notifications.import.impact"),
                        value: localized(
                            "notifications.import.impactFormat",
                            restoreImpactSummary.selectedSettingCount,
                            restoreImpactSummary.eventTypeCount
                        )
                    )
                    Text(notificationImportImpactText(restoreImpactSummary))
                        .font(.caption2)
                        .foregroundColor(restoreImpactSummary.needsAttention ? .orange : .secondary)
                    Button(localized("notifications.import.copyImpact")) {
                        TS3PlatformSupport.copyToPasteboard(restoreImpactSummary.clipboardSummary)
                    }
                    .disabled(!restoreImpactSummary.hasSelection)
                    ForEach(preview.candidates) { candidate in
                        Toggle(
                            isOn: Binding(
                                get: { selectedSettingIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedSettingIds.insert(candidate.id)
                                    } else {
                                        selectedSettingIds.remove(candidate.id)
                                    }
                                }
                            )
                        ) {
                            VStack(alignment: .leading) {
                                Text(candidate.title)
                                Text(candidate.summary)
                                    .font(.caption)
                                    .foregroundColor(.secondary)
                            }
                        }
                    }
                }

                Section {
                    Text(localized("notifications.import.behavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("notifications.import.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(NSLocalizedString("common.cancel", comment: "")) {
                        cancel()
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("notifications.import.action")) {
                        importSettings(selectedSettingIds)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canImport)
                }
            }
        }
    }

    private func notificationImportImpactText(_ summary: TS3NotificationSettingsRestoreImpactSummary) -> String {
        [
            localized("notifications.import.impactBaseFormat", optionalBoolText(summary.notificationsEnabled), optionalBoolText(summary.soundEnabled)),
            localized("notifications.import.impactMutedFormat", summary.mutedServerCount, summary.mutedContactCount),
            localized("notifications.import.impactQuietHoursFormat", optionalBoolText(summary.quietHoursEnabled))
        ].joined(separator: " | ")
    }

    private func optionalBoolText(_ value: Bool?) -> String {
        guard let value else { return localized("common.notAvailable") }
        return value ? localized("common.yes") : localized("common.no")
    }
}

struct ServerLogsSheet: View {
    private struct ServerLogArchiveImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3ServerLogArchivePreview
        let id = UUID()
    }

    private struct ServerLogQueryPresetImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3ServerLogQueryPresetImportPreview
        let id = UUID()
    }

    private enum LogLevelFilter: String, CaseIterable, Identifiable {
        case all
        case info
        case warning
        case error
        case debug

        var id: String { rawValue }

        var fallbackTitle: String {
            switch self {
            case .all: return "All Levels"
            case .info: return "Info"
            case .warning: return "Warning"
            case .error: return "Error"
            case .debug: return "Debug"
            }
        }

        func matches(_ level: String?) -> Bool {
            guard self != .all else { return true }
            return level?.caseInsensitiveCompare(rawValue) == .orderedSame
        }
    }

    private enum LogConfirmation: Identifiable {
        case clearAllResults
        case clearVisibleResults
        case deleteAllPresets

        var id: String {
            switch self {
            case .clearAllResults: return "clearAllResults"
            case .clearVisibleResults: return "clearVisibleResults"
            case .deleteAllPresets: return "deleteAllPresets"
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var lineLimit = "100"
    @State private var beginPosition = "0"
    @State private var reverseOrder = true
    @State private var instanceLogs = false
    @State private var levelFilter: LogLevelFilter = .all
    @State private var channelFilter = ""
    @State private var searchText = ""
    @State private var newLogLevel: TS3LogLevel = .info
    @State private var newLogMessage = ""
    @State private var isExportingLogs = false
    @State private var isExportingLogArchive = false
    @State private var isImportingLogArchive = false
    @State private var logExportDocument = TS3TextFileDocument()
    @State private var logArchiveDocument = TS3TextFileDocument()
    @State private var isExportingSnapshot = false
    @State private var snapshotDocument = TS3TextFileDocument()
    @State private var presetName = ""
    @State private var isImportingPresets = false
    @State private var isExportingPresets = false
    @State private var confirmation: LogConfirmation?
    @State private var pendingLogArchiveImport: ServerLogArchiveImportConfirmation?
    @State private var pendingPresetImport: ServerLogQueryPresetImportConfirmation?
    @State private var presetDocument = TS3BookmarkFileDocument()

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            List {
                Section(header: Text(localized("serverLogs.controls"))) {
                    TextField(localized("serverLogs.lines"), text: $lineLimit)
                        .ts3NumericKeyboard()
                        .ts3PlainTextField()
                    TextField(localized("serverLogs.beginPosition"), text: $beginPosition)
                        .ts3NumericKeyboard()
                        .ts3PlainTextField()
                    HStack {
                        Button {
                            moveLogPage(by: -1, refresh: false)
                        } label: {
                            Label(localized("serverLogs.previousPage"), systemImage: "chevron.left")
                        }
                        .disabled(!canMoveToPreviousPage)

                        Spacer()

                        Button {
                            moveLogPage(by: 1, refresh: false)
                        } label: {
                            Label(localized("serverLogs.nextPage"), systemImage: "chevron.right")
                        }
                        .disabled(!canRunQuery)
                    }
                    HStack {
                        Button {
                            moveLogPage(by: -1, refresh: true)
                        } label: {
                            Label(localized("serverLogs.previousPageRefresh"), systemImage: "chevron.left.circle")
                        }
                        .disabled(model.state != .connected || !canMoveToPreviousPage)

                        Spacer()

                        Button {
                            moveLogPage(by: 1, refresh: true)
                        } label: {
                            Label(localized("serverLogs.nextPageRefresh"), systemImage: "chevron.right.circle")
                        }
                        .disabled(model.state != .connected || !canRunQuery)
                    }
                    Toggle(localized("serverLogs.reverseOrder"), isOn: $reverseOrder)
                    Toggle(localized("serverLogs.instanceLogs"), isOn: $instanceLogs)
                    Picker(localized("serverLogs.levelFilter"), selection: $levelFilter) {
                        ForEach(LogLevelFilter.allCases) { filter in
