                        .font(.caption)
                        .foregroundColor(.secondary)
                        .accessibilityLabel(localized("serverLogs.currentLogQuery"))
                        .accessibilityValue(currentQueryDraft.accessibilityValue)
                    ServerInfoDetailRow(
                        label: localized("serverLogs.queryCoverage"),
                        value: localized(
                            "serverLogs.queryCoverageFormat",
                            queryCoverageSummary.remoteQueryDimensionCount,
                            queryCoverageSummary.localFilterCount
                        )
                    )
                    Text(serverLogQueryCoverageText(queryCoverageSummary))
                        .font(.caption)
                        .foregroundColor(queryCoverageSummary.needsAttention ? .orange : .secondary)
                    Button(localized("serverLogs.copyQueryCoverage")) {
                        TS3PlatformSupport.copyToPasteboard(queryCoverageSummary.clipboardSummary)
                    }
                    ForEach(queryValidationMessages, id: \.self) { message in
                        Text(message)
                            .font(.caption)
                            .foregroundColor(.red)
                    }
                    if hasLocalFilters {
                        Button(localized("serverLogs.clearFilters")) {
                            levelFilter = .all
                            channelFilter = ""
                            searchText = ""
                        }
                    }
                    Button(localized("serverLogs.copyQuerySummary")) {
                        TS3PlatformSupport.copyToPasteboard(currentQueryDraft.clipboardSummary)
                    }
                    ServerInfoDetailRow(
                        label: localized("serverLogs.visibleSummary"),
                        value: localized("serverLogs.visibleSummaryFormat", visibleLogSummary.totalCount)
                    )
                    Text(serverLogListSummaryText(visibleLogSummary))
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("serverLogs.copyVisibleSummary")) {
                        TS3PlatformSupport.copyToPasteboard(visibleLogSummary.clipboardSummary)
                    }
                    .disabled(filteredEntries.isEmpty)
                    ServerInfoDetailRow(
                        label: localized("serverLogs.clearImpact"),
                        value: localized(
                            "serverLogs.clearImpactFormat",
                            clearImpactSummary.visibleCount,
                            clearImpactSummary.hiddenCount
                        )
                    )
                    Text(serverLogClearImpactText(clearImpactSummary))
                        .font(.caption)
                        .foregroundColor(clearImpactSummary.needsAttention ? .orange : .secondary)
                    Button(localized("serverLogs.copyClearImpact")) {
                        TS3PlatformSupport.copyToPasteboard(clearImpactSummary.clipboardSummary)
                    }
                    .disabled(filteredEntries.isEmpty)
                    Button(localized("serverLogs.refresh")) {
                        model.refreshServerLogs(
                            limit: parsedLineLimit,
                            reverse: reverseOrder,
                            instance: instanceLogs,
                            beginPosition: parsedBeginPosition
                        )
                    }
                    .disabled(model.state != .connected || !canRunQuery)
                    Button(localized("serverLogs.copyVisibleLogs")) {
                        TS3PlatformSupport.copyToPasteboard(filteredTranscript)
                    }
                    .disabled(filteredEntries.isEmpty)
                    Button(localized("serverLogs.exportVisibleLogs")) {
                        logExportDocument = TS3TextFileDocument(data: Data(filteredTranscript.utf8))
                        isExportingLogs = true
                    }
                    .disabled(filteredEntries.isEmpty)
                    Button(localized("serverLogs.copySnapshot")) {
                        TS3PlatformSupport.copyToPasteboard(snapshot)
                    }
                    .disabled(model.serverLogEntries.isEmpty)
                    Button(localized("serverLogs.exportSnapshot")) {
                        snapshotDocument = TS3TextFileDocument(data: Data(snapshot.utf8))
                        isExportingSnapshot = true
                    }
                    .disabled(model.serverLogEntries.isEmpty)
                    Button(localized("serverLogs.exportLogArchive")) {
                        exportLogArchive()
                    }
                    .disabled(model.serverLogEntries.isEmpty)
                    Button(localized("serverLogs.importLogArchive")) {
                        isImportingLogArchive = true
                    }
                    Button(localized("serverLogs.clearResults")) {
                        confirmation = .clearAllResults
                    }
                    .disabled(model.serverLogEntries.isEmpty)
                    Button(localized("serverLogs.clearVisibleResults")) {
                        confirmation = .clearVisibleResults
                    }
                    .disabled(filteredEntries.isEmpty)
                }

                Section(header: Text(localized("serverLogs.queryPresets"))) {
                    TextField(localized("serverLogs.presetName"), text: $presetName)
                        .ts3PlainTextField()
                    Button(localized("serverLogs.saveCurrentQuery")) {
                        model.saveServerLogQueryPreset(
                            name: presetName,
                            limit: parsedLineLimit,
                            beginPosition: parsedBeginPosition,
                            reverse: reverseOrder,
                            instance: instanceLogs,
                            levelFilter: levelFilter.rawValue,
                            channelFilter: channelFilter,
                            searchText: searchText
                        )
                        presetName = ""
                    }
                    .disabled(presetName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty || !canRunQuery)
                    Button(localized("serverLogs.exportQueryPresets")) {
                        exportPresets()
                    }
                    .disabled(model.serverLogQueryPresets.isEmpty)
                    Button(localized("serverLogs.importQueryPresets")) {
                        isImportingPresets = true
                    }
                    Button(localized("serverLogs.deleteAllQueryPresets")) {
                        confirmation = .deleteAllPresets
                    }
                    .disabled(model.serverLogQueryPresets.isEmpty)
                    if model.serverLogQueryPresets.isEmpty {
                        Text(localized("serverLogs.noSavedQueryPresets"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(model.serverLogQueryPresets) { preset in
                            VStack(alignment: .leading, spacing: 6) {
                                HStack {
                                    VStack(alignment: .leading, spacing: 2) {
                                        Text(preset.name)
                                            .font(.subheadline.weight(.semibold))
                                        Text(presetSummary(preset))
                                            .font(.caption)
                                            .foregroundColor(.secondary)
                                    }
                                    Spacer()
                                    Menu {
                                        Button(localized("serverLogs.applyAndRefresh")) {
                                            applyPreset(preset, refresh: true)
                                        }
                                        Button(localized("serverLogs.applyOnly")) {
                                            applyPreset(preset, refresh: false)
                                        }
                                        Button(localized("serverLogs.copyQuerySummary")) {
                                            TS3PlatformSupport.copyToPasteboard(preset.clipboardSummary)
                                        }
                                        Button(localized("serverLogs.deletePreset")) {
                                            model.deleteServerLogQueryPreset(preset)
                                        }
                                    } label: {
                                        Image(systemName: "ellipsis.circle")
                                    }
                                }
                            }
                            .accessibilityElement(children: .combine)
                            .accessibilityLabel(localized("serverLogs.queryPreset"))
                            .accessibilityValue(preset.accessibilityValue)
                            .accessibilityAction(named: localized("serverLogs.copyQuerySummary")) {
                                TS3PlatformSupport.copyToPasteboard(preset.clipboardSummary)
                            }
                        }
                    }
                }

                Section(header: Text(localized("serverLogs.addEntry"))) {
                    Picker(localized("serverLogs.level"), selection: $newLogLevel) {
                        ForEach(Self.logLevels, id: \.self) { level in
                            Text(logLevelTitle(level)).tag(level)
                        }
                    }
                    TextField(localized("serverLogs.message"), text: $newLogMessage)
                        .ts3PlainTextField()
                    Button(localized("serverLogs.writeServerLogEntry")) {
                        model.addServerLogEntry(
                            level: newLogLevel,
                            message: newLogMessage,
                            limit: parsedLineLimit,
                            reverse: reverseOrder,
                            instance: instanceLogs,
                            beginPosition: parsedBeginPosition
                        )
                        newLogMessage = ""
                    }
                    .disabled(model.state != .connected || newLogMessage.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty || !canRunQuery)
                }

                Section(header: Text(localized("serverLogs.serverLog"))) {
                    if filteredEntries.isEmpty {
                        Text(isSearching ? localized("serverLogs.noMatchingEntries") : localized("serverLogs.noEntries"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(filteredEntries) { entry in
                            ServerLogRow(entry: entry)
                        }
                    }
                }
            }
            .navigationTitle(localized("serverLogs.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("serverLogs.refresh")) {
                        model.refreshServerLogs(
                            limit: parsedLineLimit,
                            reverse: reverseOrder,
                            instance: instanceLogs,
                            beginPosition: parsedBeginPosition
                        )
                    }
                    .disabled(model.state != .connected || !canRunQuery)
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.done")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .onAppear {
                if model.state == .connected {
                    model.refreshServerLogs(
                        limit: parsedLineLimit,
                        reverse: reverseOrder,
                        instance: instanceLogs,
                        beginPosition: parsedBeginPosition
                    )
                }
            }
            .fileExporter(
                isPresented: $isExportingLogs,
                document: logExportDocument,
                contentType: .plainText,
                defaultFilename: "ts3-server-logs"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingSnapshot,
                document: snapshotDocument,
                contentType: .plainText,
                defaultFilename: "ts3-server-log-snapshot"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingLogArchive,
                document: logArchiveDocument,
                contentType: .json,
                defaultFilename: "ts3-server-log-archive"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPresets,
                document: presetDocument,
                contentType: .json,
                defaultFilename: "ts3-server-log-query-presets"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingLogArchive,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareLogArchiveImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPresets,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    preparePresetImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .sheet(item: $pendingLogArchiveImport) { confirmation in
                ServerLogArchiveImportSheet(
                    preview: confirmation.preview,
                    previewMessage: logArchivePreviewMessage(confirmation.preview),
                    importArchive: { selectedEntryIds in
                        importLogArchive(data: confirmation.data, selectedEntryIds: selectedEntryIds)
                        pendingLogArchiveImport = nil
                    },
                    cancel: {
                        pendingLogArchiveImport = nil
                    }
                )
            }
            .sheet(item: $pendingPresetImport) { confirmation in
                ServerLogQueryPresetImportSheet(
                    preview: confirmation.preview,
                    importPresets: { selectedPresetIds in
                        importPresets(data: confirmation.data, selectedPresetIds: selectedPresetIds)
                        pendingPresetImport = nil
                    },
                    cancel: {
                        pendingPresetImport = nil
                    }
                )
            }
            .alert(item: $confirmation) { confirmation in
                switch confirmation {
                case .clearAllResults:
                    return Alert(
                        title: Text(localized("serverLogs.clearResultsAlert.title")),
                        message: Text(localized("serverLogs.clearResultsAlert.messageFormat", model.serverLogEntries.count)),
                        primaryButton: .destructive(Text(localized("serverLogs.clear"))) {
                            model.clearServerLogResults()
                        },
                        secondaryButton: .cancel()
                    )
                case .clearVisibleResults:
                    return Alert(
                        title: Text(localized("serverLogs.clearVisibleAlert.title")),
                        message: Text(localized("serverLogs.clearVisibleAlert.messageFormat", filteredEntries.count)),
                        primaryButton: .destructive(Text(localized("serverLogs.clear"))) {
                            model.clearServerLogResults(filteredEntries)
                        },
                        secondaryButton: .cancel()
                    )
                case .deleteAllPresets:
                    return Alert(
                        title: Text(localized("serverLogs.deleteAllPresetsAlert.title")),
                        message: Text(localized("serverLogs.deleteAllPresetsAlert.messageFormat", model.serverLogQueryPresets.count)),
                        primaryButton: .destructive(Text(localized("common.delete"))) {
                            model.deleteAllServerLogQueryPresets()
                        },
                        secondaryButton: .cancel()
                    )
                }
            }
        }
    }

    private var parsedLineLimit: Int {
        currentQueryDraft.limit ?? 100
    }

    private var parsedBeginPosition: Int {
        currentQueryDraft.beginPosition ?? 0
    }

    private var currentQueryDraft: TS3ServerLogQueryDraft {
        TS3ServerLogQueryDraft(
            limitText: lineLimit,
            beginPositionText: beginPosition,
            reverse: reverseOrder,
            instance: instanceLogs,
            levelFilter: levelFilter.rawValue,
            channelFilter: channelFilter,
            searchText: searchText
        )
    }

    private var queryCoverageSummary: TS3ServerLogQueryCoverageSummary {
        TS3ServerLogQueryCoverageSummary(draft: currentQueryDraft)
    }

    private func serverLogQueryCoverageText(_ summary: TS3ServerLogQueryCoverageSummary) -> String {
        var parts = [
            localized("serverLogs.queryCoverageRemoteFormat", summary.remoteQueryDimensionCount),
            localized("serverLogs.queryCoverageLocalFormat", summary.localFilterCount)
        ]
        if summary.hasPagination {
            parts.append(localized("serverLogs.queryCoveragePagination"))
        }
        if summary.validationIssueCount > 0 {
            parts.append(localized("serverLogs.validationIssueCountFormat", summary.validationIssueCount))
        }
        return parts.joined(separator: " · ")
    }

    private var queryValidationMessages: [String] {
        currentQueryDraft.validationMessages
    }

    private var canRunQuery: Bool {
        queryValidationMessages.isEmpty
    }

    private var canMoveToPreviousPage: Bool {
        canRunQuery && parsedBeginPosition > 0
    }

    private var normalizedSearchText: String {
        searchText.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    private var isSearching: Bool {
        !normalizedSearchText.isEmpty
    }

    private var hasLocalFilters: Bool {
        isSearching || levelFilter != .all
            || !normalizedChannelFilter.isEmpty
    }

    private var filteredEntries: [TS3ServerLogSummary] {
        return model.serverLogEntries.filter { entry in
            levelFilter.matches(entry.level)
                && matchesChannel(entry.channel)
                && (
                !isSearching
                    || containsSearch(entry.message)
                    || containsSearch(entry.level)
                    || containsSearch(entry.channel)
            )
        }
    }

    private var filteredTranscript: String {
        Self.transcript(from: filteredEntries)
    }

    private var visibleLogSummary: TS3ServerLogListSummary {
        TS3ServerLogListSummary(entries: filteredEntries)
    }

    private var clearImpactSummary: TS3ServerLogClearImpactSummary {
        TS3ServerLogClearImpactSummary(allEntries: model.serverLogEntries, visibleEntries: filteredEntries)
    }

    private var snapshot: String {
        var lines = currentQueryDraft.clipboardSummary.components(separatedBy: "\n")
        if !filteredEntries.isEmpty {
            lines.append("")
            lines.append(filteredTranscript)
        }
        return lines.joined(separator: "\n")
    }

    private func containsSearch(_ value: String?) -> Bool {
        guard let value, !normalizedSearchText.isEmpty else { return false }
        return value.lowercased().contains(normalizedSearchText)
    }

    private var normalizedChannelFilter: String {
        channelFilter.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    private func matchesChannel(_ value: String?) -> Bool {
        guard !normalizedChannelFilter.isEmpty else { return true }
        return value?.lowercased().contains(normalizedChannelFilter) == true
    }

    private func applyPreset(_ preset: TS3ServerLogQueryPreset, refresh: Bool) {
        lineLimit = String(preset.limit)
        beginPosition = String(preset.beginPosition)
        reverseOrder = preset.reverse
        instanceLogs = preset.instance
        levelFilter = LogLevelFilter(rawValue: preset.levelFilter) ?? .all
        channelFilter = preset.channelFilter
        searchText = preset.searchText
        presetName = preset.name
        if refresh {
            model.refreshServerLogs(
                limit: preset.limit,
                reverse: preset.reverse,
                instance: preset.instance,
                beginPosition: preset.beginPosition
            )
        }
    }

    private func moveLogPage(by direction: Int, refresh: Bool) {
        guard canRunQuery else { return }
        let nextPosition = max(0, min(1_000_000, parsedBeginPosition + parsedLineLimit * direction))
        beginPosition = String(nextPosition)
        guard refresh, model.state == .connected else { return }
        model.refreshServerLogs(
            limit: parsedLineLimit,
            reverse: reverseOrder,
            instance: instanceLogs,
            beginPosition: nextPosition
        )
    }

    private func exportLogArchive() {
        do {
            logArchiveDocument = TS3TextFileDocument(data: try model.serverLogArchiveData())
            isExportingLogArchive = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareLogArchiveImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.serverLogArchivePreview(from: data)
            pendingLogArchiveImport = ServerLogArchiveImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importLogArchive(data: Data, selectedEntryIds: Set<Int>) {
        do {
            try model.importServerLogArchive(from: data, selectedEntryIds: selectedEntryIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func logArchivePreviewMessage(_ preview: TS3ServerLogArchivePreview) -> String {
        var lines = [
            localized("serverLogs.archivePreview.entriesFormat", preview.entryCount),
            localized("serverLogs.archivePreview.withLevelFormat", preview.levelCount),
            localized("serverLogs.archivePreview.withChannelFormat", preview.channelCount),
            localized("serverLogs.archivePreview.withTimestampFormat", preview.timestampCount)
        ]
        if preview.skippedEntryCount > 0 {
            lines.append(localized("serverLogs.archivePreview.skippedFormat", preview.skippedEntryCount))
        }
        if !preview.levelSummaries.isEmpty {
            lines.append(localized("serverLogs.archivePreview.levelsFormat", preview.levelSummaries.joined(separator: " | ")))
        }
        if !preview.channelSummaries.isEmpty {
            lines.append(localized("serverLogs.archivePreview.channelsFormat", preview.channelSummaries.joined(separator: " | ")))
        }
        if let firstLevel = preview.firstLevel {
            lines.append(localized("serverLogs.archivePreview.firstLevelFormat", firstLevel))
        }
        if let firstChannel = preview.firstChannel {
            lines.append(localized("serverLogs.archivePreview.firstChannelFormat", firstChannel))
        }
        if let firstMessage = preview.firstMessage {
            lines.append(localized("serverLogs.archivePreview.firstMessageFormat", firstMessage))
        }
        if let firstTimestamp = preview.firstTimestamp {
            lines.append(localized("serverLogs.archivePreview.firstDateFormat", ServerLogRow.dateText(firstTimestamp)))
        }
        lines.append(preview.hasEntries ? localized("serverLogs.archivePreview.importBehavior") : localized("serverLogs.archivePreview.noUsableEntries"))
        return lines.joined(separator: "\n")
    }

    private func exportPresets() {
        do {
            presetDocument = TS3BookmarkFileDocument(data: try model.serverLogQueryPresetsExportData())
            isExportingPresets = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func preparePresetImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.serverLogQueryPresetsImportPreview(from: data)
            pendingPresetImport = ServerLogQueryPresetImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPresets(data: Data, selectedPresetIds: Set<UUID>) {
        do {
            _ = try model.importServerLogQueryPresets(from: data, selectedPresetIds: selectedPresetIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func presetSummary(_ preset: TS3ServerLogQueryPreset) -> String {
        preset.queryDraft.inlineSummary
    }

    private func serverLogListSummaryText(_ summary: TS3ServerLogListSummary) -> String {
        [
            localized("serverLogs.summaryWithLevelFormat", summary.withLevelCount),
            localized("serverLogs.summaryWithChannelFormat", summary.withChannelCount),
            localized("serverLogs.summaryWithTimestampFormat", summary.timestampCount),
            localized("serverLogs.summaryWarningsFormat", summary.warningCount),
            localized("serverLogs.summaryErrorsFormat", summary.errorCount),
            localized("serverLogs.summaryRawLinesFormat", summary.rawLineCount),
            localized("serverLogs.summaryDistinctChannelsFormat", summary.distinctChannelCount),
            localized(
                "serverLogs.summaryEntryRangeFormat",
                summary.lowestEntryId.map(String.init) ?? localized("common.none"),
                summary.highestEntryId.map(String.init) ?? localized("common.none")
            )
        ].joined(separator: " · ")
    }

    private func serverLogClearImpactText(_ summary: TS3ServerLogClearImpactSummary) -> String {
        var parts = [
            localized("serverLogs.clearImpactWarningsFormat", summary.visibleWarningCount),
            localized("serverLogs.clearImpactErrorsFormat", summary.visibleErrorCount),
            localized("serverLogs.clearImpactRawLinesFormat", summary.visibleRawLineCount),
            localized("serverLogs.clearImpactChannelsFormat", summary.distinctVisibleChannelCount)
        ]
        if summary.clearsAllCachedResults {
            parts.append(localized("serverLogs.clearImpactAllCached"))
        }
        return parts.joined(separator: " · ")
    }

    private static let logLevels: [TS3LogLevel] = [.info, .warning, .error, .debug]

    private func levelFilterTitle(_ filter: LogLevelFilter) -> String {
        switch filter {
        case .all: return localized("serverLogs.level.all")
        case .info: return localized("serverLogs.level.info")
        case .warning: return localized("serverLogs.level.warning")
        case .error: return localized("serverLogs.level.error")
        case .debug: return localized("serverLogs.level.debug")
        }
    }

    private func logLevelTitle(_ level: TS3LogLevel) -> String {
        switch level {
        case .debug: return localized("serverLogs.level.debug")
        case .info: return localized("serverLogs.level.info")
        case .warning: return localized("serverLogs.level.warning")
        case .error: return localized("serverLogs.level.error")
        }
    }

    private static func transcript(from entries: [TS3ServerLogSummary]) -> String {
        entries.map(\.clipboardSummary).joined(separator: "\n")
    }
}

private struct ServerLogArchiveImportSheet: View {
    let preview: TS3ServerLogArchivePreview
    let previewMessage: String
    let importArchive: (Set<Int>) -> Void
    let cancel: () -> Void
    @State private var selectedEntryIds: Set<Int> = []

    private var validSelectedEntryIds: Set<Int> {
        Set(selectedEntryIds.filter(preview.containsEntry))
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("serverLogs.import.preview"))) {
                    Text(previewMessage)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    if preview.hasEntries {
                        Button(localized("serverLogs.import.copyLogSummary")) {
                            TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                        }
                        HStack {
                            Button(localized("serverLogs.import.selectAll")) {
                                selectedEntryIds = Set(preview.candidates.map(\.id))
                            }
                            Button(localized("serverLogs.import.clear")) {
                                selectedEntryIds = []
                            }
                            .disabled(selectedEntryIds.isEmpty)
                        }
                        ForEach(preview.levelSummaries, id: \.self) { summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                        }
                        ForEach(preview.channelSummaries, id: \.self) { summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                        }
                        ForEach(Array(preview.entrySummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .lineLimit(2)
                                .truncationMode(.middle)
                        }
                        ForEach(preview.candidates) { candidate in
                            Toggle(isOn: Binding(
                                get: { selectedEntryIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedEntryIds.insert(candidate.id)
                                    } else {
                                        selectedEntryIds.remove(candidate.id)
                                    }
                                }
                            )) {
                                Text(candidate.summary)
                                    .font(.caption2)
                                    .lineLimit(2)
                                    .truncationMode(.middle)
                            }
                        }
                    }
                }

                Section(header: Text(localized("serverLogs.import.behaviorTitle"))) {
                    Text(localized("serverLogs.import.archiveBehavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("serverLogs.import.archiveTitle"))
            .ts3InlineNavigationTitle()
            .onAppear {
                if selectedEntryIds.isEmpty {
                    selectedEntryIds = Set(preview.candidates.map(\.id))
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("serverLogs.import.action")) {
                        importArchive(validSelectedEntryIds)
                    }
                    .disabled(!preview.hasEntries || validSelectedEntryIds.isEmpty)
                }
            }
        }
    }
}

private struct ServerLogQueryPresetImportSheet: View {
    @Environment(\.presentationMode) private var presentationMode

    let preview: TS3ServerLogQueryPresetImportPreview
    let importPresets: (Set<UUID>) -> Void
    let cancel: () -> Void
    @State private var selectedPresetIds: Set<UUID>

    init(
        preview: TS3ServerLogQueryPresetImportPreview,
        importPresets: @escaping (Set<UUID>) -> Void,
        cancel: @escaping () -> Void
    ) {
        self.preview = preview
        self.importPresets = importPresets
        self.cancel = cancel
        _selectedPresetIds = State(initialValue: Set(preview.candidates.map(\.id)))
    }

    private var canImport: Bool {
        preview.candidates.contains { selectedPresetIds.contains($0.id) }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("serverLogs.import.preview"))) {
                    Text(localized("serverLogs.import.importedPresetsFormat", preview.importedPresetCount))
                    Text(localized("serverLogs.import.usablePresetsFormat", preview.usablePresetCount))
                    Text(localized("serverLogs.import.newPresetsFormat", preview.newPresetCount))
                    Text(localized("serverLogs.import.replacingPresetsFormat", preview.replacedPresetCount))
                    Text(localized("serverLogs.import.skippedPresetsFormat", preview.skippedPresetCount))
                    Button(localized("serverLogs.import.copyBackupPreview")) {
                        TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                    }
                }

                Section(header: Text(localized("serverLogs.import.restore"))) {
                    HStack {
                        Button(localized("serverLogs.import.selectAll")) {
                            selectedPresetIds = Set(preview.candidates.map(\.id))
                        }
                        Spacer()
                        Button(localized("serverLogs.import.clear")) {
                            selectedPresetIds.removeAll()
                        }
                    }
                    ForEach(preview.candidates) { candidate in
                        Toggle(
                            isOn: Binding(
                                get: { selectedPresetIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedPresetIds.insert(candidate.id)
                                    } else {
                                        selectedPresetIds.remove(candidate.id)
                                    }
                                }
                            )
                        ) {
                            Text(candidate.summary)
                                .font(.caption2)
                                .lineLimit(3)
                                .truncationMode(.middle)
                        }
                    }
                }

                Section {
                    Text(localized("serverLogs.import.presetBehavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("serverLogs.import.presetsTitle"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("serverLogs.import.action")) {
                        importPresets(selectedPresetIds)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canImport)
                }
            }
        }
    }
}

struct ServerLogRow: View {
    let entry: TS3ServerLogSummary

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 4) {
            HStack {
                if let timestamp = entry.timestamp {
                    Text(Self.dateText(timestamp))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                if let level = entry.level, !level.isEmpty {
                    Text(level)
                        .font(.caption.weight(.semibold))
                        .foregroundColor(.secondary)
                }
                Spacer()
                if let channel = entry.channel, !channel.isEmpty {
                    Text(channel)
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            Text(entry.message)
                .font(.subheadline)
        }
        .padding(.vertical, 4)
        .contextMenu {
            Button(localized("serverLogs.copyMessage")) {
                TS3PlatformSupport.copyToPasteboard(entry.message)
            }
            Button(localized("serverLogs.copyRawLine")) {
                TS3PlatformSupport.copyToPasteboard(entry.rawLine)
            }
            Button(localized("serverLogs.copyEntry")) {
                TS3PlatformSupport.copyToPasteboard(entry.clipboardSummary)
            }
        }
        .accessibilityElement(children: .ignore)
        .accessibilityLabel(localized("serverLogs.serverLog"))
        .accessibilityValue(entry.accessibilityValue)
        .accessibilityAction(named: localized("serverLogs.copyEntry")) {
            TS3PlatformSupport.copyToPasteboard(entry.clipboardSummary)
        }
        .accessibilityAction(named: localized("serverLogs.copyMessage")) {
            TS3PlatformSupport.copyToPasteboard(entry.message)
        }
        .accessibilityAction(named: localized("serverLogs.copyRawLine")) {
            TS3PlatformSupport.copyToPasteboard(entry.rawLine)
        }
    }

    fileprivate static func dateText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .short
        formatter.timeStyle = .medium
        return formatter.string(from: date)
    }
}

