        rows.append((localized("serverInfo.currentSpeechLoss"), model.connectionInfo.packetLossSpeech.map(Self.percentText)))
        rows.append((localized("serverInfo.currentKeepaliveLoss"), model.connectionInfo.packetLossKeepalive.map(Self.percentText)))
        rows.append((localized("serverInfo.currentControlLoss"), model.connectionInfo.packetLossControl.map(Self.percentText)))
        rows.append((localized("serverInfo.currentConnected"), model.connectionInfo.connectedSeconds.map(Self.durationText)))
        rows.append((localized("serverInfo.currentIdle"), model.connectionInfo.idleSeconds.map(Self.durationText)))
        rows.append((localized("serverInfo.currentSessionDownloaded"), model.connectionInfo.bytesReceived.map(Self.byteText)))
        rows.append((localized("serverInfo.currentSessionUploaded"), model.connectionInfo.bytesSent.map(Self.byteText)))
        rows.append((localized("serverInfo.currentMonthDownloaded"), model.connectionInfo.monthlyBytesReceived.map(Self.byteText)))
        rows.append((localized("serverInfo.currentMonthUploaded"), model.connectionInfo.monthlyBytesSent.map(Self.byteText)))
        rows.append((localized("serverInfo.currentTotalDownloaded"), model.connectionInfo.totalBytesReceived.map(Self.byteText)))
        rows.append((localized("serverInfo.currentTotalUploaded"), model.connectionInfo.totalBytesSent.map(Self.byteText)))
        rows.append((localized("serverInfo.hostMessage"), model.serverInfo.hostMessage))
        rows.append((localized("serverInfo.messageMode"), model.serverInfo.hostMessageMode.map(TS3HostMessageMode.title)))
        rows.append((localized("serverInfo.bannerURL"), model.serverInfo.hostBannerURL))
        rows.append((localized("serverInfo.bannerGraphic"), model.serverInfo.hostBannerGraphicsURL))
        rows.append((localized("serverInfo.bannerMode"), model.serverInfo.hostBannerMode.map(TS3HostBannerMode.title)))
        rows.append((localized("serverInfo.bannerRefresh"), model.serverInfo.hostBannerGraphicsInterval.map(Self.durationText)))
        rows.append((localized("serverInfo.buttonTooltip"), model.serverInfo.hostButtonTooltip))
        rows.append((localized("serverInfo.buttonURL"), model.serverInfo.hostButtonURL))
        rows.append((localized("serverInfo.buttonGraphic"), model.serverInfo.hostButtonGraphicsURL))
        return rows.compactMap { label, value in
            guard let value, !value.isEmpty else { return nil }
            return "\(label): \(value)"
        }.joined(separator: "\n")
    }

    private var clientsText: String? {
        guard let clients = model.serverInfo.clientsOnline else { return nil }
        if let maxClients = model.serverInfo.maxClients {
            return "\(clients) / \(maxClients)"
        }
        return String(clients)
    }

    private var healthSummary: TS3ServerHealthSummary {
        TS3ServerHealthSummary(serverInfo: model.serverInfo, connectionInfo: model.connectionInfo)
    }

    private func healthStateTitle(_ state: TS3ServerHealthSummary.State) -> String {
        switch state {
        case .unknown:
            return localized("serverInfo.health.unknown")
        case .good:
            return localized("serverInfo.health.good")
        case .warning:
            return localized("serverInfo.health.warning")
        case .critical:
            return localized("serverInfo.health.critical")
        }
    }

    private func groupName(_ id: Int?, groups: [TS3GroupSummary]) -> String? {
        id.map { TS3GroupSummary.name(for: $0, in: groups) }
    }

    private func boolText(_ value: Bool?) -> String? {
        value.map { $0 ? localized("serverInfo.enabled") : localized("serverInfo.disabled") }
    }

    private static func dateText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short
        return formatter.string(from: date)
    }

    private static func byteText(_ value: Int64) -> String {
        ByteCountFormatter.string(fromByteCount: value, countStyle: .file)
    }

    private static func bandwidthText(_ value: Int64) -> String {
        "\(byteText(value))/s"
    }

    private static func durationText(_ seconds: Int) -> String {
        ServerInfoRows.uptimeText(seconds)
    }

    private static func decimalText(_ value: Double) -> String {
        String(format: "%.2f", value)
    }

    private static func percentText(_ value: Double) -> String {
        String(format: "%.2f%%", value * 100)
    }
}

struct ServerInfoDetailRow: View {
    let label: String
    let value: String?
    var monospaced = false

    var body: some View {
        if let value, !value.isEmpty {
            HStack(alignment: .top) {
                Text(label)
                Spacer(minLength: 12)
                Text(value)
                    .font(monospaced ? .system(.footnote, design: .monospaced) : .body)
                    .foregroundColor(.secondary)
                    .multilineTextAlignment(.trailing)
                    .lineLimit(3)
            }
            .contextMenu {
                Button("Copy Value") {
                    TS3PlatformSupport.copyToPasteboard(value)
                }
                Button("Copy Row") {
                    TS3PlatformSupport.copyToPasteboard("\(label): \(value)")
                }
                if let url = parsedURL {
                    Button("Open URL") {
                        TS3PlatformSupport.openURL(url)
                    }
                }
            }
        }
    }

    private var parsedURL: URL? {
        let trimmed = value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        guard let url = URL(string: trimmed),
              let scheme = url.scheme?.lowercased(),
              ["http", "https", "ts3server", "teamspeak"].contains(scheme) else {
            return nil
        }
        return url
    }
}

enum TS3GroupManagementTarget: String, CaseIterable, Identifiable {
    case server
    case channel

    var id: String { rawValue }

    var title: String {
        switch self {
        case .server:
            return "Server Groups"
        case .channel:
            return "Channel Groups"
        }
    }

    var singularTitle: String {
        switch self {
        case .server:
            return "Server group"
        case .channel:
            return "Channel group"
        }
    }
}

struct GroupManagementSheet: View {
    private struct GroupArchiveImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3GroupArchivePreview
        let id = UUID()
    }

    private enum GroupTypeFilter: String, CaseIterable, Identifiable {
        case all
        case template
        case regular
        case query
        case unknown

        var id: String { rawValue }

        var title: String {
            switch self {
            case .all: return "All Groups"
            case .template: return "Template"
            case .regular: return "Regular"
            case .query: return "Query"
            case .unknown: return "Unknown"
            }
        }

        func matches(_ group: TS3GroupSummary) -> Bool {
            switch self {
            case .all:
                return true
            case .template:
                return group.type == .template
            case .regular:
                return group.type == .regular
            case .query:
                return group.type == .query
            case .unknown:
                return group.type == nil
            }
        }
    }

    private enum GroupSortMode: String, CaseIterable, Identifiable {
        case name
        case id
        case type

        var id: String { rawValue }

        var title: String {
            switch self {
            case .name: return "Name"
            case .id: return "ID"
            case .type: return "Type"
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var target: TS3GroupManagementTarget = .server
    @State private var newGroupName = ""
    @State private var newGroupType: TS3PermissionGroupDatabaseType = .regular
    @State private var searchText = ""
    @State private var groupTypeFilter: GroupTypeFilter = .all
    @State private var sortMode: GroupSortMode = .name
    @State private var sortAscending = true
    @State private var presetName = ""
    @State private var isExportingGroups = false
    @State private var isExportingGroupArchive = false
    @State private var isImportingGroupArchive = false
    @State private var isExportingPresets = false
    @State private var isImportingPresets = false
    @State private var isConfirmingDeletePresets = false
    @State private var groupsExportDocument = TS3TextFileDocument()
    @State private var groupArchiveDocument = TS3TextFileDocument()
    @State private var presetsDocument = TS3BookmarkFileDocument()
    @State private var pendingGroupArchiveImport: GroupArchiveImportConfirmation?

    private var groups: [TS3GroupSummary] {
        switch target {
        case .server:
            return model.serverGroups
        case .channel:
            return model.channelGroups
        }
    }

    private var filteredGroups: [TS3GroupSummary] {
        let entries = groups.filter { group in
            groupTypeFilter.matches(group) && (
                !isSearching
                    || containsSearch(group.name)
                    || containsSearch(group.typeTitle)
                    || String(group.id).contains(normalizedSearchText)
            )
        }
        return sortedGroups(entries)
    }

    private var visibleGroupsSnapshot: String {
        filteredGroups.map(\.clipboardSummary).joined(separator: "\n")
    }

    private var visibleGroupSummary: TS3GroupListSummary {
        TS3GroupListSummary(groups: filteredGroups, target: target)
    }

    private var newGroupDraftValidationMessages: [String] {
        TS3GroupDraftValidator.validationMessages(
            operation: .create,
            name: newGroupName,
            target: target,
            type: newGroupType,
            sourceGroup: nil,
            existingGroups: groups
        )
    }

    private var newGroupDraftSummary: String {
        TS3GroupDraftValidator.creationSummary(
            operation: .create,
            name: newGroupName,
            target: target,
            type: newGroupType,
            sourceGroup: nil
        )
    }

    private var newGroupDraftCoverageSummary: TS3GroupDraftCoverageSummary {
        TS3GroupDraftCoverageSummary(
            operation: .create,
            name: newGroupName,
            target: target,
            type: newGroupType,
            sourceGroup: nil,
            validationMessages: newGroupDraftValidationMessages
        )
    }

    private var officialManagementAuditSummary: TS3GroupOfficialManagementAuditSummary {
        TS3GroupOfficialManagementAuditSummary(
            target: target,
            visibleGroupSummary: visibleGroupSummary,
            groupDraftCoverageSummary: newGroupDraftCoverageSummary
        )
    }

    var body: some View {
        NavigationView {
            List {
                Section(header: Text(localized("groups.target"))) {
                    Picker(localized("groups.groupType"), selection: $target) {
                        ForEach(TS3GroupManagementTarget.allCases) { target in
                            Text(targetTitle(target)).tag(target)
                        }
                    }
                    .pickerStyle(SegmentedPickerStyle())
                }

                Section(header: Text(localized("groups.create"))) {
                    TextField(localized("groups.groupName"), text: $newGroupName)
                        .ts3PlainTextField()
                    Picker(localized("groups.databaseType"), selection: $newGroupType) {
                        ForEach(TS3PermissionGroupDatabaseType.allCases) { type in
                            Text(databaseTypeTitle(type)).tag(type)
                        }
                    }
                    ServerInfoDetailRow(
                        label: localized("groups.draftCoverage"),
                        value: localized(
                            "groups.draftCoverageFormat",
                            newGroupDraftCoverageSummary.requiredFieldCount,
                            newGroupDraftCoverageSummary.requiredFieldTotal,
                            newGroupDraftCoverageSummary.validationIssueCount
                        )
                    )
                    Text(groupDraftCoverageText(newGroupDraftCoverageSummary))
                        .font(.caption)
                        .foregroundColor(newGroupDraftCoverageSummary.needsAttention ? .orange : .secondary)
                    Button(localized("groups.copyDraftCoverage")) {
                        TS3PlatformSupport.copyToPasteboard(newGroupDraftCoverageSummary.clipboardSummary)
                    }
                    Text(newGroupDraftSummary)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("groups.copyGroupSummary")) {
                        TS3PlatformSupport.copyToPasteboard(newGroupDraftSummary)
                    }
                    ForEach(newGroupDraftValidationMessages, id: \.self) { message in
                        Text(message)
                            .font(.caption)
                            .foregroundColor(.red)
                    }
                    Button(localized("groups.createGroup")) {
                        createGroup()
                    }
                    .disabled(model.state != .connected || !newGroupDraftValidationMessages.isEmpty)
                }

                Section(header: Text(localized("groups.filters"))) {
                    Picker(localized("groups.type"), selection: $groupTypeFilter) {
                        ForEach(GroupTypeFilter.allCases) { filter in
                            Text(groupTypeFilterTitle(filter)).tag(filter)
                        }
                    }
                    Picker(localized("groups.sortBy"), selection: $sortMode) {
                        ForEach(GroupSortMode.allCases) { mode in
                            Text(sortModeTitle(mode)).tag(mode)
                        }
                    }
                    Toggle(localized("groups.ascending"), isOn: $sortAscending)
                    TextField(localized("groups.searchGroups"), text: $searchText)
                        .ts3PlainTextField()
                    Menu {
                        TextField(localized("groups.presetName"), text: $presetName)
                        Button(localized("groups.saveCurrentFilters")) {
                            model.saveGroupFilterPreset(
                                name: presetName,
                                target: target.rawValue,
                                groupTypeFilter: groupTypeFilter.rawValue,
                                sortMode: sortMode.rawValue,
                                sortAscending: sortAscending,
                                searchText: searchText
                            )
                            presetName = ""
                        }
                        .disabled(presetName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                        if model.groupFilterPresets.isEmpty {
                            Text(localized("groups.noSavedFilterPresets"))
                        } else {
                            ForEach(model.groupFilterPresets) { preset in
                                Menu {
                                    Button(localized("groups.applyPreset")) {
                                        applyPreset(preset)
                                    }
                                    Button(localized("groups.useName")) {
                                        presetName = preset.name
                                    }
                                    Button(localized("groups.copyPresetSummary")) {
                                        TS3PlatformSupport.copyToPasteboard(preset.clipboardSummary)
                                    }
                                    Button(localized("groups.deletePreset")) {
                                        model.deleteGroupFilterPreset(preset)
                                    }
                                } label: {
                                    VStack(alignment: .leading) {
                                        Text(preset.name)
                                        Text(presetSummary(preset))
                                    }
                                }
                                .accessibilityElement(children: .combine)
                                .accessibilityLabel(localized("groups.filterPreset"))
                                .accessibilityValue(preset.accessibilityValue)
                                .accessibilityAction(named: localized("groups.copyPresetSummary")) {
                                    TS3PlatformSupport.copyToPasteboard(preset.clipboardSummary)
                                }
                            }
                        }
                        Divider()
                        Button(localized("groups.exportPresets")) {
                            exportPresets()
                        }
                        .disabled(model.groupFilterPresets.isEmpty)
                        Button(localized("groups.importPresets")) {
                            isImportingPresets = true
                        }
                        Button(localized("groups.deleteAllPresets")) {
                            isConfirmingDeletePresets = true
                        }
                        .disabled(model.groupFilterPresets.isEmpty)
                    } label: {
                        Label(localized("groups.filterPresets"), systemImage: "line.3.horizontal.decrease.circle")
                    }
                    if hasLocalFilters {
                        Button(localized("groups.clearFilters")) {
                            groupTypeFilter = .all
                            sortMode = .name
                            sortAscending = true
                            searchText = ""
                        }
                    }
                    ServerInfoDetailRow(
                        label: localized("groups.visibleSummary"),
                        value: localized(
                            "groups.visibleSummaryFormat",
                            visibleGroupSummary.totalCount,
                            targetTitle(visibleGroupSummary.target)
                        )
                    )
                    Text(groupListSummaryText(visibleGroupSummary))
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("groups.copyVisibleSummary")) {
                        TS3PlatformSupport.copyToPasteboard(visibleGroupSummary.clipboardSummary)
                    }
                    .disabled(filteredGroups.isEmpty)
                    ServerInfoDetailRow(
                        label: localized("groups.officialAudit"),
                        value: localized(
                            "groups.officialAuditFormat",
                            officialManagementAuditSummary.availableOfficialAreaCount,
                            officialManagementAuditSummary.officialAreaTotal,
                            officialManagementAuditSummary.blockedOfficialAreaCount
                        )
                    )
                    Text(officialManagementAuditText(officialManagementAuditSummary))
                        .font(.caption)
                        .foregroundColor(officialManagementAuditSummary.needsAttention ? .orange : .secondary)
                    Button(localized("groups.copyOfficialAudit")) {
                        TS3PlatformSupport.copyToPasteboard(officialManagementAuditSummary.clipboardSummary)
                    }
                    Button(localized("groups.copyVisibleGroups")) {
                        TS3PlatformSupport.copyToPasteboard(visibleGroupsSnapshot)
                    }
                    .disabled(filteredGroups.isEmpty)
                    Button(localized("groups.exportVisibleGroups")) {
                        groupsExportDocument = TS3TextFileDocument(data: Data(visibleGroupsSnapshot.utf8))
                        isExportingGroups = true
                    }
                    .disabled(filteredGroups.isEmpty)
                    Button(localized("groups.exportGroupArchive")) {
                        exportGroupArchive()
                    }
                    .disabled(model.serverGroups.isEmpty && model.channelGroups.isEmpty)
                    Button(localized("groups.importGroupArchive")) {
                        isImportingGroupArchive = true
                    }
                }

                Section(header: Text(targetTitle(target))) {
                    if groups.isEmpty {
                        Text(localized("groups.noGroups"))
                            .foregroundColor(.secondary)
                    } else if filteredGroups.isEmpty {
                        Text(localized("groups.noMatchingGroups"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(filteredGroups) { group in
                            GroupManagementRow(group: group, target: target)
                                .environmentObject(model)
                        }
                    }
                }
            }
            .navigationTitle(localized("groups.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                if model.state == .connected {
                    model.refreshGroups()
                }
            }
            .fileExporter(
                isPresented: $isExportingGroups,
                document: groupsExportDocument,
                contentType: .plainText,
                defaultFilename: target == .server ? "ts3-server-groups" : "ts3-channel-groups"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingGroupArchive,
                document: groupArchiveDocument,
                contentType: .json,
                defaultFilename: "ts3-permission-groups-archive"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPresets,
                document: presetsDocument,
                contentType: .json,
                defaultFilename: "ts3-group-filter-presets"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingGroupArchive,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareGroupArchiveImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPresets,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    importPresets(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .sheet(item: $pendingGroupArchiveImport) { confirmation in
                GroupArchiveImportSheet(
                    preview: confirmation.preview,
                    previewMessage: groupArchivePreviewMessage(confirmation.preview),
                    importArchive: { selectedGroupIds in
                        importGroupArchive(data: confirmation.data, selectedGroupIds: selectedGroupIds)
                        pendingGroupArchiveImport = nil
                    },
                    cancel: {
                        pendingGroupArchiveImport = nil
                    }
                )
            }
            .alert(isPresented: $isConfirmingDeletePresets) {
                Alert(
                    title: Text(localized("groups.deleteAllPresetsAlert.title")),
                    message: Text(localized("groups.deleteAllPresetsAlert.messageFormat", model.groupFilterPresets.count)),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deleteAllGroupFilterPresets()
                    },
                    secondaryButton: .cancel()
                )
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("groups.refresh")) {
                        model.refreshGroups()
                    }
                    .disabled(model.state != .connected)
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.done")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }

    private func createGroup() {
        switch target {
        case .server:
            model.createServerGroup(name: newGroupName, type: newGroupType)
        case .channel:
            model.createChannelGroup(name: newGroupName, type: newGroupType)
        }
        newGroupName = ""
        newGroupType = .regular
    }

    private var normalizedSearchText: String {
        searchText.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    private var isSearching: Bool {
        !normalizedSearchText.isEmpty
    }

    private var hasLocalFilters: Bool {
        isSearching || groupTypeFilter != .all || sortMode != .name || !sortAscending
    }

    private func containsSearch(_ value: String?) -> Bool {
        guard let value, !normalizedSearchText.isEmpty else { return false }
        return value.lowercased().contains(normalizedSearchText)
    }

    private func sortedGroups(_ groups: [TS3GroupSummary]) -> [TS3GroupSummary] {
        groups.sorted { lhs, rhs in
            if lhs.id == rhs.id {
                return false
            }

            let comparison: ComparisonResult
            switch sortMode {
            case .name:
                comparison = lhs.name.localizedCaseInsensitiveCompare(rhs.name)
            case .id:
                comparison = compareInts(lhs.id, rhs.id)
            case .type:
                comparison = lhs.typeTitle.localizedCaseInsensitiveCompare(rhs.typeTitle)
            }

            if comparison == .orderedSame {
                return lhs.id < rhs.id
            }
            return sortAscending ? comparison == .orderedAscending : comparison == .orderedDescending
        }
    }

    private func compareInts(_ lhs: Int, _ rhs: Int) -> ComparisonResult {
        if lhs == rhs {
            return .orderedSame
        }
        return lhs < rhs ? .orderedAscending : .orderedDescending
    }

    private func applyPreset(_ preset: TS3GroupFilterPreset) {
        target = TS3GroupManagementTarget(rawValue: preset.target) ?? .server
        groupTypeFilter = GroupTypeFilter(rawValue: preset.groupTypeFilter) ?? .all
        sortMode = GroupSortMode(rawValue: preset.sortMode) ?? .name
        sortAscending = preset.sortAscending
        searchText = preset.searchText
        presetName = preset.name
    }

    private func presetSummary(_ preset: TS3GroupFilterPreset) -> String {
        preset.inlineSummary
    }

    private func groupListSummaryText(_ summary: TS3GroupListSummary) -> String {
        var parts = [
            localized("groups.summary.templateFormat", summary.templateCount),
            localized("groups.summary.regularFormat", summary.regularCount),
            localized("groups.summary.queryFormat", summary.queryCount),
            localized("groups.summary.unknownFormat", summary.unknownTypeCount)
        ]
        if let lowestGroupId = summary.lowestGroupId, let highestGroupId = summary.highestGroupId {
            parts.append(localized("groups.summary.idRangeFormat", lowestGroupId, highestGroupId))
        }
        return parts.joined(separator: " · ")
    }

    private func targetTitle(_ target: TS3GroupManagementTarget) -> String {
        switch target {
        case .server:
            return localized("groups.target.server")
        case .channel:
            return localized("groups.target.channel")
        }
    }

    private func groupTypeFilterTitle(_ filter: GroupTypeFilter) -> String {
        switch filter {
        case .all:
            return localized("groups.filter.allGroups")
        case .template:
            return localized("groups.filter.template")
        case .regular:
            return localized("groups.filter.regular")
        case .query:
            return localized("groups.filter.query")
        case .unknown:
            return localized("common.unknown")
        }
    }

    private func sortModeTitle(_ mode: GroupSortMode) -> String {
        switch mode {
        case .name:
            return localized("groups.sort.name")
        case .id:
            return localized("groups.sort.id")
        case .type:
            return localized("groups.sort.type")
        }
    }

    private func databaseTypeTitle(_ type: TS3PermissionGroupDatabaseType) -> String {
        switch type {
        case .template:
            return localized("groups.filter.template")
        case .regular:
            return localized("groups.filter.regular")
        case .query:
            return localized("groups.filter.query")
        }
    }

    private func operationTitle(_ operation: TS3GroupDraftValidator.Operation) -> String {
        switch operation {
        case .create:
            return localized("groups.operation.create")
        case .copy:
            return localized("groups.operation.copy")
        case .rename:
            return localized("groups.operation.rename")
        }
    }

    private func groupDraftCoverageText(_ summary: TS3GroupDraftCoverageSummary) -> String {
        [
            localized("groups.draftCoverageOperationFormat", operationTitle(summary.operation)),
            localized("groups.draftCoverageTargetFormat", targetTitle(summary.target)),
            localized("groups.draftCoverageNameFormat", summary.hasName ? 1 : 0),
            localized("groups.draftCoverageSourceFormat", summary.hasSourceGroup ? 1 : 0),
            localized("groups.draftCoverageDatabaseTypeFormat", summary.hasDatabaseType ? 1 : 0)
        ].joined(separator: " | ")
    }

    private func officialManagementAuditText(_ summary: TS3GroupOfficialManagementAuditSummary) -> String {
        [
            localized("groups.officialAuditTargetFormat", targetTitle(summary.target)),
            localized("groups.officialAuditActionsFormat", summary.officialActionCount),
            localized("groups.officialAuditVisibleGroupsFormat", summary.visibleGroupSummary?.totalCount ?? 0),
            localized("groups.officialAuditAttentionFormat", summary.needsAttention ? 1 : 0)
        ].joined(separator: " | ")
    }

    private func exportGroupArchive() {
        do {
            groupArchiveDocument = TS3TextFileDocument(data: try model.groupArchiveData())
            isExportingGroupArchive = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareGroupArchiveImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.groupArchivePreview(from: data)
            pendingGroupArchiveImport = GroupArchiveImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importGroupArchive(data: Data, selectedGroupIds: Set<String>) {
        do {
            try model.importGroupArchive(from: data, selectedGroupIds: selectedGroupIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func groupArchivePreviewMessage(_ preview: TS3GroupArchivePreview) -> String {
        var lines = [
            localized("groups.archivePreview.serverGroupsFormat", preview.serverGroupCount),
            localized("groups.archivePreview.channelGroupsFormat", preview.channelGroupCount),
            localized("groups.archivePreview.templateFormat", preview.templateCount),
            localized("groups.archivePreview.regularFormat", preview.regularCount),
            localized("groups.archivePreview.queryFormat", preview.queryCount),
            localized("groups.archivePreview.unknownTypeFormat", preview.unknownTypeCount)
        ]
        if preview.skippedGroupCount > 0 {
            lines.append(localized("groups.archivePreview.skippedFormat", preview.skippedGroupCount))
        }
        if let firstServerGroupName = preview.firstServerGroupName {
            lines.append(localized("groups.archivePreview.firstServerGroupFormat", firstServerGroupName))
        }
        if let firstChannelGroupName = preview.firstChannelGroupName {
            lines.append(localized("groups.archivePreview.firstChannelGroupFormat", firstChannelGroupName))
        }
        lines.append(preview.hasGroups ? localized("groups.archivePreview.importBehavior") : localized("groups.archivePreview.noUsableGroups"))
        return lines.joined(separator: "\n")
    }

    private func exportPresets() {
        do {
            presetsDocument = TS3BookmarkFileDocument(data: try model.groupFilterPresetsExportData())
            isExportingPresets = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPresets(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            _ = try model.importGroupFilterPresets(from: Data(contentsOf: url))
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

private struct GroupArchiveImportSheet: View {
    let preview: TS3GroupArchivePreview
    let previewMessage: String
    let importArchive: (Set<String>) -> Void
    let cancel: () -> Void
    @State private var selectedGroupIds: Set<String> = []

    private var validSelectedGroupIds: Set<String> {
        Set(selectedGroupIds.filter(preview.containsGroup))
    }

    private var importImpactSummary: TS3GroupImportImpactSummary {
        TS3GroupImportImpactSummary(preview: preview, selectedGroupIds: validSelectedGroupIds)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("groups.import.preview"))) {
                    Text(previewMessage)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    if preview.hasGroups {
                        Button(localized("groups.import.copyGroupSummary")) {
                            TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                        }
                        HStack {
                            Button(localized("groups.import.selectAll")) {
                                selectedGroupIds = Set(preview.candidates.map(\.id))
                            }
                            Button(localized("groups.import.clear")) {
                                selectedGroupIds = []
                            }
                            .disabled(selectedGroupIds.isEmpty)
                        }
                        ServerInfoDetailRow(
                            label: localized("groups.import.impact"),
                            value: localized(
                                "groups.import.impactFormat",
                                importImpactSummary.selectedGroupCount,
                                importImpactSummary.selectedServerGroupCount,
                                importImpactSummary.selectedChannelGroupCount
                            )
                        )
                        Text(groupImportImpactText(importImpactSummary))
                            .font(.caption2)
                            .foregroundColor(importImpactSummary.needsAttention ? .orange : .secondary)
                        Button(localized("groups.import.copyImpact")) {
                            TS3PlatformSupport.copyToPasteboard(importImpactSummary.clipboardSummary)
                        }
                        .disabled(!importImpactSummary.hasSelection)
                    }
                }

                if !preview.serverGroupSummaries.isEmpty {
                    Section(header: Text(localized("groups.import.serverGroups"))) {
                        ForEach(Array(preview.serverGroupTypeSummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                                .lineLimit(1)
                                .truncationMode(.middle)
                        }
                        ForEach(Array(preview.serverGroupSummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .lineLimit(2)
                                .truncationMode(.middle)
                        }
                        ForEach(preview.candidates.filter { $0.target == .server }) { candidate in
                            Toggle(isOn: Binding(
                                get: { selectedGroupIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedGroupIds.insert(candidate.id)
                                    } else {
                                        selectedGroupIds.remove(candidate.id)
                                    }
                                }
                            )) {
                                Text(candidate.summary)
                                    .font(.caption2)
                                    .lineLimit(2)
                                    .truncationMode(.middle)
                            }
                        }
                    }
                }

                if !preview.channelGroupSummaries.isEmpty {
                    Section(header: Text(localized("groups.import.channelGroups"))) {
                        ForEach(Array(preview.channelGroupTypeSummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                                .lineLimit(1)
                                .truncationMode(.middle)
                        }
                        ForEach(Array(preview.channelGroupSummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .lineLimit(2)
                                .truncationMode(.middle)
                        }
                        ForEach(preview.candidates.filter { $0.target == .channel }) { candidate in
                            Toggle(isOn: Binding(
                                get: { selectedGroupIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedGroupIds.insert(candidate.id)
                                    } else {
                                        selectedGroupIds.remove(candidate.id)
                                    }
                                }
                            )) {
                                Text(candidate.summary)
                                    .font(.caption2)
                                    .lineLimit(2)
                                    .truncationMode(.middle)
                            }
                        }
                    }
                }

                Section(header: Text(localized("groups.import.behaviorTitle"))) {
                    Text(localized("groups.import.archiveBehavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("groups.import.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                if selectedGroupIds.isEmpty {
                    selectedGroupIds = Set(preview.candidates.map(\.id))
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("groups.import.action")) {
                        importArchive(validSelectedGroupIds)
                    }
                    .disabled(!preview.hasGroups || validSelectedGroupIds.isEmpty)
                }
            }
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    private func groupImportImpactText(_ summary: TS3GroupImportImpactSummary) -> String {
        [
            localized("groups.import.impactTypesFormat", summary.templateCount, summary.regularCount, summary.queryCount, summary.unknownTypeCount),
            localized("groups.import.impactSkippedFormat", summary.skippedServerGroupCount, summary.skippedChannelGroupCount)
        ].joined(separator: " | ")
    }
}

struct GroupManagementRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let group: TS3GroupSummary
    let target: TS3GroupManagementTarget
    @State private var isShowingMembers = false
    @State private var isShowingPermissions = false
    @State private var isShowingPrivilegeKeys = false
    @State private var isShowingRename = false
    @State private var isShowingCopy = false
    @State private var isConfirmingDelete = false
    @State private var isConfirmingForcedDelete = false

    var body: some View {
        HStack(alignment: .top) {
            VStack(alignment: .leading, spacing: 4) {
                Text(group.name)
                    .font(.subheadline.weight(.semibold))
                    .lineLimit(1)
                    .truncationMode(.middle)
                HStack(spacing: 8) {
                    Text("#\(group.id)")
                    Text(group.typeTitle)
                }
                .font(.caption)
                .foregroundColor(.secondary)
            }
            Spacer()
            Menu {
                Button(localized("groups.row.viewMembers")) {
                    refreshMembers()
                    isShowingMembers = true
                }
                .disabled(model.state != .connected)
                Button(localized("groups.row.editPermissions")) {
                    model.selectGroupPermissions(group, target: target)
                    isShowingPermissions = true
                }
                .disabled(model.state != .connected)
                Button(localized("groups.row.createPrivilegeKey")) {
                    isShowingPrivilegeKeys = true
                }
                .disabled(model.state != .connected || (target == .channel && model.channels.isEmpty))
                Button(localized("groups.row.copySummary")) {
                    TS3PlatformSupport.copyToPasteboard(group.clipboardSummary(target: target))
                }
                Button(localized("groups.row.rename")) {
                    isShowingRename = true
                }
                .disabled(model.state != .connected)
                Button(localized("groups.row.copy")) {
                    isShowingCopy = true
                }
                .disabled(model.state != .connected)
                Button(localized("groups.row.delete")) {
                    isConfirmingDelete = true
                }
                .disabled(model.state != .connected)
                Button(localized("groups.row.forceDelete")) {
                    isConfirmingForcedDelete = true
                }
                .disabled(model.state != .connected)
            } label: {
                Image(systemName: "ellipsis.circle")
            }
            .buttonStyle(.borderless)
        }
        .padding(.vertical, 3)
        .sheet(isPresented: $isShowingMembers) {
            GroupClientListSheet(group: group, target: target)
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingPermissions) {
            PermissionsSheet()
                .environmentObject(model)
        }
        .sheet(isPresented: $isShowingPrivilegeKeys) {
            PrivilegeKeysSheet(
                initialTargetType: privilegeKeyTargetType,
                initialServerGroupId: target == .server ? group.id : nil,
                initialChannelGroupId: target == .channel ? group.id : nil,
                initialChannelId: target == .channel ? model.currentChannel?.id ?? model.channels.first?.id : nil
            )
            .environmentObject(model)
        }
        .sheet(isPresented: $isShowingRename) {
            GroupNameSheet(
                title: localized("groups.row.renameTitle"),
                actionTitle: localized("groups.row.rename"),
                initialName: group.name,
                allowsTypeSelection: false,
                initialType: group.type ?? .regular,
                operation: .rename,
                target: target,
                sourceGroup: group,
                existingGroups: existingGroups
            ) { name, _ in
                renameGroup(name: name)
            }
        }
        .sheet(isPresented: $isShowingCopy) {
            GroupNameSheet(
                title: localized("groups.row.copyTitle"),
                actionTitle: localized("groups.row.copy"),
                initialName: localized("groups.row.copyNameFormat", group.name),
                allowsTypeSelection: true,
                initialType: group.type ?? .regular,
                operation: .copy,
                target: target,
                sourceGroup: group,
                existingGroups: existingGroups
            ) { name, type in
                copyGroup(name: name, type: type)
            }
        }
        .alert(isPresented: $isConfirmingDelete) {
            Alert(
                title: Text(localized("groups.row.deleteAlert.title")),
                message: Text(group.name),
                primaryButton: .destructive(Text(localized("groups.row.delete"))) {
                    deleteGroup(force: false)
                },
                secondaryButton: .cancel()
            )
        }
        .background(
            EmptyView().alert(isPresented: $isConfirmingForcedDelete) {
                Alert(
                    title: Text(localized("groups.row.forceDeleteAlert.title")),
                    message: Text(group.name),
                    primaryButton: .destructive(Text(localized("groups.row.forceDelete"))) {
                        deleteGroup(force: true)
                    },
                    secondaryButton: .cancel()
                )
            }
        )
        .accessibilityElement(children: .ignore)
        .accessibilityLabel(group.name)
        .accessibilityValue(group.accessibilityValue(target: target))
        .accessibilityAction(named: localized("groups.row.copySummary")) {
            TS3PlatformSupport.copyToPasteboard(group.clipboardSummary(target: target))
        }
        .accessibilityAction(named: localized("groups.row.viewMembers")) {
            guard model.state == .connected else { return }
            refreshMembers()
            isShowingMembers = true
        }
        .accessibilityAction(named: localized("groups.row.editPermissions")) {
            guard model.state == .connected else { return }
            model.selectGroupPermissions(group, target: target)
            isShowingPermissions = true
        }
    }

    private func renameGroup(name: String) {
        switch target {
        case .server:
            model.renameServerGroup(group, name: name)
        case .channel:
            model.renameChannelGroup(group, name: name)
        }
    }

    private func copyGroup(name: String, type: TS3PermissionGroupDatabaseType) {
        switch target {
        case .server:
            model.copyServerGroup(group, name: name, type: type)
        case .channel:
            model.copyChannelGroup(group, name: name, type: type)
        }
    }

    private func refreshMembers() {
        switch target {
        case .server:
            model.refreshServerGroupClients(group)
        case .channel:
            model.refreshChannelGroupClients(group)
        }
    }

    private func deleteGroup(force: Bool) {
        switch target {
        case .server:
            model.deleteServerGroup(group, force: force)
        case .channel:
            model.deleteChannelGroup(group, force: force)
        }
    }

    private var privilegeKeyTargetType: TS3PrivilegeKeyTargetType {
        switch target {
        case .server:
            return .serverGroup
        case .channel:
            return .channelGroup
        }
    }

    private var existingGroups: [TS3GroupSummary] {
        switch target {
        case .server:
            return model.serverGroups
        case .channel:
            return model.channelGroups
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

struct GroupClientListSheet: View {
    private enum MemberFilter: String, CaseIterable, Identifiable {
        case all
        case online
        case offline
        case withUniqueId
        case withoutUniqueId

        var id: String { rawValue }

        var title: String {
            switch self {
            case .all: return "All Members"
            case .online: return "Online"
            case .offline: return "Offline"
            case .withUniqueId: return "With Unique ID"
            case .withoutUniqueId: return "Without Unique ID"
            }
        }

        func matches(_ client: TS3GroupClientSummary) -> Bool {
            switch self {
            case .all:
                return true
            case .online:
                return client.channelId != nil
            case .offline:
                return client.channelId == nil
            case .withUniqueId:
                return client.uniqueIdentifier?.isEmpty == false
            case .withoutUniqueId:
                return client.uniqueIdentifier?.isEmpty != false
            }
        }
    }

    private enum MemberSortMode: String, CaseIterable, Identifiable {
        case nickname
        case databaseId
        case channel
        case uniqueId

        var id: String { rawValue }

        var title: String {
            switch self {
            case .nickname: return "Nickname"
            case .databaseId: return "Database ID"
            case .channel: return "Channel"
            case .uniqueId: return "Unique ID"
            }
        }
    }

    private enum ChannelContextFilter: String, CaseIterable, Identifiable {
        case allChannels
        case currentChannel
        case selectedChannel
        case withoutChannel

        var id: String { rawValue }

        var title: String {
            switch self {
            case .allChannels: return "All Channels"
            case .currentChannel: return "Current Channel"
            case .selectedChannel: return "Selected Channel"
            case .withoutChannel: return "No Channel"
            }
        }

        func matches(_ client: TS3GroupClientSummary, currentChannelId: Int?, selectedChannelId: Int?) -> Bool {
            switch self {
            case .allChannels:
                return true
            case .currentChannel:
                guard let currentChannelId else { return false }
                return client.channelId == currentChannelId
            case .selectedChannel:
                guard let selectedChannelId else { return false }
                return client.channelId == selectedChannelId
            case .withoutChannel:
                return client.channelId == nil
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    let group: TS3GroupSummary
    let target: TS3GroupManagementTarget
    @State private var searchText = ""
    @State private var memberFilter: MemberFilter = .all
    @State private var channelContextFilter: ChannelContextFilter = .allChannels
    @State private var selectedFilterChannelId: Int?
    @State private var sortMode: MemberSortMode = .nickname
    @State private var sortAscending = true
    @State private var newMemberDatabaseId = ""
    @State private var newMemberChannelId: Int?
    @State private var presetName = ""
    @State private var isExportingMembers = false
    @State private var isExportingPresets = false
    @State private var isImportingPresets = false
    @State private var isConfirmingRemoveVisible = false
    @State private var isConfirmingDeletePresets = false
    @State private var membersExportDocument = TS3TextFileDocument()
    @State private var presetsDocument = TS3BookmarkFileDocument()

    private var filteredClients: [TS3GroupClientSummary] {
        let clients = model.groupClients.filter { client in
            memberFilter.matches(client)
                && channelContextFilter.matches(
                    client,
                    currentChannelId: model.currentChannel?.id,
                    selectedChannelId: selectedFilterChannelId
                ) && (
                !isSearching
                    || containsSearch(client.displayName)
                    || containsSearch(client.uniqueIdentifier)
                    || client.channelId.map { String($0).contains(normalizedSearchText) } == true
                    || String(client.clientDatabaseId).contains(normalizedSearchText)
                    || client.channelId.flatMap { model.channelName(for: $0) }?.lowercased().contains(normalizedSearchText) == true
            )
        }
        return sortedClients(clients)
    }

    private var visibleMembersSnapshot: String {
        var lines = [
            localized("groups.members.snapshot.groupFormat", group.name, group.id),
            localized("groups.members.snapshot.targetFormat", targetTitle(target)),
            localized("groups.members.snapshot.statusFilterFormat", memberFilterTitle(memberFilter)),
            localized("groups.members.snapshot.channelFilterFormat", channelContextFilterTitle),
            localized("groups.members.snapshot.sortFormat", memberSortModeTitle(sortMode), sortAscending ? localized("groups.ascending") : localized("groups.members.descending"))
        ]
        if isSearching {
            lines.append(localized("groups.members.snapshot.searchFormat", searchText.trimmingCharacters(in: .whitespacesAndNewlines)))
        }
        lines.append("")
        lines += filteredClients.map { client in
            client.clipboardSummary(
                group: group,
                target: target,
                channelName: client.channelId.flatMap { model.channelName(for: $0) }
            )
        }
        return lines.joined(separator: "\n")
    }

    private var visibleMemberSummary: TS3GroupClientListSummary {
        TS3GroupClientListSummary(clients: filteredClients, target: target)
    }

    private var memberDraftOperation: TS3GroupMemberDraftValidator.Operation {
        target == .server ? .addServerMember : .setChannelGroup
    }

    private var memberDraftValidationMessages: [String] {
        TS3GroupMemberDraftValidator.validationMessages(
            operation: memberDraftOperation,
            target: target,
            group: group,
            clientDatabaseId: newMemberDatabaseId,
            channelId: target == .channel ? selectedNewMemberChannelId : nil
        )
    }

    private var memberDraftSummary: String {
        TS3GroupMemberDraftValidator.changeSummary(
            operation: memberDraftOperation,
            target: target,
            group: group,
            clientDatabaseId: newMemberDatabaseId,
            channelId: target == .channel ? selectedNewMemberChannelId : nil,
            channelName: selectedNewMemberChannelId.flatMap { model.channelName(for: $0) }
        )
    }

    private var memberDraftCoverageSummary: TS3GroupMemberDraftCoverageSummary {
        TS3GroupMemberDraftCoverageSummary(
            operation: memberDraftOperation,
            target: target,
            group: group,
            clientDatabaseId: newMemberDatabaseId,
            channelId: target == .channel ? selectedNewMemberChannelId : nil,
            validationMessages: memberDraftValidationMessages
        )
    }

    private var officialManagementAuditSummary: TS3GroupOfficialManagementAuditSummary {
        TS3GroupOfficialManagementAuditSummary(
            target: target,
            visibleMemberSummary: visibleMemberSummary,
            memberDraftCoverageSummary: memberDraftCoverageSummary
        )
    }

    var body: some View {
        NavigationView {
            List {
                Section(header: Text(localized("groups.filters"))) {
                    Picker(localized("groups.members.status"), selection: $memberFilter) {
                        ForEach(MemberFilter.allCases) { filter in
                            Text(memberFilterTitle(filter)).tag(filter)
                        }
                    }
                    Picker(localized("groups.members.channelContext"), selection: $channelContextFilter) {
                        ForEach(ChannelContextFilter.allCases) { filter in
                            Text(channelContextFilterTitle(filter)).tag(filter)
                        }
                    }
                    if channelContextFilter == .selectedChannel {
                        Picker(localized("groups.members.filterChannel"), selection: selectedFilterChannelBinding) {
                            Text(localized("groups.members.selectChannel")).tag(0)
                            ForEach(model.channels) { channel in
                                Text(channel.name).tag(channel.id)
                            }
                        }
                    }
                    Picker(localized("groups.sortBy"), selection: $sortMode) {
                        ForEach(MemberSortMode.allCases) { mode in
                            Text(memberSortModeTitle(mode)).tag(mode)
                        }
                    }
                    Toggle(localized("groups.ascending"), isOn: $sortAscending)
                    TextField(localized("groups.members.searchMembers"), text: $searchText)
                        .ts3PlainTextField()
                    Menu {
                        TextField(localized("groups.presetName"), text: $presetName)
                        Button(localized("groups.saveCurrentFilters")) {
                            model.saveGroupClientFilterPreset(
                                name: presetName,
                                memberFilter: memberFilter.rawValue,
                                channelFilter: channelContextFilter.rawValue,
                                channelId: selectedFilterChannelId,
                                sortMode: sortMode.rawValue,
                                sortAscending: sortAscending,
                                searchText: searchText
                            )
                            presetName = ""
                        }
                        .disabled(presetName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                        if model.groupClientFilterPresets.isEmpty {
                            Text(localized("groups.members.noSavedFilterPresets"))
                        } else {
                            ForEach(model.groupClientFilterPresets) { preset in
                                Menu {
                                    Button(localized("groups.applyPreset")) {
                                        applyPreset(preset)
                                    }
                                    Button(localized("groups.useName")) {
                                        presetName = preset.name
                                    }
                                    Button(localized("groups.copyPresetSummary")) {
                                        TS3PlatformSupport.copyToPasteboard(preset.clipboardSummary(channelName: channelPresetName(preset)))
                                    }
                                    Button(localized("groups.deletePreset")) {
                                        model.deleteGroupClientFilterPreset(preset)
                                    }
                                } label: {
                                    VStack(alignment: .leading) {
                                        Text(preset.name)
                                        Text(presetSummary(preset))
                                    }
                                }
                                .accessibilityElement(children: .combine)
                                .accessibilityLabel(localized("groups.members.filterPreset"))
                                .accessibilityValue(preset.accessibilityValue(channelName: channelPresetName(preset)))
                                .accessibilityAction(named: localized("groups.copyPresetSummary")) {
                                    TS3PlatformSupport.copyToPasteboard(preset.clipboardSummary(channelName: channelPresetName(preset)))
                                }
                            }
                        }
                        Divider()
                        Button(localized("groups.exportPresets")) {
                            exportPresets()
                        }
                        .disabled(model.groupClientFilterPresets.isEmpty)
                        Button(localized("groups.importPresets")) {
                            isImportingPresets = true
                        }
                        Button(localized("groups.deleteAllPresets")) {
                            isConfirmingDeletePresets = true
                        }
                        .disabled(model.groupClientFilterPresets.isEmpty)
                    } label: {
                        Label(localized("groups.filterPresets"), systemImage: "line.3.horizontal.decrease.circle")
                    }
                    if hasLocalFilters {
                        Button(localized("groups.clearFilters")) {
                            memberFilter = .all
                            channelContextFilter = .allChannels
                            selectedFilterChannelId = nil
                            sortMode = .nickname
                            sortAscending = true
                            searchText = ""
                        }
                    }
                    ServerInfoDetailRow(
                        label: localized("groups.members.visibleSummary"),
                        value: localized(
                            "groups.members.visibleSummaryFormat",
                            visibleMemberSummary.totalCount,
                            targetTitle(visibleMemberSummary.target)
                        )
                    )
                    Text(memberListSummaryText(visibleMemberSummary))
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("groups.members.copyVisibleSummary")) {
                        TS3PlatformSupport.copyToPasteboard(visibleMemberSummary.clipboardSummary)
                    }
                    .disabled(filteredClients.isEmpty)
                    ServerInfoDetailRow(
                        label: localized("groups.officialAudit"),
                        value: localized(
                            "groups.officialAuditFormat",
                            officialManagementAuditSummary.availableOfficialAreaCount,
                            officialManagementAuditSummary.officialAreaTotal,
                            officialManagementAuditSummary.blockedOfficialAreaCount
                        )
                    )
                    Text(officialManagementAuditText(officialManagementAuditSummary))
                        .font(.caption)
                        .foregroundColor(officialManagementAuditSummary.needsAttention ? .orange : .secondary)
                    Button(localized("groups.copyOfficialAudit")) {
                        TS3PlatformSupport.copyToPasteboard(officialManagementAuditSummary.clipboardSummary)
                    }
                    Button(localized("groups.members.copyVisibleMembers")) {
                        TS3PlatformSupport.copyToPasteboard(visibleMembersSnapshot)
                    }
                    .disabled(filteredClients.isEmpty)
                    Button(localized("groups.members.exportVisibleMembers")) {
                        membersExportDocument = TS3TextFileDocument(data: Data(visibleMembersSnapshot.utf8))
                        isExportingMembers = true
                    }
                    .disabled(filteredClients.isEmpty)
                    if target == .server {
                        TextField(localized("groups.members.clientDatabaseId"), text: $newMemberDatabaseId)
                            .ts3NumericKeyboard()
                        memberDraftCoverageView
                        Text(memberDraftSummary)
                            .font(.caption)
                            .foregroundColor(.secondary)
                        Button(localized("groups.members.copyMemberChangeSummary")) {
                            TS3PlatformSupport.copyToPasteboard(memberDraftSummary)
                        }
                        ForEach(memberDraftValidationMessages, id: \.self) { message in
                            Text(message)
                                .font(.caption)
                                .foregroundColor(.red)
                        }
                        Button(localized("groups.members.addByDatabaseId")) {
                            addMemberByDatabaseId()
                        }
                        .disabled(model.state != .connected || !memberDraftValidationMessages.isEmpty)
                        Button(localized("groups.members.removeVisibleMembers")) {
                            isConfirmingRemoveVisible = true
                        }
                        .disabled(model.state != .connected || filteredClients.isEmpty)
                        .foregroundColor(.red)
                    } else {
                        Picker(localized("groups.members.channel"), selection: newMemberChannelBinding) {
                            Text(localized("groups.members.selectChannel")).tag(0)
                            ForEach(model.channels) { channel in
                                Text(channel.name).tag(channel.id)
                            }
                        }
                        TextField(localized("groups.members.clientDatabaseId"), text: $newMemberDatabaseId)
                            .ts3NumericKeyboard()
                        memberDraftCoverageView
                        Text(memberDraftSummary)
                            .font(.caption)
                            .foregroundColor(.secondary)
                        Button(localized("groups.members.copyMemberChangeSummary")) {
                            TS3PlatformSupport.copyToPasteboard(memberDraftSummary)
                        }
                        ForEach(memberDraftValidationMessages, id: \.self) { message in
                            Text(message)
                                .font(.caption)
                                .foregroundColor(.red)
                        }
                        Button(localized("groups.members.setChannelGroupByDatabaseId")) {
                            setChannelGroupByDatabaseId()
                        }
                        .disabled(model.state != .connected || !memberDraftValidationMessages.isEmpty)
                    }
                }

                if model.groupClients.isEmpty {
                    Text(localized("groups.members.noMembers"))
                        .foregroundColor(.secondary)
                } else if filteredClients.isEmpty {
                    Text(localized("groups.members.noMatchingMembers"))
                        .foregroundColor(.secondary)
                } else {
                    ForEach(filteredClients) { client in
                        GroupClientRow(group: group, target: target, client: client)
                            .environmentObject(model)
                    }
                }
            }
            .navigationTitle(model.groupClientListTitle)
            .ts3InlineNavigationTitle()
            .fileExporter(
                isPresented: $isExportingMembers,
                document: membersExportDocument,
                contentType: .plainText,
                defaultFilename: "ts3-group-members"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPresets,
                document: presetsDocument,
                contentType: .json,
                defaultFilename: "ts3-group-client-filter-presets"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPresets,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    importPresets(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.done")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .alert(isPresented: $isConfirmingRemoveVisible) {
                Alert(
                    title: Text(localized("groups.members.removeVisibleAlert.title")),
                    message: Text(localized("groups.members.removeVisibleAlert.messageFormat", filteredClients.count, group.name)),
                    primaryButton: .destructive(Text(localized("groups.members.remove"))) {
                        model.removeServerGroup(group, from: filteredClients)
                    },
                    secondaryButton: .cancel()
                )
            }
            .alert(isPresented: $isConfirmingDeletePresets) {
                Alert(
                    title: Text(localized("groups.members.deleteAllPresetsAlert.title")),
                    message: Text(localized("groups.deleteAllPresetsAlert.messageFormat", model.groupClientFilterPresets.count)),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deleteAllGroupClientFilterPresets()
                    },
                    secondaryButton: .cancel()
                )
            }
        }
    }

    private var normalizedSearchText: String {
        searchText.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    private var isSearching: Bool {
        !normalizedSearchText.isEmpty
    }

    private var hasLocalFilters: Bool {
        isSearching
            || memberFilter != .all
            || channelContextFilter != .allChannels
            || sortMode != .nickname
            || !sortAscending
    }

    private var parsedNewMemberDatabaseId: Int? {
        let trimmed = newMemberDatabaseId.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let databaseId = Int(trimmed), databaseId > 0 else { return nil }
        return databaseId
    }

    private var selectedNewMemberChannelId: Int? {
        if let channelId = newMemberChannelId, model.channels.contains(where: { $0.id == channelId }) {
            return channelId
        }
        return nil
    }

    private var newMemberChannelBinding: Binding<Int> {
        Binding(
            get: { selectedNewMemberChannelId ?? 0 },
            set: { newMemberChannelId = $0 == 0 ? nil : $0 }
        )
    }

    private var selectedFilterChannelBinding: Binding<Int> {
        Binding(
            get: { selectedFilterChannelId ?? 0 },
            set: { selectedFilterChannelId = $0 == 0 ? nil : $0 }
        )
    }

    private func containsSearch(_ value: String?) -> Bool {
        guard let value, !normalizedSearchText.isEmpty else { return false }
        return value.lowercased().contains(normalizedSearchText)
    }

    private func addMemberByDatabaseId() {
        guard let databaseId = parsedNewMemberDatabaseId else { return }
        model.addServerGroup(group, toClientDatabaseId: databaseId)
        newMemberDatabaseId = ""
    }

    private func setChannelGroupByDatabaseId() {
        guard let databaseId = parsedNewMemberDatabaseId,
              let channelId = selectedNewMemberChannelId else { return }
        model.setChannelGroup(group, channelId: channelId, clientDatabaseId: databaseId)
        newMemberDatabaseId = ""
    }

    private func sortedClients(_ clients: [TS3GroupClientSummary]) -> [TS3GroupClientSummary] {
        clients.sorted { lhs, rhs in
            if lhs.id == rhs.id {
                return false
            }

            let comparison: ComparisonResult
            switch sortMode {
            case .nickname:
                comparison = lhs.displayName.localizedCaseInsensitiveCompare(rhs.displayName)
            case .databaseId:
                comparison = compareInts(lhs.clientDatabaseId, rhs.clientDatabaseId)
            case .channel:
                comparison = channelDisplayName(lhs).localizedCaseInsensitiveCompare(channelDisplayName(rhs))
            case .uniqueId:
                comparison = (lhs.uniqueIdentifier ?? "").localizedCaseInsensitiveCompare(rhs.uniqueIdentifier ?? "")
            }

            if comparison == .orderedSame {
                return lhs.clientDatabaseId < rhs.clientDatabaseId
            }
            return sortAscending ? comparison == .orderedAscending : comparison == .orderedDescending
        }
    }

    private func compareInts(_ lhs: Int, _ rhs: Int) -> ComparisonResult {
        if lhs == rhs {
            return .orderedSame
        }
        return lhs < rhs ? .orderedAscending : .orderedDescending
    }

    private func channelDisplayName(_ client: TS3GroupClientSummary) -> String {
        guard let channelId = client.channelId else { return "" }
        return model.channelName(for: channelId) ?? localized("groups.members.channelFallbackFormat", channelId)
    }

    private var channelContextFilterTitle: String {
        switch channelContextFilter {
        case .allChannels, .withoutChannel:
            return channelContextFilterTitle(channelContextFilter)
        case .currentChannel:
            return model.currentChannel.map { "\($0.name) (\($0.id))" } ?? localized("groups.members.currentChannelUnavailable")
        case .selectedChannel:
            guard let channelId = selectedFilterChannelId else { return localized("groups.members.selectedChannelUnset") }
            return "\(model.channelName(for: channelId) ?? localized("groups.members.channelFallbackFormat", channelId)) (\(channelId))"
        }
    }

    private func applyPreset(_ preset: TS3GroupClientFilterPreset) {
        memberFilter = MemberFilter(rawValue: preset.memberFilter) ?? .all
        channelContextFilter = ChannelContextFilter(rawValue: preset.channelFilter) ?? .allChannels
        selectedFilterChannelId = preset.channelId
        sortMode = MemberSortMode(rawValue: preset.sortMode) ?? .nickname
        sortAscending = preset.sortAscending
        searchText = preset.searchText
        presetName = preset.name
    }

    private func presetSummary(_ preset: TS3GroupClientFilterPreset) -> String {
        preset.inlineSummary(channelName: channelPresetName(preset))
    }

    private func channelPresetSummary(_ preset: TS3GroupClientFilterPreset) -> String {
        let filter = ChannelContextFilter(rawValue: preset.channelFilter) ?? .allChannels
        switch filter {
        case .allChannels, .currentChannel, .withoutChannel:
            return channelContextFilterTitle(filter)
        case .selectedChannel:
            guard let channelId = preset.channelId else { return localized("groups.members.filter.selectedChannel") }
            return "\(model.channelName(for: channelId) ?? localized("groups.members.channelFallbackFormat", channelId)) (\(channelId))"
        }
    }

    private func channelPresetName(_ preset: TS3GroupClientFilterPreset) -> String? {
        guard let channelId = preset.channelId else { return nil }
        return model.channelName(for: channelId)
    }

    private func exportPresets() {
        do {
            presetsDocument = TS3BookmarkFileDocument(data: try model.groupClientFilterPresetsExportData())
            isExportingPresets = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPresets(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            _ = try model.importGroupClientFilterPresets(from: Data(contentsOf: url))
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func targetTitle(_ target: TS3GroupManagementTarget) -> String {
        switch target {
        case .server:
            return localized("groups.target.server")
        case .channel:
            return localized("groups.target.channel")
        }
    }

    private func memberFilterTitle(_ filter: MemberFilter) -> String {
        switch filter {
        case .all:
            return localized("groups.members.filter.allMembers")
        case .online:
            return localized("groups.members.filter.online")
        case .offline:
            return localized("groups.members.filter.offline")
        case .withUniqueId:
            return localized("groups.members.filter.withUniqueId")
        case .withoutUniqueId:
            return localized("groups.members.filter.withoutUniqueId")
        }
    }

    private func memberSortModeTitle(_ mode: MemberSortMode) -> String {
        switch mode {
        case .nickname:
            return localized("groups.members.sort.nickname")
        case .databaseId:
            return localized("groups.members.sort.databaseId")
        case .channel:
            return localized("groups.members.sort.channel")
        case .uniqueId:
            return localized("groups.members.sort.uniqueId")
        }
    }

    private func channelContextFilterTitle(_ filter: ChannelContextFilter) -> String {
        switch filter {
        case .allChannels:
            return localized("groups.members.filter.allChannels")
        case .currentChannel:
            return localized("groups.members.filter.currentChannel")
        case .selectedChannel:
            return localized("groups.members.filter.selectedChannel")
        case .withoutChannel:
            return localized("groups.members.filter.noChannel")
        }
    }

    private func memberListSummaryText(_ summary: TS3GroupClientListSummary) -> String {
        [
            localized("groups.members.summaryOnlineFormat", summary.onlineCount),
            localized("groups.members.summaryOfflineFormat", summary.offlineCount),
            localized("groups.members.summaryWithUidFormat", summary.withUniqueIdCount),
            localized("groups.members.summaryWithoutUidFormat", summary.withoutUniqueIdCount),
            localized("groups.members.summaryDistinctChannelsFormat", summary.distinctChannelCount),
            localized(
                "groups.members.summaryDatabaseRangeFormat",
                summary.lowestClientDatabaseId.map(String.init) ?? localized("common.none"),
                summary.highestClientDatabaseId.map(String.init) ?? localized("common.none")
            )
        ].joined(separator: " · ")
    }

    @ViewBuilder
    private var memberDraftCoverageView: some View {
        ServerInfoDetailRow(
            label: localized("groups.members.draftCoverage"),
            value: localized(
                "groups.members.draftCoverageFormat",
                memberDraftCoverageSummary.requiredFieldCount,
                memberDraftCoverageSummary.requiredFieldTotal,
                memberDraftCoverageSummary.validationIssueCount
            )
        )
        Text(memberDraftCoverageText(memberDraftCoverageSummary))
            .font(.caption)
            .foregroundColor(memberDraftCoverageSummary.needsAttention ? .orange : .secondary)
        Button(localized("groups.members.copyDraftCoverage")) {
            TS3PlatformSupport.copyToPasteboard(memberDraftCoverageSummary.clipboardSummary)
        }
    }

    private func memberDraftOperationTitle(_ operation: TS3GroupMemberDraftValidator.Operation) -> String {
        switch operation {
        case .addServerMember:
            return localized("groups.members.operation.addServerMember")
        case .setChannelGroup:
            return localized("groups.members.operation.setChannelGroup")
        }
    }

    private func memberDraftCoverageText(_ summary: TS3GroupMemberDraftCoverageSummary) -> String {
        [
            localized("groups.members.draftCoverageOperationFormat", memberDraftOperationTitle(summary.operation)),
            localized("groups.members.draftCoverageTargetFormat", targetTitle(summary.target)),
            localized("groups.members.draftCoverageGroupFormat", summary.hasGroup ? 1 : 0),
            localized("groups.members.draftCoverageClientDatabaseIdFormat", summary.hasClientDatabaseId ? 1 : 0),
            localized("groups.members.draftCoverageChannelFormat", summary.hasChannel ? 1 : 0)
        ].joined(separator: " | ")
    }

    private func officialManagementAuditText(_ summary: TS3GroupOfficialManagementAuditSummary) -> String {
        [
            localized("groups.officialAuditTargetFormat", targetTitle(summary.target)),
            localized("groups.officialAuditActionsFormat", summary.officialActionCount),
            localized("groups.officialAuditVisibleMembersFormat", summary.visibleMemberSummary?.totalCount ?? 0),
            localized("groups.officialAuditAttentionFormat", summary.needsAttention ? 1 : 0)
        ].joined(separator: " | ")
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

struct GroupClientRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let group: TS3GroupSummary
    let target: TS3GroupManagementTarget
    let client: TS3GroupClientSummary
    @State private var isShowingInfo = false
    @State private var isConfirmingRemove = false
    @State private var actionMode: DatabaseClientActionMode?
    @State private var onlineActionMode: UserActionMode?

    var body: some View {
        HStack(alignment: .top) {
            VStack(alignment: .leading, spacing: 4) {
                Text(client.displayName)
                    .font(.subheadline.weight(.semibold))
                HStack(spacing: 8) {
                    Text(localized("groups.members.databaseIdShortFormat", client.clientDatabaseId))
                    if let channelId = client.channelId {
                        Text(model.channelName(for: channelId) ?? localized("groups.members.channelFallbackFormat", channelId))
                    }
                }
                .font(.caption)
                .foregroundColor(.secondary)
                if let uniqueIdentifier = client.uniqueIdentifier, !uniqueIdentifier.isEmpty {
                    Text(uniqueIdentifier)
                        .font(.system(.caption2, design: .monospaced))
                        .foregroundColor(.secondary)
                        .lineLimit(1)
                        .truncationMode(.middle)
                }
            }
            Spacer()
            Menu {
                Button(localized("groups.members.row.info")) {
                    isShowingInfo = true
                }
                Button(localized("contacts.row.copyNickname")) {
                    TS3PlatformSupport.copyToPasteboard(client.displayName)
                }
                Button(localized("groups.row.copySummary")) {
                    TS3PlatformSupport.copyToPasteboard(clipboardSummary)
                }
                Button(localized("groups.members.row.copyDatabaseId")) {
                    TS3PlatformSupport.copyToPasteboard("\(client.clientDatabaseId)")
                }
                if let uniqueIdentifier = client.uniqueIdentifier, !uniqueIdentifier.isEmpty {
                    Button(localized("contacts.row.copyUniqueId")) {
                        TS3PlatformSupport.copyToPasteboard(uniqueIdentifier)
                    }
                    Menu(localized("groups.members.row.contact")) {
                        Button(localized("groups.members.row.markFriend")) {
                            model.setContactStatus(.friend, for: databaseRecord)
                        }
                        .disabled(model.contactStatus(for: databaseRecord) == .friend)
                        Button(localized("groups.members.row.blockContact")) {
                            model.setContactStatus(.blocked, for: databaseRecord)
                        }
                        .disabled(model.contactStatus(for: databaseRecord) == .blocked)
                        Button(localized("groups.members.row.ignoreContact")) {
                            model.setContactStatus(.ignored, for: databaseRecord)
                        }
                        .disabled(model.contactStatus(for: databaseRecord) == .ignored)
                        Button(localized("groups.members.row.setNeutral")) {
                            model.setContactStatus(.neutral, for: databaseRecord)
                        }
                        .disabled(model.contactStatus(for: databaseRecord) == .neutral && model.contactNote(for: databaseRecord) == nil)
                        Button(localized("groups.members.row.editNote")) {
                            actionMode = .contactNote
                        }
                    }
                    Button(localized("groups.members.row.sendOfflineMessage")) {
                        actionMode = .offlineMessage
                    }
                    .disabled(!model.canSendOfflineMessage(to: databaseRecord))
                    Button(localized("groups.members.row.submitComplaint")) {
                        actionMode = .complain
                    }
                    Button(localized("groups.members.row.banUniqueId")) {
                        actionMode = .ban
                    }
                    .disabled(!model.canBanDatabaseClient(databaseRecord))
                    if model.hasOnlineClientActions(for: databaseRecord) {
                        Button(localized("groups.members.row.pokeOnlineClient")) {
                            onlineActionMode = .poke
                        }
                        Button(localized("contacts.row.sendPrivateMessage")) {
                            onlineActionMode = .privateMessage
                        }
                    }
                }
                Button(localized("groups.members.row.loadDatabaseDetails")) {
                    model.loadDatabaseClientDetails(databaseRecord)
                }
                if target == .server {
                    Button(localized("groups.members.row.removeFromGroup")) {
                        isConfirmingRemove = true
                    }
                    .disabled(model.state != .connected)
                } else if memberCanChangeChannelGroup {
                    Menu(localized("groups.members.row.setChannelGroup")) {
                        ForEach(model.channelGroups) { channelGroup in
                            Button(channelGroup.name) {
                                model.setChannelGroup(channelGroup, for: client)
                            }
                            .disabled(channelGroup.id == group.id)
                        }
                    }
                    .disabled(model.state != .connected)
                }
            } label: {
                Image(systemName: "ellipsis.circle")
            }
            .buttonStyle(.borderless)
        }
        .padding(.vertical, 3)
        .sheet(isPresented: $isShowingInfo) {
            GroupClientInfoSheet(group: group, target: target, client: client)
                .environmentObject(model)
        }
        .sheet(item: $actionMode) { mode in
            DatabaseClientActionSheet(mode: mode, record: databaseRecord)
                .environmentObject(model)
        }
        .sheet(item: $onlineActionMode) { mode in
            if let onlineUser {
                UserActionSheet(mode: mode, user: onlineUser)
                    .environmentObject(model)
            }
        }
        .alert(isPresented: $isConfirmingRemove) {
            Alert(
                title: Text(localized("groups.members.row.removeAlert.title")),
                message: Text(localized("groups.members.row.removeAlert.messageFormat", client.displayName, group.name)),
                primaryButton: .destructive(Text(localized("groups.members.remove"))) {
                    model.removeServerGroup(group, from: client)
                },
                secondaryButton: .cancel()
            )
        }
        .contextMenu {
            Button(localized("groups.members.row.info")) {
                isShowingInfo = true
            }
            Button(localized("contacts.row.copyNickname")) {
                TS3PlatformSupport.copyToPasteboard(client.displayName)
            }
            Button(localized("groups.row.copySummary")) {
                TS3PlatformSupport.copyToPasteboard(clipboardSummary)
            }
            Button(localized("groups.members.row.copyDatabaseId")) {
                TS3PlatformSupport.copyToPasteboard("\(client.clientDatabaseId)")
            }
            if let uniqueIdentifier = client.uniqueIdentifier, !uniqueIdentifier.isEmpty {
                Button(localized("contacts.row.copyUniqueId")) {
                    TS3PlatformSupport.copyToPasteboard(uniqueIdentifier)
                }
                Button(localized("groups.members.row.markFriend")) {
                    model.setContactStatus(.friend, for: databaseRecord)
                }
                .disabled(model.contactStatus(for: databaseRecord) == .friend)
                Button(localized("groups.members.row.blockContact")) {
                    model.setContactStatus(.blocked, for: databaseRecord)
                }
                .disabled(model.contactStatus(for: databaseRecord) == .blocked)
                Button(localized("groups.members.row.ignoreContact")) {
                    model.setContactStatus(.ignored, for: databaseRecord)
                }
                .disabled(model.contactStatus(for: databaseRecord) == .ignored)
                Button(localized("groups.members.row.setNeutral")) {
                    model.setContactStatus(.neutral, for: databaseRecord)
                }
                .disabled(model.contactStatus(for: databaseRecord) == .neutral && model.contactNote(for: databaseRecord) == nil)
                Button(localized("groups.members.row.editContactNote")) {
                    actionMode = .contactNote
                }
                Button(localized("groups.members.row.sendOfflineMessage")) {
                    actionMode = .offlineMessage
                }
                .disabled(!model.canSendOfflineMessage(to: databaseRecord))
                Button(localized("groups.members.row.submitComplaint")) {
                    actionMode = .complain
                }
                Button(localized("groups.members.row.banUniqueId")) {
                    actionMode = .ban
                }
                .disabled(!model.canBanDatabaseClient(databaseRecord))
                if model.hasOnlineClientActions(for: databaseRecord) {
                    Button(localized("groups.members.row.pokeOnlineClient")) {
                        onlineActionMode = .poke
                    }
                    Button(localized("contacts.row.sendPrivateMessage")) {
                        onlineActionMode = .privateMessage
                    }
                }
            }
            Button(localized("groups.members.row.loadDatabaseDetails")) {
                model.loadDatabaseClientDetails(databaseRecord)
            }
            if target == .server {
                Button(localized("groups.members.row.removeFromGroup")) {
                    isConfirmingRemove = true
                }
                .foregroundColor(.red)
                .disabled(model.state != .connected)
            } else if memberCanChangeChannelGroup {
                ForEach(model.channelGroups) { channelGroup in
                    Button(localized("groups.members.row.setChannelGroupFormat", channelGroup.name)) {
                        model.setChannelGroup(channelGroup, for: client)
                    }
                    .disabled(model.state != .connected || channelGroup.id == group.id)
                }
            }
        }
        .accessibilityElement(children: .ignore)
        .accessibilityLabel(client.displayName)
        .accessibilityValue(client.accessibilityValue(
            group: group,
            target: target,
            channelName: client.channelId.flatMap { model.channelName(for: $0) }
        ))
        .accessibilityAction(named: localized("groups.row.copySummary")) {
            TS3PlatformSupport.copyToPasteboard(clipboardSummary)
        }
        .accessibilityAction(named: localized("groups.members.row.memberInfo")) {
            isShowingInfo = true
        }
        .accessibilityAction(named: localized("groups.members.row.loadDatabaseDetails")) {
            model.loadDatabaseClientDetails(databaseRecord)
        }
    }

    private var memberCanChangeChannelGroup: Bool {
        target == .channel && client.channelId != nil && !model.channelGroups.isEmpty
    }

    private var databaseRecord: TS3DatabaseClientSummary {
        TS3DatabaseClientSummary(groupClient: client)
    }

    private var onlineUser: TS3UserSummary? {
        model.onlineUser(for: databaseRecord)
    }

    private var clipboardSummary: String {
        client.clipboardSummary(
            group: group,
            target: target,
            channelName: client.channelId.flatMap { model.channelName(for: $0) }
        )
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

