                    }
                    Button(localized("groups.members.row.copyDatabaseId")) {
                        TS3PlatformSupport.copyToPasteboard("\(client.clientDatabaseId)")
                    }
                    if let uniqueIdentifier = client.uniqueIdentifier, !uniqueIdentifier.isEmpty {
                        Button(localized("contacts.row.copyUniqueId")) {
                            TS3PlatformSupport.copyToPasteboard(uniqueIdentifier)
                        }
                    }
                    Button(localized("groups.members.row.loadDatabaseDetails")) {
                        model.loadDatabaseClientDetails(TS3DatabaseClientSummary(groupClient: client))
                    }
                }
            }
            .navigationTitle(localized("groups.members.row.memberInfo"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.done")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }

    private func infoRow(_ title: String, value: String) -> some View {
        HStack(alignment: .top) {
            Text(title)
            Spacer()
            Text(value)
                .foregroundColor(.secondary)
                .multilineTextAlignment(.trailing)
        }
    }

    private var clipboardSummary: String {
        client.clipboardSummary(
            group: group,
            target: target,
            channelName: client.channelId.flatMap { model.channelName(for: $0) }
        )
    }

    private func targetTitle(_ target: TS3GroupManagementTarget) -> String {
        switch target {
        case .server:
            return localized("groups.target.server")
        case .channel:
            return localized("groups.target.channel")
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

struct GroupNameSheet: View {
    @Environment(\.presentationMode) private var presentationMode
    let title: String
    let actionTitle: String
    let allowsTypeSelection: Bool
    let operation: TS3GroupDraftValidator.Operation
    let target: TS3GroupManagementTarget
    let sourceGroup: TS3GroupSummary?
    let existingGroups: [TS3GroupSummary]
    let submit: (String, TS3PermissionGroupDatabaseType) -> Void
    @State private var name: String
    @State private var type: TS3PermissionGroupDatabaseType

    init(
        title: String,
        actionTitle: String,
        initialName: String,
        allowsTypeSelection: Bool,
        initialType: TS3PermissionGroupDatabaseType,
        operation: TS3GroupDraftValidator.Operation,
        target: TS3GroupManagementTarget,
        sourceGroup: TS3GroupSummary?,
        existingGroups: [TS3GroupSummary],
        submit: @escaping (String, TS3PermissionGroupDatabaseType) -> Void
    ) {
        self.title = title
        self.actionTitle = actionTitle
        self.allowsTypeSelection = allowsTypeSelection
        self.operation = operation
        self.target = target
        self.sourceGroup = sourceGroup
        self.existingGroups = existingGroups
        self.submit = submit
        _name = State(initialValue: initialName)
        _type = State(initialValue: initialType)
    }

    var body: some View {
        NavigationView {
            Form {
                Section {
                    TextField(localized("groups.groupName"), text: $name)
                        .ts3PlainTextField()
                    if allowsTypeSelection {
                        Picker(localized("groups.databaseType"), selection: $type) {
                            ForEach(TS3PermissionGroupDatabaseType.allCases) { type in
                                Text(databaseTypeTitle(type)).tag(type)
                            }
                        }
                    }
                    ServerInfoDetailRow(
                        label: localized("groups.draftCoverage"),
                        value: localized(
                            "groups.draftCoverageFormat",
                            groupDraftCoverageSummary.requiredFieldCount,
                            groupDraftCoverageSummary.requiredFieldTotal,
                            groupDraftCoverageSummary.validationIssueCount
                        )
                    )
                    Text(groupDraftCoverageText(groupDraftCoverageSummary))
                        .font(.caption)
                        .foregroundColor(groupDraftCoverageSummary.needsAttention ? .orange : .secondary)
                    Button(localized("groups.copyDraftCoverage")) {
                        TS3PlatformSupport.copyToPasteboard(groupDraftCoverageSummary.clipboardSummary)
                    }
                    Text(groupDraftSummary)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("groups.copyGroupSummary")) {
                        TS3PlatformSupport.copyToPasteboard(groupDraftSummary)
                    }
                    ForEach(groupDraftValidationMessages, id: \.self) { message in
                        Text(message)
                            .font(.caption)
                            .foregroundColor(.red)
                    }
                }
            }
            .navigationTitle(title)
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(actionTitle) {
                        submit(name, type)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!groupDraftValidationMessages.isEmpty)
                }
            }
        }
    }

    private var groupDraftValidationMessages: [String] {
        TS3GroupDraftValidator.validationMessages(
            operation: operation,
            name: name,
            target: target,
            type: type,
            sourceGroup: sourceGroup,
            existingGroups: existingGroups
        )
    }

    private var groupDraftSummary: String {
        TS3GroupDraftValidator.creationSummary(
            operation: operation,
            name: name,
            target: target,
            type: type,
            sourceGroup: sourceGroup
        )
    }

    private var groupDraftCoverageSummary: TS3GroupDraftCoverageSummary {
        TS3GroupDraftCoverageSummary(
            operation: operation,
            name: name,
            target: target,
            type: type,
            sourceGroup: sourceGroup,
            validationMessages: groupDraftValidationMessages
        )
    }

    private func databaseTypeTitle(_ type: TS3PermissionGroupDatabaseType) -> String {
        switch type {
        case .template:
            return localized("groups.filter.template")
        case .regular:
            return localized("groups.filter.regular")
        case .query:
            return localized("groups.filter.query")
        }
    }

    private func targetTitle(_ target: TS3GroupManagementTarget) -> String {
        switch target {
        case .server:
            return localized("groups.target.server")
        case .channel:
            return localized("groups.target.channel")
        }
    }

    private func operationTitle(_ operation: TS3GroupDraftValidator.Operation) -> String {
        switch operation {
        case .create:
            return localized("groups.operation.create")
        case .copy:
            return localized("groups.operation.copy")
        case .rename:
            return localized("groups.operation.rename")
        }
    }

    private func groupDraftCoverageText(_ summary: TS3GroupDraftCoverageSummary) -> String {
        [
            localized("groups.draftCoverageOperationFormat", operationTitle(summary.operation)),
            localized("groups.draftCoverageTargetFormat", targetTitle(summary.target)),
            localized("groups.draftCoverageNameFormat", summary.hasName ? 1 : 0),
            localized("groups.draftCoverageSourceFormat", summary.hasSourceGroup ? 1 : 0),
            localized("groups.draftCoverageDatabaseTypeFormat", summary.hasDatabaseType ? 1 : 0)
        ].joined(separator: " | ")
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

struct ClientDatabaseSheet: View {
    private struct DatabaseBackupImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3DatabaseClientBackupPreview
        let id = UUID()
    }

    private struct DatabaseClientFilterPresetImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3DatabaseClientFilterPresetImportPreview
        let id = UUID()
    }

    private enum DatabaseRecordFilter: String, CaseIterable, Identifiable {
        case all
        case withUniqueId
        case withoutUniqueId
        case withDescription
        case withLastIP
        case withConnections

        var id: String { rawValue }

        var title: String {
            switch self {
            case .all: return NSLocalizedString("database.filter.allRecords", comment: "")
            case .withUniqueId: return NSLocalizedString("database.filter.withUniqueId", comment: "")
            case .withoutUniqueId: return NSLocalizedString("database.filter.withoutUniqueId", comment: "")
            case .withDescription: return NSLocalizedString("database.filter.withDescription", comment: "")
            case .withLastIP: return NSLocalizedString("database.filter.withLastIP", comment: "")
            case .withConnections: return NSLocalizedString("database.filter.withConnections", comment: "")
            }
        }

        func matches(_ record: TS3DatabaseClientSummary) -> Bool {
            switch self {
            case .all:
                return true
            case .withUniqueId:
                return record.uniqueIdentifier?.isEmpty == false
            case .withoutUniqueId:
                return record.uniqueIdentifier?.isEmpty != false
            case .withDescription:
                return record.description?.isEmpty == false
            case .withLastIP:
                return record.lastIP?.isEmpty == false
            case .withConnections:
                return record.totalConnections != nil
            }
        }
    }

    private enum DatabaseRecordSortMode: String, CaseIterable, Identifiable {
        case nickname
        case databaseId
        case created
        case lastConnected
        case connections
        case lastIP

        var id: String { rawValue }

        var title: String {
            switch self {
            case .nickname: return NSLocalizedString("contacts.sort.nickname", comment: "")
            case .databaseId: return NSLocalizedString("database.databaseId", comment: "")
            case .created: return NSLocalizedString("database.sort.created", comment: "")
            case .lastConnected: return NSLocalizedString("database.sort.lastConnected", comment: "")
            case .connections: return NSLocalizedString("database.sort.connections", comment: "")
            case .lastIP: return NSLocalizedString("database.sort.lastIP", comment: "")
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var searchText = ""
    @State private var uniqueIdSearchText = ""
    @State private var localFilterText = ""
    @State private var recordFilter: DatabaseRecordFilter = .all
    @State private var sortMode: DatabaseRecordSortMode = .nickname
    @State private var sortAscending = true
    @State private var databaseBatchSize = "100"
    @State private var presetName = ""
    @State private var isShowingDescriptionEditor = false
    @State private var actionMode: DatabaseClientActionMode?
    @State private var onlineActionMode: UserActionMode?
    @State private var isShowingPermissions = false
    @State private var isShowingComplaints = false
    @State private var isConfirmingDelete = false
    @State private var isExportingDatabase = false
    @State private var isExportingDatabaseBackup = false
    @State private var isExportingPresets = false
    @State private var isImportingDatabase = false
    @State private var isImportingPresets = false
    @State private var isConfirmingDeletePresets = false
    @State private var databaseExportDocument = TS3TextFileDocument()
    @State private var databaseBackupDocument = TS3TextFileDocument()
    @State private var presetsDocument = TS3BookmarkFileDocument()
    @State private var pendingDatabaseBackupImport: DatabaseBackupImportConfirmation?
    @State private var pendingPresetImport: DatabaseClientFilterPresetImportConfirmation?

    var displayedRecords: [TS3DatabaseClientSummary] {
        let source = model.databaseSearchResults.isEmpty ? model.databaseClients : model.databaseSearchResults
        let filtered = source.filter { record in
            recordFilter.matches(record) && (
                !isLocalFiltering
                    || containsLocalFilter(record.nickname)
                    || containsLocalFilter(record.uniqueIdentifier)
                    || containsLocalFilter(record.description)
                    || containsLocalFilter(record.lastIP)
                    || String(record.id).contains(normalizedLocalFilterText)
                    || record.totalConnections.map { String($0).contains(normalizedLocalFilterText) } == true
            )
        }
        return sortedRecords(filtered)
    }

    private var visibleContactEntries: [TS3ContactEntry] {
        displayedRecords.compactMap { record in
            guard let uniqueIdentifier = record.uniqueIdentifier, !uniqueIdentifier.isEmpty else { return nil }
            if var existing = model.contact(for: record) {
                existing.nickname = record.nickname
                return existing
            }
            return TS3ContactEntry(
                uniqueIdentifier: uniqueIdentifier,
                nickname: record.nickname,
                status: .neutral,
                note: "",
                updatedAt: Date()
            )
        }
    }

    private var canMarkVisibleFriends: Bool {
        visibleContactEntries.contains { $0.status != .friend }
    }

    private var canBlockVisibleContacts: Bool {
        visibleContactEntries.contains { $0.status != .blocked }
    }

    private var canIgnoreVisibleContacts: Bool {
        visibleContactEntries.contains { $0.status != .ignored }
    }

    private var canSetVisibleNeutral: Bool {
        visibleContactEntries.contains { $0.status != .neutral }
    }

    private func visibleContactStatusDraft(_ status: TS3ContactStatus) -> TS3ContactStatusDraft {
        TS3ContactStatusDraft(contacts: visibleContactEntries, status: status)
    }

    private func applyVisibleContactStatus(_ status: TS3ContactStatus) {
        let draft = visibleContactStatusDraft(status)
        guard draft.validationMessages.isEmpty else {
            model.lastError = draft.validationMessages.joined(separator: "\n")
            return
        }
        model.updateContacts(draft.uniqueContacts, status: status)
    }

    private func copyVisibleContactStatusDraft(_ status: TS3ContactStatus) {
        TS3PlatformSupport.copyToPasteboard(visibleContactStatusDraft(status).clipboardSummary)
    }

    var body: some View {
        NavigationView {
            List {
                Section(header: Text(localized("database.search"))) {
                    TextField(localized("contacts.editor.nickname"), text: $searchText)
                        .ts3PlainTextField()
                    HStack {
                        Button(localized("database.search")) {
                            model.searchClientDatabase(pattern: searchText)
                        }
                        .disabled(searchText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                        Spacer()
                        Button(localized("events.clear")) {
                            searchText = ""
                            uniqueIdSearchText = ""
                            model.databaseSearchResults = []
                            model.clientLocations = []
                        }
                    }
                    TextField(localized("contacts.editor.uniqueId"), text: $uniqueIdSearchText)
                        .ts3PlainTextField()
                    Button(localized("database.findByUniqueId")) {
                        model.findDatabaseClient(uniqueIdentifier: uniqueIdSearchText)
                    }
                    .disabled(uniqueIdSearchText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                }

                Section(header: Text(localized("database.listView"))) {
                    Picker(localized("channels.filter"), selection: $recordFilter) {
                        ForEach(DatabaseRecordFilter.allCases) { filter in
                            Text(filter.title).tag(filter)
                        }
                    }
                    Picker(localized("groups.sortBy"), selection: $sortMode) {
                        ForEach(DatabaseRecordSortMode.allCases) { mode in
                            Text(mode.title).tag(mode)
                        }
                    }
                    Toggle(localized("groups.ascending"), isOn: $sortAscending)
                    TextField(localized("database.filterLoadedRecords"), text: $localFilterText)
                        .ts3PlainTextField()
                    ServerInfoDetailRow(
                        label: localized("database.visibleSummary"),
                        value: localized(
                            "database.visibleSummaryFormat",
                            visibleDatabaseClientSummary.totalCount,
                            visibleDatabaseClientSummary.uniqueIdentifierCount
                        )
                    )
                    Text(databaseClientListSummaryText(visibleDatabaseClientSummary))
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("database.copyVisibleSummary")) {
                        TS3PlatformSupport.copyToPasteboard(visibleDatabaseClientSummary.clipboardSummary)
                    }
                    .disabled(displayedRecords.isEmpty)
                    Menu {
                        TextField(localized("groups.presetName"), text: $presetName)
                        Button(localized("database.saveCurrentView")) {
                            model.saveDatabaseClientFilterPreset(
                                name: presetName,
                                recordFilter: recordFilter.rawValue,
                                sortMode: sortMode.rawValue,
                                sortAscending: sortAscending,
                                localFilterText: localFilterText,
                                batchSize: parsedDatabaseBatchSize
                            )
                            presetName = ""
                        }
                        .disabled(presetName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                        if model.databaseClientFilterPresets.isEmpty {
                            Text(localized("database.noSavedFilterPresets"))
                        } else {
                            ForEach(model.databaseClientFilterPresets) { preset in
                                Menu {
                                    Button(localized("groups.applyPreset")) {
                                        applyPreset(preset)
                                    }
                                    Button(localized("groups.useName")) {
                                        presetName = preset.name
                                    }
                                    Button(localized("groups.deletePreset")) {
                                        model.deleteDatabaseClientFilterPreset(preset)
                                    }
                                } label: {
                                    VStack(alignment: .leading) {
                                        Text(preset.name)
                                        Text(presetSummary(preset))
                                    }
                                }
                            }
                        }
                        Divider()
                        Button(localized("groups.exportPresets")) {
                            exportPresets()
                        }
                        .disabled(model.databaseClientFilterPresets.isEmpty)
                        Button(localized("groups.importPresets")) {
                            isImportingPresets = true
                        }
                        Button(localized("groups.deleteAllPresets")) {
                            isConfirmingDeletePresets = true
                        }
                        .disabled(model.databaseClientFilterPresets.isEmpty)
                    } label: {
                        Label(localized("groups.filterPresets"), systemImage: "line.3.horizontal.decrease.circle")
                    }
                    if hasLocalViewOptions {
                        Button(localized("database.clearListView")) {
                            recordFilter = .all
                            sortMode = .nickname
                            sortAscending = true
                            localFilterText = ""
                        }
                    }
                }

                Section(header: Text(localized("database.range"))) {
                    TextField(localized("database.batchSize"), text: $databaseBatchSize)
                        .ts3NumericKeyboard()
                    HStack {
                        Text(localized("database.loadedFormat", model.databaseClients.count))
                            .foregroundColor(.secondary)
                        Spacer()
                        Button(localized("database.loadMore")) {
                            model.loadMoreClientDatabaseRecords(limit: parsedDatabaseBatchSize)
                        }
                        .disabled(!model.databaseSearchResults.isEmpty || !model.canLoadMoreDatabaseClients)
                    }
                }

                if !model.clientLocations.isEmpty {
                    Section(header: Text(localized("database.onlineLocations"))) {
                        ForEach(model.clientLocations) { location in
                            DatabaseClientLocationRow(location: location)
                                .environmentObject(model)
                        }
                    }
                }

                if let selected = model.selectedDatabaseClient {
                    Section(header: Text(localized("database.selectedClient"))) {
                        DatabaseClientDetailRows(record: selected)
                        let actionSummary = databaseClientActionSummary(for: selected)
                        ServerInfoDetailRow(
                            label: localized("database.actionSummary"),
                            value: localized(
                                "database.actionSummaryFormat",
                                actionSummary.availableActionCount,
                                actionSummary.onlineActionCount
                            )
                        )
                        Text(databaseClientActionSummaryText(actionSummary))
                            .font(.caption)
                            .foregroundColor(.secondary)
                        Button(localized("database.copyActionSummary")) {
                            TS3PlatformSupport.copyToPasteboard(actionSummary.clipboardSummary)
                        }
                        let officialActionAudit = databaseClientOfficialActionAuditSummary(for: selected)
                        ServerInfoDetailRow(
                            label: localized("database.officialActionAudit"),
                            value: localized(
                                "database.officialActionAuditFormat",
                                officialActionAudit.totalActionCount,
                                officialActionAudit.availableAreaCount,
                                officialActionAudit.blockedAreaCount
                            )
                        )
                        Text(databaseClientOfficialActionAuditText(officialActionAudit))
                            .font(.caption)
                            .foregroundColor(officialActionAudit.needsAttention ? .orange : .secondary)
                        Button(localized("database.copyOfficialActionAudit")) {
                            TS3PlatformSupport.copyToPasteboard(officialActionAudit.clipboardSummary)
                        }
                        Button(localized("database.copySelectedSnapshot")) {
                            TS3PlatformSupport.copyToPasteboard(databaseClientSnapshot(for: selected))
                        }
                        Button(localized("database.exportSelectedSnapshot")) {
                            databaseExportDocument = TS3TextFileDocument(data: Data(databaseClientSnapshot(for: selected).utf8))
                            isExportingDatabase = true
                        }
                        Button(localized("database.exportBackup")) {
                            exportDatabaseBackup()
                        }
                        Button(localized("contacts.row.copyNickname")) {
                            TS3PlatformSupport.copyToPasteboard(selected.nickname)
                        }
                        Button(localized("selfStatus.copyDatabaseId")) {
                            TS3PlatformSupport.copyToPasteboard("\(selected.id)")
                        }
                        if let uniqueIdentifier = selected.uniqueIdentifier, !uniqueIdentifier.isEmpty {
                            Button(localized("contacts.row.copyUniqueId")) {
                                TS3PlatformSupport.copyToPasteboard(uniqueIdentifier)
                            }
                            Menu(localized("contacts.editor.contact")) {
                                Button(localized("groups.members.row.markFriend")) {
                                    model.setContactStatus(.friend, for: selected)
                                }
                                .disabled(model.contactStatus(for: selected) == .friend)
                                Button(localized("groups.members.row.blockContact")) {
                                    model.setContactStatus(.blocked, for: selected)
                                }
                                .disabled(model.contactStatus(for: selected) == .blocked)
                                Button(localized("groups.members.row.ignoreContact")) {
                                    model.setContactStatus(.ignored, for: selected)
                                }
                                .disabled(model.contactStatus(for: selected) == .ignored)
                                Button(localized("groups.members.row.setNeutral")) {
                                    model.setContactStatus(.neutral, for: selected)
                                }
                                .disabled(model.contactStatus(for: selected) == .neutral && model.contactNote(for: selected) == nil)
                                Button(localized("groups.members.row.editNote")) {
                                    actionMode = .contactNote
                                }
                            }
                            if !model.serverGroups.isEmpty {
                                Menu(localized("database.addServerGroup")) {
                                    ForEach(model.serverGroups) { group in
                                        Button(group.name) {
                                            model.addServerGroup(group, to: selected)
                                        }
                                    }
                                }
                            }
                        }
                        Button(localized("database.resolveDatabaseIdFromUid")) {
                            model.resolveDatabaseIdForSelectedClient()
                        }
                        .disabled(selected.uniqueIdentifier == nil)
                        Button(localized("database.findOnlineClient")) {
                            model.refreshOnlineLocations(for: selected)
                        }
                        .disabled(selected.uniqueIdentifier == nil)
                        if model.hasOnlineClientActions(for: selected) {
                            Button(localized("groups.members.row.pokeOnlineClient")) {
                                onlineActionMode = .poke
                            }
                            Button(localized("contacts.row.sendPrivateMessage")) {
                                onlineActionMode = .privateMessage
                            }
                        }
                        Button(localized("database.editDescription")) {
                            isShowingDescriptionEditor = true
                        }
                        Button(localized("database.editClientPermissions")) {
                            model.selectDatabaseClientPermissions(selected)
                            isShowingPermissions = true
                        }
                        Button(localized("groups.members.row.sendOfflineMessage")) {
                            actionMode = .offlineMessage
                        }
                        .disabled(!model.canSendOfflineMessage(to: selected))
                        Button(localized("groups.members.row.submitComplaint")) {
                            actionMode = .complain
                        }
                        Button(localized("database.viewComplaints")) {
                            model.refreshComplaints(for: selected)
                            isShowingComplaints = true
                        }
                        Button(localized("groups.members.row.banUniqueId")) {
                            actionMode = .ban
                        }
                        .disabled(!model.canBanDatabaseClient(selected))
                        Button(localized("database.deleteRecord")) {
                            isConfirmingDelete = true
                        }
                    }
                }

                Section(header: Text(model.databaseSearchResults.isEmpty ? localized("database.clients") : localized("database.searchResults"))) {
                    if displayedRecords.isEmpty {
                        Text(localized("database.noClients"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(displayedRecords) { record in
                            DatabaseClientRow(record: record)
                                .environmentObject(model)
                        }
                    }
                }
            }
            .navigationTitle(localized("database.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("groups.refresh")) {
                        model.refreshClientDatabase(limit: parsedDatabaseBatchSize)
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Menu {
                        Button(localized("database.copyVisibleSnapshot")) {
                            TS3PlatformSupport.copyToPasteboard(databaseSnapshot)
                        }
                        .disabled(displayedRecords.isEmpty)
                        Button(localized("database.exportVisibleSnapshot")) {
                            databaseExportDocument = TS3TextFileDocument(data: Data(databaseSnapshot.utf8))
                            isExportingDatabase = true
                        }
                        .disabled(displayedRecords.isEmpty)
                        Button(localized("database.importBackup")) {
                            isImportingDatabase = true
                        }
                        Divider()
                        Button(localized("contacts.markVisibleFriends")) {
                            applyVisibleContactStatus(.friend)
                        }
                        .disabled(!canMarkVisibleFriends)
                        Button(localized("contacts.copyMarkFriendsDraft")) {
                            copyVisibleContactStatusDraft(.friend)
                        }
                        .disabled(visibleContactEntries.isEmpty)
                        Button(localized("contacts.blockVisibleContacts")) {
                            applyVisibleContactStatus(.blocked)
                        }
                        .disabled(!canBlockVisibleContacts)
                        Button(localized("contacts.copyBlockDraft")) {
                            copyVisibleContactStatusDraft(.blocked)
                        }
                        .disabled(visibleContactEntries.isEmpty)
                        Button(localized("contacts.ignoreVisibleContacts")) {
                            applyVisibleContactStatus(.ignored)
                        }
                        .disabled(!canIgnoreVisibleContacts)
                        Button(localized("contacts.copyIgnoreDraft")) {
                            copyVisibleContactStatusDraft(.ignored)
                        }
                        .disabled(visibleContactEntries.isEmpty)
                        Button(localized("contacts.setVisibleNeutral")) {
                            applyVisibleContactStatus(.neutral)
                        }
                        .disabled(!canSetVisibleNeutral)
                        Button(localized("contacts.copyNeutralDraft")) {
                            copyVisibleContactStatusDraft(.neutral)
                        }
                        .disabled(visibleContactEntries.isEmpty)
                    } label: {
                        Image(systemName: "ellipsis.circle")
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.done")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .sheet(item: $actionMode) { mode in
                if let selected = model.selectedDatabaseClient {
                    DatabaseClientActionSheet(mode: mode, record: selected)
                        .environmentObject(model)
                }
            }
            .sheet(item: $onlineActionMode) { mode in
                if let selected = model.selectedDatabaseClient,
                   let onlineUser = model.onlineUser(for: selected) {
                    UserActionSheet(mode: mode, user: onlineUser)
                        .environmentObject(model)
                }
            }
            .sheet(isPresented: $isShowingDescriptionEditor) {
                if let selected = model.selectedDatabaseClient {
                    DatabaseClientDescriptionSheet(record: selected) { description in
                        model.editDatabaseClientDescription(selected, description: description)
                    }
                }
            }
            .sheet(isPresented: $isShowingPermissions) {
                PermissionsSheet()
                    .environmentObject(model)
            }
            .sheet(isPresented: $isShowingComplaints) {
                ComplaintListSheet()
                    .environmentObject(model)
            }
            .alert(isPresented: $isConfirmingDelete) {
                Alert(
                    title: Text(localized("database.deleteRecordAlert.title")),
                    message: Text(model.selectedDatabaseClient?.nickname ?? localized("database.selectedClient")),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        if let selected = model.selectedDatabaseClient {
                            model.deleteDatabaseClient(selected)
                        }
                    },
                    secondaryButton: .cancel()
                )
            }
            .alert(isPresented: $isConfirmingDeletePresets) {
                Alert(
                    title: Text(localized("database.deleteAllPresetsAlert.title")),
                    message: Text(localized("groups.deleteAllPresetsAlert.messageFormat", model.databaseClientFilterPresets.count)),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deleteAllDatabaseClientFilterPresets()
                    },
                    secondaryButton: .cancel()
                )
            }
            .fileExporter(
                isPresented: $isExportingDatabase,
                document: databaseExportDocument,
                contentType: .plainText,
                defaultFilename: "ts3-client-database"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingDatabaseBackup,
                document: databaseBackupDocument,
                contentType: .json,
                defaultFilename: "ts3-client-database-backup"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPresets,
                document: presetsDocument,
                contentType: .json,
                defaultFilename: "ts3-database-client-filter-presets"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingDatabase,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareDatabaseBackupImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPresets,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    preparePresetImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .sheet(item: $pendingDatabaseBackupImport) { confirmation in
                DatabaseBackupImportSheet(
                    preview: confirmation.preview,
                    previewMessage: databaseBackupPreviewMessage(confirmation.preview),
                    importBackup: { selectedClientIds in
                        importDatabaseBackup(data: confirmation.data, selectedClientIds: selectedClientIds)
                        pendingDatabaseBackupImport = nil
                    },
                    cancel: {
                        pendingDatabaseBackupImport = nil
                    }
                )
            }
            .sheet(item: $pendingPresetImport) { confirmation in
                DatabaseClientFilterPresetImportSheet(
                    preview: confirmation.preview,
                    importPresets: { selectedPresetIds in
                        importPresets(data: confirmation.data, selectedPresetIds: selectedPresetIds)
                        pendingPresetImport = nil
                    },
                    cancel: {
                        pendingPresetImport = nil
                    }
                )
            }
            .onAppear {
                databaseBatchSize = String(model.databaseClientBatchSize)
            }
        }
    }

    private var parsedDatabaseBatchSize: Int {
        max(1, Int(databaseBatchSize.trimmingCharacters(in: .whitespacesAndNewlines)) ?? model.databaseClientBatchSize)
    }

    private var normalizedLocalFilterText: String {
        localFilterText.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    private var isLocalFiltering: Bool {
        !normalizedLocalFilterText.isEmpty
    }

    private var hasLocalViewOptions: Bool {
        isLocalFiltering || recordFilter != .all || sortMode != .nickname || !sortAscending
    }

    private func containsLocalFilter(_ value: String?) -> Bool {
        guard let value, isLocalFiltering else { return false }
        return value.lowercased().contains(normalizedLocalFilterText)
    }

    private func sortedRecords(_ records: [TS3DatabaseClientSummary]) -> [TS3DatabaseClientSummary] {
        records.sorted { lhs, rhs in
            if lhs.id == rhs.id {
                return false
            }

            let comparison: ComparisonResult
            switch sortMode {
            case .nickname:
                comparison = lhs.nickname.localizedCaseInsensitiveCompare(rhs.nickname)
            case .databaseId:
                comparison = compareInts(lhs.id, rhs.id)
            case .created:
                comparison = compareDates(lhs.createdAt, rhs.createdAt)
            case .lastConnected:
                comparison = compareDates(lhs.lastConnectedAt, rhs.lastConnectedAt)
            case .connections:
                comparison = compareOptionalInts(lhs.totalConnections, rhs.totalConnections)
            case .lastIP:
                comparison = (lhs.lastIP ?? "").localizedCaseInsensitiveCompare(rhs.lastIP ?? "")
            }

            if comparison == .orderedSame {
                return lhs.id < rhs.id
            }
            return sortAscending ? comparison == .orderedAscending : comparison == .orderedDescending
        }
    }

    private func compareDates(_ lhs: Date?, _ rhs: Date?) -> ComparisonResult {
        switch (lhs, rhs) {
        case let (lhs?, rhs?):
            return lhs.compare(rhs)
        case (nil, nil):
            return .orderedSame
        case (nil, _):
            return .orderedAscending
        case (_, nil):
            return .orderedDescending
        }
    }

    private func compareInts(_ lhs: Int, _ rhs: Int) -> ComparisonResult {
        if lhs == rhs {
            return .orderedSame
        }
        return lhs < rhs ? .orderedAscending : .orderedDescending
    }

    private func compareOptionalInts(_ lhs: Int?, _ rhs: Int?) -> ComparisonResult {
        switch (lhs, rhs) {
        case let (lhs?, rhs?):
            return compareInts(lhs, rhs)
        case (nil, nil):
            return .orderedSame
        case (nil, _):
            return .orderedAscending
        case (_, nil):
            return .orderedDescending
        }
    }

    private var databaseSnapshot: String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short

        func dateText(_ date: Date?) -> String? {
            guard let date else { return nil }
            return formatter.string(from: date)
        }

        return displayedRecords.map { record in
            var rows = [
                "Database ID: \(record.id)",
                "Nickname: \(record.nickname)"
            ]
            if let uniqueIdentifier = record.uniqueIdentifier, !uniqueIdentifier.isEmpty {
                rows.append("Unique ID: \(uniqueIdentifier)")
            }
            if let createdAt = dateText(record.createdAt) {
                rows.append("Created: \(createdAt)")
            }
            if let lastConnectedAt = dateText(record.lastConnectedAt) {
                rows.append("Last Connected: \(lastConnectedAt)")
            }
            if let totalConnections = record.totalConnections {
                rows.append("Connections: \(totalConnections)")
            }
            if let lastIP = record.lastIP, !lastIP.isEmpty {
                rows.append("Last IP: \(lastIP)")
            }
            if let description = record.description, !description.isEmpty {
                rows.append("Description: \(description)")
            }
            return rows.joined(separator: "\n")
        }
        .joined(separator: "\n\n")
    }

    private var visibleDatabaseClientSummary: TS3DatabaseClientListSummary {
        TS3DatabaseClientListSummary(clients: displayedRecords)
    }

    private func databaseClientListSummaryText(_ summary: TS3DatabaseClientListSummary) -> String {
        var parts = [
            localized("database.summary.descriptionsFormat", summary.descriptionCount),
            localized("database.summary.lastIPsFormat", summary.lastIPCount),
            localized("database.summary.connectionsFormat", summary.connectionCount),
            localized("database.summary.createdDatesFormat", summary.createdCount),
            localized("database.summary.lastConnectedDatesFormat", summary.lastConnectedCount)
        ]
        if let latestConnection = summary.latestConnection {
            let formatter = DateFormatter()
            formatter.dateStyle = .medium
            formatter.timeStyle = .short
            parts.append(localized("database.summary.latestConnectionFormat", formatter.string(from: latestConnection)))
        }
        return parts.joined(separator: " · ")
    }

    private func databaseClientActionSummary(for record: TS3DatabaseClientSummary) -> TS3DatabaseClientActionSummary {
        TS3DatabaseClientActionSummary(
            record: record,
            isOnline: model.hasOnlineClientActions(for: record),
            canSendOfflineMessage: model.canSendOfflineMessage(to: record),
            canBan: model.canBanDatabaseClient(record),
            contactStatus: model.contactStatus(for: record),
            hasContactNote: model.contactNote(for: record) != nil,
            serverGroupCount: model.serverGroups.count
        )
    }

    private func databaseClientOfficialActionAuditSummary(for record: TS3DatabaseClientSummary) -> TS3DatabaseClientOfficialActionAuditSummary {
        TS3DatabaseClientOfficialActionAuditSummary(actionSummary: databaseClientActionSummary(for: record))
    }

    private func databaseClientActionSummaryText(_ summary: TS3DatabaseClientActionSummary) -> String {
        var parts = [
            localized("database.actionSummaryIdentityFormat", summary.identityActionCount),
            localized("database.actionSummaryContactFormat", localizedContactStatusTitle(summary.contactStatus)),
            localized("database.actionSummaryMessagingFormat", summary.messagingActionCount),
            localized("database.actionSummaryAdminFormat", summary.adminActionCount)
        ]
        if summary.hasContactNote {
            parts.append(localized("database.actionSummaryHasNote"))
        }
        if !summary.hasUniqueIdentifier {
            parts.append(localized("database.actionSummaryNeedsUid"))
        }
        return parts.joined(separator: " · ")
    }

    private func databaseClientOfficialActionAuditText(_ summary: TS3DatabaseClientOfficialActionAuditSummary) -> String {
        var parts = TS3DatabaseClientOfficialActionArea.allCases.compactMap { area -> String? in
            guard let count = summary.areaActionCounts[area], count > 0 else { return nil }
            return localized("database.officialActionAuditAreaFormat", title(for: area), count)
        }
        if summary.blockedAreaCount > 0 {
            parts.append(localized("database.officialActionAuditBlockedFormat", summary.blockedAreaCount))
        }
        if !summary.actionSummary.hasUniqueIdentifier {
            parts.append(localized("database.actionSummaryNeedsUid"))
        }
        if !summary.actionSummary.isOnline {
            parts.append(localized("database.officialActionAuditOffline"))
        }
        return parts.joined(separator: " · ")
    }

    private func title(for area: TS3DatabaseClientOfficialActionArea) -> String {
        switch area {
        case .identityLookup:
            return localized("database.officialAction.identityLookup")
        case .contactManagement:
            return localized("database.officialAction.contactManagement")
        case .messaging:
            return localized("database.officialAction.messaging")
        case .administration:
            return localized("database.officialAction.administration")
        case .onlineContext:
            return localized("database.officialAction.onlineContext")
        }
    }

    private func localizedContactStatusTitle(_ status: TS3ContactStatus) -> String {
        switch status {
        case .neutral:
            return localized("contacts.status.neutral")
        case .friend:
            return localized("contacts.status.friend")
        case .ignored:
            return localized("contacts.status.ignored")
        case .blocked:
            return localized("contacts.status.blocked")
        }
    }

    private func databaseClientSnapshot(for record: TS3DatabaseClientSummary) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short

        func dateText(_ date: Date?) -> String? {
            guard let date else { return nil }
            return formatter.string(from: date)
        }

        var rows = [
            "Database ID: \(record.id)",
            "Nickname: \(record.nickname)"
        ]
        if let uniqueIdentifier = record.uniqueIdentifier, !uniqueIdentifier.isEmpty {
            rows.append("Unique ID: \(uniqueIdentifier)")
        }
        if let createdAt = dateText(record.createdAt) {
            rows.append("Created: \(createdAt)")
        }
        if let lastConnectedAt = dateText(record.lastConnectedAt) {
            rows.append("Last Connected: \(lastConnectedAt)")
        }
        if let totalConnections = record.totalConnections {
            rows.append("Connections: \(totalConnections)")
        }
        if let lastIP = record.lastIP, !lastIP.isEmpty {
            rows.append("Last IP: \(lastIP)")
        }
        if let description = record.description, !description.isEmpty {
            rows.append("Description: \(description)")
        }
        return rows.joined(separator: "\n")
    }

    private func exportDatabaseBackup() {
        do {
            databaseBackupDocument = TS3TextFileDocument(data: try model.databaseClientBackupData())
            isExportingDatabaseBackup = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func applyPreset(_ preset: TS3DatabaseClientFilterPreset) {
        recordFilter = DatabaseRecordFilter(rawValue: preset.recordFilter) ?? .all
        sortMode = DatabaseRecordSortMode(rawValue: preset.sortMode) ?? .nickname
        sortAscending = preset.sortAscending
        localFilterText = preset.localFilterText
        databaseBatchSize = String(preset.batchSize)
        presetName = preset.name
    }

    private func presetSummary(_ preset: TS3DatabaseClientFilterPreset) -> String {
        var parts = [
            (DatabaseRecordFilter(rawValue: preset.recordFilter) ?? .all).title,
            localized("permissions.presetSummary.sortFormat", (DatabaseRecordSortMode(rawValue: preset.sortMode) ?? .nickname).title),
            localized("database.presetSummary.batchFormat", preset.batchSize)
        ]
        if !preset.sortAscending {
            parts.append(localized("groups.members.descending"))
        }
        if !preset.localFilterText.isEmpty {
            parts.append(localized("database.presetSummary.filterFormat", preset.localFilterText))
        }
        return parts.joined(separator: " · ")
    }

    private func exportPresets() {
        do {
            presetsDocument = TS3BookmarkFileDocument(data: try model.databaseClientFilterPresetsExportData())
            isExportingPresets = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareDatabaseBackupImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.databaseClientBackupPreview(from: data)
            pendingDatabaseBackupImport = DatabaseBackupImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func databaseBackupPreviewMessage(_ preview: TS3DatabaseClientBackupPreview) -> String {
        var lines = [
            localized("database.backupPreview.clientsFormat", preview.clientCount),
            localized(
                "database.backupPreview.fieldsFormat",
                preview.uniqueIdentifierCount,
                preview.descriptionCount,
                preview.lastIPCount,
                preview.connectionCount
            )
        ]
        if preview.skippedClientCount > 0 {
            lines.append(localized("database.backupPreview.skippedFormat", preview.skippedClientCount))
        }
        if !preview.fieldSummaries.isEmpty {
            lines.append(localized("database.backupPreview.fieldSummariesFormat", preview.fieldSummaries.joined(separator: " | ")))
        }
        if let firstNickname = preview.firstNickname, let firstDatabaseId = preview.firstDatabaseId {
            var first = localized("database.backupPreview.firstFormat", firstNickname, firstDatabaseId)
            if let firstUniqueIdentifier = preview.firstUniqueIdentifier, !firstUniqueIdentifier.isEmpty {
                first += " " + localized("database.backupPreview.uidFormat", firstUniqueIdentifier)
            }
            lines.append(first)
        }
        lines.append(preview.hasClients ? localized("database.backupPreview.hasClients") : localized("database.backupPreview.noUsableClients"))
        return lines.joined(separator: "\n")
    }

    private func preparePresetImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.databaseClientFilterPresetsImportPreview(from: data)
            pendingPresetImport = DatabaseClientFilterPresetImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPresets(data: Data, selectedPresetIds: Set<UUID>) {
        do {
            _ = try model.importDatabaseClientFilterPresets(from: data, selectedPresetIds: selectedPresetIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importDatabaseBackup(data: Data, selectedClientIds: Set<Int>) {
        do {
            try model.importDatabaseClientBackup(from: data, selectedClientIds: selectedClientIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

private struct DatabaseClientFilterPresetImportSheet: View {
    @Environment(\.presentationMode) private var presentationMode

    let preview: TS3DatabaseClientFilterPresetImportPreview
    let importPresets: (Set<UUID>) -> Void
    let cancel: () -> Void
    @State private var selectedPresetIds: Set<UUID>

    init(
        preview: TS3DatabaseClientFilterPresetImportPreview,
        importPresets: @escaping (Set<UUID>) -> Void,
        cancel: @escaping () -> Void
    ) {
        self.preview = preview
        self.importPresets = importPresets
        self.cancel = cancel
        _selectedPresetIds = State(initialValue: Set(preview.candidates.map(\.id)))
    }

    private var canImport: Bool {
        preview.candidates.contains { selectedPresetIds.contains($0.id) }
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("database.import.preview"))) {
                    Text(localized("database.filterImport.importedPresetsFormat", preview.importedPresetCount))
                    Text(localized("database.filterImport.usablePresetsFormat", preview.usablePresetCount))
                    Text(localized("database.filterImport.newPresetsFormat", preview.newPresetCount))
                    Text(localized("database.filterImport.replacingPresetsFormat", preview.replacedPresetCount))
                    Text(localized("database.filterImport.skippedPresetsFormat", preview.skippedPresetCount))
                    Button(localized("database.filterImport.copyBackupPreview")) {
                        TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                    }
                }

                Section(header: Text(localized("database.import.restore"))) {
                    HStack {
                        Button(localized("database.import.selectAll")) {
                            selectedPresetIds = Set(preview.candidates.map(\.id))
                        }
                        Spacer()
                        Button(localized("database.import.clear")) {
                            selectedPresetIds.removeAll()
                        }
                    }
                    ForEach(preview.candidates) { candidate in
                        Toggle(
                            candidate.summary,
                            isOn: Binding(
                                get: { selectedPresetIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedPresetIds.insert(candidate.id)
                                    } else {
                                        selectedPresetIds.remove(candidate.id)
                                    }
                                }
                            )
                        )
                    }
                }

                Section {
                    Text(localized("database.filterImport.behavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("database.filterImport.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("database.import.action")) {
                        importPresets(selectedPresetIds)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canImport)
                }
            }
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

private struct DatabaseBackupImportSheet: View {
    let preview: TS3DatabaseClientBackupPreview
    let previewMessage: String
    let importBackup: (Set<Int>) -> Void
    let cancel: () -> Void
    @State private var selectedClientIds: Set<Int> = []

    private var validSelectedClientIds: Set<Int> {
        Set(selectedClientIds.filter(preview.containsClient))
    }

    private var importImpactSummary: TS3DatabaseClientImportImpactSummary {
        TS3DatabaseClientImportImpactSummary(preview: preview, selectedClientIds: validSelectedClientIds)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("database.import.preview"))) {
                    Text(previewMessage)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    if preview.hasClients {
                        Button(localized("database.import.copyClientSummary")) {
                            TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                        }
                        HStack {
                            Button(localized("database.import.selectAll")) {
                                selectedClientIds = Set(preview.candidates.map(\.id))
                            }
                            Button(localized("database.import.clear")) {
                                selectedClientIds = []
                            }
                            .disabled(selectedClientIds.isEmpty)
                        }
                        ServerInfoDetailRow(
                            label: localized("database.import.impact"),
                            value: localized(
                                "database.import.impactFormat",
                                importImpactSummary.selectedClientCount,
                                importImpactSummary.uniqueIdentifierCount,
                                importImpactSummary.missingUniqueIdentifierCount
                            )
                        )
                        Text(databaseImportImpactText(importImpactSummary))
                            .font(.caption2)
                            .foregroundColor(importImpactSummary.needsAttention ? .orange : .secondary)
                        Button(localized("database.import.copyImpact")) {
                            TS3PlatformSupport.copyToPasteboard(importImpactSummary.clipboardSummary)
                        }
                        .disabled(!importImpactSummary.hasSelection)
                        ForEach(preview.fieldSummaries, id: \.self) { summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                        }
                        ForEach(preview.candidates) { candidate in
                            Toggle(isOn: Binding(
                                get: { selectedClientIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedClientIds.insert(candidate.id)
                                    } else {
                                        selectedClientIds.remove(candidate.id)
                                    }
                                }
                            )) {
                                Text(candidate.summary)
                                    .font(.caption2)
                                    .lineLimit(2)
                                    .truncationMode(.middle)
                            }
                        }
                    }
                }

                Section(header: Text(localized("database.import.behavior"))) {
                    Text(localized("database.import.behaviorSummary"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("database.import.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                if selectedClientIds.isEmpty {
                    selectedClientIds = Set(preview.candidates.map(\.id))
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("database.import.action")) {
                        importBackup(validSelectedClientIds)
                    }
                    .disabled(!preview.hasClients || validSelectedClientIds.isEmpty)
                }
            }
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    private func databaseImportImpactText(_ summary: TS3DatabaseClientImportImpactSummary) -> String {
        [
            localized("database.import.impactFieldsFormat", summary.descriptionCount, summary.lastIPCount, summary.connectionCount),
            localized("database.import.impactDatesFormat", summary.createdDateCount, summary.lastConnectedDateCount),
            localized("database.import.impactSkippedFormat", summary.skippedClientCount)
        ].joined(separator: " | ")
    }
}

struct DatabaseClientLocationRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let location: TS3ClientLocationSummary

    var body: some View {
        VStack(alignment: .leading, spacing: 8) {
            HStack(alignment: .firstTextBaseline) {
                VStack(alignment: .leading, spacing: 3) {
                    Text(displayName)
                        .font(.subheadline.weight(.semibold))
                    Text("Client ID \(location.clientId)")
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                Spacer()
                if let channel {
                    Button("Join") {
                        model.joinChannel(channel)
                    }
                    .buttonStyle(TS3BorderedButtonStyle())
                    .disabled(channel.isCurrent)
                }
            }
            HStack(spacing: 6) {
                Image(systemName: "location")
                    .foregroundColor(.secondary)
                Text(channel?.name ?? "Online, channel not visible")
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
        }
        .padding(.vertical, 4)
    }

    private var user: TS3UserSummary? {
        model.clients.first { $0.id == location.clientId }
    }

    private var channel: TS3ChannelSummary? {
        guard let channelId = user?.channelId else { return nil }
        return model.channels.first { $0.id == channelId }
    }

    private var displayName: String {
        user?.nickname ?? location.nickname ?? "Client \(location.clientId)"
    }
}

struct DatabaseClientDescriptionSheet: View {
    @Environment(\.presentationMode) private var presentationMode
    let record: TS3DatabaseClientSummary
    let submit: (String) -> Void
    @State private var description: String

    init(record: TS3DatabaseClientSummary, submit: @escaping (String) -> Void) {
        self.record = record
        self.submit = submit
        _description = State(initialValue: record.description ?? "")
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(record.nickname)) {
                    TextField("Description", text: $description)
                        .ts3PlainTextField()
                }
            }
            .navigationTitle("Edit Description")
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button("Cancel") {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button("Save") {
                        submit(description)
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }
}

struct DatabaseClientActionSheet: View {
    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    let mode: DatabaseClientActionMode
    let record: TS3DatabaseClientSummary
    @State private var subject = ""
    @State private var text = ""
    @State private var duration: TS3BanDuration = .permanent
    @State private var customBanMinutes = "60"

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(record.nickname)) {
                    if mode == .offlineMessage {
                        TextField("Subject", text: $subject)
                            .ts3PlainTextField()
                    }
                    TextField(fieldTitle, text: $text)
                        .ts3PlainTextField()
                    if mode == .offlineMessage {
                        Text(offlineMessageDraftSummary)
                            .font(.caption)
                            .foregroundColor(.secondary)
                        Button("Copy Offline Message Summary") {
                            TS3PlatformSupport.copyToPasteboard(offlineMessageDraftSummary)
                        }
                        ForEach(offlineMessageDraftValidationMessages, id: \.self) { message in
                            Text(message)
                                .font(.caption)
                                .foregroundColor(.red)
                        }
                    }
                    if mode == .ban {
                        Picker("Duration", selection: $duration) {
                            ForEach(TS3BanDuration.allCases) { duration in
                                Text(duration.title).tag(duration)
                            }
                        }
                        if duration == .custom {
                            TextField("Minutes", text: $customBanMinutes)
                                .ts3PlainTextField()
                                .ts3NumericKeyboard()
                        }
                    }
                }
                Section {
                    Button(actionTitle) {
                        submit()
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(isActionDisabled)
                }
            }
            .navigationTitle(title)
            .ts3InlineNavigationTitle()
            .onAppear {
                if mode == .contactNote, text.isEmpty {
                    text = model.contactNote(for: record) ?? ""
                }
                if mode == .offlineMessage {
                    loadOfflineDraft()
                }
            }
            .onChange(of: subject) { _ in
                saveOfflineDraftIfNeeded()
            }
            .onChange(of: text) { _ in
                saveOfflineDraftIfNeeded()
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button("Cancel") {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }

    private var title: String {
        switch mode {
        case .offlineMessage:
            return "Offline Message"
        case .contactNote:
            return "Contact Note"
        case .complain:
            return "Submit Complaint"
        case .ban:
            return "Ban Unique ID"
        }
    }

    private var fieldTitle: String {
        switch mode {
        case .offlineMessage:
            return "Message"
        case .contactNote:
            return "Note"
        case .complain:
            return "Complaint"
        case .ban:
            return "Reason"
        }
    }

    private var actionTitle: String {
        switch mode {
        case .offlineMessage:
            return "Send"
        case .contactNote:
            return "Save Note"
        case .complain:
            return "Submit Complaint"
        case .ban:
            return "Ban"
        }
    }

    private var isActionDisabled: Bool {
        let textIsEmpty = text.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
        switch mode {
        case .offlineMessage:
            return !offlineMessageDraftValidationMessages.isEmpty
        case .contactNote:
            return false
        case .complain:
            return textIsEmpty
        case .ban:
            return duration == .custom && TS3BanDuration.customSeconds(from: customBanMinutes) == nil
        }
    }

    private func submit() {
        switch mode {
        case .offlineMessage:
            model.sendOfflineMessage(to: record, subject: subject, message: text) {
                model.clearOfflineMessageDraft(id: offlineDraftId)
            }
        case .contactNote:
            model.setContactNote(text, for: record)
        case .complain:
            model.complainAboutDatabaseClient(record, message: text)
        case .ban:
            model.banDatabaseClient(
                record,
                durationSeconds: duration.seconds(customMinutes: customBanMinutes),
                reason: text.isEmpty ? nil : text
            )
        }
    }

    private var offlineDraftId: String {
        if let uniqueIdentifier = record.uniqueIdentifier, !uniqueIdentifier.isEmpty {
            return "uid:\(uniqueIdentifier)"
        }
        return "db:\(record.id)"
    }

    private func loadOfflineDraft() {
        guard let draft = model.offlineMessageDraft(for: offlineDraftId) else { return }
        subject = draft.subject
        text = draft.message
    }

    private func saveOfflineDraftIfNeeded() {
        guard mode == .offlineMessage else { return }
        model.saveOfflineMessageDraft(
            id: offlineDraftId,
            recipientName: record.nickname,
            subject: subject,
            message: text
        )
    }

    private var offlineMessageDraftValidationMessages: [String] {
        TS3OfflineMessageDraftValidator.validationMessages(
            recipientName: record.nickname,
            recipientUniqueIdentifier: record.uniqueIdentifier,
            subject: subject,
            message: text
        )
    }

    private var offlineMessageDraftSummary: String {
        TS3OfflineMessageDraftValidator.creationSummary(
            recipientName: record.nickname,
            recipientUniqueIdentifier: record.uniqueIdentifier,
            subject: subject,
            message: text
        )
    }
}

struct DatabaseClientRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let record: TS3DatabaseClientSummary
    @State private var onlineActionMode: UserActionMode?
    @State private var databaseActionMode: DatabaseClientActionMode?
    @State private var isShowingComplaints = false

    private var onlineUser: TS3UserSummary? {
        model.onlineUser(for: record)
    }

    private var contactStatus: TS3ContactStatus {
        model.contactStatus(for: record)
    }

    var body: some View {
        Button {
            model.loadDatabaseClientDetails(record)
        } label: {
            VStack(alignment: .leading, spacing: 4) {
                HStack {
                    Text(record.nickname)
                        .font(.subheadline.weight(.semibold))
                    Spacer()
                    Text("DB \(record.id)")
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                if let uniqueIdentifier = record.uniqueIdentifier, !uniqueIdentifier.isEmpty {
                    Text(uniqueIdentifier)
                        .font(.caption)
                        .foregroundColor(.secondary)
                        .lineLimit(1)
                        .truncationMode(.middle)
                }
                HStack(spacing: 8) {
                    if contactStatus == .friend {
                        Text(localized("contacts.status.friend"))
                    }
                    if contactStatus == .blocked {
                        Text(localized("contacts.status.blocked"))
                    }
                    if let note = model.contactNote(for: record) {
                        Text(localized("clientActions.noteFormat", note))
                    }
                }
                .font(.caption)
                .foregroundColor(.secondary)
            }
            .padding(.vertical, 3)
        }
        .buttonStyle(.plain)
        .contextMenu {
            Button(localized("contacts.row.copyNickname")) {
                TS3PlatformSupport.copyToPasteboard(record.nickname)
            }
            Button(localized("groups.members.row.copyDatabaseId")) {
                TS3PlatformSupport.copyToPasteboard("\(record.id)")
            }
            Button(localized("groups.row.copySummary")) {
                TS3PlatformSupport.copyToPasteboard(record.clipboardSummary)
            }
            if let uniqueIdentifier = record.uniqueIdentifier, !uniqueIdentifier.isEmpty {
                Button(localized("contacts.row.copyUniqueId")) {
                    TS3PlatformSupport.copyToPasteboard(uniqueIdentifier)
                }
                Menu(localized("groups.members.row.contact")) {
                    Button(localized("groups.members.row.markFriend")) {
                        model.setContactStatus(.friend, for: record)
                    }
                    .disabled(contactStatus == .friend)
                    Button(localized("groups.members.row.blockContact")) {
                        model.setContactStatus(.blocked, for: record)
                    }
                    .disabled(contactStatus == .blocked)
                    Button(localized("groups.members.row.ignoreContact")) {
                        model.setContactStatus(.ignored, for: record)
                    }
                    .disabled(contactStatus == .ignored)
                    Button(localized("groups.members.row.setNeutral")) {
                        model.setContactStatus(.neutral, for: record)
                    }
                    .disabled(contactStatus == .neutral && model.contactNote(for: record) == nil)
                    Button(localized("groups.members.row.editNote")) {
                        databaseActionMode = .contactNote
                    }
                }
            }
            Button(localized("groups.members.row.sendOfflineMessage")) {
                databaseActionMode = .offlineMessage
            }
            .disabled(!model.canSendOfflineMessage(to: record))
            Button(localized("groups.members.row.submitComplaint")) {
                databaseActionMode = .complain
            }
            Button(localized("database.viewComplaints")) {
                model.refreshComplaints(for: record)
                isShowingComplaints = true
            }
            Button(localized("groups.members.row.banUniqueId")) {
                databaseActionMode = .ban
            }
            .disabled(!model.canBanDatabaseClient(record))
            if model.hasOnlineClientActions(for: record) {
                Button(localized("groups.members.row.pokeOnlineClient")) {
                    onlineActionMode = .poke
                }
                Button(localized("contacts.row.sendPrivateMessage")) {
                    onlineActionMode = .privateMessage
                }
                Button(localized("contacts.row.clientInfo")) {
                    onlineActionMode = .info
                }
            }
            if !model.serverGroups.isEmpty {
                Menu(localized("database.addServerGroup")) {
                    ForEach(model.serverGroups) { group in
                        Button(group.name) {
                            model.addServerGroup(group, to: record)
                        }
                    }
                }
            }
        }
        .accessibilityElement(children: .ignore)
        .accessibilityLabel(record.nickname)
        .accessibilityValue(record.accessibilityValue)
        .accessibilityAction(named: localized("clientActions.details")) {
            model.loadDatabaseClientDetails(record)
        }
        .accessibilityAction(named: localized("groups.row.copySummary")) {
            TS3PlatformSupport.copyToPasteboard(record.clipboardSummary)
        }
        .accessibilityAction(named: localized("groups.members.row.copyDatabaseId")) {
            TS3PlatformSupport.copyToPasteboard("\(record.id)")
        }
        .accessibilityAction(named: localized("groups.members.row.editContactNote")) {
            if record.uniqueIdentifier?.isEmpty == false {
                databaseActionMode = .contactNote
            }
        }
        .accessibilityAction(named: localized("groups.members.row.sendOfflineMessage")) {
            if model.canSendOfflineMessage(to: record) {
                databaseActionMode = .offlineMessage
            }
        }
        .accessibilityAction(named: localized("groups.members.row.submitComplaint")) {
            databaseActionMode = .complain
        }
        .accessibilityAction(named: localized("database.viewComplaints")) {
            model.refreshComplaints(for: record)
            isShowingComplaints = true
        }
        .accessibilityAction(named: localized("groups.members.row.banUniqueId")) {
            if model.canBanDatabaseClient(record) {
                databaseActionMode = .ban
            }
        }
        .sheet(item: $databaseActionMode) { mode in
            DatabaseClientActionSheet(mode: mode, record: record)
                .environmentObject(model)
        }
        .sheet(item: $onlineActionMode) { mode in
            if let onlineUser {
                UserActionSheet(mode: mode, user: onlineUser)
                    .environmentObject(model)
            }
        }
        .sheet(isPresented: $isShowingComplaints) {
            ComplaintListSheet()
                .environmentObject(model)
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

struct DatabaseClientDetailRows: View {
    let record: TS3DatabaseClientSummary

    var body: some View {
        HStack {
            Text("Nickname")
            Spacer()
            Text(record.nickname)
                .foregroundColor(.secondary)
        }
        HStack {
            Text("Database ID")
            Spacer()
            Text("\(record.id)")
                .foregroundColor(.secondary)
        }
        if let uniqueIdentifier = record.uniqueIdentifier, !uniqueIdentifier.isEmpty {
            Text(uniqueIdentifier)
                .font(.caption)
                .foregroundColor(.secondary)
                .lineLimit(1)
                .truncationMode(.middle)
        }
        if let createdAt = record.createdAt {
            HStack {
                Text("Created")
                Spacer()
                Text(Self.dateText(createdAt))
                    .foregroundColor(.secondary)
            }
        }
        if let lastConnectedAt = record.lastConnectedAt {
            HStack {
                Text("Last Connected")
                Spacer()
                Text(Self.dateText(lastConnectedAt))
                    .foregroundColor(.secondary)
            }
        }
        if let totalConnections = record.totalConnections {
            HStack {
                Text("Connections")
                Spacer()
                Text("\(totalConnections)")
                    .foregroundColor(.secondary)
            }
        }
        if let lastIP = record.lastIP, !lastIP.isEmpty {
            HStack {
                Text("Last IP")
                Spacer()
                Text(lastIP)
                    .foregroundColor(.secondary)
            }
        }
        if let description = record.description, !description.isEmpty {
            Text(description)
        }
    }

    private static func dateText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .short
        formatter.timeStyle = .short
        return formatter.string(from: date)
    }
}

