                        TextField(localized("serverSettings.buttonTooltip"), text: $hostButtonTooltip)
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.buttonLinkURL"), text: $hostButtonURL)
                            .ts3URLTextField()
                        TextField(localized("serverSettings.buttonImageURL"), text: $hostButtonGraphicsURL)
                            .ts3URLTextField()
                    } label: {
                        Label(localized("serverSettings.hostBranding"), systemImage: "rectangle.and.text.magnifyingglass")
                    }
                }

                Section {
                    DisclosureGroup(isExpanded: $isShowingLimitSettings) {
                        TextField(localized("serverSettings.downloadQuotaBytes"), text: $downloadQuota)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.uploadQuotaBytes"), text: $uploadQuota)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.maxDownloadBandwidthBytes"), text: $maxDownloadTotalBandwidth)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.maxUploadBandwidthBytes"), text: $maxUploadTotalBandwidth)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.neededIdentitySecurityLevel"), text: $neededIdentitySecurityLevel)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.minimumClientVersion"), text: $minClientVersion)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.minimumAndroidVersion"), text: $minAndroidVersion)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.minimumIOSVersion"), text: $minIOSVersion)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        Picker(localized("serverSettings.codecEncryption"), selection: $codecEncryptionMode) {
                            Text(localized("serverSettings.unchanged")).tag(Int?.none)
                            ForEach(TS3CodecEncryptionMode.allCases) { mode in
                                Text(codecEncryptionModeTitle(mode.rawValue)).tag(Optional(mode.rawValue))
                            }
                            if let codecEncryptionMode,
                               TS3CodecEncryptionMode(rawValue: codecEncryptionMode) == nil {
                                Text(codecEncryptionModeTitle(codecEncryptionMode)).tag(Optional(codecEncryptionMode))
                            }
                        }
                    } label: {
                        Label(localized("serverSettings.limitsAndSecurity"), systemImage: "speedometer")
                    }
                }

                Section {
                    DisclosureGroup(isExpanded: $isShowingGroupSettings) {
                        Picker(localized("serverSettings.serverGroup"), selection: $defaultServerGroupId) {
                            Text(localized("serverSettings.unchanged")).tag("")
                            ForEach(model.serverGroups) { group in
                                Text(groupPickerTitle(group)).tag(String(group.id))
                            }
                            if shouldShowCustomGroup(defaultServerGroupId, in: model.serverGroups) {
                                Text(groupDraftTitle(defaultServerGroupId)).tag(defaultServerGroupId)
                            }
                        }
                        TextField(localized("serverSettings.serverGroupId"), text: $defaultServerGroupId)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        Picker(localized("serverSettings.channelGroup"), selection: $defaultChannelGroupId) {
                            Text(localized("serverSettings.unchanged")).tag("")
                            ForEach(model.channelGroups) { group in
                                Text(groupPickerTitle(group)).tag(String(group.id))
                            }
                            if shouldShowCustomGroup(defaultChannelGroupId, in: model.channelGroups) {
                                Text(groupDraftTitle(defaultChannelGroupId)).tag(defaultChannelGroupId)
                            }
                        }
                        TextField(localized("serverSettings.channelGroupId"), text: $defaultChannelGroupId)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        Picker(localized("serverSettings.channelAdmin"), selection: $defaultChannelAdminGroupId) {
                            Text(localized("serverSettings.unchanged")).tag("")
                            ForEach(model.channelGroups) { group in
                                Text(groupPickerTitle(group)).tag(String(group.id))
                            }
                            if shouldShowCustomGroup(defaultChannelAdminGroupId, in: model.channelGroups) {
                                Text(groupDraftTitle(defaultChannelAdminGroupId)).tag(defaultChannelAdminGroupId)
                            }
                        }
                        TextField(localized("serverSettings.channelAdminGroupId"), text: $defaultChannelAdminGroupId)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                    } label: {
                        Label(localized("serverSettings.defaultGroups"), systemImage: "person.3")
                    }
                }

                Section {
                    DisclosureGroup(isExpanded: $isShowingSafetySettings) {
                        TextField(localized("serverSettings.autoBanComplaintCount"), text: $complainAutoBanCount)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.autoBanSeconds"), text: $complainAutoBanTime)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.complaintRemoveSeconds"), text: $complainRemoveTime)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.forcedSilenceClientCount"), text: $minClientsInChannelBeforeForcedSilence)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.prioritySpeakerDimming"), text: $prioritySpeakerDimmModificator)
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.antiFloodTickReduce"), text: $antiFloodPointsTickReduce)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.antiFloodCommandBlock"), text: $antiFloodPointsNeededCommandBlock)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.antiFloodIPBlock"), text: $antiFloodPointsNeededIPBlock)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                        TextField(localized("serverSettings.antiFloodPluginBlock"), text: $antiFloodPointsNeededPluginBlock)
                            .ts3NumericKeyboard()
                            .ts3PlainTextField()
                    } label: {
                        Label(localized("serverSettings.antiFloodAndComplaints"), systemImage: "shield")
                    }
                }

                Section {
                    DisclosureGroup(isExpanded: $isShowingLogSettings) {
                        Picker(localized("serverSettings.clientLog"), selection: $logClient) {
                            Text(localized("serverSettings.unchanged")).tag(Bool?.none)
                            Text(localized("serverSettings.enabled")).tag(Optional(true))
                            Text(localized("serverSettings.disabled")).tag(Optional(false))
                        }
                        Picker(localized("serverSettings.queryLog"), selection: $logQuery) {
                            Text(localized("serverSettings.unchanged")).tag(Bool?.none)
                            Text(localized("serverSettings.enabled")).tag(Optional(true))
                            Text(localized("serverSettings.disabled")).tag(Optional(false))
                        }
                        Picker(localized("serverSettings.channelLog"), selection: $logChannel) {
                            Text(localized("serverSettings.unchanged")).tag(Bool?.none)
                            Text(localized("serverSettings.enabled")).tag(Optional(true))
                            Text(localized("serverSettings.disabled")).tag(Optional(false))
                        }
                        Picker(localized("serverSettings.permissionLog"), selection: $logPermissions) {
                            Text(localized("serverSettings.unchanged")).tag(Bool?.none)
                            Text(localized("serverSettings.enabled")).tag(Optional(true))
                            Text(localized("serverSettings.disabled")).tag(Optional(false))
                        }
                        Picker(localized("serverSettings.serverLog"), selection: $logServer) {
                            Text(localized("serverSettings.unchanged")).tag(Bool?.none)
                            Text(localized("serverSettings.enabled")).tag(Optional(true))
                            Text(localized("serverSettings.disabled")).tag(Optional(false))
                        }
                        Picker(localized("serverSettings.fileTransferLog"), selection: $logFileTransfer) {
                            Text(localized("serverSettings.unchanged")).tag(Bool?.none)
                            Text(localized("serverSettings.enabled")).tag(Optional(true))
                            Text(localized("serverSettings.disabled")).tag(Optional(false))
                        }
                    } label: {
                        Label(localized("serverSettings.serverLogOptions"), systemImage: "doc.text.magnifyingglass")
                    }
                }
            }
            .navigationTitle(localized("serverSettings.title"))
            .ts3InlineNavigationTitle()
            .onAppear(perform: loadCurrentValues)
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("serverSettings.reset")) {
                        loadCurrentValues()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("serverSettings.save")) {
                        save()
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!isDraftValid)
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.cancel")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .fileImporter(
                isPresented: $isShowingIconImporter,
                allowedContentTypes: [.image, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    model.uploadServerIcon(from: url) { uploadedIconId in
                        iconId = String(uploadedIconId)
                    }
                }
            }
            .fileImporter(
                isPresented: $isImportingDraft,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareDraftImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingDraft,
                document: draftDocument,
                contentType: .json,
                defaultFilename: "ts3-server-settings-draft"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingSnapshot,
                document: snapshotDocument,
                contentType: .plainText,
                defaultFilename: "ts3-server-settings"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .sheet(item: $pendingDraftImport) { confirmation in
                ServerSettingsDraftImportSheet(
                    previewMessage: confirmation.previewMessage,
                    canImport: confirmation.canImport,
                    importDraft: {
                        applyDraft(confirmation.draft)
                        pendingDraftImport = nil
                    },
                    cancel: {
                        pendingDraftImport = nil
                    },
                    localized: localized
                )
            }
        }
    }

    private struct ServerSettingsDraftImportSheet: View {
        let previewMessage: String
        let canImport: Bool
        let importDraft: () -> Void
        let cancel: () -> Void
        let localized: (String, CVarArg...) -> String

        var body: some View {
            NavigationView {
                Form {
                    Section(header: Text(localized("serverSettings.preview"))) {
                        Text(previewMessage)
                            .font(.caption)
                            .foregroundColor(.secondary)
                        Button(localized("serverSettings.copySummary")) {
                            TS3PlatformSupport.copyToPasteboard(previewMessage)
                        }
                    }

                    Section(header: Text(localized("serverSettings.importBehavior"))) {
                        Text(localized("serverSettings.importBehavior.summary"))
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                }
                .navigationTitle(localized("serverSettings.importSettings"))
                .ts3InlineNavigationTitle()
                .toolbar {
                    ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                        Button(localized("common.cancel")) {
                            cancel()
                        }
                    }
                    ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                        Button(localized("serverSettings.import")) {
                            importDraft()
                        }
                        .disabled(!canImport)
                    }
                }
            }
        }
    }

    private var currentDraft: ServerSettingsDraft {
        ServerSettingsDraft(
            name: name,
            phoneticName: phoneticName,
            port: port,
            machineId: machineId,
            autostart: boolDraftText(autostart),
            welcomeMessage: welcomeMessage,
            maxClients: maxClients,
            reservedSlots: reservedSlots,
            clearPassword: clearPassword,
            password: password,
            hostMessage: hostMessage,
            hostMessageMode: hostMessageMode,
            hostBannerURL: hostBannerURL,
            hostBannerGraphicsURL: hostBannerGraphicsURL,
            hostBannerMode: hostBannerMode.map(String.init) ?? "",
            hostBannerGraphicsInterval: hostBannerGraphicsInterval,
            hostButtonTooltip: hostButtonTooltip,
            hostButtonURL: hostButtonURL,
            hostButtonGraphicsURL: hostButtonGraphicsURL,
            iconId: iconId,
            downloadQuota: downloadQuota,
            uploadQuota: uploadQuota,
            maxDownloadTotalBandwidth: maxDownloadTotalBandwidth,
            maxUploadTotalBandwidth: maxUploadTotalBandwidth,
            complainAutoBanCount: complainAutoBanCount,
            complainAutoBanTime: complainAutoBanTime,
            complainRemoveTime: complainRemoveTime,
            minClientsInChannelBeforeForcedSilence: minClientsInChannelBeforeForcedSilence,
            prioritySpeakerDimmModificator: prioritySpeakerDimmModificator,
            antiFloodPointsTickReduce: antiFloodPointsTickReduce,
            antiFloodPointsNeededCommandBlock: antiFloodPointsNeededCommandBlock,
            antiFloodPointsNeededIPBlock: antiFloodPointsNeededIPBlock,
            antiFloodPointsNeededPluginBlock: antiFloodPointsNeededPluginBlock,
            logClient: boolDraftText(logClient),
            logQuery: boolDraftText(logQuery),
            logChannel: boolDraftText(logChannel),
            logPermissions: boolDraftText(logPermissions),
            logServer: boolDraftText(logServer),
            logFileTransfer: boolDraftText(logFileTransfer),
            weblistEnabled: weblistEnabled.map { $0 ? "1" : "0" } ?? "",
            codecEncryptionMode: codecEncryptionMode.map(String.init) ?? "",
            defaultServerGroupId: defaultServerGroupId,
            defaultChannelGroupId: defaultChannelGroupId,
            defaultChannelAdminGroupId: defaultChannelAdminGroupId,
            neededIdentitySecurityLevel: neededIdentitySecurityLevel,
            minClientVersion: minClientVersion,
            minAndroidVersion: minAndroidVersion,
            minIOSVersion: minIOSVersion
        )
    }

    private var settingsSnapshot: String {
        settingsSnapshotMessage(for: currentDraft, validationMessages: isDraftValid ? [] : serverDraftValidationMessages(for: currentDraft))
    }

    private var draftChangeRows: [String] {
        draftChangeRows(for: currentDraft)
    }

    private var draftChangeSummary: String {
        draftChangeSummary(for: currentDraft)
    }

    private var settingsImpactSummary: TS3ServerSettingsImpactSummary {
        settingsImpactSummary(for: currentDraft)
    }

    private var settingsCoverageSummary: TS3ServerSettingsCoverageSummary {
        settingsCoverageSummary(for: currentDraft)
    }

    private var settingsCoverageSummaryText: String {
        settingsCoverageSummaryText(for: settingsCoverageSummary)
    }

    private var settingsCoverageSummaryClipboard: String {
        let summary = settingsCoverageSummary
        let lines = [
            localized("serverSettings.coverageSummary"),
            summary.clipboardSummary
        ]
        return lines.joined(separator: "\n")
    }

    private var settingsImpactSummaryText: String {
        settingsImpactSummaryText(for: settingsImpactSummary)
    }

    private var settingsImpactSummaryClipboard: String {
        let impact = settingsImpactSummary
        let affectedAreas = TS3ServerSettingsImpactArea.allCases
            .compactMap { area -> String? in
                guard let count = impact.areaChangeCounts[area], count > 0 else { return nil }
                return localized("serverSettings.impactAreaClipboardFormat", title(for: area), count)
            }
            .joined(separator: "\n")
        let lines = [
            localized("serverSettings.impactSummary"),
            impact.clipboardSummary,
            affectedAreas
        ]
        return lines
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
            .joined(separator: "\n")
    }

    private var settingsReviewSummary: TS3ServerSettingsReviewSummary {
        settingsReviewSummary(for: currentDraft)
    }

    private var settingsOfficialImpactSummary: TS3ServerSettingsOfficialImpactSummary {
        settingsOfficialImpactSummary(for: currentDraft)
    }

    private var settingsOfficialImpactSummaryText: String {
        settingsOfficialImpactSummaryText(for: settingsOfficialImpactSummary)
    }

    private var settingsOfficialImpactSummaryClipboard: String {
        let summary = settingsOfficialImpactSummary
        let affectedAreas = TS3ServerSettingsOfficialImpactArea.allCases
            .compactMap { area -> String? in
                guard let count = summary.areaChangeCounts[area], count > 0 else { return nil }
                return localized("serverSettings.officialImpactAreaClipboardFormat", title(for: area), count)
            }
            .joined(separator: "\n")
        let lines = [
            localized("serverSettings.officialImpactSummary"),
            summary.clipboardSummary,
            affectedAreas
        ]
        return lines
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
            .joined(separator: "\n")
    }

    private var settingsReviewSummaryText: String {
        settingsReviewSummaryText(for: settingsReviewSummary)
    }

    private var settingsReviewSummaryClipboard: String {
        let summary = settingsReviewSummary
        let lines = [
            localized("serverSettings.reviewSummary"),
            summary.clipboardSummary,
            summary.reviewItems.joined(separator: "\n")
        ]
        return lines
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
            .joined(separator: "\n")
    }

    private func draftChangeRows(for draft: ServerSettingsDraft) -> [String] {
        generalChangeRows(for: draft)
            + hostBrandingChangeRows(for: draft)
            + limitsAndSecurityChangeRows(for: draft)
            + defaultGroupChangeRows(for: draft)
            + antiFloodAndComplaintChangeRows(for: draft)
            + serverLogOptionChangeRows(for: draft)
    }

    private func settingsImpactSummary(for draft: ServerSettingsDraft) -> TS3ServerSettingsImpactSummary {
        TS3ServerSettingsImpactSummary(
            areaChangeCounts: settingsAreaChangeCounts(for: draft),
            validationIssueCount: serverDraftValidationMessages(for: draft).count
        )
    }

    private func settingsCoverageSummary(for draft: ServerSettingsDraft) -> TS3ServerSettingsCoverageSummary {
        TS3ServerSettingsCoverageSummary(
            changedAreaCounts: settingsAreaChangeCounts(for: draft),
            validationIssueCount: serverDraftValidationMessages(for: draft).count
        )
    }

    private func settingsAreaChangeCounts(for draft: ServerSettingsDraft) -> [TS3ServerSettingsImpactArea: Int] {
        [
            .general: generalChangeRows(for: draft).count,
            .hostBranding: hostBrandingChangeRows(for: draft).count,
            .limitsAndSecurity: limitsAndSecurityChangeRows(for: draft).count,
            .defaultGroups: defaultGroupChangeRows(for: draft).count,
            .antiFloodAndComplaints: antiFloodAndComplaintChangeRows(for: draft).count,
            .serverLogOptions: serverLogOptionChangeRows(for: draft).count
        ]
    }

    private func settingsReviewSummary(for draft: ServerSettingsDraft) -> TS3ServerSettingsReviewSummary {
        TS3ServerSettingsReviewSummary(
            reviewItems: settingsReviewItems(for: draft),
            validationIssueCount: serverDraftValidationMessages(for: draft).count
        )
    }

    private func settingsOfficialImpactSummary(for draft: ServerSettingsDraft) -> TS3ServerSettingsOfficialImpactSummary {
        let reviewSummary = settingsReviewSummary(for: draft)
        return TS3ServerSettingsOfficialImpactSummary(
            areaChangeCounts: settingsOfficialImpactAreaChangeCounts(for: draft),
            validationIssueCount: reviewSummary.validationIssueCount,
            sensitiveChangeCount: reviewSummary.sensitiveChangeCount
        )
    }

    private func settingsOfficialImpactAreaChangeCounts(for draft: ServerSettingsDraft) -> [TS3ServerSettingsOfficialImpactArea: Int] {
        [
            .availability: availabilityImpactRows(for: draft).count,
            .accessControl: accessControlImpactRows(for: draft).count,
            .brandingVisibility: brandingVisibilityImpactRows(for: draft).count,
            .moderationSafety: moderationSafetyImpactRows(for: draft).count,
            .loggingAudit: loggingAuditImpactRows(for: draft).count
        ]
    }

    private func availabilityImpactRows(for draft: ServerSettingsDraft) -> [String] {
        [
            optionalChangeRow(label: localized("serverSettings.serverPort"), current: model.serverInfo.port, draft: draft.port ?? ""),
            changeRow(label: localized("serverSettings.autostart"), current: model.serverInfo.isAutoStartEnabled, draft: Self.boolDraftValue(draft.autostart)),
            optionalChangeRow(label: localized("serverSettings.maxClients"), current: model.serverInfo.maxClients, draft: draft.maxClients),
            optionalChangeRow(label: localized("serverSettings.reservedSlots"), current: model.serverInfo.reservedSlots, draft: draft.reservedSlots),
            optionalChangeRow(label: localized("serverSettings.downloadQuotaBytes"), current: model.serverInfo.downloadQuota, draft: draft.downloadQuota),
            optionalChangeRow(label: localized("serverSettings.uploadQuotaBytes"), current: model.serverInfo.uploadQuota, draft: draft.uploadQuota),
            optionalChangeRow(label: localized("serverSettings.maxDownloadBandwidthBytes"), current: model.serverInfo.maxDownloadTotalBandwidth, draft: draft.maxDownloadTotalBandwidth ?? ""),
            optionalChangeRow(label: localized("serverSettings.maxUploadBandwidthBytes"), current: model.serverInfo.maxUploadTotalBandwidth, draft: draft.maxUploadTotalBandwidth ?? "")
        ].compactMap { $0 }
    }

    private func accessControlImpactRows(for draft: ServerSettingsDraft) -> [String] {
        [
            passwordChangeRow(for: draft),
            optionalChangeRow(label: localized("serverSettings.neededIdentitySecurityLevel"), current: model.serverInfo.neededIdentitySecurityLevel, draft: draft.neededIdentitySecurityLevel ?? ""),
            optionalChangeRow(label: localized("serverSettings.minimumClientVersion"), current: model.serverInfo.minClientVersion, draft: draft.minClientVersion ?? ""),
            optionalChangeRow(label: localized("serverSettings.minimumAndroidVersion"), current: model.serverInfo.minAndroidVersion, draft: draft.minAndroidVersion ?? ""),
            optionalChangeRow(label: localized("serverSettings.minimumIOSVersion"), current: model.serverInfo.minIOSVersion, draft: draft.minIOSVersion ?? ""),
            changeRow(label: localized("serverSettings.codecEncryptionMode"), current: model.serverInfo.codecEncryptionMode, draft: TS3CodecEncryptionMode.value(forDraft: draft.codecEncryptionMode)),
            optionalChangeRow(label: localized("serverSettings.defaultServerGroup"), current: model.serverInfo.defaultServerGroupId, draft: draft.defaultServerGroupId ?? ""),
            optionalChangeRow(label: localized("serverSettings.defaultChannelGroup"), current: model.serverInfo.defaultChannelGroupId, draft: draft.defaultChannelGroupId ?? ""),
            optionalChangeRow(label: localized("serverSettings.defaultChannelAdmin"), current: model.serverInfo.defaultChannelAdminGroupId, draft: draft.defaultChannelAdminGroupId ?? "")
        ].compactMap { $0 }
    }

    private func brandingVisibilityImpactRows(for draft: ServerSettingsDraft) -> [String] {
        [
            changeRow(label: localized("serverSettings.serverList"), current: model.serverInfo.isWeblistEnabled, draft: Self.boolDraftValue(draft.weblistEnabled)),
            changeRow(label: localized("serverSettings.hostMessageMode"), current: model.serverInfo.hostMessageMode, draft: TS3HostMessageMode.value(forDraft: draft.hostMessageMode)),
            changeRow(label: localized("serverSettings.hostMessage"), current: model.serverInfo.hostMessage, draft: draft.hostMessage),
            changeRow(label: localized("serverSettings.bannerLinkURL"), current: model.serverInfo.hostBannerURL, draft: draft.hostBannerURL),
            changeRow(label: localized("serverSettings.bannerImageURL"), current: model.serverInfo.hostBannerGraphicsURL, draft: draft.hostBannerGraphicsURL),
            changeRow(label: localized("serverSettings.bannerMode"), current: model.serverInfo.hostBannerMode, draft: TS3HostBannerMode.value(forDraft: draft.hostBannerMode ?? "")),
            optionalChangeRow(label: localized("serverSettings.bannerRefreshSeconds"), current: model.serverInfo.hostBannerGraphicsInterval, draft: draft.hostBannerGraphicsInterval ?? ""),
            changeRow(label: localized("serverSettings.hostButtonTooltip"), current: model.serverInfo.hostButtonTooltip, draft: draft.hostButtonTooltip),
            changeRow(label: localized("serverSettings.hostButtonURL"), current: model.serverInfo.hostButtonURL, draft: draft.hostButtonURL),
            changeRow(label: localized("serverSettings.hostButtonImageURL"), current: model.serverInfo.hostButtonGraphicsURL, draft: draft.hostButtonGraphicsURL),
            optionalChangeRow(label: localized("serverSettings.iconId"), current: model.serverInfo.iconId, draft: draft.iconId)
        ].compactMap { $0 }
    }

    private func moderationSafetyImpactRows(for draft: ServerSettingsDraft) -> [String] {
        antiFloodAndComplaintChangeRows(for: draft)
    }

    private func loggingAuditImpactRows(for draft: ServerSettingsDraft) -> [String] {
