    private func settingsImpactSummaryText(for summary: TS3ServerSettingsImpactSummary) -> String {
        guard summary.needsReview else { return localized("serverSettings.impactNoChanges") }
        var parts = TS3ServerSettingsImpactArea.allCases.compactMap { area -> String? in
            guard let count = summary.areaChangeCounts[area], count > 0 else { return nil }
            return localized("serverSettings.impactAreaFormat", title(for: area), count)
        }
        if summary.validationIssueCount > 0 {
            parts.append(localized("serverSettings.validationIssueCountFormat", summary.validationIssueCount))
        }
        return parts.joined(separator: " · ")
    }

    private func settingsCoverageSummaryText(for summary: TS3ServerSettingsCoverageSummary) -> String {
        var parts = [
            localized("serverSettings.coverageAreaFormat", summary.coveredAreaCount, summary.totalOfficialAreaCount),
            localized("serverSettings.coverageChangedAreaFormat", summary.changedAreaCount, summary.totalChangeCount)
        ]
        if summary.validationIssueCount > 0 {
            parts.append(localized("serverSettings.validationIssueCountFormat", summary.validationIssueCount))
        }
        if summary.uncoveredAreaCount > 0 {
            parts.append(localized("serverSettings.coverageUncoveredFormat", summary.uncoveredAreaCount))
        }
        return parts.joined(separator: " · ")
    }

    private func settingsReviewSummaryText(for summary: TS3ServerSettingsReviewSummary) -> String {
        guard summary.needsAttention else { return localized("serverSettings.reviewNoAttention") }
        var parts: [String] = []
        if summary.sensitiveChangeCount > 0 {
            parts.append(localized("serverSettings.sensitiveChangeCountFormat", summary.sensitiveChangeCount))
        }
        if summary.validationIssueCount > 0 {
            parts.append(localized("serverSettings.validationIssueCountFormat", summary.validationIssueCount))
        }
        let previewItems = summary.reviewItems.prefix(4).joined(separator: " · ")
        if !previewItems.isEmpty {
            parts.append(previewItems)
        }
        return parts.joined(separator: " · ")
    }

    private func settingsOfficialImpactSummaryText(for summary: TS3ServerSettingsOfficialImpactSummary) -> String {
        guard summary.needsAttention else { return localized("serverSettings.officialImpactNoChanges") }
        var parts = TS3ServerSettingsOfficialImpactArea.allCases.compactMap { area -> String? in
            guard let count = summary.areaChangeCounts[area], count > 0 else { return nil }
            return localized("serverSettings.officialImpactAreaFormat", title(for: area), count)
        }
        if summary.sensitiveChangeCount > 0 {
            parts.append(localized("serverSettings.sensitiveChangeCountFormat", summary.sensitiveChangeCount))
        }
        if summary.validationIssueCount > 0 {
            parts.append(localized("serverSettings.validationIssueCountFormat", summary.validationIssueCount))
        }
        return parts.joined(separator: " · ")
    }

    private func title(for area: TS3ServerSettingsImpactArea) -> String {
        switch area {
        case .general:
            return localized("serverSettings.general")
        case .hostBranding:
            return localized("serverSettings.hostBranding")
        case .limitsAndSecurity:
            return localized("serverSettings.limitsAndSecurity")
        case .defaultGroups:
            return localized("serverSettings.defaultGroups")
        case .antiFloodAndComplaints:
            return localized("serverSettings.antiFloodAndComplaints")
        case .serverLogOptions:
            return localized("serverSettings.serverLogOptions")
        }
    }

