    private func save() {
        model.editServerSettings(
            name: name,
            phoneticName: phoneticName,
            port: Int(port.trimmingCharacters(in: .whitespacesAndNewlines)),
            machineId: machineId,
            isAutoStartEnabled: autostart,
            welcomeMessage: welcomeMessage,
            maxClients: Int(maxClients.trimmingCharacters(in: .whitespacesAndNewlines)),
            reservedSlots: Int(reservedSlots.trimmingCharacters(in: .whitespacesAndNewlines)),
            password: clearPassword ? "" : (password.isEmpty ? nil : password),
            hostMessage: hostMessage,
            hostMessageMode: TS3HostMessageMode.value(forDraft: hostMessageMode),
            hostBannerURL: hostBannerURL,
            hostBannerGraphicsURL: hostBannerGraphicsURL,
            hostBannerMode: hostBannerMode,
            hostBannerGraphicsInterval: Int(hostBannerGraphicsInterval.trimmingCharacters(in: .whitespacesAndNewlines)),
            hostButtonTooltip: hostButtonTooltip,
            hostButtonURL: hostButtonURL,
            hostButtonGraphicsURL: hostButtonGraphicsURL,
            iconId: Int(iconId.trimmingCharacters(in: .whitespacesAndNewlines)),
            downloadQuota: Int64(downloadQuota.trimmingCharacters(in: .whitespacesAndNewlines)),
            uploadQuota: Int64(uploadQuota.trimmingCharacters(in: .whitespacesAndNewlines)),
            maxDownloadTotalBandwidth: Int64(maxDownloadTotalBandwidth.trimmingCharacters(in: .whitespacesAndNewlines)),
            maxUploadTotalBandwidth: Int64(maxUploadTotalBandwidth.trimmingCharacters(in: .whitespacesAndNewlines)),
            complainAutoBanCount: Int(complainAutoBanCount.trimmingCharacters(in: .whitespacesAndNewlines)),
            complainAutoBanTime: Int(complainAutoBanTime.trimmingCharacters(in: .whitespacesAndNewlines)),
            complainRemoveTime: Int(complainRemoveTime.trimmingCharacters(in: .whitespacesAndNewlines)),
            minClientsInChannelBeforeForcedSilence: Int(minClientsInChannelBeforeForcedSilence.trimmingCharacters(in: .whitespacesAndNewlines)),
            prioritySpeakerDimmModificator: Double(prioritySpeakerDimmModificator.trimmingCharacters(in: .whitespacesAndNewlines)),
            antiFloodPointsTickReduce: Int(antiFloodPointsTickReduce.trimmingCharacters(in: .whitespacesAndNewlines)),
            antiFloodPointsNeededCommandBlock: Int(antiFloodPointsNeededCommandBlock.trimmingCharacters(in: .whitespacesAndNewlines)),
            antiFloodPointsNeededIPBlock: Int(antiFloodPointsNeededIPBlock.trimmingCharacters(in: .whitespacesAndNewlines)),
            antiFloodPointsNeededPluginBlock: Int(antiFloodPointsNeededPluginBlock.trimmingCharacters(in: .whitespacesAndNewlines)),
            isClientLoggingEnabled: logClient,
            isQueryLoggingEnabled: logQuery,
            isChannelLoggingEnabled: logChannel,
            isPermissionLoggingEnabled: logPermissions,
            isServerLoggingEnabled: logServer,
            isFileTransferLoggingEnabled: logFileTransfer,
            isWeblistEnabled: weblistEnabled,
            codecEncryptionMode: codecEncryptionMode,
            defaultServerGroupId: Int(defaultServerGroupId.trimmingCharacters(in: .whitespacesAndNewlines)),
            defaultChannelGroupId: Int(defaultChannelGroupId.trimmingCharacters(in: .whitespacesAndNewlines)),
            defaultChannelAdminGroupId: Int(defaultChannelAdminGroupId.trimmingCharacters(in: .whitespacesAndNewlines)),
            neededIdentitySecurityLevel: Int(neededIdentitySecurityLevel.trimmingCharacters(in: .whitespacesAndNewlines)),
            minClientVersion: Int(minClientVersion.trimmingCharacters(in: .whitespacesAndNewlines)),
            minAndroidVersion: Int(minAndroidVersion.trimmingCharacters(in: .whitespacesAndNewlines)),
            minIOSVersion: Int(minIOSVersion.trimmingCharacters(in: .whitespacesAndNewlines))
        )
    }

    private func exportDraft() {
        do {
            let encoder = JSONEncoder()
            encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
            draftDocument = TS3TextFileDocument(data: try encoder.encode(currentDraft))
            isExportingDraft = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareDraftImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let draft = try JSONDecoder().decode(ServerSettingsDraft.self, from: Data(contentsOf: url))
            let validationMessages = serverDraftValidationMessages(for: draft)
            pendingDraftImport = ServerSettingsDraftImportConfirmation(
                draft: draft,
                previewMessage: settingsSnapshotMessage(
                    for: draft,
                    validationMessages: validationMessages
                ),
                validationMessages: validationMessages
            )
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func serverDraftValidationMessages(for draft: ServerSettingsDraft) -> [String] {
        TS3ServerSettingsDraftValidator.validationMessages(
            name: draft.name,
            port: draft.port ?? "",
            autostart: draft.autostart,
            maxClients: draft.maxClients,
            reservedSlots: draft.reservedSlots,
            hostMessageMode: draft.hostMessageMode,
            hostBannerMode: draft.hostBannerMode ?? "",
            hostBannerGraphicsInterval: draft.hostBannerGraphicsInterval ?? "",
            iconId: draft.iconId,
            downloadQuota: draft.downloadQuota,
            uploadQuota: draft.uploadQuota,
            maxDownloadTotalBandwidth: draft.maxDownloadTotalBandwidth ?? "",
            maxUploadTotalBandwidth: draft.maxUploadTotalBandwidth ?? "",
            complainAutoBanCount: draft.complainAutoBanCount,
            complainAutoBanTime: draft.complainAutoBanTime,
            complainRemoveTime: draft.complainRemoveTime,
            minClientsInChannelBeforeForcedSilence: draft.minClientsInChannelBeforeForcedSilence,
            prioritySpeakerDimmModificator: draft.prioritySpeakerDimmModificator,
            antiFloodPointsTickReduce: draft.antiFloodPointsTickReduce ?? "",
            antiFloodPointsNeededCommandBlock: draft.antiFloodPointsNeededCommandBlock ?? "",
            antiFloodPointsNeededIPBlock: draft.antiFloodPointsNeededIPBlock ?? "",
            antiFloodPointsNeededPluginBlock: draft.antiFloodPointsNeededPluginBlock ?? "",
            logClient: draft.logClient,
            logQuery: draft.logQuery,
            logChannel: draft.logChannel,
            logPermissions: draft.logPermissions,
            logServer: draft.logServer,
            logFileTransfer: draft.logFileTransfer,
            weblistEnabled: draft.weblistEnabled,
            codecEncryptionMode: draft.codecEncryptionMode,
            defaultServerGroupId: draft.defaultServerGroupId ?? "",
            defaultChannelGroupId: draft.defaultChannelGroupId ?? "",
            defaultChannelAdminGroupId: draft.defaultChannelAdminGroupId ?? "",
            neededIdentitySecurityLevel: draft.neededIdentitySecurityLevel ?? "",
            minClientVersion: draft.minClientVersion ?? "",
            minAndroidVersion: draft.minAndroidVersion ?? "",
            minIOSVersion: draft.minIOSVersion ?? ""
        )
    }

    private func applyDraft(_ draft: ServerSettingsDraft) {
        name = draft.name
        phoneticName = draft.phoneticName ?? ""
        port = draft.port ?? ""
        machineId = draft.machineId ?? ""
        autostart = Self.boolDraftValue(draft.autostart)
        welcomeMessage = draft.welcomeMessage
        maxClients = draft.maxClients
        reservedSlots = draft.reservedSlots
        clearPassword = draft.clearPassword
        password = draft.password
        hostMessage = draft.hostMessage
        hostMessageMode = Self.hostMessageModeDraftText(draft.hostMessageMode)
        hostBannerURL = draft.hostBannerURL
        hostBannerGraphicsURL = draft.hostBannerGraphicsURL
        hostBannerMode = (draft.hostBannerMode ?? "").trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            ? nil
            : TS3HostBannerMode.value(forDraft: draft.hostBannerMode ?? "")
        hostBannerGraphicsInterval = draft.hostBannerGraphicsInterval ?? ""
        hostButtonTooltip = draft.hostButtonTooltip
        hostButtonURL = draft.hostButtonURL
        hostButtonGraphicsURL = draft.hostButtonGraphicsURL
        iconId = draft.iconId
        downloadQuota = draft.downloadQuota
        uploadQuota = draft.uploadQuota
        maxDownloadTotalBandwidth = draft.maxDownloadTotalBandwidth ?? ""
        maxUploadTotalBandwidth = draft.maxUploadTotalBandwidth ?? ""
        complainAutoBanCount = draft.complainAutoBanCount
        complainAutoBanTime = draft.complainAutoBanTime
        complainRemoveTime = draft.complainRemoveTime
        minClientsInChannelBeforeForcedSilence = draft.minClientsInChannelBeforeForcedSilence
        prioritySpeakerDimmModificator = draft.prioritySpeakerDimmModificator
        antiFloodPointsTickReduce = draft.antiFloodPointsTickReduce ?? ""
        antiFloodPointsNeededCommandBlock = draft.antiFloodPointsNeededCommandBlock ?? ""
        antiFloodPointsNeededIPBlock = draft.antiFloodPointsNeededIPBlock ?? ""
        antiFloodPointsNeededPluginBlock = draft.antiFloodPointsNeededPluginBlock ?? ""
        logClient = Self.boolDraftValue(draft.logClient)
        logQuery = Self.boolDraftValue(draft.logQuery)
        logChannel = Self.boolDraftValue(draft.logChannel)
        logPermissions = Self.boolDraftValue(draft.logPermissions)
        logServer = Self.boolDraftValue(draft.logServer)
        logFileTransfer = Self.boolDraftValue(draft.logFileTransfer)
        weblistEnabled = Self.boolDraftValue(draft.weblistEnabled)
        codecEncryptionMode = draft.codecEncryptionMode.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            ? nil
            : TS3CodecEncryptionMode.value(forDraft: draft.codecEncryptionMode)
        defaultServerGroupId = draft.defaultServerGroupId ?? ""
        defaultChannelGroupId = draft.defaultChannelGroupId ?? ""
        defaultChannelAdminGroupId = draft.defaultChannelAdminGroupId ?? ""
        neededIdentitySecurityLevel = draft.neededIdentitySecurityLevel ?? ""
        minClientVersion = draft.minClientVersion ?? ""
        minAndroidVersion = draft.minAndroidVersion ?? ""
        minIOSVersion = draft.minIOSVersion ?? ""
    }

    private func hostMessageModeTitle(_ value: String) -> String {
        guard let numericValue = TS3HostMessageMode.value(forDraft: value) else { return value }
        return hostMessageModeTitle(numericValue)
    }

    private func hostMessageModeTitle(_ value: Int) -> String {
        let title: String
        switch TS3HostMessageMode(rawValue: value) {
        case .some(.none):
            title = localized("serverSettings.hostMessageMode.none")
        case .some(.log):
            title = localized("serverSettings.hostMessageMode.log")
        case .some(.modal):
            title = localized("serverSettings.hostMessageMode.modal")
        case .some(.modalQuit):
            title = localized("serverSettings.hostMessageMode.modalQuit")
        case nil:
            return localized("serverSettings.unknownValueFormat", value)
        }
        return localized("serverSettings.valueWithNumberFormat", title, value)
    }

    private func codecEncryptionModeTitle(_ value: String) -> String {
        guard let numericValue = TS3CodecEncryptionMode.value(forDraft: value) else { return value }
        return codecEncryptionModeTitle(numericValue)
    }

    private func codecEncryptionModeTitle(_ value: Int) -> String {
        let title: String
        switch TS3CodecEncryptionMode(rawValue: value) {
        case .some(.individual):
            title = localized("serverSettings.codecEncryption.individual")
        case .some(.disabled):
            title = localized("serverSettings.disabled")
        case .some(.enabled):
            title = localized("serverSettings.enabled")
        case nil:
            return localized("serverSettings.unknownValueFormat", value)
        }
        return localized("serverSettings.valueWithNumberFormat", title, value)
    }

    private func hostBannerModeTitle(_ value: String) -> String {
        guard let numericValue = TS3HostBannerMode.value(forDraft: value) else { return value }
        return hostBannerModeTitle(numericValue)
    }

    private func hostBannerModeTitle(_ value: Int) -> String {
        let title: String
        switch TS3HostBannerMode(rawValue: value) {
        case .some(.noAdjust):
            title = localized("serverSettings.bannerMode.noAdjustment")
        case .some(.ignoreAspect):
            title = localized("serverSettings.bannerMode.ignoreAspect")
        case .some(.keepAspect):
            title = localized("serverSettings.bannerMode.keepAspect")
        case nil:
            return localized("serverSettings.unknownValueFormat", value)
        }
        return localized("serverSettings.valueWithNumberFormat", title, value)
    }

    private func weblistTitle(_ value: String) -> String {
        guard let enabled = Self.boolDraftValue(value) else { return localized("serverSettings.unchanged") }
        return enabled ? localized("serverSettings.listed") : localized("serverSettings.hidden")
    }

    private func boolDraftText(_ value: Bool?) -> String {
        value.map { $0 ? "1" : "0" } ?? ""
    }

    private func boolTitle(_ value: String?) -> String {
        guard let enabled = Self.boolDraftValue(value) else { return localized("serverSettings.unchanged") }
        return enabled ? localized("serverSettings.enabled") : localized("serverSettings.disabled")
    }

    private func groupPickerTitle(_ group: TS3GroupSummary) -> String {
        "\(group.name) (\(group.id))"
    }

    private func groupDraftTitle(_ value: String) -> String {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? localized("serverSettings.unchanged") : localized("serverSettings.groupFormat", trimmed)
    }

    private func groupSnapshotTitle(_ value: String, groups: [TS3GroupSummary]) -> String {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let groupId = Int(trimmed) else { return localized("serverSettings.unchanged") }
        return TS3GroupSummary.name(for: groupId, in: groups)
    }

    private func shouldShowCustomGroup(_ value: String, in groups: [TS3GroupSummary]) -> Bool {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let groupId = Int(trimmed) else { return false }
        return !groups.contains { $0.id == groupId }
    }

    private static func boolDraftValue(_ value: String?) -> Bool? {
        TS3ServerSettingsDraftValidator.boolDraftValue(value)
    }

    private static func hostMessageModeDraftText(_ value: String) -> String {
        let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty, let numericValue = TS3HostMessageMode.value(forDraft: trimmed) else { return trimmed }
        return String(numericValue)
    }

    private static func decimalText(_ value: Double) -> String {
        String(format: "%.2f", value)
    }
}

struct FileBrowserSheet: View {
    private struct FileBrowserFilterPresetImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3FileBrowserFilterPresetImportPreview
        let id = UUID()
    }

    private struct UploadConflictPreview: Identifiable {
        let url: URL
        let remoteEntry: TS3FileEntrySummary
        let localSize: Int64?

        var id: String {
            "\(url.path)|\(remoteEntry.id)"
        }

        var canResume: Bool {
            !remoteEntry.isDirectory && (remoteEntry.incompleteSize ?? 0) > 0
        }

        var isBlockingOverwrite: Bool {
            remoteEntry.isDirectory
        }
    }

    private enum TransferConfirmation: Identifiable {
        case cancelActive
        case clearCompleted
        case clearFailed
        case clearInactive
        case deleteAllBookmarks
        case deleteAllFilterPresets

        var id: String {
            switch self {
            case .cancelActive: return "cancel-active"
            case .clearCompleted: return "clear-completed"
            case .clearFailed: return "clear-failed"
            case .clearInactive: return "clear-inactive"
            case .deleteAllBookmarks: return "delete-all-bookmarks"
            case .deleteAllFilterPresets: return "delete-all-filter-presets"
            }
        }
    }

    private enum FileSortMode: String, CaseIterable, Identifiable {
        case name
        case type
        case size
        case modified

        var id: String { rawValue }

        var fallbackTitle: String {
            switch self {
            case .name: return "Name"
            case .type: return "Type"
            case .size: return "Size"
            case .modified: return "Modified"
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var directoryName = ""
    @State private var bookmarkName = ""
    @State private var presetName = ""
    @State private var pathText = "/"
    @State private var searchText = ""
    @State private var sortMode: FileSortMode = .name
    @State private var sortAscending = true
    @State private var selectedEntryIDs: Set<String> = []
    @State private var isShowingFileImporter = false
    @State private var isExportingDownloadedFile = false
    @State private var downloadedFileDocument = TS3DownloadedFileDocument()
    @State private var downloadedFileExportName = "download"
    @State private var isExportingDirectorySnapshot = false
    @State private var isExportingTransferSnapshot = false
    @State private var isImportingBookmarks = false
    @State private var isExportingBookmarks = false
    @State private var isImportingPresets = false
    @State private var isExportingPresets = false
    @State private var directorySnapshotDocument = TS3TextFileDocument()
    @State private var transferSnapshotDocument = TS3TextFileDocument()
    @State private var bookmarksDocument = TS3BookmarkFileDocument()
    @State private var presetsDocument = TS3BookmarkFileDocument()
    @State private var pendingUploadURLs: [URL] = []
    @State private var uploadConflictPreviews: [UploadConflictPreview] = []
    @State private var isShowingUploadConflictActions = false
    @State private var pendingPresetImport: FileBrowserFilterPresetImportConfirmation?
    @State private var transferConfirmation: TransferConfirmation?
    @State private var isConfirmingSelectedDelete = false
    @State private var isMovingSelectedEntries = false
    @State private var selectedMoveDestinationDirectory = "/"

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var selectedChannel: TS3ChannelSummary? {
        guard let channelId = model.fileBrowserChannelId else { return nil }
        return model.channels.first { $0.id == channelId }
    }

    var body: some View {
        NavigationView {
            List {
                if !model.channels.isEmpty {
                    Section(header: Text(localized("files.channel"))) {
                        Picker(localized("files.channel"), selection: channelSelection) {
                            ForEach(model.channels) { channel in
                                Text(channel.name).tag(channel.id)
                            }
                        }
                        SecureField(localized("files.filePassword"), text: $model.fileBrowserPassword)
                            .ts3PlainTextField()
                    }
                }

                Section(header: Text(localized("files.serverFileStatus"))) {
                    fileStatusRow(localized("files.fileTransferPort"), model.serverInfo.fileTransferPort.map(String.init))
                    fileStatusRow(localized("files.fileBase"), model.serverInfo.fileBase)
                    fileStatusRow(localized("files.downloadQuota"), model.serverInfo.downloadQuota.map(Self.sizeText))
                    fileStatusRow(localized("files.uploadQuota"), model.serverInfo.uploadQuota.map(Self.sizeText))
                    fileStatusRow(localized("files.downloadedThisMonth"), model.serverInfo.monthlyBytesDownloaded.map(Self.sizeText))
                    fileStatusRow(localized("files.uploadedThisMonth"), model.serverInfo.monthlyBytesUploaded.map(Self.sizeText))
                    fileStatusRow(localized("files.totalDownloaded"), model.serverInfo.totalBytesDownloaded.map(Self.sizeText))
                    fileStatusRow(localized("files.totalUploaded"), model.serverInfo.totalBytesUploaded.map(Self.sizeText))
                    Button(localized("files.copyFileStatus")) {
                        TS3PlatformSupport.copyToPasteboard(fileStatusSnapshot)
                    }
                    .disabled(fileStatusSnapshot.isEmpty)
                }

                Section(header: Text(localized("files.path"))) {
                    HStack {
                        TextField("/", text: $pathText)
                            .ts3PlainTextField()
                        Button(localized("files.go")) {
                            model.jumpToFileDirectory(pathText)
                            pathText = model.fileBrowserPath
                        }
                        .buttonStyle(.borderless)
                        .disabled(pathText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                    }
                    Button(localized("files.copyCurrentPath")) {
                        TS3PlatformSupport.copyToPasteboard(model.fileBrowserPath)
                    }
                }

                Section(header: Text(localized("files.bookmarks"))) {
                    TextField(localized("files.bookmarkName"), text: $bookmarkName)
                        .ts3PlainTextField()
                    Button(localized("files.saveCurrentLocation")) {
                        model.saveCurrentFileBrowserBookmark(name: bookmarkName)
                        bookmarkName = ""
                    }
                    .disabled(bookmarkName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                    if model.fileBrowserBookmarks.isEmpty {
                        Text(localized("files.noSavedBookmarks"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(model.fileBrowserBookmarks) { bookmark in
                            HStack {
                                VStack(alignment: .leading, spacing: 2) {
                                    Text(bookmark.name)
                                        .font(.subheadline.weight(.semibold))
                                    Text(fileBookmarkSummary(bookmark))
                                        .font(.caption)
                                        .foregroundColor(.secondary)
                                }
                                Spacer()
                                Menu {
                                    Button(localized("files.openBookmark")) {
                                        model.applyFileBrowserBookmark(bookmark)
                                    }
                                    Button(localized("files.useName")) {
                                        bookmarkName = bookmark.name
                                    }
                                    Button(localized("files.deleteBookmark")) {
                                        model.deleteFileBrowserBookmark(bookmark)
                                    }
                                } label: {
                                    Image(systemName: "ellipsis.circle")
                                }
                            }
                        }
                    }
                    Button(localized("files.exportBookmarks")) {
                        exportBookmarks()
                    }
                    .disabled(model.fileBrowserBookmarks.isEmpty)
                    Button(localized("files.importBookmarks")) {
                        isImportingBookmarks = true
                    }
                    Button(localized("files.deleteAllBookmarks")) {
                        transferConfirmation = .deleteAllBookmarks
                    }
                    .foregroundColor(.red)
                    .disabled(model.fileBrowserBookmarks.isEmpty)
                }

                Section(header: Text(localized("files.search"))) {
                    Picker(localized("files.sortBy"), selection: $sortMode) {
                        ForEach(FileSortMode.allCases) { mode in
                            Text(sortTitle(mode)).tag(mode)
                        }
                    }
                    Toggle(localized("files.ascending"), isOn: $sortAscending)
                    TextField(localized("files.searchFiles"), text: $searchText)
                        .ts3PlainTextField()
                    Menu {
                        TextField(localized("files.presetName"), text: $presetName)
                        Button(localized("files.saveCurrentFilters")) {
                            model.saveFileBrowserFilterPreset(
                                name: presetName,
                                sortMode: sortMode.rawValue,
                                sortAscending: sortAscending,
                                searchText: searchText
                            )
                            presetName = ""
                        }
                        .disabled(presetName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                        if model.fileBrowserFilterPresets.isEmpty {
                            Text(localized("files.noSavedFilterPresets"))
                        } else {
                            ForEach(model.fileBrowserFilterPresets) { preset in
                                Menu {
                                    Button(localized("files.applyPreset")) {
                                        applyPreset(preset)
                                    }
                                    Button(localized("files.useName")) {
                                        presetName = preset.name
                                    }
                                    Button(localized("files.deletePreset")) {
                                        model.deleteFileBrowserFilterPreset(preset)
                                    }
                                } label: {
                                    VStack(alignment: .leading) {
                                        Text(preset.name)
                                        Text(presetSummary(preset))
                                    }
                                }
                            }
                        }
                        Divider()
                        Button(localized("files.exportPresets")) {
                            exportPresets()
                        }
                        .disabled(model.fileBrowserFilterPresets.isEmpty)
                        Button(localized("files.importPresets")) {
                            isImportingPresets = true
                        }
                        Button(localized("files.deleteAllPresets")) {
                            transferConfirmation = .deleteAllFilterPresets
                        }
                        .disabled(model.fileBrowserFilterPresets.isEmpty)
                    } label: {
                        Label(localized("files.filterPresets"), systemImage: "line.3.horizontal.decrease.circle")
                    }
                    if hasLocalFilters {
                        Button(localized("files.clearFilters")) {
                            sortMode = .name
                            sortAscending = true
                            searchText = ""
                        }
                    }
                }

                Section(header: Text(model.fileBrowserPath)) {
                    if model.fileBrowserPath != "/" {
                        Button(localized("files.parentDirectory")) {
                            model.leaveFileDirectory()
                        }
                    }

                    if !visibleFileEntries.isEmpty {
                        Menu {
                            Button(localized("files.selectVisibleFiles")) {
                                selectedEntryIDs.formUnion(visibleFiles.map(\.id))
                            }
                            .disabled(visibleFiles.isEmpty)
                            Button(localized("files.selectVisibleEntries")) {
                                selectedEntryIDs.formUnion(visibleFileEntries.map(\.id))
                            }
                            Button(localized("files.deselectVisibleEntries")) {
                                selectedEntryIDs.subtract(visibleFileEntries.map(\.id))
                            }
                            .disabled(selectedEntries.isEmpty)
                        } label: {
                            Label(localized("files.visibleSelection"), systemImage: "checklist")
                        }
                    }

                    if hasSelection {
                        HStack {
                            Text(localized("files.selectedFormat", selectedEntries.count))
                                .font(.caption)
                                .foregroundColor(.secondary)
                            Spacer()
                            Button(localized("files.clear")) {
                                selectedEntryIDs.removeAll()
                            }
                            .buttonStyle(.borderless)
                        }

                        HStack(spacing: 12) {
                            Button(localized("files.downloadSelected")) {
                                model.downloadFileEntries(selectedEntries)
                            }
                            .buttonStyle(.borderless)
                            .disabled(selectedEntries.allSatisfy(\.isDirectory))
                            Button(localized("files.moveSelected")) {
                                selectedMoveDestinationDirectory = model.fileBrowserPath
                                isMovingSelectedEntries = true
                            }
                            .buttonStyle(.borderless)
                            .disabled(selectedEntries.isEmpty)
                            Button(localized("files.deleteSelected")) {
                                isConfirmingSelectedDelete = true
                            }
                            .buttonStyle(.borderless)
                            .foregroundColor(.red)
                            .disabled(selectedEntries.isEmpty)
                        }
                        .font(.caption)
                    }

                    if visibleFileEntries.isEmpty {
                        Text(isSearching ? localized("files.noMatchingFiles") : localized("files.noFiles"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(visibleFileEntries) { entry in
                            FileEntryRow(
                                entry: entry,
                                isSelected: selectedEntryIDs.contains(entry.id),
                                onSelect: {
                                    if entry.isDirectory {
                                        model.enterFileDirectory(entry)
                                    } else {
                                        toggleSelection(for: entry)
                                    }
                                },
                                onSelectionToggle: {
                                    toggleSelection(for: entry)
                                }
                            )
                                .environmentObject(model)
                        }
                    }
                }

                Section(header: Text(localized("files.newDirectory"))) {
                    TextField(localized("files.directoryName"), text: $directoryName)
                        .ts3PlainTextField()
                    Button(localized("files.createDirectory")) {
                        model.createFileDirectory(named: directoryName)
                        directoryName = ""
                    }
                    .disabled(directoryName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                }

                Section(header: Text(localized("files.transfer"))) {
                    VStack(alignment: .leading, spacing: 6) {
                        Text(localized("files.downloadsFolder"))
                            .font(.caption.weight(.semibold))
                        Text(model.downloadsDirectoryURL.path)
                            .font(.system(.caption2, design: .monospaced))
                            .foregroundColor(.secondary)
                            .lineLimit(1)
                            .truncationMode(.middle)
                        if !model.downloadedFiles.isEmpty {
                            Text(localized("files.downloadsAvailabilityFormat", model.downloadedFilesExistingCount, model.downloadedFilesMissingCount))
                                .font(.caption2)
                                .foregroundColor(.secondary)
                        }
                        HStack {
                            Button(localized("files.openFolder")) {
                                model.openDownloadsDirectory()
                            }
                            .buttonStyle(.borderless)
                            Button(localized("files.copyFolderPath")) {
                                TS3PlatformSupport.copyToPasteboard(model.downloadsDirectoryURL.path)
                            }
                            .buttonStyle(.borderless)
                            Button(localized("files.removeMissing")) {
                                model.pruneMissingDownloadedFiles()
