struct RenameFileEntrySheet: View {
    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    let entry: TS3FileEntrySummary
    @Binding var newName: String

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(entry.name)) {
                    TextField(localized("files.rename.newName"), text: $newName)
                        .ts3PlainTextField()
                }
                Section(header: Text(localized("files.rename.preview"))) {
                    if trimmedNewName.isEmpty {
                        Text(localized("files.rename.enterName"))
                            .foregroundColor(.secondary)
                    } else if trimmedNewName == entry.name {
                        Text(localized("files.rename.unchanged"))
                            .foregroundColor(.secondary)
                    } else if renameConflict != nil {
                        Text(localized("files.rename.conflictFormat", trimmedNewName))
                            .foregroundColor(.red)
                    } else {
                        Text(localized("files.rename.previewFormat", entry.path, newPath))
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                }
                Section {
                    Button(localized("files.rename")) {
                        model.renameFileEntry(entry, to: newName)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(trimmedNewName.isEmpty || trimmedNewName == entry.name || renameConflict != nil)
                }
            }
            .navigationTitle(localized("files.rename"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.cancel")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }

    private var trimmedNewName: String {
        newName.trimmingCharacters(in: .whitespacesAndNewlines)
    }

    private var newPath: String {
        Self.joinedPath(parentPath: entry.parentPath, name: trimmedNewName)
    }

    private var renameConflict: TS3FileEntrySummary? {
        model.fileEntries.first {
            $0.id != entry.id
                && $0.parentPath == entry.parentPath
                && $0.name.caseInsensitiveCompare(trimmedNewName) == .orderedSame
        }
    }

    private static func joinedPath(parentPath: String, name: String) -> String {
        let parentPath = normalizedDirectoryPath(parentPath)
        if name.hasPrefix("/") {
            return name
        }
        return parentPath + name
    }

    private static func normalizedDirectoryPath(_ path: String) -> String {
        let trimmed = path.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return "/" }
        var result = trimmed
        if !result.hasPrefix("/") {
            result = "/" + result
        }
        if !result.hasSuffix("/") {
            result += "/"
        }
        return result
    }
}

struct MoveFileEntrySheet: View {
    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    let entry: TS3FileEntrySummary
    @Binding var destinationDirectory: String

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(entry.name)) {
                    TextField(localized("files.move.destinationDirectory"), text: $destinationDirectory)
                        .ts3PlainTextField()
                    Text(localized("files.move.destinationHelp"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                Section(header: Text(localized("files.move.preview"))) {
                    if destinationDirectory.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                        Text(localized("files.move.enterDestination"))
                            .foregroundColor(.secondary)
                    } else if preview.isUnchanged {
                        Text(localized("files.move.unchanged"))
