                            .foregroundColor(.secondary)
                    }
                    if !isDestinationKnown {
                        Text(localized("files.move.destinationUnknown"))
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                }
                Section {
                    Button {
                        model.refreshCachedFileDirectory(
                            channelId: entry.channelId,
                            path: normalizedDestinationDirectory
                        )
                    } label: {
                        Label(localized("files.move.loadDestinationPreview"), systemImage: "arrow.clockwise")
                    }
                    .disabled(destinationDirectory.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)

                    Button(localized("files.move.action")) {
                        model.moveFileEntry(entry, toDirectory: destinationDirectory)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(isMoveDisabled)
                }
            }
            .navigationTitle(localized("files.move.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.cancel")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }

    private var isMoveDisabled: Bool {
        destinationDirectory.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            || preview.isUnchanged
            || preview.isBlocking
    }

    private var normalizedDestinationDirectory: String {
        TS3FileMovePreview.normalizedDirectoryPath(destinationDirectory)
    }

    private var knownDestinationEntries: [TS3FileEntrySummary]? {
        model.cachedFileEntries(channelId: entry.channelId, directoryPath: normalizedDestinationDirectory)
    }

    private var isDestinationKnown: Bool {
        knownDestinationEntries != nil
    }

    private var preview: TS3FileMovePreview {
        TS3FileMovePreview.previews(
            for: [entry],
            destinationDirectory: normalizedDestinationDirectory,
            knownDestinationEntries: knownDestinationEntries
        )[0]
    }
}

struct MoveFileEntriesSheet: View {
    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    let entries: [TS3FileEntrySummary]
    @Binding var destinationDirectory: String
    let onMove: () -> Void

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("files.move.selectedEntriesFormat", entries.count))) {
                    TextField(localized("files.move.destinationDirectory"), text: $destinationDirectory)
                        .ts3PlainTextField()
                    Text(localized("files.move.destinationHelp"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                Section(header: Text(localized("files.move.preview"))) {
                    if destinationDirectory.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty {
                        Text(localized("files.move.enterDestination"))
                            .foregroundColor(.secondary)
                    } else if previewItems.isEmpty {
                        Text(localized("files.move.noEntriesMoved"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(previewItems) { item in
                            HStack(alignment: .top, spacing: 8) {
                                Image(systemName: item.entry.isDirectory ? "folder" : "doc")
                                    .foregroundColor(item.entry.isDirectory ? .accentColor : .secondary)
                                VStack(alignment: .leading, spacing: 2) {
                                    Text(item.entry.name)
                                        .lineLimit(1)
                                        .truncationMode(.middle)
                                    Text(item.detail)
                                        .font(.caption)
                                        .foregroundColor(item.isBlocking ? .red : .secondary)
                                        .lineLimit(2)
                                }
                            }
                        }
                    }
                    if !isDestinationKnown {
                        Text(localized("files.move.destinationUnknown"))
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                }
                Section(header: Text(localized("files.move.entries"))) {
                    ForEach(entries) { entry in
                        HStack {
                            Image(systemName: entry.isDirectory ? "folder" : "doc")
                                .foregroundColor(entry.isDirectory ? .accentColor : .secondary)
                            Text(entry.name)
                                .lineLimit(1)
                                .truncationMode(.middle)
                        }
                    }
                }
                Section {
                    Button {
                        model.refreshCachedFileDirectory(
                            channelId: entries.first?.channelId,
                            path: normalizedDestinationDirectory
                        )
                    } label: {
                        Label(localized("files.move.loadDestinationPreview"), systemImage: "arrow.clockwise")
                    }
                    .disabled(destinationDirectory.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)

                    Button(localized("files.move.selectedAction")) {
                        onMove()
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(isMoveDisabled)
                }
            }
            .navigationTitle(localized("files.move.selectedTitle"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.cancel")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }

    private var isMoveDisabled: Bool {
        entries.isEmpty
            || destinationDirectory.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            || previewItems.isEmpty
            || previewItems.contains { $0.isBlocking }
    }

    private var normalizedDestinationDirectory: String {
        TS3FileMovePreview.normalizedDirectoryPath(destinationDirectory)
    }

    private var knownDestinationEntries: [TS3FileEntrySummary]? {
        guard let channelId = entries.first?.channelId else { return nil }
        return model.cachedFileEntries(channelId: channelId, directoryPath: normalizedDestinationDirectory)
    }

    private var isDestinationKnown: Bool {
        knownDestinationEntries != nil
    }

    private var previewItems: [MovePreviewItem] {
        TS3FileMovePreview.previews(
            for: entries,
            destinationDirectory: normalizedDestinationDirectory,
            knownDestinationEntries: knownDestinationEntries
        )
        .compactMap { preview in
            if preview.isUnchanged {
                return nil
            }
            if preview.isMovingDirectoryIntoItself {
                return MovePreviewItem(
                    entry: preview.entry,
                    detail: localized("files.move.directoryIntoItself"),
                    isBlocking: true
                )
            }
            if preview.duplicatesSelectedName {
                return MovePreviewItem(
                    entry: preview.entry,
                    detail: localized("files.move.duplicateSelectedName"),
                    isBlocking: true
                )
            }
            if let conflict = preview.conflict {
                return MovePreviewItem(
                    entry: preview.entry,
                    detail: localized("files.move.conflictFormat", conflict.name),
                    isBlocking: true
                )
            }
            return MovePreviewItem(
                entry: preview.entry,
                detail: "\(preview.entry.path) -> \(preview.newPath)",
                isBlocking: false
            )
        }
    }
}

private struct MovePreviewItem: Identifiable {
    let entry: TS3FileEntrySummary
    let detail: String
    let isBlocking: Bool

    var id: String { entry.id }
}

struct PermissionsSheet: View {
    fileprivate struct PermissionBackupImportConfirmation: Identifiable {
        let url: URL
        let data: Data
        let preview: TS3PermissionBackupPreview
        let id = UUID()
    }

    private enum AssignedPermissionFilter: String, CaseIterable, Identifiable {
        case all
        case negated
        case skipped
        case direct
        case positiveValue
        case zeroValue
        case negativeValue

        var id: String { rawValue }

        var title: String {
            switch self {
            case .all: return "All Permissions"
            case .negated: return "Negated"
            case .skipped: return "Skipped"
            case .direct: return "Direct"
            case .positiveValue: return "Positive Value"
            case .zeroValue: return "Zero Value"
            case .negativeValue: return "Negative Value"
            }
        }

        func matches(_ permission: TS3PermissionSummary) -> Bool {
            switch self {
            case .all:
                return true
            case .negated:
                return permission.isNegated
            case .skipped:
                return permission.isSkipped
            case .direct:
                return !permission.isNegated && !permission.isSkipped
            case .positiveValue:
                return permission.value > 0
            case .zeroValue:
                return permission.value == 0
            case .negativeValue:
                return permission.value < 0
            }
        }
    }

    private enum AssignedPermissionSortMode: String, CaseIterable, Identifiable {
        case name
        case value
        case flags

        var id: String { rawValue }

        var title: String {
            switch self {
            case .name: return "Name"
            case .value: return "Value"
            case .flags: return "Flags"
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var searchText = ""
    @State private var permissionName = ""
    @State private var permissionValue = "0"
    @State private var permissionNegated = false
    @State private var permissionSkip = false
    @State private var assignedSearchText = ""
    @State private var assignedFilter: AssignedPermissionFilter = .all
    @State private var assignedSortMode: AssignedPermissionSortMode = .name
    @State private var assignedSortAscending = true
    @State private var presetName = ""
    @State private var isExportingPermissionSnapshot = false
    @State private var isExportingPermissionBackup = false
    @State private var isExportingPresets = false
    @State private var isImportingPermissions = false
    @State private var isImportingPresets = false
    @State private var isConfirmingDeletePresets = false
    @State private var permissionExportDocument = TS3TextFileDocument()
    @State private var permissionBackupDocument = TS3TextFileDocument()
    @State private var presetsDocument = TS3BookmarkFileDocument()
    @State private var pendingPermissionBackupImport: PermissionBackupImportConfirmation?
    @State private var isConfirmingDeleteVisible = false

    var filteredPermissionInfos: [TS3PermissionInfoSummary] {
        let query = searchText.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !query.isEmpty else { return model.permissionInfos }
        return model.permissionInfos.filter {
            $0.name.localizedCaseInsensitiveContains(query) ||
            String($0.id).contains(query) ||
            ($0.description?.localizedCaseInsensitiveContains(query) ?? false)
        }
    }

    var displayedPermissions: [TS3PermissionSummary] {
        model.permissionEditScope == .ownClient ? model.ownClientPermissions : model.scopedPermissions
    }

    var filteredDisplayedPermissions: [TS3PermissionSummary] {
        let query = assignedSearchText.trimmingCharacters(in: .whitespacesAndNewlines)
        let filtered = displayedPermissions.filter { permission in
            assignedFilter.matches(permission) && (
                query.isEmpty
                    || permission.name.localizedCaseInsensitiveContains(query)
                    || String(permission.value).contains(query)
                    || (permission.isNegated && "negated".localizedCaseInsensitiveContains(query))
                    || (permission.isSkipped && "skipped".localizedCaseInsensitiveContains(query))
                    || permission.statusLabels.contains { $0.localizedCaseInsensitiveContains(query) }
                    || permission.inheritanceEffectDescription.localizedCaseInsensitiveContains(query)
            )
        }
        return sortedDisplayedPermissions(filtered)
    }

    var visiblePermissionsSnapshot: String {
        filteredDisplayedPermissions.map(\.clipboardSummary).joined(separator: "\n")
    }

    var permissionDraft: TS3PermissionEditDraft {
        TS3PermissionEditDraft(
            scope: model.permissionEditScope,
            target: model.permissionEditTargetSummary(),
            name: permissionName,
            value: permissionValue,
            negated: permissionNegated,
            skip: permissionSkip
        )
    }

    var permissionDraftValidationMessages: [String] {
        permissionDraft.validationMessages
    }

    var permissionDraftCoverageSummary: TS3PermissionDraftCoverageSummary {
        TS3PermissionDraftCoverageSummary(
            draft: permissionDraft,
            validationMessages: permissionDraftValidationMessages
        )
    }

    var permissionOfficialEditAuditSummary: TS3PermissionOfficialEditAuditSummary {
        TS3PermissionOfficialEditAuditSummary(coverage: permissionDraftCoverageSummary)
    }

    var exportFilename: String {
        switch model.permissionEditScope {
        case .ownClient:
            return "ts3-own-client-permissions"
        case .databaseClient:
            return "ts3-database-client-permissions"
        case .serverGroup:
            return "ts3-server-group-permissions"
        case .channelGroup:
            return "ts3-channel-group-permissions"
        case .channel:
            return "ts3-channel-permissions"
        case .channelClient:
            return "ts3-channel-client-permissions"
        }
    }

    var body: some View {
        NavigationView {
            List {
                Section(header: Text(localized("permissions.target"))) {
                    Picker(localized("permissions.targetPicker"), selection: Binding(
                        get: { model.permissionEditScope },
                        set: { model.selectPermissionScope($0) }
                    )) {
                        ForEach(TS3PermissionEditScope.allCases) { scope in
                            Text(scopeTitle(scope)).tag(scope)
                        }
                    }
                    if model.permissionEditScope == .ownClient, let databaseId = model.ownClientDatabaseId {
                        Text(localized("permissions.databaseIdFormat", databaseId))
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                    if model.permissionEditScope == .databaseClient {
                        if let databaseId = model.selectedDatabaseClientPermissionId {
                            Text(localized("permissions.databaseIdFormat", databaseId))
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                        Picker(localized("permissions.scope.databaseClient"), selection: Binding(
                            get: { model.selectedDatabaseClientPermissionId ?? model.selectedDatabaseClient?.id ?? model.databaseClients.first?.id ?? 0 },
                            set: {
                                model.selectedDatabaseClientPermissionId = $0
                                model.refreshSelectedPermissions()
                            }
                        )) {
                            ForEach(model.databaseClients) { record in
                                Text("\(record.nickname) (#\(record.id))").tag(record.id)
                            }
                        }
                    }
                    if model.permissionEditScope == .serverGroup {
                        Picker(localized("permissions.scope.serverGroup"), selection: Binding(
                            get: { model.selectedServerGroupPermissionId ?? model.serverGroups.first?.id ?? 0 },
                            set: {
                                model.selectedServerGroupPermissionId = $0
                                model.refreshSelectedPermissions()
                            }
                        )) {
                            ForEach(model.serverGroups) { group in
                                Text(group.name).tag(group.id)
                            }
                        }
                    }
                    if model.permissionEditScope == .channelGroup {
                        Picker(localized("permissions.scope.channelGroup"), selection: Binding(
                            get: { model.selectedChannelGroupPermissionId ?? model.channelGroups.first?.id ?? 0 },
                            set: {
                                model.selectedChannelGroupPermissionId = $0
                                model.refreshSelectedPermissions()
                            }
                        )) {
                            ForEach(model.channelGroups) { group in
                                Text(group.name).tag(group.id)
                            }
                        }
                    }
                    if model.permissionEditScope == .channel {
                        Picker(localized("permissions.scope.channel"), selection: Binding(
                            get: { model.selectedChannelPermissionId ?? model.currentChannel?.id ?? model.channels.first?.id ?? 0 },
                            set: {
                                model.selectedChannelPermissionId = $0
                                model.refreshSelectedPermissions()
                            }
                        )) {
                            ForEach(model.channels) { channel in
                                Text(channel.name).tag(channel.id)
                            }
                        }
                    }
                    if model.permissionEditScope == .channelClient {
                        Picker(localized("permissions.scope.channel"), selection: Binding(
                            get: { model.selectedChannelClientPermissionChannelId ?? model.currentChannel?.id ?? model.channels.first?.id ?? 0 },
                            set: {
                                model.selectedChannelClientPermissionChannelId = $0
                                model.selectedChannelClientPermissionClientId = model.members(in: $0).first?.id
                                model.refreshSelectedPermissions()
                            }
                        )) {
                            ForEach(model.channels) { channel in
                                Text(channel.name).tag(channel.id)
                            }
                        }
                        Picker(localized("permissions.client"), selection: Binding(
                            get: { model.selectedChannelClientPermissionClientId ?? model.channelClientPermissionMembers().first?.id ?? 0 },
                            set: {
                                model.selectedChannelClientPermissionClientId = $0
                                model.refreshSelectedPermissions()
                            }
                        )) {
                            ForEach(model.channelClientPermissionMembers()) { member in
                                Text(member.nickname).tag(member.id)
                            }
                        }
                    }
                }

                Section(header: Text(localized("permissions.scopePermissionsFormat", scopeTitle(model.permissionEditScope)))) {
                    Button(localized("permissions.copyVisible")) {
                        TS3PlatformSupport.copyToPasteboard(visiblePermissionsSnapshot)
                    }
                    .disabled(filteredDisplayedPermissions.isEmpty)

                    Button(localized("permissions.exportVisible")) {
                        permissionExportDocument = TS3TextFileDocument(data: Data(visiblePermissionsSnapshot.utf8))
                        isExportingPermissionSnapshot = true
                    }
                    .disabled(filteredDisplayedPermissions.isEmpty)

                    Button(localized("permissions.exportBackup")) {
                        exportPermissionBackup()
                    }
                    .disabled(displayedPermissions.isEmpty)

                    Button(localized("permissions.importBackup")) {
                        isImportingPermissions = true
                    }
                    .disabled(model.state != .connected)

                    Button(localized("permissions.deleteVisible")) {
                        isConfirmingDeleteVisible = true
                    }
                    .disabled(model.state != .connected || filteredDisplayedPermissions.isEmpty)
                    .foregroundColor(.red)

                    Picker(localized("permissions.filter"), selection: $assignedFilter) {
                        ForEach(AssignedPermissionFilter.allCases) { filter in
                            Text(assignedFilterTitle(filter)).tag(filter)
                        }
                    }
                    Picker(localized("groups.sortBy"), selection: $assignedSortMode) {
                        ForEach(AssignedPermissionSortMode.allCases) { mode in
                            Text(assignedSortModeTitle(mode)).tag(mode)
                        }
                    }
                    Toggle(localized("groups.ascending"), isOn: $assignedSortAscending)
                    TextField(localized("permissions.searchAssigned"), text: $assignedSearchText)
                        .ts3PlainTextField()
                    Menu {
                        TextField(localized("groups.presetName"), text: $presetName)
                        Button(localized("groups.saveCurrentFilters")) {
                            model.savePermissionFilterPreset(
                                name: presetName,
                                scope: model.permissionEditScope.rawValue,
                                assignedFilter: assignedFilter.rawValue,
                                assignedSortMode: assignedSortMode.rawValue,
                                assignedSortAscending: assignedSortAscending,
                                assignedSearchText: assignedSearchText,
                                permissionSearchText: searchText
                            )
                            presetName = ""
                        }
                        .disabled(presetName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                        if model.permissionFilterPresets.isEmpty {
                            Text(localized("permissions.noSavedFilterPresets"))
                        } else {
                            ForEach(model.permissionFilterPresets) { preset in
                                Menu {
                                    Button(localized("groups.applyPreset")) {
                                        applyPreset(preset)
                                    }
                                    Button(localized("groups.useName")) {
                                        presetName = preset.name
                                    }
                                    Button(localized("groups.deletePreset")) {
                                        model.deletePermissionFilterPreset(preset)
                                    }
                                } label: {
                                    VStack(alignment: .leading) {
                                        Text(preset.name)
                                        Text(presetSummary(preset))
                                    }
                                }
                            }
                        }
                        Divider()
                        Button(localized("groups.exportPresets")) {
                            exportPresets()
                        }
                        .disabled(model.permissionFilterPresets.isEmpty)
                        Button(localized("groups.importPresets")) {
                            isImportingPresets = true
                        }
                        Button(localized("groups.deleteAllPresets")) {
                            isConfirmingDeletePresets = true
                        }
                        .disabled(model.permissionFilterPresets.isEmpty)
                    } label: {
                        Label(localized("groups.filterPresets"), systemImage: "line.3.horizontal.decrease.circle")
                    }
                    if hasAssignedPermissionOptions {
                        Button(localized("permissions.clearFilters")) {
                            assignedFilter = .all
                            assignedSortMode = .name
                            assignedSortAscending = true
                            assignedSearchText = ""
                        }
                    }

                    if displayedPermissions.isEmpty {
                        Text(localized("permissions.noPermissions"))
                            .foregroundColor(.secondary)
                    } else if filteredDisplayedPermissions.isEmpty {
                        Text(localized("permissions.noMatchingPermissions"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(filteredDisplayedPermissions) { permission in
                            PermissionRow(permission: permission, canDelete: model.state == .connected) {
                                permissionName = permission.name
                                permissionValue = "\(permission.value)"
                                permissionNegated = permission.isNegated
                                permissionSkip = permission.isSkipped
                            } delete: {
                                model.deleteSelectedPermission(permission)
                            }
                        }
                    }
                }

                Section(header: Text(localized("permissions.addPermission"))) {
                    Text(localized("permissions.targetFormat", permissionDraft.target))
                        .font(.caption)
                        .foregroundColor(.secondary)
                    TextField(localized("permissions.permissionName"), text: $permissionName)
                        .ts3PlainTextField()
                    TextField(localized("permissions.value"), text: $permissionValue)
                        .ts3NumericKeyboard()
                        .ts3PlainTextField()
                    Toggle(localized("permissions.flag.negated"), isOn: $permissionNegated)
                        .disabled(model.permissionEditScope == .ownClient || model.permissionEditScope == .databaseClient || model.permissionEditScope == .channel || model.permissionEditScope == .channelClient)
                    Toggle(localized("permissions.flag.skip"), isOn: $permissionSkip)
                        .disabled(model.permissionEditScope == .channel)
                    Text(permissionEffectDescription(isNegated: permissionDraft.effectiveNegated, isSkipped: permissionDraft.effectiveSkip))
                        .font(.caption)
                        .foregroundColor(.secondary)
                    ServerInfoDetailRow(
                        label: localized("permissions.draftCoverage"),
                        value: localized(
                            "permissions.draftCoverageFormat",
                            permissionDraftCoverageSummary.requiredFieldCount,
                            permissionDraftCoverageSummary.requiredFieldTotal,
                            permissionDraftCoverageSummary.effectiveFlagCount,
                            permissionDraftCoverageSummary.validationIssueCount
                        )
                    )
                    Text(permissionDraftCoverageText(permissionDraftCoverageSummary))
                        .font(.caption)
                        .foregroundColor(permissionDraftCoverageSummary.needsAttention ? .orange : .secondary)
                    Button(localized("permissions.copyDraftCoverage")) {
                        TS3PlatformSupport.copyToPasteboard(permissionDraftCoverageSummary.clipboardSummary)
                    }
                    ServerInfoDetailRow(
                        label: localized("permissions.officialEditAudit"),
                        value: localized(
                            "permissions.officialEditAuditFormat",
                            permissionOfficialEditAuditSummary.coveredAreaCount,
                            permissionOfficialEditAuditSummary.totalOfficialAreaCount,
                            permissionOfficialEditAuditSummary.missingAreaCount
                        )
                    )
                    Text(permissionOfficialEditAuditText(permissionOfficialEditAuditSummary))
                        .font(.caption)
                        .foregroundColor(permissionOfficialEditAuditSummary.needsAttention ? .orange : .secondary)
                    Button(localized("permissions.copyOfficialEditAudit")) {
                        TS3PlatformSupport.copyToPasteboard(permissionOfficialEditAuditSummary.clipboardSummary)
                    }
                    if !permissionDraftValidationMessages.isEmpty {
                        ForEach(permissionDraftValidationMessages, id: \.self) { message in
                            Text(message)
                                .font(.caption)
                                .foregroundColor(.red)
                        }
                    }
                    Text(permissionDraft.clipboardSummary)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("permissions.copyDraft")) {
                        TS3PlatformSupport.copyToPasteboard(permissionDraft.clipboardSummary)
                    }
                    Button(localized("permissions.addOrUpdate")) {
                        model.addSelectedPermission(permissionDraft)
                    }
                    .disabled(model.state != .connected || !permissionDraftValidationMessages.isEmpty)
                }

                Section(header: Text(localized("permissions.directory"))) {
                    TextField(localized("permissions.search"), text: $searchText)
                        .ts3PlainTextField()
                    if filteredPermissionInfos.isEmpty {
                        Text(localized("permissions.noPermissions"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(filteredPermissionInfos) { permission in
                            PermissionInfoRow(permission: permission) {
                                permissionName = permission.name
                                searchText = permission.name
                            } copyName: {
                                TS3PlatformSupport.copyToPasteboard(permission.name)
                            } copyId: {
                                TS3PlatformSupport.copyToPasteboard("\(permission.id)")
                            }
                        }
                    }
                }
            }
            .navigationTitle(localized("permissions.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                model.refreshPermissionList()
                model.refreshGroups()
                model.refreshSelectedPermissions()
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("groups.refresh")) {
                        model.refreshPermissionList()
                        model.refreshGroups()
                        model.refreshSelectedPermissions()
                    }
                    .disabled(model.state != .connected)
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.done")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .fileExporter(
                isPresented: $isExportingPermissionSnapshot,
                document: permissionExportDocument,
                contentType: .plainText,
                defaultFilename: exportFilename
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPermissionBackup,
                document: permissionBackupDocument,
                contentType: .json,
                defaultFilename: "ts3-permission-backup"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPresets,
                document: presetsDocument,
                contentType: .json,
                defaultFilename: "ts3-permission-filter-presets"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPermissions,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    preparePermissionBackupImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPresets,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    importPresets(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .alert(isPresented: $isConfirmingDeleteVisible) {
                Alert(
                    title: Text(localized("permissions.deleteVisibleAlert.title")),
                    message: Text(localized("permissions.deleteVisibleAlert.messageFormat", filteredDisplayedPermissions.count)),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deleteSelectedPermissions(filteredDisplayedPermissions)
                    },
                    secondaryButton: .cancel()
                )
            }
            .sheet(item: $pendingPermissionBackupImport) { confirmation in
                PermissionBackupImportSheet(
                    confirmation: confirmation,
                    previewMessage: permissionBackupPreviewMessage(confirmation.preview)
                ) { options in
                    importPermissionBackup(data: confirmation.data, options: options)
                    pendingPermissionBackupImport = nil
                } cancel: {
                    pendingPermissionBackupImport = nil
                }
                .environmentObject(model)
            }
            .alert(isPresented: $isConfirmingDeletePresets) {
                Alert(
                    title: Text(localized("permissions.deleteAllPresetsAlert.title")),
                    message: Text(localized("groups.deleteAllPresetsAlert.messageFormat", model.permissionFilterPresets.count)),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deleteAllPermissionFilterPresets()
                    },
                    secondaryButton: .cancel()
                )
            }
        }
    }

    private func exportPermissionBackup() {
        do {
            permissionBackupDocument = TS3TextFileDocument(data: try model.permissionBackupData())
            isExportingPermissionBackup = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private var hasAssignedPermissionOptions: Bool {
        !assignedSearchText.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            || assignedFilter != .all
            || assignedSortMode != .name
            || !assignedSortAscending
    }

    private func sortedDisplayedPermissions(_ permissions: [TS3PermissionSummary]) -> [TS3PermissionSummary] {
        permissions.sorted { lhs, rhs in
            if lhs.id == rhs.id {
                return false
            }

            let comparison: ComparisonResult
            switch assignedSortMode {
            case .name:
                comparison = lhs.name.localizedCaseInsensitiveCompare(rhs.name)
            case .value:
                comparison = compareInts(lhs.value, rhs.value)
            case .flags:
                comparison = flagText(lhs).localizedCaseInsensitiveCompare(flagText(rhs))
            }

            if comparison == .orderedSame {
                return lhs.name.localizedCaseInsensitiveCompare(rhs.name) == .orderedAscending
            }
            return assignedSortAscending ? comparison == .orderedAscending : comparison == .orderedDescending
        }
    }

    private func compareInts(_ lhs: Int, _ rhs: Int) -> ComparisonResult {
        if lhs == rhs {
            return .orderedSame
        }
        return lhs < rhs ? .orderedAscending : .orderedDescending
    }

    private func flagText(_ permission: TS3PermissionSummary) -> String {
        var flags: [String] = []
        if permission.isNegated {
            flags.append(localized("permissions.flag.negated"))
        }
        if permission.isSkipped {
            flags.append(localized("permissions.flag.skip"))
        }
        return flags.isEmpty ? localized("permissions.filter.direct") : flags.joined(separator: " ")
    }

    private func applyPreset(_ preset: TS3PermissionFilterPreset) {
        if let scope = TS3PermissionEditScope(rawValue: preset.scope) {
            model.selectPermissionScope(scope)
        }
        assignedFilter = AssignedPermissionFilter(rawValue: preset.assignedFilter) ?? .all
        assignedSortMode = AssignedPermissionSortMode(rawValue: preset.assignedSortMode) ?? .name
        assignedSortAscending = preset.assignedSortAscending
        assignedSearchText = preset.assignedSearchText
        searchText = preset.permissionSearchText
        presetName = preset.name
    }

    private func presetSummary(_ preset: TS3PermissionFilterPreset) -> String {
        var parts = [
            scopeTitle(TS3PermissionEditScope(rawValue: preset.scope) ?? .ownClient),
            assignedFilterTitle(AssignedPermissionFilter(rawValue: preset.assignedFilter) ?? .all),
            localized("permissions.presetSummary.sortFormat", assignedSortModeTitle(AssignedPermissionSortMode(rawValue: preset.assignedSortMode) ?? .name))
        ]
        if !preset.assignedSortAscending {
            parts.append(localized("groups.members.descending"))
        }
        if !preset.assignedSearchText.isEmpty {
            parts.append(localized("permissions.presetSummary.assignedFormat", preset.assignedSearchText))
        }
        if !preset.permissionSearchText.isEmpty {
            parts.append(localized("permissions.presetSummary.directoryFormat", preset.permissionSearchText))
        }
        return parts.joined(separator: " · ")
    }

    private func exportPresets() {
        do {
            presetsDocument = TS3BookmarkFileDocument(data: try model.permissionFilterPresetsExportData())
            isExportingPresets = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPresets(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            _ = try model.importPermissionFilterPresets(from: Data(contentsOf: url))
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func preparePermissionBackupImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.permissionBackupPreview(from: data)
            pendingPermissionBackupImport = PermissionBackupImportConfirmation(url: url, data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func permissionBackupPreviewMessage(_ preview: TS3PermissionBackupPreview) -> String {
        var lines = [
            localized("permissions.backupPreview.targetFormat", scopeTitle(preview.scope), preview.targetDescription),
            localized("permissions.backupPreview.backupPermissionsFormat", preview.permissionCount)
        ]
        if let currentPermissionCount = preview.currentPermissionCount,
           let overwriteCount = preview.overwriteCount,
           let changedCount = preview.changedCount,
           let unchangedCount = preview.unchangedCount,
           let newPermissionCount = preview.newPermissionCount {
            lines.append(localized("permissions.backupPreview.currentPermissionsFormat", currentPermissionCount))
            lines.append(localized("permissions.backupPreview.existingEntriesFormat", overwriteCount, changedCount, unchangedCount))
            lines.append(localized("permissions.backupPreview.restorePlanFormat", changedCount, newPermissionCount))
            if !preview.changedPermissionNames.isEmpty {
                lines.append(localized("permissions.backupPreview.changingFormat", permissionNameSummary(preview.changedPermissionNames)))
            }
            if !preview.changedPermissionDetails.isEmpty {
                lines.append(localized("permissions.backupPreview.changeDetailsFormat", permissionDetailSummary(preview.changedPermissionDetails)))
            }
            if !preview.overwritePermissionNames.isEmpty {
                lines.append(localized("permissions.backupPreview.existingFormat", permissionNameSummary(preview.overwritePermissionNames)))
            }
            if !preview.unchangedPermissionNames.isEmpty {
                lines.append(localized("permissions.backupPreview.unchangedFormat", permissionNameSummary(preview.unchangedPermissionNames)))
            }
            if !preview.newPermissionNames.isEmpty {
                lines.append(localized("permissions.backupPreview.addingFormat", permissionNameSummary(preview.newPermissionNames)))
            }
        } else {
            lines.append(localized("permissions.backupPreview.uncomparable"))
        }
        lines.append(localized("permissions.backupPreview.restoreBehavior"))
        return lines.joined(separator: "\n")
    }

    private func permissionNameSummary(_ names: [String]) -> String {
        let visible = names.prefix(6).joined(separator: ", ")
        let remainingCount = names.count - min(names.count, 6)
        guard remainingCount > 0 else { return visible }
        return localized("permissions.moreFormat", visible, remainingCount)
    }

    private func permissionDetailSummary(_ details: [String]) -> String {
        let visible = details.prefix(3).joined(separator: "; ")
        let remainingCount = details.count - min(details.count, 3)
        guard remainingCount > 0 else { return visible }
        return localized("permissions.moreSemicolonFormat", visible, remainingCount)
    }

    private func importPermissionBackup(data: Data, options: TS3PermissionBackupRestoreOptions) {
        do {
            try model.importPermissionBackup(from: data, options: options)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func scopeTitle(_ scope: TS3PermissionEditScope) -> String {
        switch scope {
        case .ownClient:
            return localized("permissions.scope.ownClient")
        case .databaseClient:
            return localized("permissions.scope.databaseClient")
        case .serverGroup:
            return localized("permissions.scope.serverGroup")
        case .channelGroup:
            return localized("permissions.scope.channelGroup")
        case .channel:
            return localized("permissions.scope.channel")
        case .channelClient:
            return localized("permissions.scope.channelClient")
        }
    }

    private func assignedFilterTitle(_ filter: AssignedPermissionFilter) -> String {
        switch filter {
        case .all:
            return localized("permissions.filter.all")
        case .negated:
            return localized("permissions.filter.negated")
        case .skipped:
            return localized("permissions.filter.skipped")
        case .direct:
            return localized("permissions.filter.direct")
        case .positiveValue:
            return localized("permissions.filter.positiveValue")
        case .zeroValue:
            return localized("permissions.filter.zeroValue")
        case .negativeValue:
            return localized("permissions.filter.negativeValue")
        }
    }

    private func assignedSortModeTitle(_ mode: AssignedPermissionSortMode) -> String {
        switch mode {
        case .name:
            return localized("permissions.sort.name")
        case .value:
            return localized("permissions.sort.value")
        case .flags:
            return localized("permissions.sort.flags")
        }
    }

    private func permissionEffectDescription(isNegated: Bool, isSkipped: Bool) -> String {
        switch (isNegated, isSkipped) {
        case (true, true):
            return localized("permissions.effect.negatedSkipped")
        case (true, false):
            return localized("permissions.effect.negated")
        case (false, true):
            return localized("permissions.effect.skipped")
        case (false, false):
            return localized("permissions.effect.direct")
        }
    }

    private func permissionDraftCoverageText(_ summary: TS3PermissionDraftCoverageSummary) -> String {
        [
            localized("permissions.draftCoverageScopeFormat", scopeTitle(summary.scope)),
            localized("permissions.draftCoverageTargetFormat", summary.hasTarget ? 1 : 0),
            localized("permissions.draftCoverageNameFormat", summary.hasName ? 1 : 0),
            localized("permissions.draftCoverageValueFormat", summary.hasNumericValue ? 1 : 0),
            localized("permissions.draftCoverageNegatedFormat", summary.usesNegated ? 1 : 0, summary.supportsNegated ? 1 : 0),
            localized("permissions.draftCoverageSkipFormat", summary.usesSkip ? 1 : 0, summary.supportsSkip ? 1 : 0)
        ].joined(separator: " | ")
    }

    private func permissionOfficialEditAuditText(_ summary: TS3PermissionOfficialEditAuditSummary) -> String {
        var parts = TS3PermissionOfficialEditArea.allCases.compactMap { area -> String? in
            guard let count = summary.areaCoverageCounts[area], count > 0 else { return nil }
            return localized("permissions.officialEditAuditAreaFormat", title(for: area), count)
        }
        if summary.missingAreaCount > 0 {
            parts.append(localized("permissions.officialEditAuditMissingFormat", summary.missingAreaCount))
        }
        if summary.coverage.unsupportedRequestedFlagCount > 0 {
            parts.append(localized("permissions.officialEditAuditUnsupportedFlagsFormat", summary.coverage.unsupportedRequestedFlagCount))
        }
        if summary.coverage.validationIssueCount > 0 {
            parts.append(localized("permissions.officialEditAuditValidationFormat", summary.coverage.validationIssueCount))
        }
        return parts.joined(separator: " | ")
    }

    private func title(for area: TS3PermissionOfficialEditArea) -> String {
        switch area {
        case .targetScope:
            return localized("permissions.officialEdit.targetScope")
        case .permissionValue:
            return localized("permissions.officialEdit.permissionValue")
        case .inheritanceFlags:
            return localized("permissions.officialEdit.inheritanceFlags")
        case .validation:
            return localized("permissions.officialEdit.validation")
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

private struct PermissionBackupImportSheet: View {
    let confirmation: PermissionsSheet.PermissionBackupImportConfirmation
    let previewMessage: String
    let restore: (TS3PermissionBackupRestoreOptions) -> Void
    let cancel: () -> Void

    @EnvironmentObject private var model: TS3AppModel
    @State private var options = TS3PermissionBackupRestoreOptions.all
    @State private var isExportingRestorePlan = false
    @State private var restorePlanDocument = TS3TextFileDocument()

    private var plan: TS3PermissionBackupRestorePlan? {
        try? model.permissionBackupRestorePlan(from: confirmation.data, options: options)
    }

    private var canRestore: Bool {
        if confirmation.preview.targetMatchesCurrentSelection {
            return options.hasSelectedComparableEntries && (plan?.permissionCount ?? 0) > 0
        }
        return options.restoreWhenTargetCannotBeCompared && (plan?.permissionCount ?? 0) > 0
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("permissions.restore.preview"))) {
                    Text(previewMessage)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("permissions.restore.copyBackupPreview")) {
                        TS3PlatformSupport.copyToPasteboard(confirmation.preview.clipboardSummary)
                    }
                    if let plan {
                        let impact = TS3PermissionBackupRestoreImpactSummary(plan: plan)
                        Text(localized("permissions.restore.selectedEntriesFormat", plan.permissionCount))
                            .font(.caption.weight(.semibold))
                        Text(localized(
                            "permissions.restore.inheritanceImpactFormat",
                            plan.negatedEntryCount,
                            plan.inheritanceStopEntryCount
                        ))
                        .font(.caption2)
                        .foregroundColor(.secondary)
                        ServerInfoDetailRow(
                            label: localized("permissions.restore.impact"),
                            value: localized(
                                "permissions.restore.impactFormat",
                                impact.selectedEntryCount,
                                impact.changedExistingSelectedCount,
                                impact.newPermissionSelectedCount
                            )
                        )
                        Text(permissionRestoreImpactText(impact))
                            .font(.caption2)
                            .foregroundColor(impact.needsAttention ? .orange : .secondary)
                        Button(localized("permissions.restore.copyImpact")) {
                            TS3PlatformSupport.copyToPasteboard(impact.clipboardSummary)
                        }
                        .disabled(!impact.hasSelection)
                        if !plan.entries.isEmpty {
                            Button(localized("permissions.restore.copyPlan")) {
                                TS3PlatformSupport.copyToPasteboard(plan.auditSummary)
                            }
                            Button(localized("permissions.restore.exportPlan")) {
                                restorePlanDocument = TS3TextFileDocument(data: Data(plan.auditSummary.utf8))
                                isExportingRestorePlan = true
                            }
                            ForEach(plan.entries.prefix(6), id: \.name) { entry in
                                VStack(alignment: .leading, spacing: 2) {
                                    Text(entry.name)
                                        .font(.caption.weight(.semibold))
                                        .lineLimit(1)
                                        .truncationMode(.middle)
                                    Text(localized(
                                        "permissions.restore.entryFlagsFormat",
                                        entry.value,
                                        boolText(entry.isNegated),
                                        boolText(entry.isSkipped)
                                    ))
                                        .font(.caption2)
                                        .foregroundColor(.secondary)
                                    Text(entry.changeSummary ?? entry.restoreReason)
                                        .font(.caption2)
                                        .foregroundColor(.secondary)
                                    Text(entry.inheritanceEffectDescription)
                                        .font(.caption2)
                                        .foregroundColor(.secondary)
                                }
                            }
                            if plan.permissionCount > 6 {
                                Text(localized("permissions.restore.moreFormat", plan.permissionCount - 6))
                                    .font(.caption2)
                                    .foregroundColor(.secondary)
                            }
                        }
                    }
                }

                Section(header: Text(localized("permissions.restore.entries"))) {
                    if confirmation.preview.targetMatchesCurrentSelection {
                        Toggle(
                            localized("permissions.restore.changedExisting"),
                            isOn: $options.changedExisting
                        )
                        .disabled((confirmation.preview.changedCount ?? 0) == 0)
                        Toggle(
                            localized("permissions.restore.newPermissions"),
                            isOn: $options.newPermissions
                        )
                        .disabled((confirmation.preview.newPermissionCount ?? 0) == 0)
                    } else {
                        Toggle(
                            localized("permissions.restore.withoutComparison"),
                            isOn: $options.restoreWhenTargetCannotBeCompared
                        )
                    }
                }
            }
            .navigationTitle(localized("permissions.restore.title"))
            .ts3InlineNavigationTitle()
            .fileExporter(
                isPresented: $isExportingRestorePlan,
                document: restorePlanDocument,
                contentType: .plainText,
                defaultFilename: "ts3-permission-restore-plan"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("permissions.restore.action")) {
                        restore(options)
                    }
                    .disabled(!canRestore)
                }
            }
        }
    }

    private func boolText(_ value: Bool) -> String {
        localized(value ? "common.on" : "common.off")
    }

    private func permissionRestoreImpactText(_ impact: TS3PermissionBackupRestoreImpactSummary) -> String {
        var parts = [
            localized("permissions.restore.impactUncomparableFormat", impact.uncomparableSelectedCount),
            localized("permissions.restore.impactNegatedFormat", impact.negatedEntryCount),
            localized("permissions.restore.impactSkipFormat", impact.inheritanceStopEntryCount)
        ]
        if let changedExistingAvailableCount = impact.changedExistingAvailableCount,
           let newPermissionAvailableCount = impact.newPermissionAvailableCount,
           let unchangedSkippedCount = impact.unchangedSkippedCount {
            parts.append(localized(
                "permissions.restore.impactAvailableFormat",
                changedExistingAvailableCount,
                newPermissionAvailableCount,
                unchangedSkippedCount
            ))
        }
        if !impact.targetMatchesCurrentSelection {
            parts.append(localized("permissions.restore.impactTargetUnmatched"))
        }
        if !impact.hasSelection {
            parts.append(localized("permissions.restore.impactEmpty"))
        }
        return parts.joined(separator: " | ")
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

struct PermissionRow: View {
    let permission: TS3PermissionSummary
    let canDelete: Bool
    let edit: () -> Void
    let delete: () -> Void
    @State private var isConfirmingDelete = false

    var body: some View {
        VStack(alignment: .leading, spacing: 4) {
            HStack {
                Text(permission.name)
                    .font(.subheadline.weight(.semibold))
                    .lineLimit(1)
                    .truncationMode(.middle)
                Spacer()
                Text("\(permission.value)")
                    .foregroundColor(.secondary)
            }
            HStack(spacing: 10) {
                ForEach(statusLabels, id: \.self) { label in
                    Text(label)
                }
                Spacer()
                Button(localized("permissions.row.edit")) {
                    edit()
                }
                .buttonStyle(.borderless)
                Button(localized("common.delete")) {
                    isConfirmingDelete = true
                }
                .buttonStyle(.borderless)
                .disabled(!canDelete)
                .foregroundColor(.red)
            }
            .font(.caption)
            .foregroundColor(.secondary)
            Text(effectDescription)
                .font(.caption)
                .foregroundColor(.secondary)
        }
        .padding(.vertical, 3)
        .alert(isPresented: $isConfirmingDelete) {
            Alert(
                title: Text(localized("permissions.row.deleteAlert.title")),
                message: Text(permission.name),
                primaryButton: .destructive(Text(localized("common.delete"))) {
                    delete()
                },
                secondaryButton: .cancel()
            )
        }
        .contextMenu {
            Button(localized("permissions.row.editPermission")) {
                edit()
            }
            Button(localized("permissions.row.copyName")) {
                TS3PlatformSupport.copyToPasteboard(permission.name)
            }
            Button(localized("permissions.row.copyValue")) {
                TS3PlatformSupport.copyToPasteboard("\(permission.value)")
            }
            Button(localized("groups.row.copySummary")) {
                TS3PlatformSupport.copyToPasteboard(permission.clipboardSummary)
            }
            Button(localized("common.delete")) {
                isConfirmingDelete = true
            }
            .disabled(!canDelete)
            .foregroundColor(.red)
        }
        .accessibilityElement(children: .ignore)
        .accessibilityLabel(permission.name)
        .accessibilityValue(accessibilityValue)
        .accessibilityAction(named: localized("groups.row.copySummary")) {
            TS3PlatformSupport.copyToPasteboard(permission.clipboardSummary)
        }
        .accessibilityAction(named: localized("permissions.row.editPermission")) {
            edit()
        }
        .accessibilityAction(named: localized("permissions.row.deletePermission")) {
            if canDelete {
                isConfirmingDelete = true
            }
        }
    }

    private var statusLabels: [String] {
        var labels: [String] = []
        if permission.isNegated {
            labels.append(localized("permissions.filter.negated"))
        }
        if permission.isSkipped {
            labels.append(localized("permissions.status.skipsInherited"))
        }
        return labels.isEmpty ? [localized("permissions.filter.direct")] : labels
    }

    private var effectDescription: String {
        switch (permission.isNegated, permission.isSkipped) {
        case (true, true):
            return localized("permissions.effect.negatedSkipped")
        case (true, false):
            return localized("permissions.effect.negated")
        case (false, true):
            return localized("permissions.effect.skipped")
        case (false, false):
            return localized("permissions.effect.direct")
        }
    }

    private var accessibilityValue: String {
        [
            localized("permissions.accessibility.valueFormat", permission.value),
            statusLabels.joined(separator: ", "),
            effectDescription
        ].joined(separator: ". ")
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

