struct TemporaryServerPasswordsSheet: View {
    private struct TemporaryServerPasswordFilterPresetImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3TemporaryServerPasswordFilterPresetImportPreview
        let id = UUID()
    }

    private enum PasswordFilter: String, CaseIterable, Identifiable {
        case all
        case serverDefault
        case channelTarget
        case withDescription
        case withCreator
        case withExpiration

        var id: String { rawValue }

        var title: String {
            switch self {
            case .all: return "All Passwords"
            case .serverDefault: return "Server Default"
            case .channelTarget: return "Channel Target"
            case .withDescription: return "With Description"
            case .withCreator: return "With Creator"
            case .withExpiration: return "With Expiration"
            }
        }

        func matches(_ entry: TS3TemporaryServerPasswordSummary) -> Bool {
            switch self {
            case .all:
                return true
            case .serverDefault:
                return entry.targetChannelId == nil || entry.targetChannelId == 0
            case .channelTarget:
                return (entry.targetChannelId ?? 0) > 0
            case .withDescription:
                return entry.description?.isEmpty == false
            case .withCreator:
                return entry.creatorName?.isEmpty == false
                    || entry.creatorUniqueIdentifier?.isEmpty == false
                    || entry.creatorDatabaseId != nil
            case .withExpiration:
                return entry.durationSeconds != nil
            }
        }
    }

    private enum PasswordSortMode: String, CaseIterable, Identifiable {
        case created
        case password
        case target
        case duration
        case creator
        case description

        var id: String { rawValue }

        var title: String {
            switch self {
            case .created: return "Created"
            case .password: return "Password"
            case .target: return "Target"
            case .duration: return "Duration"
            case .creator: return "Creator"
            case .description: return "Description"
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var password = ""
    @State private var description = ""
    @State private var duration: TS3TemporaryPasswordDuration = .oneHour
    @State private var customMinutes = "60"
    @State private var targetChannelId = 0
    @State private var targetChannelPassword = ""
    @State private var searchText = ""
    @State private var passwordFilter: PasswordFilter = .all
    @State private var sortMode: PasswordSortMode = .created
    @State private var sortAscending = false
    @State private var presetName = ""
    @State private var isExportingPasswords = false
    @State private var isExportingPresets = false
    @State private var isImportingPresets = false
    @State private var isConfirmingDeleteVisible = false
    @State private var isConfirmingDeletePresets = false
    @State private var passwordsDocument = TS3TextFileDocument()
    @State private var presetsDocument = TS3BookmarkFileDocument()
    @State private var pendingPresetImport: TemporaryServerPasswordFilterPresetImportConfirmation?

    private var passwordsSnapshot: String {
        filteredPasswords.map { $0.clipboardSummary(channels: model.channels) }.joined(separator: "\n")
    }

    private var visiblePasswordSummary: TS3TemporaryServerPasswordListSummary {
        TS3TemporaryServerPasswordListSummary(passwords: filteredPasswords)
    }

    var body: some View {
        NavigationView {
            List {
                Section(header: Text(localized("temporaryPasswords.create"))) {
                    TextField(localized("temporaryPasswords.password"), text: $password)
                        .ts3PlainTextField()
                    Picker(localized("temporaryPasswords.duration"), selection: $duration) {
                        ForEach(TS3TemporaryPasswordDuration.allCases) { duration in
                            Text(durationTitle(duration)).tag(duration)
                        }
                    }
                    if duration == .custom {
                        TextField(localized("temporaryPasswords.minutes"), text: $customMinutes)
                            .ts3PlainTextField()
                            .ts3NumericKeyboard()
                    }
                    TextField(localized("temporaryPasswords.description"), text: $description)
                        .ts3PlainTextField()
                    Picker(localized("temporaryPasswords.targetChannel"), selection: $targetChannelId) {
                        Text(localized("temporaryPasswords.serverDefault")).tag(0)
                        ForEach(model.channels) { channel in
                            Text(channel.name).tag(channel.id)
                        }
                    }
                    SecureField(localized("temporaryPasswords.targetChannelPassword"), text: $targetChannelPassword)
                    ServerInfoDetailRow(
                        label: localized("temporaryPasswords.draftCoverage"),
                        value: localized(
                            "temporaryPasswords.draftCoverageFormat",
                            temporaryPasswordDraftCoverageSummary.requiredFieldCount,
                            temporaryPasswordDraftCoverageSummary.optionalFieldCount,
                            temporaryPasswordDraftCoverageSummary.validationIssueCount
                        )
                    )
                    Text(temporaryPasswordDraftCoverageText(temporaryPasswordDraftCoverageSummary))
                        .font(.caption)
                        .foregroundColor(temporaryPasswordDraftCoverageSummary.needsAttention ? .orange : .secondary)
                    Button(localized("temporaryPasswords.copyDraftCoverage")) {
                        TS3PlatformSupport.copyToPasteboard(temporaryPasswordDraftCoverageSummary.clipboardSummary)
                    }
                    Text(temporaryPasswordDraftSummary)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("temporaryPasswords.copyCreationSummary")) {
                        TS3PlatformSupport.copyToPasteboard(temporaryPasswordDraftSummary)
                    }
                    ForEach(temporaryPasswordDraftValidationMessages, id: \.self) { message in
                        Text(message)
                            .font(.caption)
                            .foregroundColor(.red)
                    }
                    Button(localized("temporaryPasswords.createTemporaryPassword")) {
                        model.addTemporaryServerPassword(
                            password: password,
                            durationSeconds: duration.seconds(customMinutes: customMinutes),
                            description: description,
                            targetChannelId: targetChannelId == 0 ? nil : targetChannelId,
                            targetChannelPassword: targetChannelPassword
                        )
                        clearCreateForm()
                    }
                    .disabled(model.state != .connected || isCreateDisabled)
                }

                Section(header: Text(localized("temporaryPasswords.passwords"))) {
                    Picker(localized("groups.type"), selection: $passwordFilter) {
                        ForEach(PasswordFilter.allCases) { filter in
                            Text(passwordFilterTitle(filter)).tag(filter)
                        }
                    }
                    Picker(localized("groups.sortBy"), selection: $sortMode) {
                        ForEach(PasswordSortMode.allCases) { mode in
                            Text(passwordSortModeTitle(mode)).tag(mode)
                        }
                    }
                    Toggle(localized("groups.ascending"), isOn: $sortAscending)
                    TextField(localized("temporaryPasswords.searchPasswords"), text: $searchText)
                        .ts3PlainTextField()
                    ServerInfoDetailRow(
                        label: localized("temporaryPasswords.visibleSummary"),
                        value: localized(
                            "temporaryPasswords.visibleSummaryFormat",
                            visiblePasswordSummary.totalCount,
                            visiblePasswordSummary.channelTargetCount
                        )
                    )
                    Text(temporaryPasswordListSummaryText(visiblePasswordSummary))
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Menu {
                        TextField(localized("groups.presetName"), text: $presetName)
                        Button(localized("groups.saveCurrentFilters")) {
                            model.saveTemporaryServerPasswordFilterPreset(
                                name: presetName,
                                passwordFilter: passwordFilter.rawValue,
                                sortMode: sortMode.rawValue,
                                sortAscending: sortAscending,
                                searchText: searchText
                            )
                            presetName = ""
                        }
                        .disabled(presetName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                        if model.temporaryServerPasswordFilterPresets.isEmpty {
                            Text(localized("temporaryPasswords.noSavedFilterPresets"))
                        } else {
                            ForEach(model.temporaryServerPasswordFilterPresets) { preset in
                                Menu {
                                    Button(localized("groups.applyPreset")) {
                                        applyPreset(preset)
                                    }
                                    Button(localized("groups.useName")) {
                                        presetName = preset.name
                                    }
                                    Button(localized("groups.deletePreset")) {
                                        model.deleteTemporaryServerPasswordFilterPreset(preset)
                                    }
                                } label: {
                                    VStack(alignment: .leading) {
                                        Text(preset.name)
                                        Text(presetSummary(preset))
                                    }
                                }
                            }
                        }
                        Divider()
                        Button(localized("groups.exportPresets")) {
                            exportPresets()
                        }
                        .disabled(model.temporaryServerPasswordFilterPresets.isEmpty)
                        Button(localized("groups.importPresets")) {
                            isImportingPresets = true
                        }
                        Button(localized("groups.deleteAllPresets")) {
                            isConfirmingDeletePresets = true
                        }
                        .disabled(model.temporaryServerPasswordFilterPresets.isEmpty)
                    } label: {
                        Label(localized("groups.filterPresets"), systemImage: "line.3.horizontal.decrease.circle")
                    }
                    if hasLocalFilters {
                        Button(localized("groups.clearFilters")) {
                            passwordFilter = .all
                            sortMode = .created
                            sortAscending = false
                            searchText = ""
                        }
                    }
                    Button(localized("temporaryPasswords.copyVisibleSummary")) {
                        TS3PlatformSupport.copyToPasteboard(visiblePasswordSummary.clipboardSummary)
                    }
                    .disabled(filteredPasswords.isEmpty)
                    Button(localized("temporaryPasswords.copyVisiblePasswords")) {
                        TS3PlatformSupport.copyToPasteboard(passwordsSnapshot)
                    }
                    .disabled(filteredPasswords.isEmpty)
                    Button(localized("temporaryPasswords.exportVisiblePasswords")) {
                        passwordsDocument = TS3TextFileDocument(data: Data(passwordsSnapshot.utf8))
                        isExportingPasswords = true
                    }
                    .disabled(filteredPasswords.isEmpty)
                    Button(localized("temporaryPasswords.deleteVisiblePasswords")) {
                        isConfirmingDeleteVisible = true
                    }
                    .foregroundColor(.red)
                    .disabled(model.state != .connected || filteredPasswords.isEmpty)

                    if model.temporaryServerPasswords.isEmpty {
                        Text(localized("temporaryPasswords.noTemporaryPasswords"))
                            .foregroundColor(.secondary)
                    } else if filteredPasswords.isEmpty {
                        Text(localized("temporaryPasswords.noMatchingTemporaryPasswords"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(filteredPasswords) { entry in
                            TemporaryServerPasswordRow(entry: entry)
                                .environmentObject(model)
                        }
                    }
                }
            }
            .navigationTitle(localized("temporaryPasswords.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                normalizeChannelSelection()
                if model.state == .connected {
                    model.refreshTemporaryServerPasswords()
                }
            }
            .onChange(of: model.channels.map(\.id)) { _ in
                normalizeChannelSelection()
            }
            .fileExporter(
                isPresented: $isExportingPasswords,
                document: passwordsDocument,
                contentType: .plainText,
                defaultFilename: "ts3-temporary-passwords"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPresets,
                document: presetsDocument,
                contentType: .json,
                defaultFilename: "ts3-temporary-password-filter-presets"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPresets,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    preparePresetImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .sheet(item: $pendingPresetImport) { confirmation in
                TemporaryServerPasswordFilterPresetImportSheet(
                    preview: confirmation.preview,
                    importPresets: { selectedPresetIds in
                        importPresets(data: confirmation.data, selectedPresetIds: selectedPresetIds)
                        pendingPresetImport = nil
                    },
                    cancel: {
                        pendingPresetImport = nil
                    }
                )
            }
            .alert(isPresented: $isConfirmingDeleteVisible) {
                Alert(
                    title: Text(localized("temporaryPasswords.deleteVisibleAlert.title")),
                    message: Text(localized("temporaryPasswords.deleteVisibleAlert.messageFormat", filteredPasswords.count)),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deleteTemporaryServerPasswords(filteredPasswords)
                    },
                    secondaryButton: .cancel()
                )
            }
            .alert(isPresented: $isConfirmingDeletePresets) {
                Alert(
                    title: Text(localized("temporaryPasswords.deleteAllPresetsAlert.title")),
                    message: Text(localized("groups.deleteAllPresetsAlert.messageFormat", model.temporaryServerPasswordFilterPresets.count)),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deleteAllTemporaryServerPasswordFilterPresets()
                    },
                    secondaryButton: .cancel()
                )
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("groups.refresh")) {
                        model.refreshTemporaryServerPasswords()
                    }
                    .disabled(model.state != .connected)
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.done")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }

    private var isCreateDisabled: Bool {
        !temporaryPasswordDraftValidationMessages.isEmpty
    }

    private var temporaryPasswordDraftValidationMessages: [String] {
        TS3TemporaryServerPasswordDraftValidator.validationMessages(
            password: password,
            durationSeconds: duration.seconds(customMinutes: customMinutes),
            description: description,
            targetChannelId: targetChannelId == 0 ? nil : targetChannelId,
            targetChannelPassword: targetChannelPassword
        )
    }

    private var temporaryPasswordDraftSummary: String {
        TS3TemporaryServerPasswordDraftValidator.creationSummary(
            password: password,
            durationSeconds: duration.seconds(customMinutes: customMinutes),
            description: description,
            targetChannelId: targetChannelId == 0 ? nil : targetChannelId,
            targetChannelName: targetChannelId == 0 ? nil : channelName(targetChannelId),
            targetChannelPassword: targetChannelPassword
        )
    }

    private var temporaryPasswordDraftCoverageSummary: TS3TemporaryServerPasswordDraftCoverageSummary {
        TS3TemporaryServerPasswordDraftCoverageSummary(
            password: password,
            durationSeconds: duration.seconds(customMinutes: customMinutes),
            description: description,
            targetChannelId: targetChannelId == 0 ? nil : targetChannelId,
            targetChannelPassword: targetChannelPassword,
            validationMessages: temporaryPasswordDraftValidationMessages
        )
    }

    private func temporaryPasswordDraftCoverageText(_ summary: TS3TemporaryServerPasswordDraftCoverageSummary) -> String {
        [
            localized("temporaryPasswords.draftCoveragePasswordFormat", summary.hasPassword ? 1 : 0),
            localized("temporaryPasswords.draftCoverageDurationFormat", summary.hasDuration ? 1 : 0),
            localized("temporaryPasswords.draftCoverageDescriptionFormat", summary.hasDescription ? 1 : 0),
            localized("temporaryPasswords.draftCoverageTargetChannelFormat", summary.hasTargetChannel ? 1 : 0),
            localized("temporaryPasswords.draftCoverageTargetPasswordFormat", summary.hasTargetChannelPassword ? 1 : 0)
        ].joined(separator: " | ")
    }

    private var normalizedSearchText: String {
        searchText.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    private var isSearching: Bool {
        !normalizedSearchText.isEmpty
    }

    private var hasLocalFilters: Bool {
        isSearching || passwordFilter != .all || sortMode != .created || sortAscending
    }

    private var filteredPasswords: [TS3TemporaryServerPasswordSummary] {
        let entries = model.temporaryServerPasswords.filter { entry in
            passwordFilter.matches(entry) && (
                !isSearching
                    || containsSearch(entry.password)
                    || containsSearch(entry.description)
                    || containsSearch(entry.creatorName)
                    || containsSearch(entry.creatorUniqueIdentifier)
                    || entry.creatorDatabaseId.map { String($0).contains(normalizedSearchText) } == true
                    || entry.targetChannelId.map { String($0).contains(normalizedSearchText) } == true
                    || entry.targetChannelId.flatMap(channelName).map { $0.lowercased().contains(normalizedSearchText) } == true
            )
        }
        return sortedPasswords(entries)
    }

    private func containsSearch(_ value: String?) -> Bool {
        guard let value, !normalizedSearchText.isEmpty else { return false }
        return value.lowercased().contains(normalizedSearchText)
    }

    private func sortedPasswords(_ entries: [TS3TemporaryServerPasswordSummary]) -> [TS3TemporaryServerPasswordSummary] {
        entries.sorted { lhs, rhs in
            if lhs.id == rhs.id {
                return false
            }

            let comparison: ComparisonResult
            switch sortMode {
            case .created:
                comparison = compareDates(lhs.createdAt, rhs.createdAt)
            case .password:
                comparison = lhs.password.localizedCaseInsensitiveCompare(rhs.password)
            case .target:
                comparison = targetDisplayName(lhs).localizedCaseInsensitiveCompare(targetDisplayName(rhs))
            case .duration:
                comparison = compareOptionalInts(lhs.durationSeconds, rhs.durationSeconds)
            case .creator:
                comparison = creatorDisplayName(lhs).localizedCaseInsensitiveCompare(creatorDisplayName(rhs))
            case .description:
                comparison = (lhs.description ?? "").localizedCaseInsensitiveCompare(rhs.description ?? "")
            }

            if comparison == .orderedSame {
                return lhs.password.localizedCaseInsensitiveCompare(rhs.password) == .orderedAscending
            }
            return sortAscending ? comparison == .orderedAscending : comparison == .orderedDescending
        }
    }

    private func compareDates(_ lhs: Date?, _ rhs: Date?) -> ComparisonResult {
        switch (lhs, rhs) {
        case let (lhs?, rhs?):
            return lhs.compare(rhs)
        case (nil, nil):
            return .orderedSame
        case (nil, _):
            return .orderedAscending
        case (_, nil):
            return .orderedDescending
        }
    }

    private func compareOptionalInts(_ lhs: Int?, _ rhs: Int?) -> ComparisonResult {
        switch (lhs, rhs) {
        case let (lhs?, rhs?):
            if lhs == rhs {
                return .orderedSame
            }
            return lhs < rhs ? .orderedAscending : .orderedDescending
        case (nil, nil):
            return .orderedSame
        case (nil, _):
            return .orderedAscending
        case (_, nil):
            return .orderedDescending
        }
    }

    private func normalizeChannelSelection() {
        if targetChannelId != 0 && !model.channels.contains(where: { $0.id == targetChannelId }) {
            targetChannelId = 0
        }
    }

    private func channelName(_ id: Int) -> String? {
        model.channels.first { $0.id == id }?.name
    }

    private func targetDisplayName(_ entry: TS3TemporaryServerPasswordSummary) -> String {
        guard let targetChannelId = entry.targetChannelId, targetChannelId > 0 else {
            return localized("temporaryPasswords.serverDefault")
        }
        return channelName(targetChannelId) ?? localized("groups.members.channelFallbackFormat", targetChannelId)
    }

    private func creatorDisplayName(_ entry: TS3TemporaryServerPasswordSummary) -> String {
        if let creatorName = entry.creatorName, !creatorName.isEmpty {
            return creatorName
        }
        if let creatorDatabaseId = entry.creatorDatabaseId {
            return localized("temporaryPasswords.clientDbFormat", creatorDatabaseId)
        }
        return entry.creatorUniqueIdentifier ?? ""
    }

    private func applyPreset(_ preset: TS3TemporaryServerPasswordFilterPreset) {
        passwordFilter = PasswordFilter(rawValue: preset.passwordFilter) ?? .all
        sortMode = PasswordSortMode(rawValue: preset.sortMode) ?? .created
        sortAscending = preset.sortAscending
        searchText = preset.searchText
        presetName = preset.name
    }

    private func presetSummary(_ preset: TS3TemporaryServerPasswordFilterPreset) -> String {
        var parts = [
            passwordFilterTitle(PasswordFilter(rawValue: preset.passwordFilter) ?? .all),
            localized("permissions.presetSummary.sortFormat", passwordSortModeTitle(PasswordSortMode(rawValue: preset.sortMode) ?? .created))
        ]
        if preset.sortAscending {
            parts.append(localized("groups.ascending"))
        }
        if !preset.searchText.isEmpty {
            parts.append(localized("temporaryPasswords.presetSummary.searchFormat", preset.searchText))
        }
        return parts.joined(separator: " · ")
    }

    private func exportPresets() {
        do {
            presetsDocument = TS3BookmarkFileDocument(data: try model.temporaryServerPasswordFilterPresetsExportData())
            isExportingPresets = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func preparePresetImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.temporaryServerPasswordFilterPresetsImportPreview(from: data)
            pendingPresetImport = TemporaryServerPasswordFilterPresetImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPresets(data: Data, selectedPresetIds: Set<UUID>) {
        do {
            _ = try model.importTemporaryServerPasswordFilterPresets(from: data, selectedPresetIds: selectedPresetIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func clearCreateForm() {
        password = ""
        description = ""
        duration = .oneHour
        customMinutes = "60"
        targetChannelPassword = ""
    }

    private func durationTitle(_ duration: TS3TemporaryPasswordDuration) -> String {
        switch duration {
        case .tenMinutes:
            return localized("temporaryPasswords.duration.tenMinutes")
        case .oneHour:
            return localized("temporaryPasswords.duration.oneHour")
        case .oneDay:
            return localized("temporaryPasswords.duration.oneDay")
        case .oneWeek:
            return localized("temporaryPasswords.duration.oneWeek")
        case .custom:
            return localized("temporaryPasswords.duration.custom")
        }
    }

    private func passwordFilterTitle(_ filter: PasswordFilter) -> String {
        switch filter {
        case .all:
            return localized("temporaryPasswords.filter.all")
        case .serverDefault:
            return localized("temporaryPasswords.filter.serverDefault")
        case .channelTarget:
            return localized("temporaryPasswords.filter.channelTarget")
        case .withDescription:
            return localized("temporaryPasswords.filter.withDescription")
        case .withCreator:
            return localized("temporaryPasswords.filter.withCreator")
        case .withExpiration:
            return localized("temporaryPasswords.filter.withExpiration")
        }
    }

    private func passwordSortModeTitle(_ mode: PasswordSortMode) -> String {
        switch mode {
        case .created:
            return localized("temporaryPasswords.sort.created")
        case .password:
            return localized("temporaryPasswords.sort.password")
        case .target:
            return localized("temporaryPasswords.sort.target")
        case .duration:
            return localized("temporaryPasswords.sort.duration")
        case .creator:
            return localized("temporaryPasswords.sort.creator")
        case .description:
            return localized("temporaryPasswords.sort.description")
        }
    }

    private func temporaryPasswordListSummaryText(_ summary: TS3TemporaryServerPasswordListSummary) -> String {
        [
            localized("temporaryPasswords.summaryServerDefaultFormat", summary.serverDefaultCount),
            localized("temporaryPasswords.summaryChannelTargetFormat", summary.channelTargetCount),
            localized("temporaryPasswords.summaryWithDescriptionFormat", summary.describedCount),
            localized("temporaryPasswords.summaryWithCreatorFormat", summary.withCreatorCount),
            localized("temporaryPasswords.summaryWithExpirationFormat", summary.withExpirationCount),
            localized("temporaryPasswords.summaryTargetPasswordsFormat", summary.withTargetChannelPasswordCount),
            localized("temporaryPasswords.summaryTargetChannelsFormat", summary.distinctTargetChannelCount),
            localized(
                "temporaryPasswords.summaryCreatedRangeFormat",
                summary.earliestCreatedAt.map(TS3TemporaryServerPasswordSummary.dateText) ?? localized("common.none"),
                summary.latestCreatedAt.map(TS3TemporaryServerPasswordSummary.dateText) ?? localized("common.none")
            )
        ].joined(separator: " · ")
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

private struct TemporaryServerPasswordFilterPresetImportSheet: View {
    @Environment(\.presentationMode) private var presentationMode

    let preview: TS3TemporaryServerPasswordFilterPresetImportPreview
    let importPresets: (Set<UUID>) -> Void
    let cancel: () -> Void
    @State private var selectedPresetIds: Set<UUID>

    init(
        preview: TS3TemporaryServerPasswordFilterPresetImportPreview,
        importPresets: @escaping (Set<UUID>) -> Void,
        cancel: @escaping () -> Void
    ) {
        self.preview = preview
        self.importPresets = importPresets
        self.cancel = cancel
        _selectedPresetIds = State(initialValue: Set(preview.candidates.map(\.id)))
    }

    private var canImport: Bool {
        preview.candidates.contains { selectedPresetIds.contains($0.id) }
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text("Preview")) {
                    Text("Imported presets: \(preview.importedPresetCount)")
                    Text("Usable presets: \(preview.usablePresetCount)")
                    Text("New presets: \(preview.newPresetCount)")
                    Text("Replacing presets: \(preview.replacedPresetCount)")
                    Text("Skipped presets: \(preview.skippedPresetCount)")
                    Button("Copy Backup Preview") {
                        TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                    }
                }

                Section(header: Text("Restore")) {
                    HStack {
                        Button("Select All") {
                            selectedPresetIds = Set(preview.candidates.map(\.id))
                        }
                        Spacer()
                        Button("Clear") {
                            selectedPresetIds.removeAll()
                        }
                    }
                    ForEach(preview.candidates) { candidate in
                        Toggle(
                            candidate.summary,
                            isOn: Binding(
                                get: { selectedPresetIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedPresetIds.insert(candidate.id)
                                    } else {
                                        selectedPresetIds.remove(candidate.id)
                                    }
                                }
                            )
                        )
                    }
                }

                Section {
                    Text(localized("temporaryPasswords.import.behavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("temporaryPasswords.import.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("temporaryPasswords.import.action")) {
                        importPresets(selectedPresetIds)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canImport)
                }
            }
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

struct TemporaryServerPasswordRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let entry: TS3TemporaryServerPasswordSummary
    @State private var isConfirmingDelete = false

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            HStack(alignment: .top) {
                VStack(alignment: .leading, spacing: 4) {
                    Text(entry.password)
                        .font(.system(.footnote, design: .monospaced))
                        .lineLimit(3)
                    Text(targetText)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    if let description = entry.description, !description.isEmpty {
                        Text(description)
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                    if let creator = creatorText {
                        Text(creator)
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                    Text(lifetimeText)
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                Spacer()
                Menu {
                    Button(localized("temporaryPasswords.row.copyPassword")) {
                        TS3PlatformSupport.copyToPasteboard(entry.password)
                    }
                    Button(localized("groups.row.copySummary")) {
                        TS3PlatformSupport.copyToPasteboard(entry.clipboardSummary(channels: model.channels))
                    }
                    Button(localized("temporaryPasswords.row.copyFullInviteLink")) {
                        model.copyFullInviteLink(for: entry)
                    }
                    Button(localized("temporaryPasswords.row.deletePassword")) {
                        isConfirmingDelete = true
                    }
                    .disabled(model.state != .connected)
                } label: {
                    Image(systemName: "ellipsis.circle")
                }
            }
        }
        .padding(.vertical, 3)
        .accessibilityElement(children: .ignore)
        .accessibilityLabel(entry.password)
        .accessibilityValue(accessibilityValue)
        .accessibilityAction(named: localized("temporaryPasswords.row.copyPassword")) {
            TS3PlatformSupport.copyToPasteboard(entry.password)
        }
        .accessibilityAction(named: localized("groups.row.copySummary")) {
            TS3PlatformSupport.copyToPasteboard(entry.clipboardSummary(channels: model.channels))
        }
        .accessibilityAction(named: localized("temporaryPasswords.row.copyFullInviteLink")) {
            model.copyFullInviteLink(for: entry)
        }
        .accessibilityAction(named: localized("temporaryPasswords.row.deletePassword")) {
            if model.state == .connected {
                isConfirmingDelete = true
            }
        }
        .alert(isPresented: $isConfirmingDelete) {
            Alert(
                title: Text(localized("temporaryPasswords.row.deleteAlert.title")),
                message: Text(entry.password),
                primaryButton: .destructive(Text(localized("common.delete"))) {
                    model.deleteTemporaryServerPassword(entry)
                },
                secondaryButton: .cancel()
            )
        }
    }

    private var targetText: String {
        localized("temporaryPasswords.row.targetFormat", localizedTargetText)
    }

    private var creatorText: String? {
        localizedCreatorText.map { localized("temporaryPasswords.row.creatorFormat", $0) }
    }

    private var lifetimeText: String {
        var parts: [String] = []
        if let durationSeconds = entry.durationSeconds {
            parts.append(localized("temporaryPasswords.row.durationFormat", TS3TemporaryServerPasswordSummary.durationText(durationSeconds)))
        }
        if let createdAt = entry.createdAt {
            parts.append(localized("temporaryPasswords.row.createdFormat", TS3TemporaryServerPasswordSummary.dateText(createdAt)))
        }
        return parts.isEmpty ? localized("temporaryPasswords.row.lifetimeUnknown") : parts.joined(separator: " · ")
    }

    private var localizedTargetText: String {
        guard let targetChannelId = entry.targetChannelId, targetChannelId > 0 else {
            return localized("temporaryPasswords.serverDefault")
        }
        return model.channels.first { $0.id == targetChannelId }?.name ?? localized("groups.members.channelFallbackFormat", targetChannelId)
    }

    private var localizedCreatorText: String? {
        if let creatorName = entry.creatorName, !creatorName.isEmpty {
            return creatorName
        }
        if let creatorDatabaseId = entry.creatorDatabaseId {
            return localized("temporaryPasswords.clientDbFormat", creatorDatabaseId)
        }
        return nil
    }

    private var accessibilityValue: String {
        var parts = [
            localized("temporaryPasswords.accessibility.temporaryPassword"),
            localized("temporaryPasswords.accessibility.targetFormat", localizedTargetText)
        ]
        if let durationSeconds = entry.durationSeconds {
            parts.append(localized("temporaryPasswords.accessibility.durationFormat", TS3TemporaryServerPasswordSummary.durationText(durationSeconds)))
        }
        if entry.createdAt != nil {
            parts.append(localized("temporaryPasswords.accessibility.createdDateAvailable"))
        }
        if let description = entry.description, !description.isEmpty {
            parts.append(localized("temporaryPasswords.accessibility.descriptionFormat", description))
        }
        if let localizedCreatorText {
            parts.append(localized("temporaryPasswords.accessibility.creatorFormat", localizedCreatorText))
        }
        return parts.joined(separator: ". ")
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

struct PrivilegeKeysSheet: View {
    private struct KeyBackupImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3PrivilegeKeyBackupPreview
        let id = UUID()
    }

    private enum KeyFilter: String, CaseIterable, Identifiable {
        case all
        case serverGroup
        case channelGroup
        case unknown
        case withDescription
        case withCustomSet

        var id: String { rawValue }

        var title: String {
            switch self {
            case .all: return "All Keys"
            case .serverGroup: return "Server Group"
            case .channelGroup: return "Channel Group"
            case .unknown: return "Unknown Type"
            case .withDescription: return "With Description"
            case .withCustomSet: return "With Custom Set"
            }
        }

        func matches(_ key: TS3PrivilegeKeySummary) -> Bool {
            switch self {
            case .all:
                return true
            case .serverGroup:
                return key.type == .serverGroup
            case .channelGroup:
                return key.type == .channelGroup
            case .unknown:
                return key.type == nil
            case .withDescription:
                return key.description?.isEmpty == false
            case .withCustomSet:
                return key.customSet?.isEmpty == false
            }
        }
    }

    private enum KeySortMode: String, CaseIterable, Identifiable {
        case created
        case type
        case group
        case channel
        case description

        var id: String { rawValue }

        var title: String {
            switch self {
            case .created: return "Created"
            case .type: return "Type"
            case .group: return "Group"
            case .channel: return "Channel"
            case .description: return "Description"
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    let initialTargetType: TS3PrivilegeKeyTargetType?
    let initialServerGroupId: Int?
    let initialChannelGroupId: Int?
    let initialChannelId: Int?
    @State private var targetType: TS3PrivilegeKeyTargetType = .serverGroup
    @State private var selectedServerGroupId = 0
    @State private var selectedChannelGroupId = 0
    @State private var selectedChannelId = 0
    @State private var description = ""
    @State private var customSet = ""
    @State private var searchText = ""
    @State private var keyFilter: KeyFilter = .all
    @State private var sortMode: KeySortMode = .created
    @State private var sortAscending = false
    @State private var presetName = ""
    @State private var isExportingKeys = false
    @State private var isExportingGeneratedKey = false
    @State private var isExportingKeyBackup = false
    @State private var isImportingKeyBackup = false
    @State private var isExportingPresets = false
    @State private var isImportingPresets = false
    @State private var keysExportDocument = TS3TextFileDocument()
    @State private var generatedKeyDocument = TS3TextFileDocument()
    @State private var keysBackupDocument = TS3TextFileDocument()
    @State private var presetsDocument = TS3BookmarkFileDocument()
    @State private var pendingKeyBackupImport: KeyBackupImportConfirmation?
    @State private var isConfirmingDeleteAll = false
    @State private var isConfirmingDeletePresets = false

    private var privilegeKeysSnapshot: String {
        filteredPrivilegeKeys
            .map {
                $0.clipboardSummary(
                    serverGroups: model.serverGroups,
                    channelGroups: model.channelGroups,
                    channels: model.channels
                )
            }
            .joined(separator: "\n")
    }

    private var visiblePrivilegeKeySummary: TS3PrivilegeKeyListSummary {
        TS3PrivilegeKeyListSummary(keys: filteredPrivilegeKeys)
    }

    init(
        initialTargetType: TS3PrivilegeKeyTargetType? = nil,
        initialServerGroupId: Int? = nil,
        initialChannelGroupId: Int? = nil,
        initialChannelId: Int? = nil
    ) {
        self.initialTargetType = initialTargetType
        self.initialServerGroupId = initialServerGroupId
        self.initialChannelGroupId = initialChannelGroupId
        self.initialChannelId = initialChannelId
    }

    var body: some View {
        NavigationView {
            List {
                if let key = model.generatedPrivilegeKey {
                    Section(header: Text(localized("privilegeKeys.generatedKey"))) {
                        Text(key)
                            .font(.system(.footnote, design: .monospaced))
                            .lineLimit(3)
                        Button(localized("privilegeKeys.useGeneratedKey")) {
                            model.usePrivilegeKey(key)
                        }
                        .disabled(model.state != .connected)
                        Button(localized("privilegeKeys.copyGeneratedKey")) {
                            TS3PlatformSupport.copyToPasteboard(key)
                        }
                        Button(localized("privilegeKeys.copyGeneratedKeySummary")) {
                            TS3PlatformSupport.copyToPasteboard(generatedKeySnapshot(key))
                        }
                        Button(localized("privilegeKeys.copyFullInviteLinkWithKey")) {
                            model.copyCurrentFullInviteLink(privilegeKey: key)
                        }
                        Button(localized("privilegeKeys.saveAsConnectionKey")) {
                            model.saveCurrentConnectionPrivilegeKey(key)
                        }
                        Button(localized("privilegeKeys.exportGeneratedKey")) {
                            generatedKeyDocument = TS3TextFileDocument(data: Data(generatedKeySnapshot(key).utf8))
                            isExportingGeneratedKey = true
                        }
                    }
                }

                Section(header: Text(localized("privilegeKeys.create"))) {
                    Picker(localized("groups.type"), selection: $targetType) {
                        ForEach(TS3PrivilegeKeyTargetType.allCases) { type in
                            Text(targetTypeTitle(type)).tag(type)
                        }
                    }

                    if targetType == .serverGroup {
                        Picker(localized("privilegeKeys.serverGroup"), selection: $selectedServerGroupId) {
                            ForEach(model.serverGroups) { group in
                                Text(group.name).tag(group.id)
                            }
                        }
                        Text(localized("privilegeKeys.targetFormat", serverGroupName(selectedServerGroupId), selectedServerGroupId))
                            .font(.caption)
                            .foregroundColor(.secondary)
                    } else {
                        Picker(localized("privilegeKeys.channelGroup"), selection: $selectedChannelGroupId) {
                            ForEach(model.channelGroups) { group in
                                Text(group.name).tag(group.id)
                            }
                        }
                        Picker(localized("privilegeKeys.channel"), selection: $selectedChannelId) {
                            ForEach(model.channels) { channel in
                                Text(channel.name).tag(channel.id)
                            }
                        }
                        Text(localized(
                            "privilegeKeys.channelTargetFormat",
                            channelGroupName(selectedChannelGroupId),
                            selectedChannelGroupId,
                            channelName(selectedChannelId),
                            selectedChannelId
                        ))
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }

                    TextField(localized("temporaryPasswords.description"), text: $description)
                        .ts3PlainTextField()
                    TextField(localized("privilegeKeys.customSet"), text: $customSet)
                        .ts3PlainTextField()
                    ServerInfoDetailRow(
                        label: localized("privilegeKeys.draftCoverage"),
                        value: localized(
                            "privilegeKeys.draftCoverageFormat",
                            privilegeKeyDraftCoverageSummary.coveredTargetFieldCount,
                            privilegeKeyDraftCoverageSummary.requiredTargetFieldCount,
                            privilegeKeyDraftCoverageSummary.validationIssueCount
                        )
                    )
                    Text(privilegeKeyDraftCoverageText(privilegeKeyDraftCoverageSummary))
                        .font(.caption)
                        .foregroundColor(privilegeKeyDraftCoverageSummary.needsAttention ? .orange : .secondary)
                    Button(localized("privilegeKeys.copyDraftCoverage")) {
                        TS3PlatformSupport.copyToPasteboard(privilegeKeyDraftCoverageSummary.clipboardSummary)
                    }
                    Text(privilegeKeyDraftSummary)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("temporaryPasswords.copyCreationSummary")) {
                        TS3PlatformSupport.copyToPasteboard(privilegeKeyDraftSummary)
                    }
                    ForEach(privilegeKeyDraftValidationMessages, id: \.self) { message in
                        Text(message)
                            .font(.caption)
                            .foregroundColor(.red)
                    }
                    Button(localized("privilegeKeys.createPrivilegeKey")) {
                        model.createPrivilegeKey(
                            targetType: targetType,
                            groupId: selectedGroupId,
                            channelId: selectedChannelId == 0 ? nil : selectedChannelId,
                            description: description,
                            customSet: customSet
                        )
                        description = ""
                        customSet = ""
                    }
                    .disabled(model.state != .connected || !canCreate)
                }

                Section(header: Text(localized("privilegeKeys.existingKeys"))) {
                    Picker(localized("groups.type"), selection: $keyFilter) {
                        ForEach(KeyFilter.allCases) { filter in
                            Text(keyFilterTitle(filter)).tag(filter)
                        }
                    }
                    Picker(localized("groups.sortBy"), selection: $sortMode) {
                        ForEach(KeySortMode.allCases) { mode in
                            Text(keySortModeTitle(mode)).tag(mode)
                        }
                    }
                    Toggle(localized("groups.ascending"), isOn: $sortAscending)
                    TextField(localized("privilegeKeys.searchKeys"), text: $searchText)
                        .ts3PlainTextField()
                    Menu {
                        TextField(localized("groups.presetName"), text: $presetName)
                        Button(localized("groups.saveCurrentFilters")) {
                            model.savePrivilegeKeyFilterPreset(
                                name: presetName,
                                keyFilter: keyFilter.rawValue,
                                sortMode: sortMode.rawValue,
                                sortAscending: sortAscending,
                                searchText: searchText
                            )
                            presetName = ""
                        }
                        .disabled(presetName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                        if model.privilegeKeyFilterPresets.isEmpty {
                            Text(localized("privilegeKeys.noSavedFilterPresets"))
                        } else {
                            ForEach(model.privilegeKeyFilterPresets) { preset in
                                Menu {
                                    Button(localized("groups.applyPreset")) {
                                        applyPreset(preset)
                                    }
                                    Button(localized("groups.useName")) {
                                        presetName = preset.name
                                    }
                                    Button(localized("groups.deletePreset")) {
                                        model.deletePrivilegeKeyFilterPreset(preset)
                                    }
                                } label: {
                                    VStack(alignment: .leading) {
                                        Text(preset.name)
                                        Text(presetSummary(preset))
                                    }
                                }
                            }
                        }
                        Divider()
                        Button(localized("groups.exportPresets")) {
                            exportPresets()
                        }
                        .disabled(model.privilegeKeyFilterPresets.isEmpty)
                        Button(localized("groups.importPresets")) {
                            isImportingPresets = true
                        }
                        Button(localized("groups.deleteAllPresets")) {
                            isConfirmingDeletePresets = true
                        }
                        .disabled(model.privilegeKeyFilterPresets.isEmpty)
                    } label: {
                        Label(localized("groups.filterPresets"), systemImage: "line.3.horizontal.decrease.circle")
                    }
                    if hasLocalFilters {
                        Button(localized("groups.clearFilters")) {
                            keyFilter = .all
                            sortMode = .created
                            sortAscending = false
                            searchText = ""
                        }
                    }
                    if !filteredPrivilegeKeys.isEmpty {
                        ServerInfoDetailRow(
                            label: localized("privilegeKeys.visibleSummary"),
                            value: localized(
                                "privilegeKeys.visibleSummaryFormat",
                                visiblePrivilegeKeySummary.totalCount,
                                visiblePrivilegeKeySummary.channelScopedCount
                            )
                        )
                        Text(privilegeKeyListSummaryText(visiblePrivilegeKeySummary))
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }

                    Button(localized("privilegeKeys.copyVisibleSummary")) {
                        TS3PlatformSupport.copyToPasteboard(visiblePrivilegeKeySummary.clipboardSummary)
                    }
                    .disabled(filteredPrivilegeKeys.isEmpty)

                    Button(localized("privilegeKeys.copyVisibleKeys")) {
                        TS3PlatformSupport.copyToPasteboard(privilegeKeysSnapshot)
                    }
                    .disabled(filteredPrivilegeKeys.isEmpty)

                    Button(localized("privilegeKeys.exportVisibleKeys")) {
                        keysExportDocument = TS3TextFileDocument(data: Data(privilegeKeysSnapshot.utf8))
                        isExportingKeys = true
                    }
                    .disabled(filteredPrivilegeKeys.isEmpty)

                    Button(localized("privilegeKeys.exportBackup")) {
                        exportPrivilegeKeyBackup()
                    }
                    .disabled(model.privilegeKeys.isEmpty)

                    Button(localized("privilegeKeys.importBackup")) {
                        isImportingKeyBackup = true
                    }

                    Button(localized("privilegeKeys.deleteVisibleKeys")) {
                        isConfirmingDeleteAll = true
                    }
                    .disabled(model.state != .connected || filteredPrivilegeKeys.isEmpty)
                    .foregroundColor(.red)

                    if model.privilegeKeys.isEmpty {
                        Text(localized("privilegeKeys.noKeys"))
                            .foregroundColor(.secondary)
                    } else if filteredPrivilegeKeys.isEmpty {
                        Text(localized("privilegeKeys.noMatchingKeys"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(filteredPrivilegeKeys) { key in
                            PrivilegeKeyRow(key: key)
                                .environmentObject(model)
                        }
                    }
                }
            }
            .fileExporter(
                isPresented: $isExportingKeys,
                document: keysExportDocument,
                contentType: .plainText,
                defaultFilename: "ts3-privilege-keys"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingGeneratedKey,
                document: generatedKeyDocument,
                contentType: .plainText,
                defaultFilename: "ts3-generated-privilege-key"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingKeyBackup,
                document: keysBackupDocument,
                contentType: .json,
                defaultFilename: "ts3-privilege-key-backup"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingKeyBackup,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    preparePrivilegeKeyBackupImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPresets,
                document: presetsDocument,
                contentType: .json,
                defaultFilename: "ts3-privilege-key-filter-presets"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPresets,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    importPresets(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .alert(isPresented: $isConfirmingDeleteAll) {
                Alert(
                    title: Text(localized("privilegeKeys.deleteVisibleAlert.title")),
                    message: Text(localized("privilegeKeys.deleteVisibleAlert.messageFormat", filteredPrivilegeKeys.count)),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deletePrivilegeKeys(filteredPrivilegeKeys)
                    },
                    secondaryButton: .cancel()
                )
            }
            .sheet(item: $pendingKeyBackupImport) { confirmation in
                PrivilegeKeyBackupImportSheet(
                    preview: confirmation.preview,
                    previewMessage: privilegeKeyBackupPreviewMessage(confirmation.preview),
                    importBackup: { selectedKey in
                        importPrivilegeKeyBackup(data: confirmation.data, selectedKey: selectedKey)
                        pendingKeyBackupImport = nil
                    },
                    cancel: {
                        pendingKeyBackupImport = nil
                    }
                )
            }
            .alert(isPresented: $isConfirmingDeletePresets) {
                Alert(
                    title: Text(localized("privilegeKeys.deleteAllPresetsAlert.title")),
                    message: Text(localized("groups.deleteAllPresetsAlert.messageFormat", model.privilegeKeyFilterPresets.count)),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deleteAllPrivilegeKeyFilterPresets()
                    },
                    secondaryButton: .cancel()
                )
            }
            .navigationTitle(localized("privilegeKeys.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                applyInitialSelection()
                normalizeSelections()
                if model.state == .connected {
                    model.refreshGroups()
                    model.refreshPrivilegeKeys()
                }
            }
            .onChange(of: model.serverGroups.map(\.id)) { _ in
                normalizeSelections()
            }
            .onChange(of: model.channelGroups.map(\.id)) { _ in
                normalizeSelections()
            }
            .onChange(of: model.channels.map(\.id)) { _ in
                normalizeSelections()
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("groups.refresh")) {
                        model.refreshGroups()
                        model.refreshPrivilegeKeys()
                    }
                    .disabled(model.state != .connected)
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.done")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
        }
    }

    private var selectedGroupId: Int {
        targetType == .serverGroup ? selectedServerGroupId : selectedChannelGroupId
    }

    private var canCreate: Bool {
        privilegeKeyDraftValidationMessages.isEmpty
    }

    private var privilegeKeyDraftValidationMessages: [String] {
        TS3PrivilegeKeyDraftValidator.validationMessages(
            targetType: targetType,
            groupId: selectedGroupId,
            channelId: selectedChannelId == 0 ? nil : selectedChannelId,
            description: description,
            customSet: customSet
        )
    }

    private var privilegeKeyDraftSummary: String {
        TS3PrivilegeKeyDraftValidator.creationSummary(
            targetType: targetType,
            groupId: selectedGroupId,
            groupName: selectedGroupName,
            channelId: selectedChannelId == 0 ? nil : selectedChannelId,
            channelName: selectedChannelId == 0 ? nil : channelName(selectedChannelId),
            description: description,
            customSet: customSet
        )
    }

    private var privilegeKeyDraftCoverageSummary: TS3PrivilegeKeyDraftCoverageSummary {
        TS3PrivilegeKeyDraftCoverageSummary(
            targetType: targetType,
            groupId: selectedGroupId,
            channelId: selectedChannelId == 0 ? nil : selectedChannelId,
            description: description,
            customSet: customSet,
            validationMessages: privilegeKeyDraftValidationMessages
        )
    }

    private func privilegeKeyDraftCoverageText(_ summary: TS3PrivilegeKeyDraftCoverageSummary) -> String {
        [
            localized("privilegeKeys.draftCoverageTypeFormat", targetTypeTitle(summary.targetType)),
            localized("privilegeKeys.draftCoverageGroupFormat", summary.hasGroup ? 1 : 0),
            localized("privilegeKeys.draftCoverageChannelFormat", summary.requiresChannel ? (summary.hasChannel ? 1 : 0) : 0),
            localized("privilegeKeys.draftCoverageDescriptionFormat", summary.hasDescription ? 1 : 0),
            localized("privilegeKeys.draftCoverageCustomSetFormat", summary.hasCustomSet ? 1 : 0)
        ].joined(separator: " | ")
    }

    private var normalizedSearchText: String {
        searchText.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    private var isSearching: Bool {
        !normalizedSearchText.isEmpty
    }

    private var hasLocalFilters: Bool {
        isSearching || keyFilter != .all || sortMode != .created || sortAscending
    }

    private var filteredPrivilegeKeys: [TS3PrivilegeKeySummary] {
        let keys = model.privilegeKeys.filter { key in
            keyFilter.matches(key) && (
                !isSearching
                    || containsSearch(key.key)
                    || containsSearch(key.description)
                    || containsSearch(key.customSet)
                    || key.type.map { containsSearch($0.title) || String($0.rawValue).contains(normalizedSearchText) } == true
                    || String(key.groupId).contains(normalizedSearchText)
                    || key.channelId.map { String($0).contains(normalizedSearchText) } == true
            )
        }
        return sortedPrivilegeKeys(keys)
    }

    private func containsSearch(_ value: String?) -> Bool {
        guard let value, !normalizedSearchText.isEmpty else { return false }
        return value.lowercased().contains(normalizedSearchText)
    }

    private func sortedPrivilegeKeys(_ keys: [TS3PrivilegeKeySummary]) -> [TS3PrivilegeKeySummary] {
        keys.sorted { lhs, rhs in
            if lhs.id == rhs.id {
                return false
            }

            let comparison: ComparisonResult
            switch sortMode {
            case .created:
                comparison = compareDates(lhs.createdAt, rhs.createdAt)
            case .type:
                comparison = typeText(lhs).localizedCaseInsensitiveCompare(typeText(rhs))
            case .group:
                comparison = compareInts(lhs.groupId, rhs.groupId)
            case .channel:
                comparison = compareOptionalInts(lhs.channelId, rhs.channelId)
            case .description:
                comparison = (lhs.description ?? "").localizedCaseInsensitiveCompare(rhs.description ?? "")
            }

            if comparison == .orderedSame {
                return lhs.key.localizedCaseInsensitiveCompare(rhs.key) == .orderedAscending
            }
            return sortAscending ? comparison == .orderedAscending : comparison == .orderedDescending
        }
    }

    private func compareDates(_ lhs: Date?, _ rhs: Date?) -> ComparisonResult {
        switch (lhs, rhs) {
        case let (lhs?, rhs?):
            return lhs.compare(rhs)
        case (nil, nil):
            return .orderedSame
        case (nil, _):
            return .orderedAscending
        case (_, nil):
            return .orderedDescending
        }
    }

    private func compareInts(_ lhs: Int, _ rhs: Int) -> ComparisonResult {
        if lhs == rhs {
            return .orderedSame
        }
        return lhs < rhs ? .orderedAscending : .orderedDescending
    }

    private func compareOptionalInts(_ lhs: Int?, _ rhs: Int?) -> ComparisonResult {
        switch (lhs, rhs) {
        case let (lhs?, rhs?):
            return compareInts(lhs, rhs)
        case (nil, nil):
            return .orderedSame
        case (nil, _):
            return .orderedAscending
        case (_, nil):
            return .orderedDescending
        }
    }

    private func typeText(_ key: TS3PrivilegeKeySummary) -> String {
        key.type.map(typeTitle) ?? localized("common.unknown")
    }

    private func normalizeSelections() {
        if selectedServerGroupId == 0 || (!model.serverGroups.isEmpty && !model.serverGroups.contains(where: { $0.id == selectedServerGroupId })) {
            selectedServerGroupId = model.serverGroups.first?.id ?? 0
        }
        if selectedChannelGroupId == 0 || (!model.channelGroups.isEmpty && !model.channelGroups.contains(where: { $0.id == selectedChannelGroupId })) {
            selectedChannelGroupId = model.channelGroups.first?.id ?? 0
        }
        if selectedChannelId == 0 || (!model.channels.isEmpty && !model.channels.contains(where: { $0.id == selectedChannelId })) {
            selectedChannelId = model.currentChannel?.id ?? model.channels.first?.id ?? 0
        }
    }

    private func applyInitialSelection() {
        if let initialTargetType {
            targetType = initialTargetType
        }
        if let initialServerGroupId {
            selectedServerGroupId = initialServerGroupId
        }
        if let initialChannelGroupId {
            selectedChannelGroupId = initialChannelGroupId
        }
        if let initialChannelId {
            selectedChannelId = initialChannelId
        }
    }

    private func exportPrivilegeKeyBackup() {
        do {
            keysBackupDocument = TS3TextFileDocument(data: try model.privilegeKeyBackupData())
            isExportingKeyBackup = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func preparePrivilegeKeyBackupImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.privilegeKeyBackupPreview(from: data)
            pendingKeyBackupImport = KeyBackupImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPrivilegeKeyBackup(data: Data, selectedKey: String) {
        do {
            try model.importPrivilegeKeyBackup(from: data, selectedKey: selectedKey)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func privilegeKeyListSummaryText(_ summary: TS3PrivilegeKeyListSummary) -> String {
        var parts = [
            localized("privilegeKeys.summary.serverGroupFormat", summary.serverGroupCount),
            localized("privilegeKeys.summary.channelGroupFormat", summary.channelGroupCount),
            localized("privilegeKeys.summary.unknownFormat", summary.unknownTypeCount),
            localized("privilegeKeys.summary.describedFormat", summary.describedCount),
            localized("privilegeKeys.summary.customSetFormat", summary.customSetCount)
        ]
        if let latestCreatedAt = summary.latestCreatedAt {
            let formatter = DateFormatter()
            formatter.dateStyle = .medium
            formatter.timeStyle = .short
            parts.append(localized("privilegeKeys.summary.createdFormat", formatter.string(from: latestCreatedAt)))
        }
        return parts.joined(separator: " · ")
    }

    private func privilegeKeyBackupPreviewMessage(_ preview: TS3PrivilegeKeyBackupPreview) -> String {
        var lines = [
            localized("privilegeKeys.backupPreview.keysFormat", preview.keyCount),
            localized("privilegeKeys.backupPreview.serverGroupKeysFormat", preview.serverGroupCount),
            localized("privilegeKeys.backupPreview.channelGroupKeysFormat", preview.channelGroupCount)
        ]
        if preview.unknownTypeCount > 0 {
            lines.append(localized("privilegeKeys.backupPreview.unknownTypeKeysFormat", preview.unknownTypeCount))
        }
        if !preview.typeSummaries.isEmpty {
            lines.append(localized("privilegeKeys.backupPreview.typesFormat", preview.typeSummaries.joined(separator: " | ")))
        }
        if !preview.targetSummaries.isEmpty {
            lines.append(localized("privilegeKeys.backupPreview.targetsFormat", preview.targetSummaries.joined(separator: " | ")))
        }
        if let firstKey = preview.firstKey {
            lines.append(localized("privilegeKeys.backupPreview.firstKeyFormat", firstKey))
        }
        if let firstType = preview.firstType {
            lines.append(localized("privilegeKeys.backupPreview.firstTargetTypeFormat", typeTitle(firstType)))
        }
        if let groupId = preview.firstGroupId {
            lines.append(localized("privilegeKeys.backupPreview.firstGroupFormat", selectedBackupGroupName(type: preview.firstType, groupId: groupId), groupId))
        }
        if let channelId = preview.firstChannelId {
            lines.append(localized("privilegeKeys.backupPreview.firstChannelFormat", channelName(channelId), channelId))
        }
        if let description = preview.firstDescription, !description.isEmpty {
            lines.append(localized("privilegeKeys.backupPreview.firstDescriptionFormat", description))
        }
        if let customSet = preview.firstCustomSet, !customSet.isEmpty {
            lines.append(localized("privilegeKeys.backupPreview.firstCustomSetFormat", customSet))
        }
        lines.append(preview.hasKeys ? localized("privilegeKeys.backupPreview.hasKeys") : localized("privilegeKeys.backupPreview.noUsableKeys"))
        return lines.joined(separator: "\n")
    }

    private func selectedBackupGroupName(type: TS3PrivilegeKeyType?, groupId: Int) -> String {
        switch type {
        case .serverGroup:
            return serverGroupName(groupId)
        case .channelGroup:
            return channelGroupName(groupId)
        case nil:
            return localized("groups.groupFallbackFormat", groupId)
        }
    }

    private func applyPreset(_ preset: TS3PrivilegeKeyFilterPreset) {
        keyFilter = KeyFilter(rawValue: preset.keyFilter) ?? .all
        sortMode = KeySortMode(rawValue: preset.sortMode) ?? .created
        sortAscending = preset.sortAscending
        searchText = preset.searchText
        presetName = preset.name
    }

    private func presetSummary(_ preset: TS3PrivilegeKeyFilterPreset) -> String {
        var parts = [
            keyFilterTitle(KeyFilter(rawValue: preset.keyFilter) ?? .all),
            localized("permissions.presetSummary.sortFormat", keySortModeTitle(KeySortMode(rawValue: preset.sortMode) ?? .created))
        ]
        if preset.sortAscending {
            parts.append(localized("groups.ascending"))
        }
        if !preset.searchText.isEmpty {
            parts.append(localized("temporaryPasswords.presetSummary.searchFormat", preset.searchText))
        }
        return parts.joined(separator: " · ")
    }

    private func exportPresets() {
        do {
            presetsDocument = TS3BookmarkFileDocument(data: try model.privilegeKeyFilterPresetsExportData())
            isExportingPresets = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPresets(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            _ = try model.importPrivilegeKeyFilterPresets(from: Data(contentsOf: url))
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func generatedKeySnapshot(_ key: String) -> String {
        if let entry = model.privilegeKeys.first(where: { $0.key == key }) {
            return entry.clipboardSummary(
                serverGroups: model.serverGroups,
                channelGroups: model.channelGroups,
                channels: model.channels
            )
        }
        return [
            "key=\(key)",
            "targetType=\(targetType.title)",
            "group=\(selectedGroupName) (\(selectedGroupId))",
            "channel=\(selectedChannelText)",
            "description=\(description.trimmingCharacters(in: .whitespacesAndNewlines))",
            "customSet=\(customSet.trimmingCharacters(in: .whitespacesAndNewlines))"
        ]
        .filter { !$0.hasSuffix("=") }
        .joined(separator: " | ")
    }

    private var selectedGroupName: String {
        targetType == .serverGroup ? serverGroupName(selectedServerGroupId) : channelGroupName(selectedChannelGroupId)
    }

    private var selectedChannelText: String {
        targetType == .channelGroup ? "\(channelName(selectedChannelId)) (\(selectedChannelId))" : localized("common.none")
    }

    private func serverGroupName(_ id: Int) -> String {
        TS3GroupSummary.name(for: id, in: model.serverGroups)
    }

    private func channelGroupName(_ id: Int) -> String {
        TS3GroupSummary.name(for: id, in: model.channelGroups)
    }

    private func channelName(_ id: Int) -> String {
        model.channels.first { $0.id == id }?.name ?? localized("groups.members.channelFallbackFormat", id)
    }

    private func targetTypeTitle(_ type: TS3PrivilegeKeyTargetType) -> String {
        switch type {
        case .serverGroup:
            return localized("privilegeKeys.serverGroup")
        case .channelGroup:
            return localized("privilegeKeys.channelGroup")
        }
    }

    private func typeTitle(_ type: TS3PrivilegeKeyType) -> String {
        switch type {
        case .serverGroup:
            return localized("privilegeKeys.serverGroup")
        case .channelGroup:
            return localized("privilegeKeys.channelGroup")
        }
    }

    private func keyFilterTitle(_ filter: KeyFilter) -> String {
        switch filter {
        case .all:
            return localized("privilegeKeys.filter.all")
        case .serverGroup:
            return localized("privilegeKeys.serverGroup")
        case .channelGroup:
            return localized("privilegeKeys.channelGroup")
        case .unknown:
            return localized("privilegeKeys.filter.unknown")
        case .withDescription:
            return localized("privilegeKeys.filter.withDescription")
        case .withCustomSet:
            return localized("privilegeKeys.filter.withCustomSet")
        }
    }

    private func keySortModeTitle(_ mode: KeySortMode) -> String {
        switch mode {
        case .created:
            return localized("privilegeKeys.sort.created")
        case .type:
            return localized("groups.type")
        case .group:
            return localized("privilegeKeys.sort.group")
        case .channel:
            return localized("privilegeKeys.channel")
        case .description:
            return localized("temporaryPasswords.description")
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

}

private struct PrivilegeKeyBackupImportSheet: View {
    let preview: TS3PrivilegeKeyBackupPreview
    let previewMessage: String
    let importBackup: (String) -> Void
    let cancel: () -> Void
    @State private var selectedKey: String = ""

    private var selectedKeyOrFirst: String {
        preview.containsKey(selectedKey) ? selectedKey : (preview.candidates.first?.key ?? "")
    }

    private var selectedCandidate: TS3PrivilegeKeyBackupPreview.Candidate? {
        preview.candidates.first { $0.key == selectedKeyOrFirst }
    }

    private var selectedImpact: TS3PrivilegeKeyImportImpactSummary? {
        selectedCandidate.map(TS3PrivilegeKeyImportImpactSummary.init(candidate:))
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("privilegeKeys.import.preview"))) {
                    Text(previewMessage)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    if preview.hasKeys {
                        Button(localized("privilegeKeys.copyKeySummary")) {
                            TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                        }
                        Picker(localized("privilegeKeys.key"), selection: $selectedKey) {
                            ForEach(preview.candidates) { candidate in
                                Text(candidate.key)
                                    .tag(candidate.key)
                            }
                        }
                        if let selectedCandidate {
                            Text(selectedCandidate.summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                                .lineLimit(2)
                                .truncationMode(.middle)
                        }
                        if let selectedImpact {
                            ServerInfoDetailRow(
                                label: localized("privilegeKeys.import.impact"),
                                value: localized(
                                    "privilegeKeys.import.impactFormat",
                                    selectedImpact.type.map(typeTitle) ?? localized("privilegeKeys.filter.unknown"),
                                    selectedImpact.groupId
                                )
                            )
                            Text(privilegeKeyImportImpactText(selectedImpact))
                                .font(.caption2)
                                .foregroundColor(selectedImpact.needsAttention ? .orange : .secondary)
                            Button(localized("privilegeKeys.import.copyImpact")) {
                                TS3PlatformSupport.copyToPasteboard(selectedImpact.clipboardSummary)
                            }
                        }
                        ForEach(preview.typeSummaries, id: \.self) { summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                        }
                        ForEach(preview.targetSummaries, id: \.self) { summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                        }
                        ForEach(Array(preview.keySummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .lineLimit(2)
                                .truncationMode(.middle)
                        }
                    }
                }

                Section(header: Text(localized("privilegeKeys.import.behavior"))) {
                    Text(localized("privilegeKeys.import.behaviorSummary"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("privilegeKeys.import.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                if selectedKey.isEmpty {
                    selectedKey = preview.firstKey ?? ""
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("privilegeKeys.import.action")) {
                        importBackup(selectedKeyOrFirst)
                    }
                    .disabled(!preview.hasKeys || selectedKeyOrFirst.isEmpty)
                }
            }
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    private func privilegeKeyImportImpactText(_ impact: TS3PrivilegeKeyImportImpactSummary) -> String {
        var parts = [
            localized("privilegeKeys.import.impactChannelScopedFormat", impact.isChannelScoped ? 1 : 0),
            localized("privilegeKeys.import.impactDescriptionFormat", impact.hasDescription ? 1 : 0),
            localized("privilegeKeys.import.impactCustomSetFormat", impact.hasCustomSet ? 1 : 0)
        ]
        if impact.isAnyChannelGroupKey {
            parts.append(localized("privilegeKeys.import.impactAnyChannel"))
        }
        if !impact.isKnownType {
            parts.append(localized("privilegeKeys.import.impactUnknownType"))
        }
        return parts.joined(separator: " | ")
    }

    private func typeTitle(_ type: TS3PrivilegeKeyType) -> String {
        switch type {
        case .serverGroup:
            return localized("privilegeKeys.serverGroup")
        case .channelGroup:
            return localized("privilegeKeys.channelGroup")
        }
    }
}

struct PrivilegeKeyRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let key: TS3PrivilegeKeySummary
    @State private var isConfirmingDelete = false

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            HStack(alignment: .top) {
                VStack(alignment: .leading, spacing: 4) {
                    Text(key.key)
                        .font(.system(.footnote, design: .monospaced))
                        .lineLimit(3)
                    Text(targetText)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    if let description = key.description, !description.isEmpty {
                        Text(description)
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                    if let customSet = key.customSet, !customSet.isEmpty {
                        Text(customSet)
                            .font(.caption)
                            .foregroundColor(.secondary)
                            .lineLimit(2)
                    }
                }
                Spacer()
                Menu {
                    Button(localized("privilegeKeys.useKey")) {
                        model.usePrivilegeKey(key.key)
                    }
                    .disabled(model.state != .connected)
                    Button(localized("privilegeKeys.copyFullInviteLinkWithKey")) {
                        model.copyCurrentFullInviteLink(privilegeKey: key.key)
                    }
                    Button(localized("privilegeKeys.saveAsConnectionKey")) {
                        model.saveCurrentConnectionPrivilegeKey(key.key)
                    }
                    Button(localized("privilegeKeys.copyKey")) {
                        TS3PlatformSupport.copyToPasteboard(key.key)
                    }
                    Button(localized("groups.row.copySummary")) {
                        TS3PlatformSupport.copyToPasteboard(clipboardSummary)
                    }
                    Button(localized("privilegeKeys.deleteKey")) {
                        isConfirmingDelete = true
                    }
                    .disabled(model.state != .connected)
                } label: {
                    Image(systemName: "ellipsis.circle")
                }
            }
            if let createdAt = key.createdAt {
                Text(Self.dateText(createdAt))
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
        }
        .padding(.vertical, 3)
        .alert(isPresented: $isConfirmingDelete) {
            Alert(
                title: Text(localized("privilegeKeys.deleteKeyAlert.title")),
                message: Text(key.key),
                primaryButton: .destructive(Text(localized("common.delete"))) {
                    model.deletePrivilegeKey(key)
                },
                secondaryButton: .cancel()
            )
        }
        .contextMenu {
            Button(localized("privilegeKeys.useKey")) {
                model.usePrivilegeKey(key.key)
            }
            .disabled(model.state != .connected)
            Button(localized("privilegeKeys.copyFullInviteLinkWithKey")) {
                model.copyCurrentFullInviteLink(privilegeKey: key.key)
            }
            Button(localized("privilegeKeys.saveAsConnectionKey")) {
                model.saveCurrentConnectionPrivilegeKey(key.key)
            }
            Button(localized("privilegeKeys.copyKey")) {
                TS3PlatformSupport.copyToPasteboard(key.key)
            }
            Button(localized("groups.row.copySummary")) {
                TS3PlatformSupport.copyToPasteboard(clipboardSummary)
            }
            Button(localized("privilegeKeys.deleteKey")) {
                isConfirmingDelete = true
            }
            .foregroundColor(.red)
            .disabled(model.state != .connected)
        }
        .accessibilityElement(children: .ignore)
        .accessibilityLabel(localized("privilegeKeys.accessibility.privilegeKey"))
        .accessibilityValue(key.accessibilityValue(
            serverGroups: model.serverGroups,
            channelGroups: model.channelGroups,
            channels: model.channels
        ))
        .accessibilityAction(named: localized("groups.row.copySummary")) {
            TS3PlatformSupport.copyToPasteboard(clipboardSummary)
        }
        .accessibilityAction(named: localized("privilegeKeys.useKey")) {
            if model.state == .connected {
                model.usePrivilegeKey(key.key)
            }
        }
        .accessibilityAction(named: localized("privilegeKeys.saveAsConnectionKey")) {
            model.saveCurrentConnectionPrivilegeKey(key.key)
        }
        .accessibilityAction(named: localized("privilegeKeys.deleteKey")) {
            if model.state == .connected {
                isConfirmingDelete = true
            }
        }
    }

    private var targetText: String {
        key.targetSummary(
            serverGroups: model.serverGroups,
            channelGroups: model.channelGroups,
            channels: model.channels
        )
    }

    private var clipboardSummary: String {
        key.clipboardSummary(
            serverGroups: model.serverGroups,
            channelGroups: model.channelGroups,
            channels: model.channels
        )
    }

    private static func dateText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .short
        formatter.timeStyle = .short
        return formatter.string(from: date)
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

struct BanListSheet: View {
    private struct BanBackupImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3BanBackupPreview
        let id = UUID()
    }

    private struct BanFilterPresetImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3BanFilterPresetImportPreview
        let id = UUID()
    }

    private enum BanFilter: String, CaseIterable, Identifiable {
        case all
        case ip
        case name
        case uniqueIdentifier
        case permanent
        case temporary

        var id: String { rawValue }

        var title: String {
            switch self {
            case .all: return NSLocalizedString("ban.filter.all", comment: "")
            case .ip: return NSLocalizedString("ban.filter.ip", comment: "")
            case .name: return NSLocalizedString("ban.filter.name", comment: "")
            case .uniqueIdentifier: return NSLocalizedString("contacts.editor.uniqueId", comment: "")
            case .permanent: return NSLocalizedString("ban.duration.permanent", comment: "")
            case .temporary: return NSLocalizedString("ban.filter.temporary", comment: "")
            }
        }

        func matches(_ entry: TS3BanEntrySummary) -> Bool {
            switch self {
            case .all:
                return true
            case .ip:
                return entry.ip?.isEmpty == false
            case .name:
                return entry.name?.isEmpty == false || entry.lastNickname?.isEmpty == false
            case .uniqueIdentifier:
                return entry.uniqueIdentifier?.isEmpty == false
            case .permanent:
                return entry.durationSeconds == nil || entry.durationSeconds == 0
            case .temporary:
                return (entry.durationSeconds ?? 0) > 0
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var isConfirmingDeleteAll = false
    @State private var isConfirmingDeleteVisible = false
    @State private var isExportingBans = false
    @State private var isExportingBanBackup = false
    @State private var isExportingPresets = false
    @State private var isImportingBans = false
    @State private var isImportingPresets = false
    @State private var isConfirmingDeletePresets = false
    @State private var banExportDocument = TS3TextFileDocument()
    @State private var banBackupDocument = TS3TextFileDocument()
    @State private var presetsDocument = TS3BookmarkFileDocument()
    @State private var pendingBanBackupImport: BanBackupImportConfirmation?
    @State private var pendingPresetImport: BanFilterPresetImportConfirmation?
    @State private var searchText = ""
    @State private var banFilter: BanFilter = .all
    @State private var presetName = ""
    @State private var ip = ""
    @State private var name = ""
    @State private var uniqueIdentifier = ""
    @State private var myTeamSpeakId = ""
    @State private var lastNickname = ""
    @State private var reason = ""
    @State private var duration: TS3BanDuration = .permanent
    @State private var customBanMinutes = "60"

    private var visibleBanSnapshot: String {
        filteredBanEntries.map(\.clipboardSummary).joined(separator: "\n")
    }

    private var visibleBanSummary: TS3BanListSummary {
        TS3BanListSummary(entries: filteredBanEntries)
    }

    var body: some View {
        NavigationView {
            List {
                Section(header: Text(localized("ban.addBan"))) {
                    TextField(localized("ban.ipAddress"), text: $ip)
                        .ts3PlainTextField()
                    TextField(localized("groups.sort.name"), text: $name)
                        .ts3PlainTextField()
                    TextField(localized("contacts.editor.uniqueId"), text: $uniqueIdentifier)
                        .ts3PlainTextField()
                    TextField(localized("ban.myTeamSpeakId"), text: $myTeamSpeakId)
                        .ts3PlainTextField()
                    TextField(localized("ban.lastNickname"), text: $lastNickname)
                        .ts3PlainTextField()
                    TextField(localized("ban.reason"), text: $reason)
                        .ts3PlainTextField()
                    Picker(localized("ban.duration"), selection: $duration) {
                        ForEach(TS3BanDuration.allCases) { duration in
                            Text(duration.title).tag(duration)
                        }
                    }
                    if duration == .custom {
                        TextField(localized("ban.minutes"), text: $customBanMinutes)
                            .ts3PlainTextField()
                            .ts3NumericKeyboard()
                    }
                    ServerInfoDetailRow(
                        label: localized("ban.draftCoverage"),
                        value: localized(
                            "ban.draftCoverageFormat",
                            banDraftCoverageSummary.targetFieldCount,
                            banDraftCoverageSummary.validationIssueCount
                        )
                    )
                    Text(banDraftCoverageText(banDraftCoverageSummary))
                        .font(.caption)
                        .foregroundColor(banDraftCoverageSummary.needsAttention ? .orange : .secondary)
                    Button(localized("ban.copyDraftCoverage")) {
                        TS3PlatformSupport.copyToPasteboard(banDraftCoverageSummary.clipboardSummary)
                    }
                    Text(banDraftSummary)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    Button(localized("ban.copyRuleSummary")) {
                        TS3PlatformSupport.copyToPasteboard(banDraftSummary)
                    }
                    ForEach(banDraftValidationMessages, id: \.self) { message in
                        Text(message)
                            .font(.caption)
                            .foregroundColor(.red)
                    }
                    Button(localized("ban.addRule")) {
                        model.addBan(
                            ip: ip,
                            name: name,
                            uniqueIdentifier: uniqueIdentifier,
                            myTeamSpeakId: myTeamSpeakId,
                            lastNickname: lastNickname,
                            durationSeconds: duration.seconds(customMinutes: customBanMinutes),
                            reason: reason,
                            isCustomDuration: duration == .custom
                        )
                        clearForm()
                    }
                    .disabled(model.state != .connected || isAddDisabled)
                }

                Section(header: Text(localized("events.filters"))) {
                    Picker(localized("groups.type"), selection: $banFilter) {
                        ForEach(BanFilter.allCases) { filter in
                            Text(filter.title).tag(filter)
                        }
                    }
                    TextField(localized("ban.searchBans"), text: $searchText)
                        .ts3PlainTextField()
                    Menu {
                        TextField(localized("groups.presetName"), text: $presetName)
                        Button(localized("groups.saveCurrentFilters")) {
                            model.saveBanFilterPreset(
                                name: presetName,
                                banFilter: banFilter.rawValue,
                                searchText: searchText
                            )
                            presetName = ""
                        }
                        .disabled(presetName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                        if model.banFilterPresets.isEmpty {
                            Text(localized("ban.noSavedFilterPresets"))
                        } else {
                            ForEach(model.banFilterPresets) { preset in
                                Menu {
                                    Button(localized("groups.applyPreset")) {
                                        applyPreset(preset)
                                    }
                                    Button(localized("groups.useName")) {
                                        presetName = preset.name
                                    }
                                    Button(localized("groups.deletePreset")) {
                                        model.deleteBanFilterPreset(preset)
                                    }
                                } label: {
                                    VStack(alignment: .leading) {
                                        Text(preset.name)
                                        Text(presetSummary(preset))
                                    }
                                }
                            }
                        }
                        Divider()
                        Button(localized("groups.exportPresets")) {
                            exportPresets()
                        }
                        .disabled(model.banFilterPresets.isEmpty)
                        Button(localized("groups.importPresets")) {
                            isImportingPresets = true
                        }
                        Button(localized("groups.deleteAllPresets")) {
                            isConfirmingDeletePresets = true
                        }
                        .disabled(model.banFilterPresets.isEmpty)
                    } label: {
                        Label(localized("groups.filterPresets"), systemImage: "line.3.horizontal.decrease.circle")
                    }
                    if hasLocalFilters {
                        Button(localized("groups.clearFilters")) {
                            banFilter = .all
                            searchText = ""
                        }
                    }
                }

                if model.banEntries.isEmpty {
                    Text(localized("ban.noBans"))
                        .foregroundColor(.secondary)
                } else {
                    Section(header: Text(localized("ban.visibleBans"))) {
                        ServerInfoDetailRow(
                            label: localized("ban.visibleSummary"),
                            value: localized("ban.visibleSummaryFormat", visibleBanSummary.totalCount)
                        )
                        Text(banListSummaryText(visibleBanSummary))
                            .font(.caption)
                            .foregroundColor(.secondary)
                        Button(localized("ban.copyVisibleSummary")) {
                            TS3PlatformSupport.copyToPasteboard(visibleBanSummary.clipboardSummary)
                        }
                        .disabled(filteredBanEntries.isEmpty)
                        Button(localized("ban.copyVisibleBans")) {
                            TS3PlatformSupport.copyToPasteboard(visibleBanSnapshot)
                        }
                        .disabled(filteredBanEntries.isEmpty)
                        Button(localized("ban.exportVisibleBans")) {
                            banExportDocument = TS3TextFileDocument(data: Data(visibleBanSnapshot.utf8))
                            isExportingBans = true
                        }
                        .disabled(filteredBanEntries.isEmpty)
                        Button(localized("ban.exportBackup")) {
                            exportBanBackup()
                        }
                        .disabled(model.banEntries.isEmpty)
                        Button(localized("ban.importBackup")) {
                            isImportingBans = true
                        }
                        .disabled(model.state != .connected)
                        Button(localized("ban.deleteVisibleBans")) {
                            isConfirmingDeleteVisible = true
                        }
                        .foregroundColor(.red)
                        .disabled(model.state != .connected || filteredBanEntries.isEmpty)
                    }

                    if filteredBanEntries.isEmpty {
                        Text(localized("ban.noMatchingBans"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(filteredBanEntries) { entry in
                            BanEntryRow(entry: entry) {
                                applyBanDraft(from: entry)
                            }
                                .environmentObject(model)
                        }
                    }
                    Section {
                        Button(localized("ban.deleteAllBans")) {
                            isConfirmingDeleteAll = true
                        }
                        .foregroundColor(.red)
                        .disabled(model.state != .connected)
                    }
                }
            }
            .fileExporter(
                isPresented: $isExportingBans,
                document: banExportDocument,
                contentType: .plainText,
                defaultFilename: "ts3-ban-list"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingBanBackup,
                document: banBackupDocument,
                contentType: .json,
                defaultFilename: "ts3-ban-backup"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPresets,
                document: presetsDocument,
                contentType: .json,
                defaultFilename: "ts3-ban-filter-presets"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingBans,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareBanBackupImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPresets,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    preparePresetImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .navigationTitle(localized("ban.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                if model.state == .connected {
                    model.refreshBanList()
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("groups.refresh")) {
                        model.refreshBanList()
                    }
                    .disabled(model.state != .connected)
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.done")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .alert(isPresented: $isConfirmingDeleteAll) {
                Alert(
                    title: Text(localized("ban.deleteAllAlert.title")),
                    message: Text(localized("ban.deleteAllAlert.message")),
                    primaryButton: .destructive(Text(localized("ban.deleteAllBans"))) {
                        model.deleteAllBans()
                    },
                    secondaryButton: .cancel()
                )
            }
            .alert(isPresented: $isConfirmingDeleteVisible) {
                Alert(
                    title: Text(localized("ban.deleteVisibleAlert.title")),
                    message: Text(localized("ban.deleteVisibleAlert.messageFormat", filteredBanEntries.count)),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deleteBans(filteredBanEntries)
                    },
                    secondaryButton: .cancel()
                )
            }
            .sheet(item: $pendingBanBackupImport) { confirmation in
                BanBackupImportSheet(
                    preview: confirmation.preview,
                    previewMessage: banBackupPreviewMessage(confirmation.preview),
                    importBackup: { selectedRuleIds in
                        importBanBackup(data: confirmation.data, selectedRuleIds: selectedRuleIds)
                        pendingBanBackupImport = nil
                    },
                    cancel: {
                        pendingBanBackupImport = nil
                    }
                )
            }
            .sheet(item: $pendingPresetImport) { confirmation in
                BanFilterPresetImportSheet(
                    preview: confirmation.preview,
                    importPresets: { selectedPresetIds in
                        importPresets(data: confirmation.data, selectedPresetIds: selectedPresetIds)
                        pendingPresetImport = nil
                    },
                    cancel: {
                        pendingPresetImport = nil
                    }
                )
            }
            .alert(isPresented: $isConfirmingDeletePresets) {
                Alert(
                    title: Text(localized("ban.deleteAllPresetsAlert.title")),
                    message: Text(localized("groups.deleteAllPresetsAlert.messageFormat", model.banFilterPresets.count)),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deleteAllBanFilterPresets()
                    },
                    secondaryButton: .cancel()
                )
            }
        }
    }

    private var isAddDisabled: Bool {
        !banDraftValidationMessages.isEmpty
    }

    private var banDraftValidationMessages: [String] {
        TS3BanDraftValidator.validationMessages(
            ip: ip,
            name: name,
            uniqueIdentifier: uniqueIdentifier,
            myTeamSpeakId: myTeamSpeakId,
            lastNickname: lastNickname,
            durationSeconds: duration.seconds(customMinutes: customBanMinutes),
            isCustomDuration: duration == .custom,
            reason: reason
        )
    }

    private var banDraftSummary: String {
        TS3BanDraftValidator.creationSummary(
            ip: ip,
            name: name,
            uniqueIdentifier: uniqueIdentifier,
            myTeamSpeakId: myTeamSpeakId,
            lastNickname: lastNickname,
            durationSeconds: duration.seconds(customMinutes: customBanMinutes),
            isPermanent: duration == .permanent,
            reason: reason
        )
    }

    private var banDraftCoverageSummary: TS3BanDraftCoverageSummary {
        TS3BanDraftCoverageSummary(
            ip: ip,
            name: name,
            uniqueIdentifier: uniqueIdentifier,
            myTeamSpeakId: myTeamSpeakId,
            lastNickname: lastNickname,
            reason: reason,
            isPermanent: duration == .permanent,
            isCustomDuration: duration == .custom,
            validationMessages: banDraftValidationMessages
        )
    }

    private func banDraftCoverageText(_ summary: TS3BanDraftCoverageSummary) -> String {
        [
            localized("ban.draftCoverageIPFormat", summary.hasIP ? 1 : 0),
            localized("ban.draftCoverageNameFormat", summary.hasName ? 1 : 0),
            localized("ban.draftCoverageUniqueIdFormat", summary.hasUniqueIdentifier ? 1 : 0),
            localized("ban.draftCoverageMyTeamSpeakIdFormat", summary.hasMyTeamSpeakId ? 1 : 0),
            localized("ban.draftCoverageLastNicknameFormat", summary.hasLastNickname ? 1 : 0),
            localized("ban.draftCoverageDurationFormat", summary.isPermanent ? localized("ban.draftCoveragePermanent") : localized("ban.draftCoverageTemporary")),
            localized("ban.draftCoverageReasonFormat", summary.hasReason ? 1 : 0)
        ].joined(separator: " | ")
    }

    private func clearForm() {
        ip = ""
        name = ""
        uniqueIdentifier = ""
        myTeamSpeakId = ""
        lastNickname = ""
        reason = ""
        duration = .permanent
        customBanMinutes = "60"
    }

    private func applyBanDraft(from entry: TS3BanEntrySummary) {
        ip = entry.ip ?? ""
        name = entry.name ?? ""
        uniqueIdentifier = entry.uniqueIdentifier ?? ""
        myTeamSpeakId = ""
        lastNickname = entry.lastNickname ?? ""
        reason = entry.reason ?? ""
        let selection = TS3BanDuration.draftSelection(for: entry.durationSeconds)
        duration = selection.duration
        customBanMinutes = selection.customMinutes
    }

    private var normalizedSearchText: String {
        searchText.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    private var isSearching: Bool {
        !normalizedSearchText.isEmpty
    }

    private var hasLocalFilters: Bool {
        isSearching || banFilter != .all
    }

    private var filteredBanEntries: [TS3BanEntrySummary] {
        return model.banEntries.filter { entry in
            banFilter.matches(entry) && (
                !isSearching
                    || containsSearch(entry.name)
                    || containsSearch(entry.lastNickname)
                    || containsSearch(entry.ip)
                    || containsSearch(entry.uniqueIdentifier)
                    || containsSearch(entry.invokerName)
                    || containsSearch(entry.reason)
            )
        }
    }

    private func containsSearch(_ value: String?) -> Bool {
        guard let value, !normalizedSearchText.isEmpty else { return false }
        return value.lowercased().contains(normalizedSearchText)
    }

    private func applyPreset(_ preset: TS3BanFilterPreset) {
        banFilter = BanFilter(rawValue: preset.banFilter) ?? .all
        searchText = preset.searchText
        presetName = preset.name
    }

    private func presetSummary(_ preset: TS3BanFilterPreset) -> String {
        var parts = [
            (BanFilter(rawValue: preset.banFilter) ?? .all).title
        ]
        if !preset.searchText.isEmpty {
            parts.append(localized("events.searchPresetSummaryFormat", preset.searchText))
        }
        return parts.joined(separator: " · ")
    }

    private func banListSummaryText(_ summary: TS3BanListSummary) -> String {
        [
            localized("ban.summaryIPFormat", summary.ipRuleCount),
            localized("ban.summaryNameFormat", summary.nameRuleCount),
            localized("ban.summaryUniqueIdFormat", summary.uniqueIdentifierRuleCount),
            localized("ban.summaryPermanentFormat", summary.permanentCount),
            localized("ban.summaryTemporaryFormat", summary.temporaryCount),
            localized("ban.summaryWithReasonFormat", summary.withReasonCount),
            localized("ban.summaryEnforcementsFormat", summary.enforcementCount),
            localized(
                "ban.summaryIdRangeFormat",
                summary.lowestBanId.map(String.init) ?? localized("common.none"),
                summary.highestBanId.map(String.init) ?? localized("common.none")
            )
        ].joined(separator: " · ")
    }

    private func exportPresets() {
        do {
            presetsDocument = TS3BookmarkFileDocument(data: try model.banFilterPresetsExportData())
            isExportingPresets = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func preparePresetImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.banFilterPresetsImportPreview(from: data)
            pendingPresetImport = BanFilterPresetImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPresets(data: Data, selectedPresetIds: Set<UUID>) {
        do {
            _ = try model.importBanFilterPresets(from: data, selectedPresetIds: selectedPresetIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func exportBanBackup() {
        do {
            banBackupDocument = TS3TextFileDocument(data: try model.banBackupData())
            isExportingBanBackup = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareBanBackupImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.banBackupPreview(from: data)
            pendingBanBackupImport = BanBackupImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importBanBackup(data: Data, selectedRuleIds: Set<String>) {
        do {
            try model.importBanBackup(from: data, selectedRuleIds: selectedRuleIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func banBackupPreviewMessage(_ preview: TS3BanBackupPreview) -> String {
        var lines = [
            localized("ban.backupPreview.rulesFormat", preview.ruleCount),
            localized("ban.backupPreview.ipRulesFormat", preview.ipRuleCount),
            localized("ban.backupPreview.nameRulesFormat", preview.nameRuleCount),
            localized("ban.backupPreview.uniqueIdRulesFormat", preview.uniqueIdentifierRuleCount),
            localized("ban.backupPreview.lastNicknameRulesFormat", preview.lastNicknameRuleCount)
        ]
        if preview.skippedRuleCount > 0 {
            lines.append(localized("ban.backupPreview.skippedFormat", preview.skippedRuleCount))
        }
        if !preview.targetTypeSummaries.isEmpty {
            lines.append(localized("ban.backupPreview.targetsFormat", preview.targetTypeSummaries.joined(separator: " | ")))
        }
        if !preview.durationSummaries.isEmpty {
            lines.append(localized("ban.backupPreview.durationsFormat", preview.durationSummaries.joined(separator: " | ")))
        }
        if let ip = preview.firstIP {
            lines.append(localized("ban.backupPreview.firstIPFormat", ip))
        }
        if let name = preview.firstName {
            lines.append(localized("ban.backupPreview.firstNameFormat", name))
        }
        if let uniqueIdentifier = preview.firstUniqueIdentifier {
            lines.append(localized("ban.backupPreview.firstUniqueIdFormat", uniqueIdentifier))
        }
        if let lastNickname = preview.firstLastNickname {
            lines.append(localized("ban.backupPreview.firstLastNicknameFormat", lastNickname))
        }
        if let duration = preview.firstDurationSeconds {
            let durationText = duration == 0 ? localized("ban.duration.permanent") : localized("ban.backupPreview.secondsFormat", duration)
            lines.append(localized("ban.backupPreview.firstDurationFormat", durationText))
        }
        if let reason = preview.firstReason {
            lines.append(localized("ban.backupPreview.firstReasonFormat", reason))
        }
        lines.append(preview.hasRules ? localized("ban.backupPreview.hasRules") : localized("ban.backupPreview.noUsableRules"))
        return lines.joined(separator: "\n")
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

private struct BanBackupImportSheet: View {
    let preview: TS3BanBackupPreview
    let previewMessage: String
    let importBackup: (Set<String>) -> Void
    let cancel: () -> Void
    @State private var selectedRuleIds: Set<String> = []

    private var validSelectedRuleIds: Set<String> {
        Set(selectedRuleIds.filter(preview.containsRule))
    }

    private var importImpactSummary: TS3BanImportImpactSummary {
        TS3BanImportImpactSummary(
            candidates: preview.candidates,
            selectedRuleIds: validSelectedRuleIds,
            skippedRuleCount: preview.skippedRuleCount
        )
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("ban.import.preview"))) {
                    Text(previewMessage)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    if preview.hasRules {
                        Button(localized("ban.import.copyRuleSummary")) {
                            TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                        }
                        HStack {
                            Button(localized("ban.import.selectAll")) {
                                selectedRuleIds = Set(preview.candidates.map(\.id))
                            }
                            Button(localized("ban.import.clear")) {
                                selectedRuleIds = []
                            }
                            .disabled(selectedRuleIds.isEmpty)
                        }
                        ServerInfoDetailRow(
                            label: localized("ban.import.impact"),
                            value: localized(
                                "ban.import.impactFormat",
                                importImpactSummary.selectedRuleCount,
                                importImpactSummary.permanentRuleCount,
                                importImpactSummary.temporaryRuleCount
                            )
                        )
                        Text(banImportImpactText(importImpactSummary))
                            .font(.caption2)
                            .foregroundColor(importImpactSummary.needsAttention ? .orange : .secondary)
                        Button(localized("ban.import.copyImpact")) {
                            TS3PlatformSupport.copyToPasteboard(importImpactSummary.clipboardSummary)
                        }
                        .disabled(!importImpactSummary.hasSelection)
                        ForEach(preview.targetTypeSummaries, id: \.self) { summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                        }
                        ForEach(preview.durationSummaries, id: \.self) { summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                        }
                        ForEach(Array(preview.ruleSummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .lineLimit(2)
                                .truncationMode(.middle)
                        }
                        ForEach(preview.candidates) { candidate in
                            Toggle(isOn: Binding(
                                get: { selectedRuleIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedRuleIds.insert(candidate.id)
                                    } else {
                                        selectedRuleIds.remove(candidate.id)
                                    }
                                }
                            )) {
                                Text(candidate.summary)
                                    .font(.caption2)
                                    .lineLimit(2)
                                    .truncationMode(.middle)
                            }
                        }
                    }
                }

                Section(header: Text(localized("ban.import.behavior"))) {
                    Text(localized("ban.import.behaviorSummary"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("ban.import.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                if selectedRuleIds.isEmpty {
                    selectedRuleIds = Set(preview.candidates.map(\.id))
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("ban.import.action")) {
                        importBackup(validSelectedRuleIds)
                    }
                    .disabled(!preview.hasRules || validSelectedRuleIds.isEmpty)
                }
            }
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    private func banImportImpactText(_ summary: TS3BanImportImpactSummary) -> String {
        [
            localized("ban.import.impactTargetsFormat", summary.ipRuleCount, summary.nameRuleCount, summary.uniqueIdentifierRuleCount, summary.lastNicknameRuleCount),
            localized("ban.import.impactUnspecifiedDurationFormat", summary.unspecifiedDurationCount),
            localized("ban.import.impactReasonFormat", summary.withReasonCount),
            localized("ban.import.impactSkippedFormat", summary.skippedRuleCount)
        ].joined(separator: " | ")
    }
}

private struct BanFilterPresetImportSheet: View {
    @Environment(\.presentationMode) private var presentationMode

    let preview: TS3BanFilterPresetImportPreview
    let importPresets: (Set<UUID>) -> Void
    let cancel: () -> Void
    @State private var selectedPresetIds: Set<UUID>

    init(
        preview: TS3BanFilterPresetImportPreview,
        importPresets: @escaping (Set<UUID>) -> Void,
        cancel: @escaping () -> Void
    ) {
        self.preview = preview
        self.importPresets = importPresets
        self.cancel = cancel
        _selectedPresetIds = State(initialValue: Set(preview.candidates.map(\.id)))
    }

    private var canImport: Bool {
        preview.candidates.contains { selectedPresetIds.contains($0.id) }
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("ban.import.preview"))) {
                    Text(localized("ban.filterImport.importedPresetsFormat", preview.importedPresetCount))
                    Text(localized("ban.filterImport.usablePresetsFormat", preview.usablePresetCount))
                    Text(localized("ban.filterImport.newPresetsFormat", preview.newPresetCount))
                    Text(localized("ban.filterImport.replacingPresetsFormat", preview.replacedPresetCount))
                    Text(localized("ban.filterImport.skippedPresetsFormat", preview.skippedPresetCount))
                    Button(localized("ban.filterImport.copyBackupPreview")) {
                        TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                    }
                }

                Section(header: Text(localized("ban.import.restore"))) {
                    HStack {
                        Button(localized("ban.import.selectAll")) {
                            selectedPresetIds = Set(preview.candidates.map(\.id))
                        }
                        Spacer()
                        Button(localized("ban.import.clear")) {
                            selectedPresetIds.removeAll()
                        }
                    }
                    ForEach(preview.candidates) { candidate in
                        Toggle(
                            candidate.summary,
                            isOn: Binding(
                                get: { selectedPresetIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedPresetIds.insert(candidate.id)
                                    } else {
                                        selectedPresetIds.remove(candidate.id)
                                    }
                                }
                            )
                        )
                    }
                }

                Section {
                    Text(localized("ban.filterImport.behavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("ban.filterImport.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("ban.import.action")) {
                        importPresets(selectedPresetIds)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canImport)
                }
            }
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

struct ComplaintListSheet: View {
    private struct ComplaintArchiveImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3ComplaintArchivePreview
        let id = UUID()
    }

    private struct ComplaintFilterPresetImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3ComplaintFilterPresetImportPreview
        let id = UUID()
    }

    private enum ComplaintFilter: String, CaseIterable, Identifiable {
        case all
        case namedSource
        case anonymousSource
        case withMessage
        case withoutMessage
        case withTimestamp

        var id: String { rawValue }

        var title: String {
            switch self {
            case .all: return NSLocalizedString("complaints.filter.all", comment: "")
            case .namedSource: return NSLocalizedString("complaints.filter.namedSource", comment: "")
            case .anonymousSource: return NSLocalizedString("complaints.filter.anonymousSource", comment: "")
            case .withMessage: return NSLocalizedString("complaints.filter.withMessage", comment: "")
            case .withoutMessage: return NSLocalizedString("complaints.filter.withoutMessage", comment: "")
            case .withTimestamp: return NSLocalizedString("complaints.filter.withDate", comment: "")
            }
        }

        func matches(_ entry: TS3ComplaintSummary) -> Bool {
            switch self {
            case .all:
                return true
            case .namedSource:
                return entry.sourceName?.isEmpty == false
            case .anonymousSource:
                return entry.sourceName?.isEmpty != false
            case .withMessage:
                return entry.message?.isEmpty == false
            case .withoutMessage:
                return entry.message?.isEmpty != false
            case .withTimestamp:
                return entry.timestamp != nil
            }
        }
    }

    private enum ComplaintSortMode: String, CaseIterable, Identifiable {
        case date
        case source
        case sourceDatabaseId
        case message

        var id: String { rawValue }

        var title: String {
            switch self {
            case .date: return NSLocalizedString("complaints.sort.date", comment: "")
            case .source: return NSLocalizedString("complaints.sort.source", comment: "")
            case .sourceDatabaseId: return NSLocalizedString("complaints.sort.sourceDb", comment: "")
            case .message: return NSLocalizedString("chat.message", comment: "")
            }
        }
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var isConfirmingDeleteAll = false
    @State private var isConfirmingDeleteVisible = false
    @State private var isExportingComplaints = false
    @State private var isExportingComplaintArchive = false
    @State private var isImportingComplaintArchive = false
    @State private var isExportingPresets = false
    @State private var isImportingPresets = false
    @State private var isConfirmingDeletePresets = false
    @State private var complaintExportDocument = TS3TextFileDocument()
    @State private var complaintArchiveDocument = TS3TextFileDocument()
    @State private var presetsDocument = TS3BookmarkFileDocument()
    @State private var pendingComplaintArchiveImport: ComplaintArchiveImportConfirmation?
    @State private var pendingPresetImport: ComplaintFilterPresetImportConfirmation?
    @State private var searchText = ""
    @State private var complaintFilter: ComplaintFilter = .all
    @State private var sortMode: ComplaintSortMode = .date
    @State private var sortAscending = false
    @State private var presetName = ""
    @State private var newComplaintMessage = ""

    private var complaintSnapshot: String {
        filteredComplaintEntries.map(\.clipboardSummary).joined(separator: "\n")
    }

    private var visibleComplaintSummary: TS3ComplaintListSummary {
        TS3ComplaintListSummary(complaints: filteredComplaintEntries)
    }

