                    if !model.clients.filter({ !$0.isCurrentUser }).isEmpty {
                        Picker(localized("chat.user"), selection: selectedUserId) {
                            ForEach(model.clients.filter { !$0.isCurrentUser }) { user in
                                Text(user.nickname).tag(user.id)
                            }
