                        Text(complaintDraftCoverageText(complaintDraftCoverageSummary(for: target)))
                            .font(.caption)
                            .foregroundColor(complaintDraftCoverageSummary(for: target).needsAttention ? .orange : .secondary)
                        Button(localized("complaints.copyDraftCoverage")) {
                            TS3PlatformSupport.copyToPasteboard(complaintDraftCoverageSummary(for: target).clipboardSummary)
                        }
                        Text(complaintDraftSummary(for: target))
                            .font(.caption)
                            .foregroundColor(.secondary)
                        Button(localized("complaints.copyComplaintSummary")) {
                            TS3PlatformSupport.copyToPasteboard(complaintDraftSummary(for: target))
                        }
                        ForEach(complaintDraftValidationMessages(for: target), id: \.self) { message in
                            Text(message)
                                .font(.caption)
                                .foregroundColor(.red)
                        }
                        Button(localized("groups.members.row.submitComplaint")) {
                            model.complainAboutUser(target, message: newComplaintMessage)
