            }
            .fileExporter(
                isPresented: $isExportingComplaints,
                document: complaintExportDocument,
                contentType: .plainText,
                defaultFilename: "ts3-complaints"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingComplaintArchive,
                document: complaintArchiveDocument,
                contentType: .json,
                defaultFilename: "ts3-complaint-archive"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingPresets,
                document: presetsDocument,
                contentType: .json,
                defaultFilename: "ts3-complaint-filter-presets"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingComplaintArchive,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareComplaintArchiveImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingPresets,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    preparePresetImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .navigationTitle(localized("complaints.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("groups.refresh")) {
                        if let target = model.complaintTarget {
                            model.refreshComplaints(for: target)
                        }
                    }
                    .disabled(model.state != .connected || model.complaintTarget == nil)
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.done")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .alert(isPresented: $isConfirmingDeleteAll) {
                Alert(
                    title: Text(localized("complaints.deleteAllAlert.title")),
                    message: Text(model.complaintTarget?.nickname ?? localized("complaints.selectedUser")),
                    primaryButton: .destructive(Text(localized("complaints.deleteAll"))) {
                        model.deleteAllComplaintsForCurrentTarget()
                    },
                    secondaryButton: .cancel()
                )
            }
            .alert(isPresented: $isConfirmingDeleteVisible) {
                Alert(
                    title: Text(localized("complaints.deleteVisibleAlert.title")),
                    message: Text(model.complaintTarget?.nickname ?? localized("complaints.selectedUser")),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deleteComplaints(filteredComplaintEntries)
                    },
                    secondaryButton: .cancel()
                )
            }
            .sheet(item: $pendingComplaintArchiveImport) { confirmation in
                ComplaintArchiveImportSheet(
                    preview: confirmation.preview,
                    previewMessage: complaintArchivePreviewMessage(confirmation.preview),
                    importArchive: { selectedComplaintIds in
                        importComplaintArchive(data: confirmation.data, selectedComplaintIds: selectedComplaintIds)
                        pendingComplaintArchiveImport = nil
                    },
                    cancel: {
                        pendingComplaintArchiveImport = nil
                    }
                )
            }
            .sheet(item: $pendingPresetImport) { confirmation in
                ComplaintFilterPresetImportSheet(
                    preview: confirmation.preview,
                    importPresets: { selectedPresetIds in
                        importPresets(data: confirmation.data, selectedPresetIds: selectedPresetIds)
                        pendingPresetImport = nil
                    },
                    cancel: {
                        pendingPresetImport = nil
                    }
                )
            }
            .alert(isPresented: $isConfirmingDeletePresets) {
                Alert(
                    title: Text(localized("complaints.deleteAllPresetsAlert.title")),
                    message: Text(localized("groups.deleteAllPresetsAlert.messageFormat", model.complaintFilterPresets.count)),
                    primaryButton: .destructive(Text(localized("common.delete"))) {
                        model.deleteAllComplaintFilterPresets()
                    },
                    secondaryButton: .cancel()
                )
            }
        }
    }

    private var selectedUserId: Binding<Int> {
        Binding(
            get: { model.complaintTarget?.id ?? model.clients.first(where: { !$0.isCurrentUser })?.id ?? 0 },
            set: { userId in
                if model.state == .connected, let user = model.clients.first(where: { $0.id == userId }) {
                    model.refreshComplaints(for: user)
                }
            }
        )
    }

    private var normalizedSearchText: String {
        searchText.trimmingCharacters(in: .whitespacesAndNewlines).lowercased()
    }

    private var isSearching: Bool {
        !normalizedSearchText.isEmpty
    }

    private var hasLocalFilters: Bool {
        isSearching || complaintFilter != .all || sortMode != .date || sortAscending
    }

    private var filteredComplaintEntries: [TS3ComplaintSummary] {
        let entries = model.complaintEntries.filter { entry in
            complaintFilter.matches(entry) && (
                !isSearching
                    || containsSearch(entry.targetName)
                    || containsSearch(entry.sourceName)
                    || containsSearch(entry.message)
                    || String(entry.targetClientDatabaseId).contains(normalizedSearchText)
                    || String(entry.sourceClientDatabaseId).contains(normalizedSearchText)
            )
        }
        return sortedComplaintEntries(entries)
    }

    private func containsSearch(_ value: String?) -> Bool {
        guard let value, !normalizedSearchText.isEmpty else { return false }
        return value.lowercased().contains(normalizedSearchText)
    }

    private func sortedComplaintEntries(_ entries: [TS3ComplaintSummary]) -> [TS3ComplaintSummary] {
        entries.sorted { lhs, rhs in
            if lhs.id == rhs.id {
                return false
            }

            let comparison: ComparisonResult
            switch sortMode {
            case .date:
                comparison = compareDates(lhs.timestamp, rhs.timestamp)
            case .source:
                comparison = sourceDisplayName(lhs).localizedCaseInsensitiveCompare(sourceDisplayName(rhs))
            case .sourceDatabaseId:
                comparison = compareInts(lhs.sourceClientDatabaseId, rhs.sourceClientDatabaseId)
            case .message:
                comparison = (lhs.message ?? "").localizedCaseInsensitiveCompare(rhs.message ?? "")
            }

            if comparison == .orderedSame {
                return lhs.sourceClientDatabaseId < rhs.sourceClientDatabaseId
            }
            return sortAscending ? comparison == .orderedAscending : comparison == .orderedDescending
        }
    }

    private func compareDates(_ lhs: Date?, _ rhs: Date?) -> ComparisonResult {
        switch (lhs, rhs) {
        case let (lhs?, rhs?):
            return lhs.compare(rhs)
        case (nil, nil):
            return .orderedSame
        case (nil, _):
            return .orderedAscending
        case (_, nil):
            return .orderedDescending
        }
    }

    private func compareInts(_ lhs: Int, _ rhs: Int) -> ComparisonResult {
        if lhs == rhs {
            return .orderedSame
        }
        return lhs < rhs ? .orderedAscending : .orderedDescending
    }

    private func sourceDisplayName(_ entry: TS3ComplaintSummary) -> String {
        if let sourceName = entry.sourceName, !sourceName.isEmpty {
            return sourceName
        }
        return "Client DB \(entry.sourceClientDatabaseId)"
    }

    private func complaintDraftValidationMessages(for target: TS3UserSummary) -> [String] {
        TS3ComplaintDraftValidator.validationMessages(
            targetName: target.nickname,
            targetClientId: target.id,
            targetDatabaseId: target.databaseId,
            message: newComplaintMessage
        )
    }

    private func complaintDraftSummary(for target: TS3UserSummary) -> String {
        TS3ComplaintDraftValidator.creationSummary(
            targetName: target.nickname,
            targetClientId: target.id,
            targetDatabaseId: target.databaseId,
            message: newComplaintMessage
        )
    }

    private func complaintDraftCoverageSummary(for target: TS3UserSummary) -> TS3ComplaintDraftCoverageSummary {
        TS3ComplaintDraftCoverageSummary(
            targetName: target.nickname,
            targetClientId: target.id,
            targetDatabaseId: target.databaseId,
            message: newComplaintMessage,
            validationMessages: complaintDraftValidationMessages(for: target)
        )
    }

    private func complaintDraftCoverageText(_ summary: TS3ComplaintDraftCoverageSummary) -> String {
        [
            localized("complaints.draftCoverageTargetNameFormat", summary.hasTargetName ? 1 : 0),
            localized("complaints.draftCoverageClientIdFormat", summary.hasTargetClientId ? 1 : 0),
            localized("complaints.draftCoverageDatabaseIdFormat", summary.hasTargetDatabaseId ? 1 : 0),
            localized("complaints.draftCoverageMessageFormat", summary.hasMessage ? 1 : 0)
        ].joined(separator: " | ")
    }

    private func complaintListSummaryText(_ summary: TS3ComplaintListSummary) -> String {
        var parts = [
            localized("complaints.summary.namedSourcesFormat", summary.namedSourceCount),
            localized("complaints.summary.anonymousSourcesFormat", summary.anonymousSourceCount),
            localized("complaints.summary.withMessagesFormat", summary.messageCount),
            localized("complaints.summary.withDatesFormat", summary.datedCount)
        ]
        if let latestTimestamp = summary.latestTimestamp {
            let formatter = DateFormatter()
            formatter.dateStyle = .medium
            formatter.timeStyle = .short
            parts.append(localized("complaints.summary.latestFormat", formatter.string(from: latestTimestamp)))
        }
        return parts.joined(separator: " · ")
    }

    private func applyPreset(_ preset: TS3ComplaintFilterPreset) {
        complaintFilter = ComplaintFilter(rawValue: preset.complaintFilter) ?? .all
        sortMode = ComplaintSortMode(rawValue: preset.sortMode) ?? .date
        sortAscending = preset.sortAscending
        searchText = preset.searchText
        presetName = preset.name
    }

    private func presetSummary(_ preset: TS3ComplaintFilterPreset) -> String {
        var parts = [
            (ComplaintFilter(rawValue: preset.complaintFilter) ?? .all).title,
            localized("permissions.presetSummary.sortFormat", (ComplaintSortMode(rawValue: preset.sortMode) ?? .date).title)
        ]
        if preset.sortAscending {
            parts.append(localized("groups.ascending"))
        }
        if !preset.searchText.isEmpty {
            parts.append(localized("events.searchPresetSummaryFormat", preset.searchText))
        }
        return parts.joined(separator: " · ")
    }

    private func exportPresets() {
        do {
            presetsDocument = TS3BookmarkFileDocument(data: try model.complaintFilterPresetsExportData())
            isExportingPresets = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func preparePresetImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.complaintFilterPresetsImportPreview(from: data)
            pendingPresetImport = ComplaintFilterPresetImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importPresets(data: Data, selectedPresetIds: Set<UUID>) {
        do {
            _ = try model.importComplaintFilterPresets(from: data, selectedPresetIds: selectedPresetIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func exportComplaintArchive() {
        do {
            complaintArchiveDocument = TS3TextFileDocument(data: try model.complaintArchiveData())
            isExportingComplaintArchive = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareComplaintArchiveImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.complaintArchivePreview(from: data)
            pendingComplaintArchiveImport = ComplaintArchiveImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importComplaintArchive(data: Data, selectedComplaintIds: Set<String>) {
        do {
            try model.importComplaintArchive(from: data, selectedComplaintIds: selectedComplaintIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func complaintArchivePreviewMessage(_ preview: TS3ComplaintArchivePreview) -> String {
        var lines = [
            localized("complaints.archivePreview.complaintsFormat", preview.complaintCount),
            localized("complaints.archivePreview.targetsFormat", preview.targetCount),
            localized("complaints.archivePreview.namedSourcesFormat", preview.namedSourceCount),
            localized("complaints.archivePreview.anonymousSourcesFormat", preview.anonymousSourceCount),
            localized("complaints.archivePreview.withMessagesFormat", preview.messageCount)
        ]
        if preview.skippedComplaintCount > 0 {
            lines.append(localized("complaints.archivePreview.skippedFormat", preview.skippedComplaintCount))
        }
        if !preview.targetSummaries.isEmpty {
            lines.append(localized("complaints.archivePreview.targetSummaryFormat", preview.targetSummaries.joined(separator: " | ")))
        }
        if !preview.sourceSummaries.isEmpty {
            lines.append(localized("complaints.archivePreview.sourceSummaryFormat", preview.sourceSummaries.joined(separator: " | ")))
        }
        if let targetName = preview.firstTargetName {
            lines.append(localized("complaints.archivePreview.firstTargetFormat", targetName))
        } else if let targetDatabaseId = preview.firstTargetDatabaseId {
            lines.append(localized("complaints.archivePreview.firstTargetDbFormat", targetDatabaseId))
        }
        if let sourceName = preview.firstSourceName {
            lines.append(localized("complaints.archivePreview.firstSourceFormat", sourceName))
        } else if let sourceDatabaseId = preview.firstSourceDatabaseId {
            lines.append(localized("complaints.archivePreview.firstSourceDbFormat", sourceDatabaseId))
        }
        if let firstTimestamp = preview.firstTimestamp {
            lines.append(localized("complaints.archivePreview.firstDateFormat", ComplaintEntryRow.dateText(firstTimestamp)))
        }
        if let firstMessage = preview.firstMessage {
            lines.append(localized("complaints.archivePreview.firstMessageFormat", firstMessage))
        }
        lines.append(preview.hasComplaints ? localized("complaints.archivePreview.hasComplaints") : localized("complaints.archivePreview.noUsableComplaints"))
        return lines.joined(separator: "\n")
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

private struct ComplaintArchiveImportSheet: View {
    let preview: TS3ComplaintArchivePreview
    let previewMessage: String
    let importArchive: (Set<String>) -> Void
    let cancel: () -> Void
    @State private var selectedComplaintIds: Set<String> = []

    private var validSelectedComplaintIds: Set<String> {
        Set(selectedComplaintIds.filter(preview.containsComplaint))
    }

    private var importImpactSummary: TS3ComplaintImportImpactSummary {
        TS3ComplaintImportImpactSummary(
            candidates: preview.candidates,
            selectedComplaintIds: validSelectedComplaintIds,
            skippedComplaintCount: preview.skippedComplaintCount
        )
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("complaints.import.preview"))) {
                    Text(previewMessage)
                        .font(.caption)
                        .foregroundColor(.secondary)
                    if preview.hasComplaints {
                        Button(localized("complaints.copyComplaintSummary")) {
                            TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                        }
                        HStack {
                            Button(localized("complaints.import.selectAll")) {
                                selectedComplaintIds = Set(preview.candidates.map(\.id))
                            }
                            Button(localized("complaints.import.clear")) {
                                selectedComplaintIds = []
                            }
                            .disabled(selectedComplaintIds.isEmpty)
                        }
                        ServerInfoDetailRow(
                            label: localized("complaints.import.impact"),
                            value: localized(
                                "complaints.import.impactFormat",
                                importImpactSummary.selectedComplaintCount,
                                importImpactSummary.targetCount
                            )
                        )
                        Text(complaintImportImpactText(importImpactSummary))
                            .font(.caption2)
                            .foregroundColor(importImpactSummary.needsAttention ? .orange : .secondary)
                        Button(localized("complaints.import.copyImpact")) {
                            TS3PlatformSupport.copyToPasteboard(importImpactSummary.clipboardSummary)
                        }
                        .disabled(!importImpactSummary.hasSelection)
                        ForEach(preview.targetSummaries, id: \.self) { summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                        }
                        ForEach(preview.sourceSummaries, id: \.self) { summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.secondary)
                        }
                        ForEach(Array(preview.complaintSummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .lineLimit(2)
                                .truncationMode(.middle)
                        }
                        ForEach(preview.candidates) { candidate in
                            Toggle(isOn: Binding(
                                get: { selectedComplaintIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedComplaintIds.insert(candidate.id)
                                    } else {
                                        selectedComplaintIds.remove(candidate.id)
                                    }
                                }
                            )) {
                                Text(candidate.summary)
                                    .font(.caption2)
                                    .lineLimit(2)
                                    .truncationMode(.middle)
                            }
                        }
                    }
                }

                Section(header: Text(localized("complaints.import.behavior"))) {
                    Text(localized("complaints.import.behaviorSummary"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("complaints.import.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                if selectedComplaintIds.isEmpty {
                    selectedComplaintIds = Set(preview.candidates.map(\.id))
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("complaints.import.action")) {
                        importArchive(validSelectedComplaintIds)
                    }
                    .disabled(!preview.hasComplaints || validSelectedComplaintIds.isEmpty)
                }
            }
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    private func complaintImportImpactText(_ summary: TS3ComplaintImportImpactSummary) -> String {
        [
            localized("complaints.import.impactSourcesFormat", summary.namedSourceCount, summary.anonymousSourceCount),
            localized("complaints.import.impactMessagesFormat", summary.messageCount, summary.missingMessageCount),
            localized("complaints.import.impactDatesFormat", summary.datedCount, summary.missingDateCount),
            localized("complaints.import.impactSkippedFormat", summary.skippedComplaintCount)
        ].joined(separator: " | ")
    }
}

private struct ComplaintFilterPresetImportSheet: View {
    @Environment(\.presentationMode) private var presentationMode

    let preview: TS3ComplaintFilterPresetImportPreview
    let importPresets: (Set<UUID>) -> Void
    let cancel: () -> Void
    @State private var selectedPresetIds: Set<UUID>

    init(
        preview: TS3ComplaintFilterPresetImportPreview,
        importPresets: @escaping (Set<UUID>) -> Void,
        cancel: @escaping () -> Void
    ) {
        self.preview = preview
        self.importPresets = importPresets
        self.cancel = cancel
        _selectedPresetIds = State(initialValue: Set(preview.candidates.map(\.id)))
    }

    private var canImport: Bool {
        preview.candidates.contains { selectedPresetIds.contains($0.id) }
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("complaints.import.preview"))) {
                    Text(localized("complaints.filterImport.importedPresetsFormat", preview.importedPresetCount))
                    Text(localized("complaints.filterImport.usablePresetsFormat", preview.usablePresetCount))
                    Text(localized("complaints.filterImport.newPresetsFormat", preview.newPresetCount))
                    Text(localized("complaints.filterImport.replacingPresetsFormat", preview.replacedPresetCount))
                    Text(localized("complaints.filterImport.skippedPresetsFormat", preview.skippedPresetCount))
                    Button(localized("complaints.filterImport.copyBackupPreview")) {
                        TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                    }
                }

                Section(header: Text(localized("complaints.import.restore"))) {
                    HStack {
                        Button(localized("complaints.import.selectAll")) {
                            selectedPresetIds = Set(preview.candidates.map(\.id))
                        }
                        Spacer()
                        Button(localized("complaints.import.clear")) {
                            selectedPresetIds.removeAll()
                        }
                    }
                    ForEach(preview.candidates) { candidate in
                        Toggle(
                            candidate.summary,
                            isOn: Binding(
                                get: { selectedPresetIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedPresetIds.insert(candidate.id)
                                    } else {
                                        selectedPresetIds.remove(candidate.id)
                                    }
                                }
                            )
                        )
                    }
                }

                Section {
                    Text(localized("complaints.filterImport.behavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("complaints.filterImport.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("complaints.import.action")) {
                        importPresets(selectedPresetIds)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canImport)
                }
            }
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }
}

struct ComplaintEntryRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let entry: TS3ComplaintSummary
    @State private var isConfirmingDelete = false

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            HStack(alignment: .top) {
                VStack(alignment: .leading, spacing: 3) {
                    Text(entry.sourceTitle)
                        .font(.subheadline.weight(.semibold))
