                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                Spacer()
                if let timestamp = entry.timestamp {
                    Text(Self.dateText(timestamp))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            if let message = entry.message, !message.isEmpty {
                Text(message)
            }
            Button(localized("complaints.row.deleteComplaint")) {
                isConfirmingDelete = true
            }
