struct ServerInfoRows: View {
    @EnvironmentObject private var model: TS3AppModel

    var body: some View {
        if !model.serverInfo.name.isEmpty {
            infoRow(label: "serverInfo.name", value: model.serverInfo.name)
        }
        if let status = model.serverInfo.status, !status.isEmpty {
            infoRow(label: "serverInfo.status", value: status)
        }
        if let port = model.serverInfo.port {
            infoRow(label: "serverInfo.port", value: String(port))
        }
        if let clientsOnline = model.serverInfo.clientsOnline {
            infoRow(label: "serverInfo.clients", value: clientsText(clientsOnline))
        }
        if let channelsOnline = model.serverInfo.channelsOnline {
            infoRow(label: "serverInfo.channels", value: String(channelsOnline))
        }
        if let uptime = model.serverInfo.uptimeSeconds {
            infoRow(label: "serverInfo.uptime", value: Self.uptimeText(uptime))
        }
        infoRow(
            label: "serverInfo.password",
            value: model.serverInfo.passwordProtected
                ? NSLocalizedString("serverInfo.protected", comment: "")
                : NSLocalizedString("serverInfo.notProtected", comment: "")
        )
        if let isListed = model.serverInfo.isWeblistEnabled {
            infoRow(
                label: "serverInfo.serverList",
                value: isListed
                    ? NSLocalizedString("serverInfo.listed", comment: "")
                    : NSLocalizedString("serverInfo.hidden", comment: "")
            )
        }
        if let defaultServerGroup = groupName(model.serverInfo.defaultServerGroupId, groups: model.serverGroups) {
            infoRow(label: "serverInfo.defaultServerGroup", value: defaultServerGroup)
        }
        if let defaultChannelGroup = groupName(model.serverInfo.defaultChannelGroupId, groups: model.channelGroups) {
            infoRow(label: "serverInfo.defaultChannelGroup", value: defaultChannelGroup)
        }
        if let reservedSlots = model.serverInfo.reservedSlots {
            infoRow(label: "serverInfo.reservedSlots", value: String(reservedSlots))
        }
        if let fileTransferPort = model.serverInfo.fileTransferPort {
            infoRow(label: "serverInfo.fileTransferPort", value: String(fileTransferPort))
        }
        if let codecEncryptionMode = model.serverInfo.codecEncryptionMode {
            infoRow(label: "serverInfo.codecEncryption", value: TS3CodecEncryptionMode.title(for: codecEncryptionMode))
        }
        if let neededIdentitySecurityLevel = model.serverInfo.neededIdentitySecurityLevel {
            infoRow(label: "serverInfo.neededIdentitySecurityLevel", value: String(neededIdentitySecurityLevel))
        }
        if let version = model.serverInfo.version, !version.isEmpty {
            infoRow(label: "serverInfo.version", value: version)
        }
        if let message = model.serverInfo.welcomeMessage, !message.isEmpty {
            VStack(alignment: .leading, spacing: 4) {
                Text(NSLocalizedString("serverInfo.welcomeMessage", comment: ""))
                    .font(.caption)
                    .foregroundColor(.secondary)
                Text(message)
                    .font(.footnote)
                    .foregroundColor(.secondary)
            }
        }
    }

    private func infoRow(label: String, value: String) -> some View {
        HStack {
            Text(NSLocalizedString(label, comment: ""))
            Spacer()
            Text(value)
                .foregroundColor(.secondary)
                .lineLimit(1)
                .truncationMode(.middle)
        }
    }

    private func clientsText(_ clientsOnline: Int) -> String {
        if let maxClients = model.serverInfo.maxClients {
            return "\(clientsOnline) / \(maxClients)"
        }
        return "\(clientsOnline)"
    }

    private func groupName(_ id: Int?, groups: [TS3GroupSummary]) -> String? {
        id.map { TS3GroupSummary.name(for: $0, in: groups) }
    }

    static func uptimeText(_ seconds: Int) -> String {
        let days = seconds / 86_400
        let hours = (seconds % 86_400) / 3_600
        let minutes = (seconds % 3_600) / 60
        if days > 0 {
            return "\(days)d \(hours)h"
        }
        if hours > 0 {
            return "\(hours)h \(minutes)m"
        }
        return "\(minutes)m"
    }
}

struct IdentitySummaryRows: View {
    @EnvironmentObject private var model: TS3AppModel
    @Binding var importedIdentity: String
    @State private var isConfirmingRegenerate = false
    @State private var targetSecurityLevel = "8"

    var body: some View {
        HStack {
            Text(NSLocalizedString("identity.uid", comment: ""))
            Spacer()
            Text(model.identitySummary.uid.isEmpty ? NSLocalizedString("identity.unavailable", comment: "") : model.identitySummary.uid)
                .foregroundColor(.secondary)
                .lineLimit(1)
                .truncationMode(.middle)
        }
        HStack {
            Text(NSLocalizedString("identity.security", comment: ""))
            Spacer()
            Text("\(model.identitySummary.securityLevel)")
                .foregroundColor(.secondary)
        }
        Button(NSLocalizedString("identity.refresh", comment: "")) {
            Task { @MainActor in
                await model.refreshIdentitySummary()
            }
        }
        Button(NSLocalizedString("identity.copyBackup", comment: "")) {
            model.copyIdentityExport()
        }
        .disabled(model.identitySummary.exportString.isEmpty)
        HStack {
            Text(NSLocalizedString("identity.newSecurityLevel", comment: ""))
            Spacer()
            TextField("8", text: $targetSecurityLevel)
                .multilineTextAlignment(.trailing)
                .ts3NumericKeyboard()
        }
        TextField(NSLocalizedString("identity.backupPlaceholder", comment: ""), text: $importedIdentity)
            .ts3PlainTextField()
        Button(NSLocalizedString("identity.import", comment: "")) {
            model.importIdentity(importedIdentity)
            importedIdentity = ""
        }
        .disabled(importedIdentity.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
        Button(NSLocalizedString("identity.regenerate", comment: "")) {
            isConfirmingRegenerate = true
        }
        .foregroundColor(.red)
        .disabled(model.state != .disconnected || parsedSecurityLevel == nil)
        .alert(isPresented: $isConfirmingRegenerate) {
            Alert(
                title: Text(NSLocalizedString("identity.regenerateAlert.title", comment: "")),
                message: Text(NSLocalizedString("identity.regenerateAlert.message", comment: "")),
                primaryButton: .destructive(Text(NSLocalizedString("identity.regenerate", comment: ""))) {
                    model.regenerateIdentity(securityLevel: parsedSecurityLevel ?? 8)
                },
                secondaryButton: .cancel()
            )
        }
    }

    private var parsedSecurityLevel: Int? {
        let trimmed = targetSecurityLevel.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let level = Int(trimmed), level >= 0, level <= 32 else {
            return nil
        }
        return level
    }
}

struct IdentityManagementSheet: View {
    private struct IdentityProfileImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3IdentityProfileImportPreview
        let id = UUID()
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var importedIdentity = ""
    @State private var identityProfileName = ""
    @State private var isImportingIdentity = false
    @State private var isImportingIdentityProfile = false
    @State private var isImportingIdentityProfiles = false
    @State private var isExportingIdentity = false
    @State private var isExportingIdentitySnapshot = false
    @State private var isExportingIdentityProfiles = false
    @State private var pendingIdentityProfileImport: IdentityProfileImportConfirmation?
    @State private var identityExportDocument = TS3TextFileDocument()
    @State private var identitySnapshotDocument = TS3TextFileDocument()
    @State private var identityProfilesDocument = TS3TextFileDocument()

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(NSLocalizedString("identity.title", comment: ""))) {
                    IdentitySummaryRows(importedIdentity: $importedIdentity)
                    Button(NSLocalizedString("identity.copySnapshot", comment: "")) {
                        model.copyIdentitySnapshot()
                    }
                    Button(NSLocalizedString("identity.exportSnapshot", comment: "")) {
                        exportIdentitySnapshot()
                    }
                    Button(NSLocalizedString("identity.importBackup", comment: "")) {
                        isImportingIdentity = true
                    }
                    Button(NSLocalizedString("identity.exportBackup", comment: "")) {
                        exportIdentityBackup()
                    }
                    .disabled(model.identitySummary.exportString.isEmpty)
                }
                Section(header: Text(NSLocalizedString("identity.profiles", comment: ""))) {
                    TextField(NSLocalizedString("identity.profileName", comment: ""), text: $identityProfileName)
                        .ts3PlainTextField()
                    Button(NSLocalizedString("identity.saveCurrentAsProfile", comment: "")) {
                        model.saveCurrentIdentityProfile(name: identityProfileName)
                        identityProfileName = ""
                    }
                    .disabled(model.identitySummary.exportString.isEmpty)
                    Button(NSLocalizedString("identity.importBackupAsProfile", comment: "")) {
                        isImportingIdentityProfile = true
                    }
                    Button(NSLocalizedString("identity.exportProfileBackup", comment: "")) {
                        exportIdentityProfiles()
                    }
                    .disabled(model.identityProfiles.isEmpty)
                    Button(NSLocalizedString("identity.importProfileBackup", comment: "")) {
                        isImportingIdentityProfiles = true
                    }
                    if model.identityProfiles.isEmpty {
                        Text(NSLocalizedString("identity.noSavedProfiles", comment: ""))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(model.identityProfiles) { profile in
                            IdentityProfileRow(profile: profile)
                                .environmentObject(model)
                        }
                    }
                }
            }
            .navigationTitle(NSLocalizedString("identity.title", comment: ""))
            .ts3InlineNavigationTitle()
            .onAppear {
                Task { @MainActor in
                    await model.refreshIdentitySummary()
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(NSLocalizedString("common.done", comment: "")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .fileImporter(
                isPresented: $isImportingIdentity,
                allowedContentTypes: [.plainText, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    importIdentity(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingIdentityProfile,
                allowedContentTypes: [.plainText, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    importIdentityProfile(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingIdentityProfiles,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareIdentityProfilesImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingIdentity,
                document: identityExportDocument,
                contentType: .plainText,
                defaultFilename: "ts3-identity-backup"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingIdentitySnapshot,
                document: identitySnapshotDocument,
                contentType: .plainText,
                defaultFilename: "ts3-identity-snapshot"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingIdentityProfiles,
                document: identityProfilesDocument,
                contentType: .json,
                defaultFilename: "ts3-identity-profiles"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .sheet(
                item: $pendingIdentityProfileImport,
                onDismiss: {
                    pendingIdentityProfileImport = nil
                }
            ) { confirmation in
                IdentityProfileImportSheet(
                    preview: confirmation.preview,
                    importProfiles: { selectedProfileIds in
                        importIdentityProfiles(
                            from: confirmation.data,
                            selectedProfileIds: selectedProfileIds
                        )
                        pendingIdentityProfileImport = nil
                    },
                    cancel: {
                        pendingIdentityProfileImport = nil
                    }
                )
            }
        }
    }

    private func exportIdentityBackup() {
        guard !model.identitySummary.exportString.isEmpty else { return }
        identityExportDocument = TS3TextFileDocument(data: Data(model.identitySummary.exportString.utf8))
        isExportingIdentity = true
    }

    private func exportIdentitySnapshot() {
        identitySnapshotDocument = TS3TextFileDocument(data: model.identitySnapshotData())
        isExportingIdentitySnapshot = true
    }

    private func exportIdentityProfiles() {
        do {
            identityProfilesDocument = TS3TextFileDocument(data: try model.identityProfilesExportData())
            isExportingIdentityProfiles = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importIdentity(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            guard let exportString = String(data: data, encoding: .utf8) else {
                throw CocoaError(.fileReadCorruptFile)
            }
            model.importIdentity(exportString)
            importedIdentity = ""
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importIdentityProfile(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            guard let exportString = String(data: data, encoding: .utf8) else {
                throw CocoaError(.fileReadCorruptFile)
            }
            model.importIdentityProfile(name: identityProfileName, exportString: exportString)
            identityProfileName = ""
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareIdentityProfilesImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.identityProfilesImportPreview(from: data)
            pendingIdentityProfileImport = IdentityProfileImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importIdentityProfiles(from data: Data, selectedProfileIds: Set<UUID>) {
        do {
            try model.importIdentityProfiles(from: data, selectedProfileIds: selectedProfileIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }
}

private struct IdentityProfileImportSheet: View {
    @Environment(\.presentationMode) private var presentationMode

    let preview: TS3IdentityProfileImportPreview
    let importProfiles: (Set<UUID>) -> Void
    let cancel: () -> Void
    @State private var selectedProfileIds: Set<UUID>

    init(
        preview: TS3IdentityProfileImportPreview,
        importProfiles: @escaping (Set<UUID>) -> Void,
        cancel: @escaping () -> Void
    ) {
        self.preview = preview
        self.importProfiles = importProfiles
        self.cancel = cancel
        _selectedProfileIds = State(initialValue: Set(preview.candidates.map(\.id)))
    }

    private var canImport: Bool {
        preview.candidates.contains { selectedProfileIds.contains($0.id) }
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(NSLocalizedString("identity.import.preview", comment: ""))) {
                    Text(localized("identity.import.importedProfilesFormat", preview.importedProfileCount))
                    Text(localized("identity.import.usableProfilesFormat", preview.usableProfileCount))
                    Text(localized("identity.import.newProfilesFormat", preview.newProfileCount))
                    Text(localized("identity.import.replacingProfilesFormat", preview.replacedProfileCount))
                    Text(localized("identity.import.skippedProfilesFormat", preview.skippedProfileCount))
                    Button(NSLocalizedString("identity.import.copyProfileBackupPreview", comment: "")) {
                        TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                    }
                }

                Section(header: Text(NSLocalizedString("identity.import.restore", comment: ""))) {
                    HStack {
                        Button(NSLocalizedString("identity.import.selectAll", comment: "")) {
                            selectedProfileIds = Set(preview.candidates.map(\.id))
                        }
                        Spacer()
                        Button(NSLocalizedString("identity.import.clear", comment: "")) {
                            selectedProfileIds.removeAll()
                        }
                    }
                    ForEach(preview.candidates) { candidate in
                        Toggle(
                            candidate.summary,
                            isOn: Binding(
                                get: { selectedProfileIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedProfileIds.insert(candidate.id)
                                    } else {
                                        selectedProfileIds.remove(candidate.id)
                                    }
                                }
                            )
                        )
                    }
                }

                Section {
                    Text(NSLocalizedString("identity.import.behavior", comment: ""))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(NSLocalizedString("identity.import.title", comment: ""))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(NSLocalizedString("common.cancel", comment: "")) {
                        cancel()
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(NSLocalizedString("identity.import.action", comment: "")) {
                        importProfiles(selectedProfileIds)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canImport)
                }
            }
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return String(format: format, locale: Locale.current, arguments: arguments)
    }
}

private struct IdentityProfileRow: View {
    @EnvironmentObject private var model: TS3AppModel
    let profile: TS3IdentityProfile
    @State private var editedName = ""
    @State private var isEditingName = false
    @State private var isConfirmingDelete = false

    private var isActive: Bool {
        model.activeIdentityProfileId == profile.id
    }

    var body: some View {
        VStack(alignment: .leading, spacing: 6) {
            HStack(alignment: .top) {
                VStack(alignment: .leading, spacing: 3) {
                    Text(profile.name)
                        .font(.subheadline.weight(.semibold))
                    Text(profile.uid)
                        .font(.caption)
                        .foregroundColor(.secondary)
                        .lineLimit(1)
                        .truncationMode(.middle)
                    Text(localized("identity.row.securityOffsetFormat", profile.securityLevel, profile.keyOffset))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
                Spacer()
                if isActive {
                    Text(NSLocalizedString("identity.row.active", comment: ""))
                        .font(.caption.weight(.semibold))
                        .foregroundColor(.accentColor)
                }
            }
            HStack {
                Button(NSLocalizedString("identity.row.use", comment: "")) {
                    model.activateIdentityProfile(profile)
                }
                .buttonStyle(.borderless)
                .disabled(model.state != .disconnected || isActive)
                Button(NSLocalizedString("identity.row.rename", comment: "")) {
                    editedName = profile.name
                    isEditingName = true
                }
                .buttonStyle(.borderless)
                Button(NSLocalizedString("identity.row.copyBackup", comment: "")) {
                    TS3PlatformSupport.copyToPasteboard(profile.exportString)
                }
                .buttonStyle(.borderless)
                Button(NSLocalizedString("common.delete", comment: "")) {
                    isConfirmingDelete = true
                }
                .buttonStyle(.borderless)
                .foregroundColor(.red)
            }
            .font(.caption)
        }
        .padding(.vertical, 3)
        .accessibilityElement(children: .ignore)
        .accessibilityLabel(profile.name)
        .accessibilityValue(profile.accessibilityValue(isActive: isActive, canSwitch: model.state == .disconnected))
        .accessibilityAction(named: NSLocalizedString("common.copySummary", comment: "")) {
            TS3PlatformSupport.copyToPasteboard(profile.clipboardSummary)
        }
        .accessibilityAction(named: NSLocalizedString("identity.row.useIdentity", comment: "")) {
            model.activateIdentityProfile(profile)
        }
        .contextMenu {
            Button(NSLocalizedString("identity.row.useIdentity", comment: "")) {
                model.activateIdentityProfile(profile)
            }
            .disabled(model.state != .disconnected || isActive)
            Button(NSLocalizedString("identity.row.copyBackup", comment: "")) {
                TS3PlatformSupport.copyToPasteboard(profile.exportString)
            }
            Button(NSLocalizedString("common.copySummary", comment: "")) {
                TS3PlatformSupport.copyToPasteboard(profile.clipboardSummary)
            }
            Button(NSLocalizedString("identity.row.copyUid", comment: "")) {
                TS3PlatformSupport.copyToPasteboard(profile.uid)
            }
            Button(NSLocalizedString("identity.row.rename", comment: "")) {
                editedName = profile.name
                isEditingName = true
            }
            Button(NSLocalizedString("common.delete", comment: "")) {
                isConfirmingDelete = true
            }
            .foregroundColor(.red)
        }
        .sheet(isPresented: $isEditingName) {
            NavigationView {
                Form {
                    TextField(NSLocalizedString("identity.profileName", comment: ""), text: $editedName)
                        .ts3PlainTextField()
                }
                .navigationTitle(NSLocalizedString("identity.row.renameIdentity", comment: ""))
                .ts3InlineNavigationTitle()
                .toolbar {
                    ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                        Button(NSLocalizedString("common.cancel", comment: "")) {
                            isEditingName = false
                        }
                    }
                    ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                        Button(NSLocalizedString("common.save", comment: "")) {
                            model.renameIdentityProfile(profile, name: editedName)
                            isEditingName = false
                        }
                        .disabled(editedName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                    }
                }
            }
        }
        .alert(isPresented: $isConfirmingDelete) {
            Alert(
                title: Text(NSLocalizedString("identity.row.deleteAlert.title", comment: "")),
                message: Text(profile.name),
                primaryButton: .destructive(Text(NSLocalizedString("common.delete", comment: ""))) {
                    model.deleteIdentityProfile(profile)
                },
                secondaryButton: .cancel()
            )
        }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return String(format: format, locale: Locale.current, arguments: arguments)
    }
}

private struct ClientPackageImportConfirmation: Identifiable {
    let url: URL
    let preview: TS3ClientMigrationPackagePreview
    let id = UUID()
}

struct ClientMigrationSheet: View {
    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var isImportingClientPackage = false
    @State private var isExportingClientPackage = false
    @State private var clientPackageDocument = TS3BookmarkFileDocument()
    @State private var pendingClientPackageImport: ClientPackageImportConfirmation?

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, locale: Locale.current, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("clientMigration.clientPackage"))) {
                    Button(localized("connect.exportClientPackage")) {
                        exportClientPackage()
                    }
