                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .sheet(item: $pendingClientPackageImport) { confirmation in
                ClientPackageImportSheet(
                    confirmation: confirmation,
                    previewMessage: clientPackagePreviewMessage(confirmation.preview)
                ) { options in
                    importClientPackage(from: confirmation.url, options: options)
                }
            }
        }
    }

    private func exportClientPackage() {
        do {
            clientPackageDocument = TS3BookmarkFileDocument(data: try model.clientMigrationPackageExportData())
            isExportingClientPackage = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareClientPackageImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let preview = try model.clientMigrationPackagePreview(from: Data(contentsOf: url))
            pendingClientPackageImport = ClientPackageImportConfirmation(url: url, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importClientPackage(from url: URL, options: TS3ClientMigrationRestoreOptions) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            try model.importClientMigrationPackage(from: Data(contentsOf: url), options: options)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func clientPackagePreviewMessage(_ preview: TS3ClientMigrationPackagePreview) -> String {
        var lines = [
            localized("clientMigration.preview.schemaFormat", preview.schemaVersion),
            localized("clientMigration.preview.exportedFormat", Self.dateText(preview.exportedAt)),
            localized("clientMigration.preview.itemsFormat", preview.totalItemCount)
        ]
        if !preview.itemCounts.isEmpty {
            lines.append(preview.itemCounts.map { localized("clientMigration.preview.itemCountFormat", $0.0, $0.1) }.joined(separator: "\n"))
        }
        lines.append(localized("clientMigration.preview.settingsGroupsFormat", preview.settingsGroups.joined(separator: ", ")))
        if !preview.settingsDetails.isEmpty {
            lines.append(preview.settingsDetails.joined(separator: "\n"))
        }
        lines.append(localized("clientMigration.preview.importBehavior"))
        return lines.joined(separator: "\n")
    }

    private static func dateText(_ date: Date) -> String {
        let formatter = DateFormatter()
        formatter.dateStyle = .medium
        formatter.timeStyle = .short
        return formatter.string(from: date)
    }
}

