            }
        }
    }
}

struct NotificationSettingsSheet: View {
    private struct NotificationSettingsImportConfirmation: Identifiable {
        let url: URL
        let preview: TS3NotificationSettingsPreview
        let id = UUID()
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var isImportingNotificationSettings = false
    @State private var isExportingNotificationSettings = false
    @State private var isConfirmingResetNotificationSettings = false
    @State private var pendingNotificationSettingsImport: NotificationSettingsImportConfirmation?
    @State private var notificationSettingsDocument = TS3TextFileDocument()

    private var notificationsBinding: Binding<Bool> {
        Binding(
            get: { model.notificationsEnabled },
            set: { model.setNotificationsEnabled($0) }
        )
    }

    private var privateMessageNotificationsBinding: Binding<Bool> {
        Binding(
            get: { model.privateMessageNotificationsEnabled },
            set: { model.setPrivateMessageNotificationsEnabled($0) }
        )
    }

    private var notificationSoundBinding: Binding<Bool> {
        Binding(
            get: { model.notificationSoundEnabled },
            set: { model.setNotificationSoundEnabled($0) }
        )
    }

    private var pokeNotificationsBinding: Binding<Bool> {
        Binding(
            get: { model.pokeNotificationsEnabled },
            set: { model.setPokeNotificationsEnabled($0) }
        )
    }

    private var activityNotificationsBinding: Binding<Bool> {
        Binding(
            get: { model.activityNotificationsEnabled },
            set: { model.setActivityNotificationsEnabled($0) }
        )
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("notifications.section"))) {
                    Toggle(localized("notifications.enable"), isOn: notificationsBinding)
                    Toggle(localized("notifications.sound"), isOn: notificationSoundBinding)
                        .disabled(!model.notificationsEnabled)
                    Toggle(localized("notifications.privateMessages"), isOn: privateMessageNotificationsBinding)
                        .disabled(!model.notificationsEnabled)
                    Toggle(localized("notifications.pokes"), isOn: pokeNotificationsBinding)
                        .disabled(!model.notificationsEnabled)
                    Toggle(localized("notifications.serverActivity"), isOn: activityNotificationsBinding)
                        .disabled(!model.notificationsEnabled)
                    Text(localized("notifications.backgroundNote"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }

                Section(header: Text(localized("notifications.presets"))) {
                    Button(localized("notifications.directPreset")) {
                        model.applyDirectNotificationPreset()
                    }
                    Button(localized("notifications.silentDirectPreset")) {
                        model.applyDirectNotificationPreset(soundEnabled: false)
                    }
                    Button(localized("notifications.allEventsPreset")) {
                        model.applyAllEventsNotificationPreset()
                    }
                    Button(localized("notifications.resetSettings")) {
                        isConfirmingResetNotificationSettings = true
                    }
                }

                NotificationRulesSection()

                Section(header: Text(localized("notifications.backup"))) {
                    Button(localized("notifications.exportSettings")) {
                        exportNotificationSettings()
                    }
                    Button(localized("notifications.importSettings")) {
                        isImportingNotificationSettings = true
                    }
                }
            }
            .navigationTitle(localized("notifications.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(NSLocalizedString("common.done", comment: "")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .fileImporter(
                isPresented: $isImportingNotificationSettings,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareNotificationSettingsImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingNotificationSettings,
                document: notificationSettingsDocument,
                contentType: .json,
                defaultFilename: "ts3-notification-settings"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .alert(isPresented: $isConfirmingResetNotificationSettings) {
                Alert(
                    title: Text(localized("notifications.resetAlert.title")),
                    message: Text(localized("notifications.resetAlert.message")),
                    primaryButton: .destructive(Text(localized("notifications.reset"))) {
                        model.resetNotificationSettings()
                    },
                    secondaryButton: .cancel()
                )
            }
            .sheet(
                item: $pendingNotificationSettingsImport,
                onDismiss: {
                    pendingNotificationSettingsImport = nil
                }
            ) { confirmation in
                NotificationSettingsImportSheet(
                    preview: confirmation.preview,
                    importSettings: { selectedSettingIds in
                        importNotificationSettings(
                            from: confirmation.url,
                            selectedSettingIds: selectedSettingIds
                        )
                        pendingNotificationSettingsImport = nil
                    },
                    cancel: {
                        pendingNotificationSettingsImport = nil
                    }
                )
            }
        }
    }

    private func exportNotificationSettings() {
        do {
            notificationSettingsDocument = TS3TextFileDocument(data: try model.notificationSettingsExportData())
            isExportingNotificationSettings = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareNotificationSettingsImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.notificationSettingsPreview(from: data)
            pendingNotificationSettingsImport = NotificationSettingsImportConfirmation(
                url: url,
                preview: preview
            )
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importNotificationSettings(from url: URL, selectedSettingIds: Set<String>) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            try model.importNotificationSettings(
                from: Data(contentsOf: url),
                options: TS3NotificationSettingsImportOptions(
                    baseSettings: selectedSettingIds.contains("base"),
                    mutedRules: selectedSettingIds.contains("muted-rules"),
                    quietHours: selectedSettingIds.contains("quiet-hours")
                )
            )
        } catch {
            model.lastError = error.localizedDescription
        }
    }
}

struct NotificationRulesSection: View {
    @EnvironmentObject private var model: TS3AppModel

    private var hasRules: Bool {
        !model.mutedNotificationServerKeys.isEmpty ||
        !model.mutedNotificationContactUniqueIdentifiers.isEmpty
    }

    private var quietHoursEnabledBinding: Binding<Bool> {
        Binding(
            get: { model.notificationQuietHoursEnabled },
            set: { model.setNotificationQuietHoursEnabled($0) }
        )
    }

    private var quietHoursStartBinding: Binding<Date> {
        Binding(
            get: { Self.date(minuteOfDay: model.notificationQuietHoursStartMinute) },
            set: { model.setNotificationQuietHours(startMinute: Self.minuteOfDay(from: $0), endMinute: model.notificationQuietHoursEndMinute) }
        )
    }

    private var quietHoursEndBinding: Binding<Date> {
        Binding(
            get: { Self.date(minuteOfDay: model.notificationQuietHoursEndMinute) },
            set: { model.setNotificationQuietHours(startMinute: model.notificationQuietHoursStartMinute, endMinute: Self.minuteOfDay(from: $0)) }
        )
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        Section(header: Text(localized("notifications.rules"))) {
            Toggle(localized("notifications.muteCurrentServer"), isOn: Binding(
                get: { model.isCurrentServerNotificationsMuted() },
                set: { model.setCurrentServerNotificationsMuted($0) }
            ))
            .disabled(model.serverHost.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)

            Toggle(localized("notifications.quietHours"), isOn: quietHoursEnabledBinding)
            DatePicker(localized("notifications.start"), selection: quietHoursStartBinding, displayedComponents: .hourAndMinute)
                .disabled(!model.notificationQuietHoursEnabled)
            DatePicker(localized("notifications.end"), selection: quietHoursEndBinding, displayedComponents: .hourAndMinute)
                .disabled(!model.notificationQuietHoursEnabled)

            HStack {
                Text(localized("notifications.mutedServers"))
                Spacer()
                Text("\(model.mutedNotificationServerKeys.count)")
                    .foregroundColor(.secondary)
            }
            HStack {
                Text(localized("notifications.mutedContacts"))
                Spacer()
                Text("\(model.mutedNotificationContactUniqueIdentifiers.count)")
                    .foregroundColor(.secondary)
            }

            if !model.contacts.isEmpty {
                ForEach(model.contacts) { contact in
                    Toggle(contact.nickname, isOn: Binding(
                        get: { model.isContactNotificationsMuted(contact) },
                        set: { model.setContactNotificationsMuted($0, contact: contact) }
                    ))
                }
            }

            Button(localized("notifications.clearRules")) {
                model.clearNotificationRules()
            }
            .disabled(!hasRules)
        }
    }

    private static func date(minuteOfDay: Int) -> Date {
        let minute = min(max(minuteOfDay, 0), 23 * 60 + 59)
        let calendar = Calendar.current
        let startOfDay = calendar.startOfDay(for: Date())
        return calendar.date(byAdding: .minute, value: minute, to: startOfDay) ?? startOfDay
    }

    private static func minuteOfDay(from date: Date) -> Int {
        let components = Calendar.current.dateComponents([.hour, .minute], from: date)
        return min(max((components.hour ?? 0) * 60 + (components.minute ?? 0), 0), 23 * 60 + 59)
    }
}

enum ChannelEditorMode {
