                            }
                            if let numericQuality = Int(codecQuality.trimmingCharacters(in: .whitespacesAndNewlines)),
                               TS3ChannelCodecQuality.title(for: numericQuality) == "Unknown (\(numericQuality))" {
                                Text(codecQualityTitle(for: String(numericQuality))).tag(codecQuality)
                            }
                        }
                        TextField(localized("channelEditor.codecLatencyFactor"), text: $codecLatencyFactor)
                            .ts3NumericKeyboard()
                        Toggle(localized("channelEditor.unencryptedVoice"), isOn: $isCodecUnencrypted)
                        if !codecValidationMessages.isEmpty {
                            ForEach(codecValidationMessages, id: \.self) { message in
                                Text(message)
                                    .font(.caption)
                                    .foregroundColor(.red)
                            }
                        }
                        if !codecDiagnosticMessages.isEmpty {
                            ForEach(codecDiagnosticMessages, id: \.self) { message in
                                Text(message)
                                    .font(.caption)
                                    .foregroundColor(.secondary)
                            }
                        }
                        Button(localized("channelEditor.copyCodecSummary")) {
                            TS3PlatformSupport.copyToPasteboard(codecConfiguration.clipboardSummary)
                        }
                        TextField(localized("channelEditor.neededTalkPower"), text: $neededTalkPower)
                            .ts3NumericKeyboard()
                        TextField(localized("channelEditor.neededJoinPower"), text: $neededJoinPower)
                            .ts3NumericKeyboard()
                        TextField(localized("channelEditor.neededSubscribePower"), text: $neededSubscribePower)
                            .ts3NumericKeyboard()
                        TextField(localized("channelEditor.neededModifyPower"), text: $neededModifyPower)
                            .ts3NumericKeyboard()
                        TextField(localized("channelEditor.neededDeletePower"), text: $neededDeletePower)
                            .ts3NumericKeyboard()
                        TextField(localized("channelEditor.neededDescriptionViewPower"), text: $neededDescriptionViewPower)
                            .ts3NumericKeyboard()
                        if !permissionGateSummaryRows.isEmpty {
                            ServerInfoDetailRow(
                                label: localized("channelEditor.permissionGateSummary"),
                                value: localized(
                                    "channelEditor.permissionGateSummaryFormat",
                                    permissionGateSummary.configuredCount,
                                    permissionGateSummary.inheritedCount
                                )
                            )
                            if let highestGate = permissionGateSummary.highestGate {
                                ServerInfoDetailRow(
                                    label: localized("channelEditor.highestPermissionGate"),
                                    value: localized(
                                        "channelEditor.permissionGateValueFormat",
                                        permissionGateTitle(highestGate),
                                        highestGate.value ?? 0
                                    )
                                )
                            }
                            ForEach(permissionGateSummaryRows, id: \.self) { row in
                                Text(row)
                                    .font(.caption)
                                    .foregroundColor(.secondary)
                            }
                            Button(localized("channelEditor.copyPermissionGateSummary")) {
                                TS3PlatformSupport.copyToPasteboard(permissionGateSummary.clipboardSummary)
                            }
                        }
                        TextField(localized("channelEditor.deleteDelaySeconds"), text: $deleteDelaySeconds)
                            .ts3NumericKeyboard()
                    } label: {
                        Label(localized("channelEditor.voice"), systemImage: "waveform")
                    }
                }

                Section {
                    DisclosureGroup(isExpanded: $isShowingLimitSettings) {
                        Toggle(localized("channelEditor.unlimitedClients"), isOn: $maxClientsUnlimited)
                        if !maxClientsUnlimited {
                            TextField(localized("channelEditor.maxClients"), text: $maxClients)
                                .ts3NumericKeyboard()
                        }
                        Toggle(localized("channelEditor.inheritFamilyLimit"), isOn: $maxFamilyClientsInherited)
                        if !maxFamilyClientsInherited {
                            Toggle(localized("channelEditor.unlimitedFamilyClients"), isOn: $maxFamilyClientsUnlimited)
                            if !maxFamilyClientsUnlimited {
                                TextField(localized("channelEditor.maxFamilyClients"), text: $maxFamilyClients)
                                    .ts3NumericKeyboard()
                            }
                        }
                    } label: {
                        Label(localized("channelEditor.limits"), systemImage: "person.2")
                    }
                }
                Section {
                    Button(title) {
                        switch mode {
                        case let .create(parent):
                            model.createChannel(
                                name: name,
                                parentId: parent?.id,
                                password: password.isEmpty ? nil : password,
                                channelType: channelType,
                                phoneticName: phoneticName,
                                topic: topic,
                                description: description,
                                filePath: filePath,
                                neededTalkPower: parsedOptionalInt(neededTalkPower),
                                neededJoinPower: parsedOptionalInt(neededJoinPower),
                                neededSubscribePower: parsedOptionalInt(neededSubscribePower),
                                neededModifyPower: parsedOptionalInt(neededModifyPower),
                                neededDeletePower: parsedOptionalInt(neededDeletePower),
                                neededDescriptionViewPower: parsedOptionalInt(neededDescriptionViewPower),
                                order: selectedOrderId,
                                codec: codec,
                                codecQuality: parsedOptionalInt(codecQuality),
                                codecLatencyFactor: parsedOptionalInt(codecLatencyFactor),
                                isCodecUnencrypted: isCodecUnencrypted,
                                bannerGraphicsURL: bannerGraphicsURL,
                                bannerMode: bannerMode,
                                deleteDelaySeconds: parsedOptionalInt(deleteDelaySeconds),
                                maxClients: parsedOptionalInt(maxClients),
                                maxFamilyClients: parsedOptionalInt(maxFamilyClients),
                                maxClientsUnlimited: maxClientsUnlimited,
                                maxFamilyClientsUnlimited: maxFamilyClientsUnlimited,
                                maxFamilyClientsInherited: maxFamilyClientsInherited,
                                iconId: parsedOptionalInt(iconId)
                            )
                        case let .edit(channel):
                            model.editChannel(
                                channel,
                                name: name,
                                phoneticName: phoneticName,
                                topic: topic,
                                description: description,
                                filePath: filePath,
                                password: clearPassword ? "" : (password.isEmpty ? nil : password),
                                isDefault: isDefault,
                                channelType: channelType,
                                neededTalkPower: parsedOptionalInt(neededTalkPower),
                                neededJoinPower: parsedOptionalInt(neededJoinPower),
                                neededSubscribePower: parsedOptionalInt(neededSubscribePower),
                                neededModifyPower: parsedOptionalInt(neededModifyPower),
                                neededDeletePower: parsedOptionalInt(neededDeletePower),
                                neededDescriptionViewPower: parsedOptionalInt(neededDescriptionViewPower),
                                order: selectedOrderId,
                                codec: codec,
                                codecQuality: parsedOptionalInt(codecQuality),
                                codecLatencyFactor: parsedOptionalInt(codecLatencyFactor),
                                isCodecUnencrypted: isCodecUnencrypted,
                                bannerGraphicsURL: bannerGraphicsURL,
                                bannerMode: bannerMode,
                                deleteDelaySeconds: parsedOptionalInt(deleteDelaySeconds),
                                maxClients: parsedOptionalInt(maxClients),
                                maxFamilyClients: parsedOptionalInt(maxFamilyClients),
                                maxClientsUnlimited: maxClientsUnlimited,
                                maxFamilyClientsUnlimited: maxFamilyClientsUnlimited,
                                maxFamilyClientsInherited: maxFamilyClientsInherited,
                                iconId: parsedOptionalInt(iconId)
                            )
                        }
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canSubmit)
                }
            }
            .navigationTitle(title)
            .ts3InlineNavigationTitle()
            .onAppear {
                if case let .edit(channel) = mode {
                    name = channel.name
                    phoneticName = channel.phoneticName ?? ""
                    topic = channel.topic ?? ""
                    description = channel.description ?? ""
                    filePath = channel.filePath ?? ""
                    clearPassword = false
                    channelType = channelType(for: channel)
                    isDefault = channel.isDefault
                    neededTalkPower = channel.neededTalkPower.map(String.init) ?? ""
                    neededJoinPower = channel.neededJoinPower.map(String.init) ?? ""
                    neededSubscribePower = channel.neededSubscribePower.map(String.init) ?? ""
                    neededModifyPower = channel.neededModifyPower.map(String.init) ?? ""
                    neededDeletePower = channel.neededDeletePower.map(String.init) ?? ""
                    neededDescriptionViewPower = channel.neededDescriptionViewPower.map(String.init) ?? ""
                    codec = channel.codec
                    codecQuality = channel.codecQuality.map(String.init) ?? ""
                    codecLatencyFactor = channel.codecLatencyFactor.map(String.init) ?? ""
                    isCodecUnencrypted = channel.isCodecUnencrypted ?? false
                    selectedOrderId = normalizedOrderId(channel.order)
                    deleteDelaySeconds = channel.deleteDelaySeconds.map(String.init) ?? ""
                    maxClients = channel.maxClients.map(String.init) ?? ""
                    maxFamilyClients = channel.maxFamilyClients.map(String.init) ?? ""
                    maxClientsUnlimited = channel.maxClientsUnlimited ?? true
                    maxFamilyClientsUnlimited = channel.maxFamilyClientsUnlimited ?? true
                    maxFamilyClientsInherited = channel.maxFamilyClientsInherited ?? false
                    iconId = channel.iconId.map(String.init) ?? ""
                    bannerGraphicsURL = channel.bannerGraphicsURL ?? ""
                    bannerMode = channel.bannerMode
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.cancel")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .fileImporter(
                isPresented: $isShowingIconImporter,
                allowedContentTypes: [.image, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    switch mode {
                    case .create:
                        model.uploadDraftChannelIcon(from: url) { uploadedIconId in
                            iconId = String(uploadedIconId)
                        }
                    case let .edit(channel):
                        model.uploadChannelIcon(from: url, for: channel) { uploadedIconId in
                            iconId = String(uploadedIconId)
                        }
                    }
                }
            }
            .fileImporter(
                isPresented: $isImportingDraft,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareDraftImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingDraft,
                document: draftDocument,
                contentType: .json,
                defaultFilename: "ts3-channel-draft"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingSnapshot,
                document: snapshotDocument,
                contentType: .plainText,
                defaultFilename: "ts3-channel-settings"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .sheet(item: $pendingDraftImport) { confirmation in
                ChannelDraftImportSheet(
                    previewMessage: confirmation.previewMessage,
                    canImport: confirmation.canImport,
                    importDraft: {
                        applyDraft(confirmation.draft)
                        pendingDraftImport = nil
                    },
                    cancel: {
                        pendingDraftImport = nil
                    },
                    localized: localized
                )
            }
        }
    }

    private struct ChannelDraftImportSheet: View {
        let previewMessage: String
        let canImport: Bool
        let importDraft: () -> Void
        let cancel: () -> Void
        let localized: (String, CVarArg...) -> String

        var body: some View {
            NavigationView {
                Form {
                    Section(header: Text(localized("channelEditor.preview"))) {
                        Text(previewMessage)
                            .font(.caption)
                            .foregroundColor(.secondary)
                        Button(localized("channelEditor.copySummary")) {
                            TS3PlatformSupport.copyToPasteboard(previewMessage)
                        }
                    }

                    Section(header: Text(localized("channelEditor.importBehavior"))) {
                        Text(localized("channelEditor.importBehavior.summary"))
                            .font(.caption)
                            .foregroundColor(.secondary)
                    }
                }
                .navigationTitle(localized("channelEditor.importChannel"))
                .ts3InlineNavigationTitle()
                .toolbar {
                    ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                        Button(localized("common.cancel")) {
                            cancel()
                        }
                    }
                    ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                        Button(localized("channelEditor.import")) {
                            importDraft()
                        }
                        .disabled(!canImport)
                    }
                }
            }
        }
    }

    private var currentDraft: ChannelDraft {
        ChannelDraft(
            name: name,
            phoneticName: phoneticName,
            topic: topic,
            description: description,
            filePath: filePath,
            password: password,
            clearPassword: clearPassword,
            channelType: channelType.rawValue,
            isDefault: isDefault,
            neededTalkPower: neededTalkPower,
            neededJoinPower: neededJoinPower,
            neededSubscribePower: neededSubscribePower,
            neededModifyPower: neededModifyPower,
            neededDeletePower: neededDeletePower,
            neededDescriptionViewPower: neededDescriptionViewPower,
            codec: codec.map(String.init) ?? "",
            codecQuality: codecQuality,
            codecLatencyFactor: codecLatencyFactor,
            isCodecUnencrypted: isCodecUnencrypted,
            order: selectedOrderId.map(String.init) ?? "",
            deleteDelaySeconds: deleteDelaySeconds,
            maxClients: maxClients,
            maxFamilyClients: maxFamilyClients,
            maxClientsUnlimited: maxClientsUnlimited,
            maxFamilyClientsUnlimited: maxFamilyClientsUnlimited,
            maxFamilyClientsInherited: maxFamilyClientsInherited,
            iconId: iconId,
            bannerGraphicsURL: bannerGraphicsURL,
            bannerMode: bannerMode.map(String.init) ?? ""
        )
    }

    private var channelDraftSnapshot: String {
        let draft = currentDraft
        var rows: [(String, String)] = [
            (localized("channelEditor.mode"), title),
            (localized("channelEditor.name"), draft.name),
            (localized("channelEditor.phoneticName"), draft.phoneticName),
            (localized("channelEditor.topic"), draft.topic),
            (localized("channelEditor.description"), draft.description),
            (localized("channelEditor.filePath"), draft.filePath ?? ""),
            (localized("channelEditor.password"), draft.clearPassword ? localized("channelEditor.clearPassword") : (draft.password.isEmpty ? localized("channelEditor.unchanged") : localized("channelEditor.newPasswordSet"))),
            (localized("channelEditor.type"), channelTypeTitle(draft.channelType)),
            (localized("channelEditor.defaultChannel"), draft.isDefault ? localized("channelEditor.yes") : localized("channelEditor.no")),
            (localized("channelEditor.neededTalkPower"), draft.neededTalkPower),
            (localized("channelEditor.neededJoinPower"), draft.neededJoinPower ?? ""),
            (localized("channelEditor.neededSubscribePower"), draft.neededSubscribePower),
            (localized("channelEditor.neededModifyPower"), draft.neededModifyPower ?? ""),
            (localized("channelEditor.neededDeletePower"), draft.neededDeletePower ?? ""),
            (localized("channelEditor.neededDescriptionViewPower"), draft.neededDescriptionViewPower ?? ""),
            (localized("channelEditor.permissionGateSummary"), permissionGateSummary.clipboardSummary),
            (localized("channelEditor.codec"), codecTitle(for: draft.codec)),
            (localized("channelEditor.codecQuality"), codecQualityTitle(for: draft.codecQuality)),
            (localized("channelEditor.codecLatencyFactor"), draft.codecLatencyFactor ?? ""),
            (localized("channelEditor.codecProfile"), codecConfigurationProfileText),
            (localized("channelEditor.codecSummary"), codecConfiguration.clipboardSummary),
            (localized("channelEditor.codecValidation"), codecValidationMessages.joined(separator: "; ")),
            (localized("channelEditor.codecDiagnostics"), codecDiagnosticMessages.joined(separator: "; ")),
            (localized("channelEditor.unencryptedVoice"), draft.isCodecUnencrypted == true ? localized("channelEditor.yes") : localized("channelEditor.no")),
            (localized("channelEditor.position"), positionTitle(for: draft.order ?? "")),
            (localized("channelEditor.deleteDelaySeconds"), draft.deleteDelaySeconds),
            (localized("channelEditor.maxClients"), draft.maxClientsUnlimited ? localized("channelEditor.unlimited") : draft.maxClients),
            (localized("channelEditor.maxFamilyClients"), draft.maxFamilyClientsInherited ? localized("channelEditor.inherited") : (draft.maxFamilyClientsUnlimited ? localized("channelEditor.unlimited") : draft.maxFamilyClients)),
            (localized("channelEditor.iconId"), draft.iconId),
            (localized("channelEditor.bannerGraphicURL"), draft.bannerGraphicsURL ?? ""),
            (localized("channelEditor.bannerMode"), bannerModeTitle(draft.bannerMode ?? ""))
        ]
        rows.append((localized("channelEditor.draftValid"), canSubmit ? localized("channelEditor.yes") : localized("channelEditor.no")))
        return rows.compactMap { label, value in
            let trimmed = value.trimmingCharacters(in: .whitespacesAndNewlines)
            guard !trimmed.isEmpty else { return nil }
            return "\(label): \(trimmed)"
        }.joined(separator: "\n")
    }

    private var draftChangeRows: [String] {
        draftChangeRows(for: currentDraft)
    }

    private var draftChangeSummary: String {
        let rows = draftChangeRows
        guard !rows.isEmpty else { return localized("channelEditor.noDraftChanges") }
        return rows.joined(separator: "\n")
    }

    private var channelImpactSummary: TS3ChannelEditorImpactSummary {
        channelImpactSummary(for: currentDraft)
    }

    private var channelCoverageSummary: TS3ChannelEditorCoverageSummary {
        channelCoverageSummary(for: currentDraft)
    }

    private var channelCoverageSummaryText: String {
        channelCoverageSummaryText(for: channelCoverageSummary)
    }

    private var channelCoverageSummaryClipboard: String {
        [
            localized("channelEditor.coverageSummary"),
            channelCoverageSummary.clipboardSummary
        ].joined(separator: "\n")
    }

    private var channelImpactSummaryText: String {
        channelImpactSummaryText(for: channelImpactSummary)
    }

    private var channelImpactSummaryClipboard: String {
        let impact = channelImpactSummary
        let affectedAreas = TS3ChannelEditorImpactArea.allCases
            .compactMap { area -> String? in
                guard let count = impact.areaChangeCounts[area], count > 0 else { return nil }
                return localized("channelEditor.impactAreaClipboardFormat", title(for: area), count)
            }
            .joined(separator: "\n")
        return [
            localized("channelEditor.impactSummary"),
            impact.clipboardSummary,
            affectedAreas
        ]
        .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
        .filter { !$0.isEmpty }
        .joined(separator: "\n")
    }

    private var channelReviewSummary: TS3ChannelEditorReviewSummary {
        channelReviewSummary(for: currentDraft)
    }

    private var channelOfficialImpactSummary: TS3ChannelEditorOfficialImpactSummary {
        channelOfficialImpactSummary(for: currentDraft)
    }

    private var channelOfficialImpactSummaryText: String {
        channelOfficialImpactSummaryText(for: channelOfficialImpactSummary)
    }

    private var channelOfficialImpactSummaryClipboard: String {
        let summary = channelOfficialImpactSummary
        let affectedAreas = TS3ChannelEditorOfficialImpactArea.allCases
            .compactMap { area -> String? in
                guard let count = summary.areaChangeCounts[area], count > 0 else { return nil }
                return localized("channelEditor.officialImpactAreaClipboardFormat", title(for: area), count)
            }
            .joined(separator: "\n")
        return [
            localized("channelEditor.officialImpactSummary"),
            summary.clipboardSummary,
            affectedAreas
        ]
        .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
        .filter { !$0.isEmpty }
        .joined(separator: "\n")
    }

    private var channelReviewSummaryText: String {
        channelReviewSummaryText(for: channelReviewSummary)
    }

    private var channelReviewSummaryClipboard: String {
        let summary = channelReviewSummary
        let lines = [
            localized("channelEditor.reviewSummary"),
            summary.clipboardSummary,
            summary.reviewItems.joined(separator: "\n")
        ]
        return lines
            .map { $0.trimmingCharacters(in: .whitespacesAndNewlines) }
            .filter { !$0.isEmpty }
            .joined(separator: "\n")
    }

    private var permissionGateSummary: TS3ChannelPermissionGateSummary {
        TS3ChannelPermissionGateSummary(
            neededTalkPower: parsedOptionalInt(neededTalkPower),
            neededJoinPower: parsedOptionalInt(neededJoinPower),
            neededSubscribePower: parsedOptionalInt(neededSubscribePower),
            neededModifyPower: parsedOptionalInt(neededModifyPower),
            neededDeletePower: parsedOptionalInt(neededDeletePower),
            neededDescriptionViewPower: parsedOptionalInt(neededDescriptionViewPower)
        )
    }

    private var permissionGateSummaryRows: [String] {
        let configuredRows = permissionGateSummary.configuredGates.map { gate in
            localized(
                "channelEditor.permissionGateConfiguredFormat",
                permissionGateTitle(gate),
                gate.value ?? 0
            )
        }
        let inheritedRows = permissionGateSummary.inheritedGates.map { gate in
            localized("channelEditor.permissionGateInheritedFormat", permissionGateTitle(gate))
        }
        return configuredRows + inheritedRows
    }

    private func permissionGateTitle(_ gate: TS3ChannelPermissionGateSummary.Gate) -> String {
        switch gate.id {
        case "i_channel_needed_talk_power":
            return localized("channelEditor.neededTalkPower")
        case "i_channel_needed_join_power":
            return localized("channelEditor.neededJoinPower")
        case "i_channel_needed_subscribe_power":
            return localized("channelEditor.neededSubscribePower")
        case "i_channel_needed_modify_power":
            return localized("channelEditor.neededModifyPower")
        case "i_channel_needed_delete_power":
            return localized("channelEditor.neededDeletePower")
        case "i_channel_needed_description_view_power":
            return localized("channelEditor.neededDescriptionViewPower")
        default:
            return gate.title
        }
    }

    private func draftChangeRows(for draft: ChannelDraft) -> [String] {
        guard case let .edit(channel) = mode else { return [] }
        return channelChangeRows(for: channel, draft: draft)
            + voiceChangeRows(for: channel, draft: draft)
            + permissionGateChangeRows(for: channel, draft: draft)
            + limitChangeRows(for: channel, draft: draft)
    }

    private func channelImpactSummary(for draft: ChannelDraft) -> TS3ChannelEditorImpactSummary {
        guard case .edit = mode else {
            return TS3ChannelEditorImpactSummary(
                areaChangeCounts: [:],
                validationIssueCount: draftValidationMessages(for: draft).count,
                codecWarningCount: codecDiagnosticMessages.count
            )
        }
        return TS3ChannelEditorImpactSummary(
            areaChangeCounts: channelAreaChangeCounts(for: draft),
            validationIssueCount: draftValidationMessages(for: draft).count,
            codecWarningCount: codecDiagnosticMessages.count
        )
    }

    private func channelCoverageSummary(for draft: ChannelDraft) -> TS3ChannelEditorCoverageSummary {
        TS3ChannelEditorCoverageSummary(
            changedAreaCounts: channelAreaChangeCounts(for: draft),
            validationIssueCount: draftValidationMessages(for: draft).count,
            codecWarningCount: codecDiagnosticMessages.count
        )
    }

    private func channelAreaChangeCounts(for draft: ChannelDraft) -> [TS3ChannelEditorImpactArea: Int] {
        guard case let .edit(channel) = mode else { return [:] }
        return [
            .channel: channelChangeRows(for: channel, draft: draft).count,
            .voice: voiceChangeRows(for: channel, draft: draft).count,
            .permissionGates: permissionGateChangeRows(for: channel, draft: draft).count,
            .limits: limitChangeRows(for: channel, draft: draft).count
        ]
    }

    private func channelReviewSummary(for draft: ChannelDraft) -> TS3ChannelEditorReviewSummary {
        TS3ChannelEditorReviewSummary(
            reviewItems: channelReviewItems(for: draft),
            validationIssueCount: draftValidationMessages(for: draft).count,
            codecWarningCount: codecDiagnosticMessages.count
        )
    }

    private func channelOfficialImpactSummary(for draft: ChannelDraft) -> TS3ChannelEditorOfficialImpactSummary {
        let reviewSummary = channelReviewSummary(for: draft)
        return TS3ChannelEditorOfficialImpactSummary(
            areaChangeCounts: channelOfficialImpactAreaChangeCounts(for: draft),
            validationIssueCount: reviewSummary.validationIssueCount,
            codecWarningCount: reviewSummary.codecWarningCount,
            sensitiveChangeCount: reviewSummary.sensitiveChangeCount
        )
    }

    private func channelOfficialImpactAreaChangeCounts(for draft: ChannelDraft) -> [TS3ChannelEditorOfficialImpactArea: Int] {
        guard case let .edit(channel) = mode else { return [:] }
        return [
            .structureVisibility: structureVisibilityImpactRows(for: channel, draft: draft).count,
            .accessPermissions: accessPermissionImpactRows(for: channel, draft: draft).count,
            .voiceCodec: voiceCodecImpactRows(for: channel, draft: draft).count,
            .capacityLimits: capacityLimitImpactRows(for: channel, draft: draft).count
        ]
    }

    private func structureVisibilityImpactRows(for channel: TS3ChannelSummary, draft: ChannelDraft) -> [String] {
        [
            changeRow(label: localized("channelEditor.name"), current: channel.name, draft: draft.name),
            changeRow(label: localized("channelEditor.phoneticName"), current: channel.phoneticName, draft: draft.phoneticName),
            changeRow(label: localized("channelEditor.topic"), current: channel.topic, draft: draft.topic),
            changeRow(label: localized("channelEditor.description"), current: channel.description, draft: draft.description),
            changeRow(label: localized("channelEditor.filePath"), current: channel.filePath, draft: draft.filePath),
            changeRow(label: localized("channelEditor.type"), current: channelTypeTitle(channelType(for: channel)), draft: channelTypeTitle(draft.channelType)),
            changeRow(label: localized("channelEditor.defaultChannel"), current: boolTitle(channel.isDefault), draft: boolTitle(draft.isDefault)),
            changeRow(label: localized("channelEditor.position"), current: positionTitle(for: normalizedOrderId(channel.order).map(String.init) ?? ""), draft: positionTitle(for: draft.order ?? "")),
            changeRow(label: localized("channelEditor.iconId"), current: channel.iconId, draft: draft.iconId),
            changeRow(label: localized("channelEditor.bannerGraphicURL"), current: channel.bannerGraphicsURL, draft: draft.bannerGraphicsURL),
            changeRow(label: localized("channelEditor.bannerMode"), current: channel.bannerMode.map(bannerModeTitle), draft: bannerModeTitle(draft.bannerMode ?? ""))
        ].compactMap { $0 }
    }

    private func accessPermissionImpactRows(for channel: TS3ChannelSummary, draft: ChannelDraft) -> [String] {
        [
            passwordChangeRow(for: channel, draft: draft),
            changeRow(label: localized("channelEditor.neededTalkPower"), current: channel.neededTalkPower, draft: draft.neededTalkPower),
            changeRow(label: localized("channelEditor.neededJoinPower"), current: channel.neededJoinPower, draft: draft.neededJoinPower),
            changeRow(label: localized("channelEditor.neededSubscribePower"), current: channel.neededSubscribePower, draft: draft.neededSubscribePower),
            changeRow(label: localized("channelEditor.neededModifyPower"), current: channel.neededModifyPower, draft: draft.neededModifyPower),
            changeRow(label: localized("channelEditor.neededDeletePower"), current: channel.neededDeletePower, draft: draft.neededDeletePower),
            changeRow(label: localized("channelEditor.neededDescriptionViewPower"), current: channel.neededDescriptionViewPower, draft: draft.neededDescriptionViewPower)
        ].compactMap { $0 }
    }

    private func voiceCodecImpactRows(for channel: TS3ChannelSummary, draft: ChannelDraft) -> [String] {
        voiceChangeRows(for: channel, draft: draft)
    }

    private func capacityLimitImpactRows(for channel: TS3ChannelSummary, draft: ChannelDraft) -> [String] {
        limitChangeRows(for: channel, draft: draft)
    }

    private func channelReviewItems(for draft: ChannelDraft) -> [String] {
        guard case let .edit(channel) = mode else { return [] }
        return [
            passwordChangeRow(for: channel, draft: draft),
            changeRow(label: localized("channelEditor.type"), current: channelTypeTitle(channelType(for: channel)), draft: channelTypeTitle(draft.channelType)),
            changeRow(label: localized("channelEditor.defaultChannel"), current: boolTitle(channel.isDefault), draft: boolTitle(draft.isDefault)),
            changeRow(label: localized("channelEditor.codec"), current: channel.codec.map(codecTitle), draft: codecTitle(for: draft.codec)),
            changeRow(label: localized("channelEditor.codecQuality"), current: channel.codecQuality.map { codecQualityTitle(for: String($0)) }, draft: codecQualityTitle(for: draft.codecQuality)),
            changeRow(label: localized("channelEditor.codecLatencyFactor"), current: channel.codecLatencyFactor, draft: draft.codecLatencyFactor),
            changeRow(label: localized("channelEditor.codecProfile"), current: codecConfigurationProfileText(codecConfiguration(for: channel).profile), draft: codecConfigurationProfileText),
            changeRow(label: localized("channelEditor.unencryptedVoice"), current: boolTitle(channel.isCodecUnencrypted ?? false), draft: boolTitle(draft.isCodecUnencrypted ?? false)),
            changeRow(label: localized("channelEditor.neededTalkPower"), current: channel.neededTalkPower, draft: draft.neededTalkPower),
            changeRow(label: localized("channelEditor.neededJoinPower"), current: channel.neededJoinPower, draft: draft.neededJoinPower),
            changeRow(label: localized("channelEditor.neededSubscribePower"), current: channel.neededSubscribePower, draft: draft.neededSubscribePower),
            changeRow(label: localized("channelEditor.neededModifyPower"), current: channel.neededModifyPower, draft: draft.neededModifyPower),
            changeRow(label: localized("channelEditor.neededDeletePower"), current: channel.neededDeletePower, draft: draft.neededDeletePower),
            changeRow(label: localized("channelEditor.neededDescriptionViewPower"), current: channel.neededDescriptionViewPower, draft: draft.neededDescriptionViewPower),
            changeRow(label: localized("channelEditor.maxClients"), current: directLimitTitle(maxClients: channel.maxClients, unlimited: channel.maxClientsUnlimited), draft: directLimitTitle(maxClients: parsedOptionalInt(draft.maxClients), unlimited: draft.maxClientsUnlimited)),
            changeRow(label: localized("channelEditor.maxFamilyClients"), current: familyLimitTitle(maxFamilyClients: channel.maxFamilyClients, unlimited: channel.maxFamilyClientsUnlimited, inherited: channel.maxFamilyClientsInherited), draft: familyLimitTitle(maxFamilyClients: parsedOptionalInt(draft.maxFamilyClients), unlimited: draft.maxFamilyClientsUnlimited, inherited: draft.maxFamilyClientsInherited))
        ].compactMap { $0 }
    }

    private func channelImpactSummaryText(for summary: TS3ChannelEditorImpactSummary) -> String {
        guard summary.needsReview else { return localized("channelEditor.impactNoChanges") }
        var parts = TS3ChannelEditorImpactArea.allCases.compactMap { area -> String? in
            guard let count = summary.areaChangeCounts[area], count > 0 else { return nil }
            return localized("channelEditor.impactAreaFormat", title(for: area), count)
        }
        if summary.validationIssueCount > 0 {
            parts.append(localized("channelEditor.validationIssueCountFormat", summary.validationIssueCount))
        }
        if summary.codecWarningCount > 0 {
            parts.append(localized("channelEditor.codecWarningCountFormat", summary.codecWarningCount))
        }
        return parts.joined(separator: " · ")
    }

    private func channelCoverageSummaryText(for summary: TS3ChannelEditorCoverageSummary) -> String {
        var parts = [
            localized("channelEditor.coverageAreaFormat", summary.coveredAreaCount, summary.totalOfficialAreaCount),
            localized("channelEditor.coverageChangedAreaFormat", summary.changedAreaCount, summary.totalChangeCount)
        ]
        if summary.validationIssueCount > 0 {
            parts.append(localized("channelEditor.validationIssueCountFormat", summary.validationIssueCount))
        }
        if summary.codecWarningCount > 0 {
            parts.append(localized("channelEditor.codecWarningCountFormat", summary.codecWarningCount))
        }
        if summary.uncoveredAreaCount > 0 {
            parts.append(localized("channelEditor.coverageUncoveredFormat", summary.uncoveredAreaCount))
        }
        return parts.joined(separator: " · ")
    }

    private func channelReviewSummaryText(for summary: TS3ChannelEditorReviewSummary) -> String {
        guard summary.needsAttention else { return localized("channelEditor.reviewNoAttention") }
        var parts: [String] = []
        if summary.sensitiveChangeCount > 0 {
            parts.append(localized("channelEditor.sensitiveChangeCountFormat", summary.sensitiveChangeCount))
        }
        if summary.validationIssueCount > 0 {
            parts.append(localized("channelEditor.validationIssueCountFormat", summary.validationIssueCount))
        }
        if summary.codecWarningCount > 0 {
            parts.append(localized("channelEditor.codecWarningCountFormat", summary.codecWarningCount))
        }
        let previewItems = summary.reviewItems.prefix(4).joined(separator: " · ")
        if !previewItems.isEmpty {
            parts.append(previewItems)
        }
        return parts.joined(separator: " · ")
    }

    private func channelOfficialImpactSummaryText(for summary: TS3ChannelEditorOfficialImpactSummary) -> String {
        guard summary.needsAttention else { return localized("channelEditor.officialImpactNoChanges") }
        var parts = TS3ChannelEditorOfficialImpactArea.allCases.compactMap { area -> String? in
            guard let count = summary.areaChangeCounts[area], count > 0 else { return nil }
            return localized("channelEditor.officialImpactAreaFormat", title(for: area), count)
        }
        if summary.sensitiveChangeCount > 0 {
            parts.append(localized("channelEditor.sensitiveChangeCountFormat", summary.sensitiveChangeCount))
        }
        if summary.validationIssueCount > 0 {
            parts.append(localized("channelEditor.validationIssueCountFormat", summary.validationIssueCount))
        }
        if summary.codecWarningCount > 0 {
            parts.append(localized("channelEditor.codecWarningCountFormat", summary.codecWarningCount))
        }
        return parts.joined(separator: " · ")
    }

