    private func limitChangeRows(for channel: TS3ChannelSummary, draft: ChannelDraft) -> [String] {
        [
            changeRow(label: localized("channelEditor.maxClients"), current: directLimitTitle(maxClients: channel.maxClients, unlimited: channel.maxClientsUnlimited), draft: directLimitTitle(maxClients: parsedOptionalInt(draft.maxClients), unlimited: draft.maxClientsUnlimited)),
            changeRow(label: localized("channelEditor.maxFamilyClients"), current: familyLimitTitle(maxFamilyClients: channel.maxFamilyClients, unlimited: channel.maxFamilyClientsUnlimited, inherited: channel.maxFamilyClientsInherited), draft: familyLimitTitle(maxFamilyClients: parsedOptionalInt(draft.maxFamilyClients), unlimited: draft.maxFamilyClientsUnlimited, inherited: draft.maxFamilyClientsInherited))
        ].compactMap { $0 }
    }

    private func changeRow(label: String, current: String?, draft: String?) -> String? {
        let currentText = normalizedDraftValue(current)
        let draftText = normalizedDraftValue(draft)
        guard currentText != draftText else { return nil }
        return localized(
            "channelEditor.changeFormat",
            label,
            displayDraftValue(currentText),
            displayDraftValue(draftText)
        )
    }

    private func changeRow(label: String, current: Int?, draft: String?) -> String? {
        changeRow(label: label, current: current.map(String.init), draft: draft)
    }

    private func passwordChangeRow(for channel: TS3ChannelSummary, draft: ChannelDraft) -> String? {
        if draft.clearPassword {
            return localized(
                "channelEditor.changeFormat",
                localized("channelEditor.password"),
                channel.isPasswordProtected ? localized("channelEditor.protected") : localized("channelEditor.emptyValue"),
                localized("channelEditor.clearExistingPassword")
            )
        }
        guard !draft.password.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty else { return nil }
        return localized(
            "channelEditor.changeFormat",
            localized("channelEditor.password"),
            channel.isPasswordProtected ? localized("channelEditor.protected") : localized("channelEditor.emptyValue"),
            localized("channelEditor.newPasswordSet")
        )
    }

    private func normalizedDraftValue(_ value: String?) -> String {
        value?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
    }

    private func displayDraftValue(_ value: String) -> String {
        value.isEmpty ? localized("channelEditor.emptyValue") : value
    }

    private func boolTitle(_ value: Bool) -> String {
        value ? localized("channelEditor.yes") : localized("channelEditor.no")
    }

    private func directLimitTitle(maxClients: Int?, unlimited: Bool?) -> String {
        if unlimited == true {
            return localized("channelEditor.unlimited")
        }
        return maxClients.map(String.init) ?? ""
    }

    private func familyLimitTitle(maxFamilyClients: Int?, unlimited: Bool?, inherited: Bool?) -> String {
        if inherited == true {
            return localized("channelEditor.inherited")
        }
        if unlimited == true {
            return localized("channelEditor.unlimited")
        }
        return maxFamilyClients.map(String.init) ?? ""
    }

    private var canSubmit: Bool {
        !name.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            && isOptionalInt(neededTalkPower)
            && isOptionalInt(neededJoinPower)
            && isOptionalInt(neededSubscribePower)
            && isOptionalInt(neededModifyPower)
            && isOptionalInt(neededDeletePower)
            && isOptionalInt(neededDescriptionViewPower)
            && isCodecQualityValid
            && isCodecLatencyFactorValid
            && isValidOrderSelection
            && isOptionalInt(deleteDelaySeconds)
            && isOptionalInt(iconId)
            && (maxClientsUnlimited || isRequiredInt(maxClients))
            && (maxFamilyClientsInherited || maxFamilyClientsUnlimited || isRequiredInt(maxFamilyClients))
    }

    private func channelType(for channel: TS3ChannelSummary) -> TS3ChannelType {
        if channel.isPermanent {
            return .permanent
        }
        if channel.isSemiPermanent == true {
            return .semiPermanent
        }
        return .temporary
    }

    private func parsedOptionalInt(_ text: String) -> Int? {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? nil : Int(trimmed)
    }

    private func applyCodecPreset(_ preset: TS3ChannelCodecPreset) {
        codec = preset.codec
        codecQuality = String(preset.quality)
        codecLatencyFactor = String(preset.latencyFactor)
        isCodecUnencrypted = preset.isCodecUnencrypted
    }

    private func codecPresetTitle(_ preset: TS3ChannelCodecPreset) -> String {
        switch preset.id {
        case TS3ChannelCodecPreset.voice.id:
            return localized("channelEditor.codecPreset.voice")
        case TS3ChannelCodecPreset.music.id:
            return localized("channelEditor.codecPreset.music")
        case TS3ChannelCodecPreset.compatibilityVoice.id:
            return localized("channelEditor.codecPreset.compatibilityVoice")
        default:
            return preset.title
        }
    }

    private func exportDraft() {
        do {
            let encoder = JSONEncoder()
            encoder.outputFormatting = [.prettyPrinted, .sortedKeys]
            draftDocument = TS3TextFileDocument(data: try encoder.encode(currentDraft))
            isExportingDraft = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareDraftImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let draft = try JSONDecoder().decode(ChannelDraft.self, from: Data(contentsOf: url))
            let validationMessages = draftValidationMessages(for: draft)
            pendingDraftImport = ChannelDraftImportConfirmation(
                draft: draft,
                previewMessage: draftImportPreviewMessage(for: draft, validationMessages: validationMessages),
                validationMessages: validationMessages
            )
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func draftImportPreviewMessage(for draft: ChannelDraft, validationMessages: [String]) -> String {
        let name = draft.name.trimmingCharacters(in: .whitespacesAndNewlines)
        let type = channelTypeTitle(draft.channelType)
        let codec = codecTitle(for: draft.codec)
        let quality = codecQualityTitle(for: draft.codecQuality)
        let latency = draft.codecLatencyFactor?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let position = positionTitle(for: draft.order ?? "")
        let maxClients = draft.maxClientsUnlimited ? localized("channelEditor.unlimited") : draft.maxClients
        let maxFamilyClients = draft.maxFamilyClientsInherited ? localized("channelEditor.inherited") : (draft.maxFamilyClientsUnlimited ? localized("channelEditor.unlimited") : draft.maxFamilyClients)
        let bannerURL = draft.bannerGraphicsURL?.trimmingCharacters(in: .whitespacesAndNewlines) ?? ""
        let bannerMode = bannerModeTitle(draft.bannerMode ?? "")
        var lines = [
            "\(localized("channelEditor.name")): \(name.isEmpty ? localized("channelEditor.missing") : name)",
            "\(localized("channelEditor.type")): \(type)",
            "\(localized("channelEditor.position")): \(position)",
            "\(localized("channelEditor.maxClients")): \(maxClients)",
            "\(localized("channelEditor.maxFamilyClients")): \(maxFamilyClients)"
        ]
        if !codec.isEmpty {
            lines.append("\(localized("channelEditor.codec")): \(codec)")
        }
        if !quality.isEmpty {
            lines.append("\(localized("channelEditor.codecQuality")): \(quality)")
        }
        if !latency.isEmpty {
            lines.append("\(localized("channelEditor.codecLatencyFactor")): \(latency)")
        }
        if !bannerURL.isEmpty {
            lines.append("\(localized("channelEditor.bannerGraphicURL")): \(bannerURL)")
        }
        if !bannerMode.isEmpty {
            lines.append("\(localized("channelEditor.bannerMode")): \(bannerMode)")
        }
        if draft.isCodecUnencrypted == true {
            lines.append("\(localized("channelEditor.voiceEncryption")): \(localized("channelEditor.disabled"))")
        }
        if draft.clearPassword {
            lines.append("\(localized("channelEditor.password")): \(localized("channelEditor.clearExistingPassword"))")
        } else if !draft.password.isEmpty {
            lines.append("\(localized("channelEditor.password")): \(localized("channelEditor.newPasswordSet"))")
        }
        if validationMessages.isEmpty {
            lines.append("\(localized("channelEditor.draftValid")): \(localized("channelEditor.yes"))")
        } else {
            lines.append("\(localized("channelEditor.draftValid")): \(localized("channelEditor.no"))")
            lines.append(contentsOf: validationMessages)
        }
        return lines.joined(separator: "\n")
    }

    private func draftValidationMessages(for draft: ChannelDraft) -> [String] {
        TS3ChannelDraftValidator.validationMessages(
            name: draft.name,
            channelType: draft.channelType,
            neededTalkPower: draft.neededTalkPower,
            neededJoinPower: draft.neededJoinPower ?? "",
            neededSubscribePower: draft.neededSubscribePower,
            neededModifyPower: draft.neededModifyPower ?? "",
            neededDeletePower: draft.neededDeletePower ?? "",
            neededDescriptionViewPower: draft.neededDescriptionViewPower ?? "",
            codec: draft.codec,
            codecQuality: draft.codecQuality,
            codecLatencyFactor: draft.codecLatencyFactor ?? "",
            bannerMode: draft.bannerMode ?? "",
            order: draft.order ?? "",
            deleteDelaySeconds: draft.deleteDelaySeconds,
            iconId: draft.iconId,
            maxClients: draft.maxClients,
            maxClientsUnlimited: draft.maxClientsUnlimited,
            maxFamilyClients: draft.maxFamilyClients,
            maxFamilyClientsUnlimited: draft.maxFamilyClientsUnlimited,
            maxFamilyClientsInherited: draft.maxFamilyClientsInherited
        )
    }

    private func applyDraft(_ draft: ChannelDraft) {
        name = draft.name
        phoneticName = draft.phoneticName
        topic = draft.topic
        description = draft.description
        filePath = draft.filePath ?? ""
        password = draft.password
        clearPassword = draft.clearPassword
        channelType = TS3ChannelType.value(forDraft: draft.channelType) ?? .permanent
        isDefault = draft.isDefault
        neededTalkPower = draft.neededTalkPower
        neededJoinPower = draft.neededJoinPower ?? ""
        neededSubscribePower = draft.neededSubscribePower
        neededModifyPower = draft.neededModifyPower ?? ""
        neededDeletePower = draft.neededDeletePower ?? ""
        neededDescriptionViewPower = draft.neededDescriptionViewPower ?? ""
        codec = parsedOptionalCodec(draft.codec)
        codecQuality = draft.codecQuality
        codecLatencyFactor = draft.codecLatencyFactor ?? ""
        isCodecUnencrypted = draft.isCodecUnencrypted ?? false
        selectedOrderId = parsedOptionalInt(draft.order ?? "")
        deleteDelaySeconds = draft.deleteDelaySeconds
        maxClients = draft.maxClients
        maxFamilyClients = draft.maxFamilyClients
        maxClientsUnlimited = draft.maxClientsUnlimited
        maxFamilyClientsUnlimited = draft.maxFamilyClientsUnlimited
        maxFamilyClientsInherited = draft.maxFamilyClientsInherited
        iconId = draft.iconId
        bannerGraphicsURL = draft.bannerGraphicsURL ?? ""
        bannerMode = (draft.bannerMode ?? "").trimmingCharacters(in: .whitespacesAndNewlines).isEmpty
            ? nil
            : TS3HostBannerMode.value(forDraft: draft.bannerMode ?? "")
    }

    private func channelTypeTitle(_ rawValue: String) -> String {
        channelTypeTitle(TS3ChannelType.value(forDraft: rawValue) ?? .permanent)
    }

    private func channelTypeTitle(_ type: TS3ChannelType) -> String {
        switch type {
        case .temporary:
            return localized("channelEditor.channelType.temporary")
        case .semiPermanent:
            return localized("channelEditor.channelType.semiPermanent")
        case .permanent:
            return localized("channelEditor.channelType.permanent")
        }
    }

    private func codecTitle(for rawValue: String) -> String {
        let trimmed = rawValue.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty else { return "" }
        guard let codec = parsedOptionalCodec(trimmed) else { return trimmed }
        return codecTitle(for: codec)
    }

    private func codecTitle(for rawValue: Int) -> String {
        let title: String
        switch TS3ChannelCodec(rawValue: rawValue) {
        case .some(.speexNarrowband):
            title = localized("channelEditor.codec.speexNarrowband")
        case .some(.speexWideband):
            title = localized("channelEditor.codec.speexWideband")
        case .some(.speexUltraWideband):
            title = localized("channelEditor.codec.speexUltraWideband")
        case .some(.celtMono):
            title = localized("channelEditor.codec.celtMono")
        case .some(.opusVoice):
            title = localized("channelEditor.codec.opusVoice")
        case .some(.opusMusic):
            title = localized("channelEditor.codec.opusMusic")
        case nil:
            return localized("channelEditor.unknownValueFormat", rawValue)
        }
        return localized("channelEditor.valueWithNumberFormat", title, rawValue)
    }

    private func codecQualityTitle(for rawValue: String) -> String {
        let trimmed = rawValue.trimmingCharacters(in: .whitespacesAndNewlines)
        guard let numericValue = Int(trimmed) else { return trimmed }
        return TS3ChannelCodecConstraints.qualityRange.contains(numericValue)
            ? localized("channelEditor.qualityFormat", numericValue)
            : localized("channelEditor.unknownValueFormat", numericValue)
    }

    private func bannerModeTitle(_ rawValue: String) -> String {
        let trimmed = rawValue.trimmingCharacters(in: .whitespacesAndNewlines)
        guard !trimmed.isEmpty, let numericValue = TS3HostBannerMode.value(forDraft: trimmed) else { return trimmed }
        return bannerModeTitle(numericValue)
    }

    private func bannerModeTitle(_ rawValue: Int) -> String {
        let title: String
        switch TS3HostBannerMode(rawValue: rawValue) {
        case .some(.noAdjust):
            title = localized("channelEditor.bannerMode.noAdjustment")
        case .some(.ignoreAspect):
            title = localized("channelEditor.bannerMode.ignoreAspect")
        case .some(.keepAspect):
            title = localized("channelEditor.bannerMode.keepAspect")
        case nil:
            return localized("channelEditor.unknownValueFormat", rawValue)
        }
        return localized("channelEditor.valueWithNumberFormat", title, rawValue)
    }

    private var codecProfileSummary: String {
        let parts = [
            codec.map { codecTitle(for: $0) },
            parsedOptionalInt(codecQuality).map { localized("channelEditor.qualityInlineFormat", $0) },
            parsedOptionalInt(codecLatencyFactor).map { localized("channelEditor.latencyInlineFormat", $0) },
            isCodecUnencrypted ? localized("channelEditor.unencrypted") : nil
        ].compactMap { $0 }
        return parts.joined(separator: " | ")
    }

    private var codecConfiguration: TS3ChannelCodecConfigurationSummary {
        TS3ChannelCodecConfigurationSummary(
            codec: codec,
            codecQuality: parsedOptionalInt(codecQuality),
            codecLatencyFactor: parsedOptionalInt(codecLatencyFactor),
            isCodecUnencrypted: isCodecUnencrypted
        )
    }

    private func codecConfiguration(for channel: TS3ChannelSummary) -> TS3ChannelCodecConfigurationSummary {
        TS3ChannelCodecConfigurationSummary(
            codec: channel.codec,
            codecQuality: channel.codecQuality,
            codecLatencyFactor: channel.codecLatencyFactor,
            isCodecUnencrypted: channel.isCodecUnencrypted
        )
    }

    private var codecConfigurationProfileText: String {
        codecConfigurationProfileText(codecConfiguration.profile)
    }

    private func codecConfigurationProfileText(_ profile: TS3ChannelCodecConfigurationSummary.Profile) -> String {
        switch profile {
        case .unchanged:
            return localized("channelEditor.codecProfile.unchanged")
        case .voice:
            return localized("channelEditor.codecProfile.voice")
        case .music:
            return localized("channelEditor.codecProfile.music")
        case .compatibility:
            return localized("channelEditor.codecProfile.compatibility")
        case .highQuality:
            return localized("channelEditor.codecProfile.highQuality")
        case .lowLatency:
            return localized("channelEditor.codecProfile.lowLatency")
        case .custom:
            return localized("channelEditor.codecProfile.custom")
        }
    }

    private var codecValidationMessages: [String] {
        var messages: [String] = []
        if !isCodecQualityValid {
            messages.append(localized(
                "channelEditor.codecQualityRangeError",
                TS3ChannelCodecConstraints.qualityRange.lowerBound,
                TS3ChannelCodecConstraints.qualityRange.upperBound
            ))
        }
        if !isCodecLatencyFactorValid {
            messages.append(localized(
                "channelEditor.codecLatencyRangeError",
                TS3ChannelCodecConstraints.latencyFactorRange.lowerBound,
                TS3ChannelCodecConstraints.latencyFactorRange.upperBound
            ))
        }
        return messages
    }

    private var codecDiagnosticMessages: [String] {
        var messages: [String] = []
        if let codec, TS3ChannelCodecConstraints.legacyCodecIds.contains(codec) {
            messages.append(localized("channelEditor.legacyCodecWarning"))
        }
        if isCodecUnencrypted {
            messages.append(localized("channelEditor.voiceEncryptionDisabledWarning"))
        }
        return messages
    }

    private var positionSiblingOptions: [TS3ChannelSummary] {
        orderedSiblings(
            model.channels.filter { candidate in
                candidate.id != editingChannelId
                    && normalizedParentId(candidate.parentId) == targetParentId
            }
        )
    }

    private var editingChannelId: Int? {
        if case let .edit(channel) = mode {
            return channel.id
        }
        return nil
    }

    private var targetParentId: Int? {
        switch mode {
        case let .create(parent):
            return normalizedParentId(parent?.id)
        case let .edit(channel):
            return normalizedParentId(channel.parentId)
        }
    }

    private var isValidOrderSelection: Bool {
        guard let selectedOrderId else { return true }
        return positionSiblingOptions.contains { $0.id == selectedOrderId }
    }

    private func positionTitle(for rawValue: String) -> String {
        guard let orderId = Int(rawValue.trimmingCharacters(in: .whitespacesAndNewlines)) else {
            return localized("channelEditor.first")
        }
        let channelName = model.channels.first { $0.id == orderId }?.name ?? localized("channelEditor.channelWithIdFormat", orderId)
        return localized("channelEditor.afterFormat", channelName)
    }

    private func normalizedParentId(_ parentId: Int?) -> Int? {
        guard let parentId, parentId > 0 else { return nil }
        return parentId
    }

    private func normalizedOrderId(_ orderId: Int?) -> Int? {
        guard let orderId, orderId > 0 else { return nil }
        return orderId
    }

    private func orderedSiblings(_ channels: [TS3ChannelSummary]) -> [TS3ChannelSummary] {
        let ids = Set(channels.map(\.id))
        let byPreviousId = Dictionary(grouping: channels) { channel -> Int? in
            guard let previousId = channel.order, ids.contains(previousId) else { return nil }
            return previousId
        }
        var visited: Set<Int> = []
        var result: [TS3ChannelSummary] = []

        func stableSort(_ lhs: TS3ChannelSummary, _ rhs: TS3ChannelSummary) -> Bool {
            if lhs.order != rhs.order {
                return (lhs.order ?? Int.min) < (rhs.order ?? Int.min)
            }
            if lhs.name != rhs.name {
                return lhs.name.localizedCaseInsensitiveCompare(rhs.name) == .orderedAscending
            }
            return lhs.id < rhs.id
        }

        func appendChain(startingAt channel: TS3ChannelSummary) {
            var current: TS3ChannelSummary? = channel
            while let channel = current, !visited.contains(channel.id) {
                visited.insert(channel.id)
                result.append(channel)
                current = byPreviousId[channel.id]?.sorted(by: stableSort).first {
                    !visited.contains($0.id)
                }
            }
        }

        for channel in (byPreviousId[nil] ?? []).sorted(by: stableSort) {
            appendChain(startingAt: channel)
        }
        for channel in channels.sorted(by: stableSort) where !visited.contains(channel.id) {
            appendChain(startingAt: channel)
        }
        return result
    }

    private var isCodecQualityValid: Bool {
        isOptionalInt(codecQuality)
            && TS3ChannelCodecConstraints.isValidQuality(parsedOptionalInt(codecQuality))
    }

    private var isCodecLatencyFactorValid: Bool {
        isOptionalInt(codecLatencyFactor)
            && TS3ChannelCodecConstraints.isValidLatencyFactor(parsedOptionalInt(codecLatencyFactor))
    }

    private func isOptionalInt(_ text: String) -> Bool {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty || Int(trimmed) != nil
    }

    private func parsedOptionalCodec(_ text: String) -> Int? {
        let trimmed = text.trimmingCharacters(in: .whitespacesAndNewlines)
        return trimmed.isEmpty ? nil : TS3ChannelCodec.value(forDraft: trimmed)
    }

    private func isRequiredInt(_ text: String) -> Bool {
        Int(text.trimmingCharacters(in: .whitespacesAndNewlines)) != nil
    }
}

