struct TalkControlBar: View {
    @EnvironmentObject private var model: TS3AppModel

    var body: some View {
        VStack(spacing: 8) {
            HStack(spacing: 12) {
                Text(model.talkStatus)
                    .font(.footnote)
                    .foregroundColor(.secondary)
                Spacer()
                Button {
                    model.toggleInputMuted()
                } label: {
                    Label(model.isInputMuted ? "Mic Muted" : "Mic", systemImage: model.isInputMuted ? "mic.slash" : "mic")
                }
                .buttonStyle(TS3BorderedButtonStyle())
                .ts3KeyboardShortcut("toggle-input-muted", in: model)
                Button {
                    model.toggleOutputMuted()
                } label: {
                    Label(model.isOutputMuted ? "Sound Muted" : "Sound", systemImage: model.isOutputMuted ? "speaker.slash" : "speaker.wave.2")
                }
                .buttonStyle(TS3BorderedButtonStyle())
                .ts3KeyboardShortcut("toggle-output-muted", in: model)
                Button {
                    model.isShowingSelfStatus = true
                } label: {
                    Label(
                        model.isAway ? NSLocalizedString("selfStatus.awayShort", comment: "") : NSLocalizedString("selfStatus.selfShort", comment: ""),
                        systemImage: model.isAway ? "moon.zzz" : "person.crop.circle"
                    )
                }
                .buttonStyle(TS3BorderedButtonStyle())
                Button {
                    model.isShowingAudioSettings = true
                } label: {
                    Label(model.playbackVolumePercentText, systemImage: "slider.horizontal.3")
                }
                .buttonStyle(TS3BorderedButtonStyle())
            }
            if let error = model.lastError {
                Text(error)
                    .frame(maxWidth: .infinity, alignment: .leading)
                    .font(.footnote)
                    .foregroundColor(.red)
            }
            Button(action: {
                model.toggleTalking()
            }) {
                Text(model.transmitButtonTitle)
                    .frame(maxWidth: .infinity)
            }
            .buttonStyle(TS3BorderedButtonStyle(isProminent: true))
            .ts3KeyboardShortcut("toggle-talk", in: model)
            if model.whisperActivationMode == .tapToToggle {
                Button(action: {
                    model.toggleCurrentWhisperActivation()
                }) {
                    Text(model.isWhisperActivationActive ? LocalizedStringKey("whisper.stopTemporary") : LocalizedStringKey("whisper.startTemporary"))
                        .frame(maxWidth: .infinity)
                }
                .buttonStyle(TS3BorderedButtonStyle(isProminent: model.isWhisperActivationActive))
                .ts3KeyboardShortcut("toggle-whisper-activation", in: model)
                .disabled(model.state != .connected || model.whisperRoute == .none)
            } else {
                WhisperHoldButton()
                    .environmentObject(model)
                    .disabled(model.state != .connected || model.whisperRoute == .none)
            }
            HStack(spacing: 12) {
                Button("whisper.start") {
                    model.beginCurrentWhisperActivation()
                }
                .buttonStyle(TS3BorderedButtonStyle())
                .frame(maxWidth: .infinity)
                .ts3KeyboardShortcut("start-whisper-activation", in: model)
                .disabled(model.state != .connected || model.whisperRoute == .none || model.isWhisperActivationActive)
                Button("whisper.stop") {
                    model.endWhisperActivation()
                }
                .buttonStyle(TS3BorderedButtonStyle())
                .frame(maxWidth: .infinity)
                .ts3KeyboardShortcut("stop-whisper-activation", in: model)
                .disabled(!model.isWhisperActivationActive)
            }
        }
        .padding()
        .alert(item: $model.microphonePermissionPrompt) { prompt in
            Alert(
                title: Text(prompt.title),
                message: Text(prompt.message),
                primaryButton: .default(Text(prompt.confirmTitle)) {
                    model.confirmMicrophonePermissionPrompt(prompt)
                },
                secondaryButton: .cancel {
                    model.dismissMicrophonePermissionPrompt()
                }
            )
        }
    }
}

struct WhisperHoldButton: View {
    @EnvironmentObject private var model: TS3AppModel
    @Environment(\.isEnabled) private var isEnabled
    @State private var isPressing = false

    var body: some View {
        Text(isPressing || model.isWhisperActivationActive ? LocalizedStringKey("whisper.releaseToStop") : LocalizedStringKey("whisper.holdToWhisper"))
            .frame(maxWidth: .infinity)
            .padding(.vertical, 8)
            .contentShape(Rectangle())
            .background(isPressing || model.isWhisperActivationActive ? Color.accentColor.opacity(0.15) : Color.clear)
            .cornerRadius(8)
            .overlay(
                RoundedRectangle(cornerRadius: 8)
                    .stroke(Color.accentColor.opacity(isEnabled ? 0.8 : 0.25), lineWidth: 1)
            )
            .foregroundColor(isEnabled ? .primary : .secondary)
            .gesture(
                DragGesture(minimumDistance: 0)
                    .onChanged { _ in
                        guard isEnabled, !isPressing else { return }
                        isPressing = true
                        model.beginCurrentWhisperActivation()
                    }
                    .onEnded { _ in
                        guard isPressing else { return }
                        isPressing = false
                        model.endWhisperActivation()
                    }
            )
            .onDisappear {
                if isPressing {
                    isPressing = false
                    model.endWhisperActivation()
                }
            }
            .accessibilityAddTraits(.isButton)
            .accessibilityLabel(Text("whisper.holdToWhisper"))
            .accessibilityValue(model.whisperActivationStatus)
    }
}

struct SelfStatusSheet: View {
    private enum SelfStatusConfirmation: Identifiable {
        case importBackup(URL, applyToServer: Bool)
        case deleteAllProfiles
        case resetPresence

        var id: String {
            switch self {
            case .importBackup(_, let applyToServer): return applyToServer ? "importAndApply" : "importBackup"
            case .deleteAllProfiles: return "deleteAllProfiles"
            case .resetPresence: return "resetPresence"
            }
        }
    }

    private struct SelfStatusProfileImportConfirmation: Identifiable {
        let data: Data
        let preview: TS3SelfStatusProfileImportPreview
        let id = UUID()
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var nickname = ""
    @State private var descriptionText = ""
    @State private var isAway = false
    @State private var awayMessage = ""
    @State private var isInputMuted = false
    @State private var isOutputMuted = false
    @State private var isChannelCommander = false
    @State private var talkRequestMessage = ""
    @State private var selfIconId = ""
    @State private var statusProfileName = ""
    @State private var isShowingIconImporter = false
    @State private var isShowingAvatarImporter = false
    @State private var isConfirmingClearIcon = false
    @State private var isConfirmingClearAvatar = false
    @State private var isExportingStatus = false
    @State private var isExportingStatusBackup = false
    @State private var isImportingStatus = false
    @State private var isImportingAppliedStatus = false
    @State private var isImportingStatusProfiles = false
    @State private var confirmation: SelfStatusConfirmation?
    @State private var pendingProfileImport: SelfStatusProfileImportConfirmation?
    @State private var statusDocument = TS3TextFileDocument()
    @State private var statusBackupDocument = TS3TextFileDocument()

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    private func yesNo(_ value: Bool) -> String {
        localized(value ? "common.yes" : "common.no")
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("selfStatus.snapshot"))) {
                    Button(localized("selfStatus.copySnapshot")) {
                        TS3PlatformSupport.copyToPasteboard(statusSnapshot)
                    }
                    Button(localized("selfStatus.exportSnapshot")) {
                        statusDocument = TS3TextFileDocument(data: Data(statusSnapshot.utf8))
                        isExportingStatus = true
                    }
                    Button(localized("selfStatus.exportStatusBackup")) {
                        exportStatusBackup()
                    }
                    Button(localized("selfStatus.importStatusBackup")) {
                        isImportingStatus = true
                    }
                    Button(localized("selfStatus.importAndApplyStatus")) {
                        isImportingAppliedStatus = true
                    }
                    Button(localized("selfStatus.exportProfileBackup")) {
                        exportStatusProfiles()
                    }
                    .disabled(model.selfStatusProfiles.isEmpty)
                    Button(localized("selfStatus.importProfileBackup")) {
                        isImportingStatusProfiles = true
                    }
                    if let currentUser {
                        Menu(localized("selfStatus.copyIdentifiers")) {
                            Button(localized("selfStatus.copyClientId")) {
                                TS3PlatformSupport.copyToPasteboard("\(currentUser.id)")
                            }
                            if let databaseId = currentUser.databaseId {
                                Button(localized("selfStatus.copyDatabaseId")) {
                                    TS3PlatformSupport.copyToPasteboard("\(databaseId)")
                                }
                            }
                            if let uniqueIdentifier = currentUser.uniqueIdentifier, !uniqueIdentifier.isEmpty {
                                Button(localized("selfStatus.copyUniqueId")) {
                                    TS3PlatformSupport.copyToPasteboard(uniqueIdentifier)
                                }
                            }
                            if let avatarHash = currentUser.avatarHash, !avatarHash.isEmpty {
                                Button(localized("selfStatus.copyAvatarHash")) {
                                    TS3PlatformSupport.copyToPasteboard(avatarHash)
                                }
                            }
                        }
                    }
                }

                Section(header: Text(localized("selfStatus.profiles"))) {
                    TextField(localized("selfStatus.profileName"), text: $statusProfileName)
                        .ts3PlainTextField()
                    Button(localized("selfStatus.saveCurrentProfile")) {
                        model.saveCurrentSelfStatusProfile(name: statusProfileName)
                        statusProfileName = ""
                    }
                    .disabled(statusProfileName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                    Button(localized("selfStatus.deleteAllProfiles")) {
                        confirmation = .deleteAllProfiles
                    }
                    .disabled(model.selfStatusProfiles.isEmpty)

                    if model.selfStatusProfiles.isEmpty {
                        Text(localized("selfStatus.noSavedProfiles"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(model.selfStatusProfiles) { profile in
                            HStack {
                                VStack(alignment: .leading, spacing: 2) {
                                    Text(profile.name)
                                        .font(.subheadline.weight(.semibold))
                                    Text(profile.displaySummary)
                                        .font(.caption)
                                        .foregroundColor(.secondary)
                                }
                                Spacer()
                                Menu {
                                    Button(localized("selfStatus.applyProfile")) {
                                        model.applySelfStatusProfile(profile)
                                        refreshDraft()
                                    }
                                    Button(localized("selfStatus.renameFromProfile")) {
                                        statusProfileName = profile.name
                                    }
                                    Button(localized("common.copySummary")) {
                                        TS3PlatformSupport.copyToPasteboard(profile.clipboardSummary)
                                    }
                                    Button(localized("selfStatus.deleteProfile")) {
                                        model.deleteSelfStatusProfile(profile)
                                    }
                                } label: {
                                    Image(systemName: "ellipsis.circle")
                                }
                            }
                            .accessibilityElement(children: .ignore)
                            .accessibilityLabel(profile.name)
                            .accessibilityValue(profile.accessibilityValue)
                            .accessibilityAction(named: localized("selfStatus.applyProfile")) {
                                model.applySelfStatusProfile(profile)
                                refreshDraft()
                            }
                            .accessibilityAction(named: localized("common.copySummary")) {
                                TS3PlatformSupport.copyToPasteboard(profile.clipboardSummary)
                            }
                            .contextMenu {
                                Button(localized("selfStatus.applyProfile")) {
                                    model.applySelfStatusProfile(profile)
                                    refreshDraft()
                                }
                                Button(localized("selfStatus.renameFromProfile")) {
                                    statusProfileName = profile.name
                                }
                                Button(localized("common.copySummary")) {
                                    TS3PlatformSupport.copyToPasteboard(profile.clipboardSummary)
                                }
                                Button(localized("selfStatus.deleteProfile")) {
                                    model.deleteSelfStatusProfile(profile)
                                }
                            }
                        }
                    }
                }

                Section(header: Text(localized("selfStatus.profile"))) {
                    TextField(localized("selfStatus.nickname"), text: $nickname)
                        .ts3PlainTextField()
                    Button(localized("selfStatus.updateNickname")) {
                        model.updateNickname(to: nickname)
                    }
                    .disabled(nickname.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                    TextEditor(text: $descriptionText)
                        .frame(minHeight: 88)
                    Button(localized("selfStatus.updateDescription")) {
                        if let currentUser {
                            model.editUserDescription(currentUser, description: descriptionText)
                        }
                    }
                    .disabled(currentUser == nil)
                    Button(localized("selfStatus.refreshSelfDetails")) {
                        if let currentUser {
                            model.refreshUserDetails(currentUser)
                        }
                    }
                    .disabled(currentUser == nil)
                    Button(localized("selfStatus.downloadAvatar")) {
                        if let currentUser {
                            model.refreshUserAvatar(currentUser)
                        }
                    }
                    .disabled(currentUser == nil)
                }

                Section(header: Text(localized("selfStatus.status"))) {
                    Toggle(localized("selfStatus.away"), isOn: $isAway)
                    if isAway {
                        TextField(localized("selfStatus.awayMessage"), text: $awayMessage)
                            .ts3PlainTextField()
                    }
                    Button(isAway ? localized("selfStatus.setAway") : localized("selfStatus.clearAway")) {
                        model.setAway(isAway, message: awayMessage)
                    }
                }

                Section(header: Text(localized("selfStatus.mute"))) {
                    Toggle(localized("selfStatus.microphoneMuted"), isOn: inputMutedBinding)
                    Toggle(localized("selfStatus.outputMuted"), isOn: outputMutedBinding)
                }

                Section(header: Text(localized("selfStatus.role"))) {
                    Toggle(localized("selfStatus.channelCommander"), isOn: channelCommanderBinding)
                    TextField(localized("selfStatus.iconId"), text: $selfIconId)
                        .ts3NumericKeyboard()
                    Button(localized("selfStatus.setClientIcon")) {
                        model.setSelfIcon(iconId: Int(selfIconId.trimmingCharacters(in: .whitespacesAndNewlines)))
                    }
                    .disabled(!selfIconId.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty && Int(selfIconId.trimmingCharacters(in: .whitespacesAndNewlines)) == nil)
                    Button(localized("selfStatus.clearClientIcon")) {
                        isConfirmingClearIcon = true
                    }
                    .disabled((currentUser?.iconId ?? 0) == 0)
                    Button {
                        isShowingIconImporter = true
                    } label: {
                        Label(localized("selfStatus.uploadClientIcon"), systemImage: "photo")
                    }
                    Button {
                        isShowingAvatarImporter = true
                    } label: {
                        Label(localized("selfStatus.uploadAvatar"), systemImage: "person.crop.square")
                    }
                    Button(localized("selfStatus.clearAvatar")) {
                        isConfirmingClearAvatar = true
                    }
                    .disabled(currentUser?.avatarHash?.isEmpty ?? true)
                }

                Section(header: Text(localized("selfStatus.voiceStatus"))) {
                    if let currentUser {
                        Button(currentUser.isPrioritySpeaker ? localized("selfStatus.removePrioritySpeaker") : localized("selfStatus.grantPrioritySpeaker")) {
                            model.setPrioritySpeaker(!currentUser.isPrioritySpeaker, for: currentUser)
                        }
                        Button(currentUser.isTalker ? localized("selfStatus.removeTalker") : localized("selfStatus.markAsTalker")) {
                            model.setTalker(!currentUser.isTalker, for: currentUser)
                        }
                    } else {
                        Text(localized("selfStatus.currentClientUnavailable"))
                            .foregroundColor(.secondary)
                    }
                }

                Section {
                    Button(localized("selfStatus.resetPresenceState")) {
                        confirmation = .resetPresence
                    }
                }

                Section(header: Text(localized("selfStatus.talkPower"))) {
                    TextField(localized("selfStatus.requestMessage"), text: $talkRequestMessage)
                        .ts3PlainTextField()
                        .disabled(model.isRequestingTalkPower)
                    if model.isRequestingTalkPower {
                        Button(localized("selfStatus.cancelTalkRequest")) {
                            model.setTalkRequest(false, message: "")
                        }
                    } else {
                        Button(localized("selfStatus.requestTalkPower")) {
                            model.setTalkRequest(true, message: talkRequestMessage)
                        }
                        .disabled(talkRequestMessage.count > 50)
                    }
                }
            }
            .navigationTitle(localized("selfStatus.title"))
            .ts3InlineNavigationTitle()
            .onAppear {
                refreshDraft()
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("common.done")) {
                        presentationMode.wrappedValue.dismiss()
                    }
                }
            }
            .fileImporter(
                isPresented: $isShowingIconImporter,
                allowedContentTypes: [.image, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    model.uploadSelfIcon(from: url) { uploadedIconId in
                        selfIconId = String(uploadedIconId)
                    }
                }
            }
            .alert(isPresented: $isConfirmingClearIcon) {
                Alert(
                    title: Text(localized("selfStatus.clearClientIcon")),
                    message: Text(localized("selfStatus.clearClientIconAlert.message")),
                    primaryButton: .destructive(Text(localized("selfStatus.clear"))) {
                        model.clearSelfIcon()
                        selfIconId = ""
                    },
                    secondaryButton: .cancel()
                )
            }
            .fileImporter(
                isPresented: $isShowingAvatarImporter,
                allowedContentTypes: [.image, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    model.uploadSelfAvatar(from: url)
                }
            }
            .alert(isPresented: $isConfirmingClearAvatar) {
                Alert(
                    title: Text(localized("selfStatus.clearAvatar")),
                    message: Text(localized("selfStatus.clearAvatarAlert.message")),
                    primaryButton: .destructive(Text(localized("selfStatus.clear"))) {
                        model.clearSelfAvatar()
                    },
                    secondaryButton: .cancel()
                )
            }
            .fileExporter(
                isPresented: $isExportingStatus,
                document: statusDocument,
                contentType: .plainText,
                defaultFilename: "ts3-self-status"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileExporter(
                isPresented: $isExportingStatusBackup,
                document: statusBackupDocument,
                contentType: .json,
                defaultFilename: "ts3-self-status-backup"
            ) { result in
                if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingStatus,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    confirmation = .importBackup(url, applyToServer: false)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingAppliedStatus,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    confirmation = .importBackup(url, applyToServer: true)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .fileImporter(
                isPresented: $isImportingStatusProfiles,
                allowedContentTypes: [.json, .data],
                allowsMultipleSelection: false
            ) { result in
                if case .success(let urls) = result, let url = urls.first {
                    prepareStatusProfilesImport(from: url)
                } else if case .failure(let error) = result {
                    model.lastError = error.localizedDescription
                }
            }
            .alert(item: $confirmation) { confirmation in
                switch confirmation {
                case .importBackup(let url, let applyToServer):
                    return Alert(
                        title: Text(applyToServer ? localized("selfStatus.importAndApplyAlert.title") : localized("selfStatus.importBackupAlert.title")),
                        message: Text(applyToServer ? localized("selfStatus.importAndApplyAlert.message") : localized("selfStatus.importBackupAlert.message")),
                        primaryButton: .destructive(Text(localized("selfStatus.import"))) {
                            importStatusBackup(from: url, applyToServer: applyToServer)
                        },
                        secondaryButton: .cancel()
                    )
                case .deleteAllProfiles:
                    return Alert(
                        title: Text(localized("selfStatus.deleteAllProfilesAlert.title")),
                        message: Text(localized("selfStatus.deleteAllProfilesAlert.messageFormat", model.selfStatusProfiles.count)),
                        primaryButton: .destructive(Text(localized("common.delete"))) {
                            model.deleteSelfStatusProfiles(model.selfStatusProfiles)
                        },
                        secondaryButton: .cancel()
                    )
                case .resetPresence:
                    return Alert(
                        title: Text(localized("selfStatus.resetPresenceAlert.title")),
                        message: Text(localized("selfStatus.resetPresenceAlert.message")),
                        primaryButton: .destructive(Text(localized("selfStatus.reset"))) {
                            resetPresenceState()
                        },
                        secondaryButton: .cancel()
                    )
                }
            }
            .sheet(
                item: $pendingProfileImport,
                onDismiss: {
                    pendingProfileImport = nil
                }
            ) { confirmation in
                SelfStatusProfileImportSheet(
                    preview: confirmation.preview,
                    importProfiles: { selectedProfileIds in
                        importStatusProfiles(
                            from: confirmation.data,
                            selectedProfileIds: selectedProfileIds
                        )
                        pendingProfileImport = nil
                    },
                    cancel: {
                        pendingProfileImport = nil
                    }
                )
            }
        }
    }

    private var statusSnapshot: String {
        var rows = [
            localized("selfStatus.snapshot.nicknameFormat", model.nickname),
            localized("selfStatus.snapshot.awayFormat", yesNo(model.isAway)),
            localized("selfStatus.snapshot.microphoneMutedFormat", yesNo(model.isInputMuted)),
            localized("selfStatus.snapshot.outputMutedFormat", yesNo(model.isOutputMuted)),
            localized("selfStatus.snapshot.channelCommanderFormat", yesNo(model.isChannelCommander)),
            localized("selfStatus.snapshot.requestingTalkPowerFormat", yesNo(model.isRequestingTalkPower))
        ]
        if !model.awayMessage.isEmpty {
            rows.append(localized("selfStatus.snapshot.awayMessageFormat", model.awayMessage))
        }
        if !model.talkRequestMessage.isEmpty {
            rows.append(localized("selfStatus.snapshot.talkRequestMessageFormat", model.talkRequestMessage))
        }
        rows.append(localized("selfStatus.snapshot.savedProfilesFormat", model.selfStatusProfiles.count))
        if let selfUser = model.clients.first(where: { $0.isCurrentUser }) {
            rows.append(localized("selfStatus.snapshot.clientIdFormat", selfUser.id))
            if let databaseId = selfUser.databaseId {
                rows.append(localized("selfStatus.snapshot.databaseIdFormat", databaseId))
            }
            if let uniqueIdentifier = selfUser.uniqueIdentifier, !uniqueIdentifier.isEmpty {
                rows.append(localized("selfStatus.snapshot.uniqueIdFormat", uniqueIdentifier))
            }
            if let channel = model.channelName(for: selfUser.channelId) {
                rows.append(localized("selfStatus.snapshot.channelFormat", channel))
            }
            if let iconId = selfUser.iconId {
                rows.append(localized("selfStatus.snapshot.iconIdFormat", iconId))
            }
            if let avatarHash = selfUser.avatarHash, !avatarHash.isEmpty {
                rows.append(localized("selfStatus.snapshot.avatarHashFormat", avatarHash))
            }
            if let avatarURL = selfUser.avatarURL {
                rows.append(localized("selfStatus.snapshot.avatarPathFormat", avatarURL.path))
            }
            rows.append(localized("selfStatus.snapshot.prioritySpeakerFormat", yesNo(selfUser.isPrioritySpeaker)))
            rows.append(localized("selfStatus.snapshot.talkerFormat", yesNo(selfUser.isTalker)))
        }
        if !model.identitySummary.uid.isEmpty {
            rows.append(localized("selfStatus.snapshot.identityUidFormat", model.identitySummary.uid))
            rows.append(localized("selfStatus.snapshot.identitySecurityLevelFormat", model.identitySummary.securityLevel))
        }
        if let currentUserDescription = currentUser?.description, !currentUserDescription.isEmpty {
            rows.append(localized("selfStatus.snapshot.descriptionFormat", currentUserDescription))
        }
        return rows.joined(separator: "\n")
    }

    private func refreshDraft() {
        nickname = model.nickname
        descriptionText = currentUser?.description ?? ""
        isAway = model.isAway
        awayMessage = model.awayMessage
        isInputMuted = model.isInputMuted
        isOutputMuted = model.isOutputMuted
        isChannelCommander = model.isChannelCommander
        talkRequestMessage = model.talkRequestMessage
        selfIconId = model.clients.first(where: { $0.isCurrentUser })?.iconId.map(String.init) ?? ""
    }

    private func exportStatusBackup() {
        do {
            statusBackupDocument = TS3TextFileDocument(data: try model.selfStatusBackupData())
            isExportingStatusBackup = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func exportStatusProfiles() {
        do {
            statusBackupDocument = TS3TextFileDocument(data: try model.selfStatusProfilesExportData())
            isExportingStatusBackup = true
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importStatusBackup(from url: URL, applyToServer: Bool) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            if applyToServer {
                try model.importAndApplySelfStatusBackup(from: data)
            } else {
                try model.importSelfStatusBackup(from: data)
            }
            refreshDraft()
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func prepareStatusProfilesImport(from url: URL) {
        let canAccess = url.startAccessingSecurityScopedResource()
        defer {
            if canAccess {
                url.stopAccessingSecurityScopedResource()
            }
        }
        do {
            let data = try Data(contentsOf: url)
            let preview = try model.selfStatusProfilesImportPreview(from: data)
            pendingProfileImport = SelfStatusProfileImportConfirmation(data: data, preview: preview)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func importStatusProfiles(from data: Data, selectedProfileIds: Set<UUID>) {
        do {
            try model.importSelfStatusProfiles(from: data, selectedProfileIds: selectedProfileIds)
        } catch {
            model.lastError = error.localizedDescription
        }
    }

    private func resetPresenceState() {
        model.setAway(false, message: "")
        model.setTalkRequest(false, message: "")
        model.setChannelCommander(false)
        if let currentUser {
            model.setPrioritySpeaker(false, for: currentUser)
            model.setTalker(false, for: currentUser)
        }
        refreshDraft()
    }

    private var currentUser: TS3UserSummary? {
        model.clients.first(where: { $0.isCurrentUser })
    }

    private var inputMutedBinding: Binding<Bool> {
        Binding(
            get: { isInputMuted },
            set: { value in
                isInputMuted = value
                model.setInputMuted(value)
            }
        )
    }

    private var outputMutedBinding: Binding<Bool> {
        Binding(
            get: { isOutputMuted },
            set: { value in
                isOutputMuted = value
                model.setOutputMuted(value)
            }
        )
    }

    private var channelCommanderBinding: Binding<Bool> {
        Binding(
            get: { isChannelCommander },
            set: { value in
                isChannelCommander = value
                model.setChannelCommander(value)
            }
        )
    }
}

private struct SelfStatusProfileImportSheet: View {
    @Environment(\.presentationMode) private var presentationMode

    let preview: TS3SelfStatusProfileImportPreview
    let importProfiles: (Set<UUID>) -> Void
    let cancel: () -> Void
    @State private var selectedProfileIds: Set<UUID>

    init(
        preview: TS3SelfStatusProfileImportPreview,
        importProfiles: @escaping (Set<UUID>) -> Void,
        cancel: @escaping () -> Void
    ) {
        self.preview = preview
        self.importProfiles = importProfiles
        self.cancel = cancel
        _selectedProfileIds = State(initialValue: Set(preview.candidates.map(\.id)))
    }

    private var canImport: Bool {
        preview.candidates.contains { selectedProfileIds.contains($0.id) }
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("selfStatus.import.preview"))) {
                    Text(localized("selfStatus.import.importedProfilesFormat", preview.importedProfileCount))
                    Text(localized("selfStatus.import.usableProfilesFormat", preview.usableProfileCount))
                    Text(localized("selfStatus.import.newProfilesFormat", preview.newProfileCount))
                    Text(localized("selfStatus.import.replacingProfilesFormat", preview.replacedProfileCount))
                    Text(localized("selfStatus.import.skippedProfilesFormat", preview.skippedProfileCount))
                    Button(localized("selfStatus.import.copyPreview")) {
                        TS3PlatformSupport.copyToPasteboard(preview.clipboardSummary)
                    }
                }

                Section(header: Text(localized("selfStatus.import.restore"))) {
                    HStack {
                        Button(localized("selfStatus.import.selectAll")) {
                            selectedProfileIds = Set(preview.candidates.map(\.id))
                        }
                        Spacer()
                        Button(localized("selfStatus.import.clear")) {
                            selectedProfileIds.removeAll()
                        }
                    }
                    ForEach(preview.candidates) { candidate in
                        Toggle(
                            candidate.summary,
                            isOn: Binding(
                                get: { selectedProfileIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedProfileIds.insert(candidate.id)
                                    } else {
                                        selectedProfileIds.remove(candidate.id)
                                    }
                                }
                            )
                        )
                    }
                }

                Section {
                    Text(localized("selfStatus.import.behavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("selfStatus.import.title"))
            .ts3InlineNavigationTitle()
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(localized("common.cancel")) {
                        cancel()
                        presentationMode.wrappedValue.dismiss()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("selfStatus.import.action")) {
                        importProfiles(selectedProfileIds)
                        presentationMode.wrappedValue.dismiss()
                    }
                    .disabled(!canImport)
                }
            }
        }
    }
}

struct AudioSettingsSheet: View {
    private struct AudioSettingsImportConfirmation: Identifiable {
        let id = UUID()
        let data: Data
        let preview: TS3AudioSettingsImportPreview
    }

    private struct AudioProfileImportConfirmation: Identifiable {
        let id = UUID()
        let data: Data
        let preview: TS3AudioProfileImportPreview
    }

    private struct UserPlaybackImportConfirmation: Identifiable {
        let id = UUID()
        let data: Data
        let preview: TS3UserPlaybackImportPreview
    }

    @Environment(\.presentationMode) private var presentationMode
    @EnvironmentObject private var model: TS3AppModel
    @State private var audioProfileName = ""
    @State private var isExportingAudioSettings = false
    @State private var isImportingAudioSettings = false
    @State private var isImportingAudioProfiles = false
    @State private var isImportingUserPlayback = false
    @State private var isConfirmingDeleteProfiles = false
    @State private var isConfirmingResetAudioSettings = false
    @State private var isConfirmingResetUserPlayback = false
    @State private var pendingAudioSettingsImport: AudioSettingsImportConfirmation?
    @State private var pendingAudioProfileImport: AudioProfileImportConfirmation?
    @State private var pendingUserPlaybackImport: UserPlaybackImportConfirmation?
    @State private var audioSettingsDocument = TS3TextFileDocument()

    private var volumeBinding: Binding<Double> {
        Binding(
            get: { model.playbackVolume },
            set: { model.updatePlaybackVolume($0) }
        )
    }

    private var inputGainBinding: Binding<Double> {
        Binding(
            get: { model.inputGain },
            set: { model.updateInputGain($0) }
        )
    }

    private var thresholdBinding: Binding<Double> {
        Binding(
            get: { model.voiceActivationThreshold },
            set: { model.updateVoiceActivationThreshold($0) }
        )
    }

    private var prefersSpeakerBinding: Binding<Bool> {
        Binding(
            get: { model.prefersSpeakerOutput },
            set: { model.updatePrefersSpeakerOutput($0) }
        )
    }

    private var selectedInputDeviceBinding: Binding<String> {
        Binding(
            get: { model.audioInputDevices.first(where: { $0.isSelected })?.id ?? "" },
            set: { model.selectAudioInputDevice(id: $0.isEmpty ? nil : $0) }
        )
    }

    private var transmitModeBinding: Binding<TS3AudioTransmitMode> {
        Binding(
            get: { model.audioTransmitMode },
            set: { model.updateAudioTransmitMode($0) }
        )
    }

    private func localized(_ key: String, _ arguments: CVarArg...) -> String {
        let format = NSLocalizedString(key, comment: "")
        return arguments.isEmpty ? format : String(format: format, arguments: arguments)
    }

    var body: some View {
        NavigationView {
            Form {
                Section(header: Text(localized("audio.snapshot"))) {
                    Button(localized("audio.copySnapshot")) {
                        TS3PlatformSupport.copyToPasteboard(audioSettingsSnapshot)
                    }
                    Button(localized("audio.exportSnapshot")) {
                        audioSettingsDocument = TS3TextFileDocument(data: Data(audioSettingsSnapshot.utf8))
                        isExportingAudioSettings = true
                    }
                    Button(localized("audio.exportSettings")) {
                        exportAudioSettings()
                    }
                    Button(localized("audio.importSettings")) {
                        isImportingAudioSettings = true
                    }
                }

                Section(header: Text(localized("audio.profiles"))) {
                    TextField(localized("audio.profileName"), text: $audioProfileName)
                        .ts3PlainTextField()
                    Button(localized("audio.saveCurrentProfile")) {
                        model.saveCurrentAudioProfile(name: audioProfileName)
                        audioProfileName = ""
                    }
                    .disabled(audioProfileName.trimmingCharacters(in: .whitespacesAndNewlines).isEmpty)
                    Button(localized("audio.exportProfileBackup")) {
                        exportAudioProfiles()
                    }
                    .disabled(model.audioProfiles.isEmpty)
                    Button(localized("audio.importProfileBackup")) {
                        isImportingAudioProfiles = true
                    }
                    Button(localized("audio.deleteAllProfiles")) {
                        isConfirmingDeleteProfiles = true
                    }
                    .disabled(model.audioProfiles.isEmpty)

                    if model.audioProfiles.isEmpty {
                        Text(localized("audio.noSavedProfiles"))
                            .foregroundColor(.secondary)
                    } else {
                        ForEach(model.audioProfiles) { profile in
                            HStack {
                                VStack(alignment: .leading, spacing: 2) {
                                    Text(profile.name)
                                        .font(.subheadline.weight(.semibold))
                                    Text(profile.displaySummary)
                                        .font(.caption)
                                        .foregroundColor(.secondary)
                                }
                                Spacer()
                                Menu {
                                    Button(localized("audio.applyProfile")) {
                                        model.applyAudioProfile(profile)
                                    }
                                    Button(localized("audio.renameFromProfile")) {
                                        audioProfileName = profile.name
                                    }
                                    Button(localized("common.copySummary")) {
                                        TS3PlatformSupport.copyToPasteboard(profile.clipboardSummary)
                                    }
                                    Button(localized("audio.deleteProfile")) {
                                        model.deleteAudioProfile(profile)
                                    }
                                } label: {
                                    Image(systemName: "ellipsis.circle")
                                }
                            }
                            .accessibilityElement(children: .ignore)
                            .accessibilityLabel(profile.name)
                            .accessibilityValue(profile.accessibilityValue)
                            .accessibilityAction(named: localized("audio.applyProfile")) {
                                model.applyAudioProfile(profile)
                            }
                            .accessibilityAction(named: localized("common.copySummary")) {
                                TS3PlatformSupport.copyToPasteboard(profile.clipboardSummary)
                            }
                            .contextMenu {
                                Button(localized("audio.applyProfile")) {
                                    model.applyAudioProfile(profile)
                                }
                                Button(localized("audio.renameFromProfile")) {
                                    audioProfileName = profile.name
                                }
                                Button(localized("common.copySummary")) {
                                    TS3PlatformSupport.copyToPasteboard(profile.clipboardSummary)
                                }
                                Button(localized("audio.deleteProfile")) {
                                    model.deleteAudioProfile(profile)
                                }
                            }
                        }
                    }
                }

                Section(header: Text(localized("audio.device"))) {
                    audioRouteRow(title: localized("audio.inputRoute"), value: model.audioInputRoute)
                    audioRouteRow(title: localized("audio.outputRoute"), value: model.audioOutputRoute)
                    if !model.audioRouteAvailabilityNotes.isEmpty {
                        ForEach(model.audioRouteAvailabilityNotes, id: \.self) { note in
                            Text(note)
                                .font(.caption)
                                .foregroundColor(.secondary)
                        }
                    }
                    Toggle(localized("audio.defaultToSpeaker"), isOn: prefersSpeakerBinding)
                    Picker(localized("audio.inputDevice"), selection: selectedInputDeviceBinding) {
                        Text(localized("audio.systemDefault")).tag("")
