                        .buttonStyle(.borderless)
                        Button(localized("audio.voicePreset")) {
                            model.applyAudioPreset(mode: .voiceActivation, inputGain: 1, threshold: 0.03)
                        }
                        .buttonStyle(.borderless)
                        Button(localized("audio.continuousPreset")) {
