                        VStack(alignment: .leading, spacing: 12) {
                            HStack {
                                Text(localized("audio.activationThreshold"))
                                Spacer()
                                Text(model.voiceActivationThresholdText)
                                    .foregroundColor(.secondary)
                            }
                            Slider(value: thresholdBinding, in: 0.001...0.5, step: 0.001)
