                            )
                        )
                        Text(userPlaybackImportImpactText(importImpactSummary))
                            .font(.caption2)
                            .foregroundColor(importImpactSummary.needsAttention ? .orange : .secondary)
                        Button(localized("audio.import.copyPlaybackImpact")) {
                            TS3PlatformSupport.copyToPasteboard(importImpactSummary.clipboardSummary)
                        }
                        .disabled(!importImpactSummary.hasSelection)
                    }
                }

                if !preview.adjustmentSummaries.isEmpty {
                    Section(header: Text(localized("audio.import.adjustedPreferences"))) {
                        ForEach(Array(preview.adjustmentSummaries.enumerated()), id: \.offset) { _, summary in
                            Text(summary)
                                .font(.caption2)
                                .foregroundColor(.orange)
                                .lineLimit(2)
                                .truncationMode(.middle)
                        }
                    }
                }

                if !preview.preferenceSummaries.isEmpty {
                    Section(header: Text(localized("audio.import.preferences"))) {
                        ForEach(preview.candidates) { candidate in
                            Toggle(isOn: Binding(
                                get: { selectedPreferenceIds.contains(candidate.id) },
                                set: { isSelected in
                                    if isSelected {
                                        selectedPreferenceIds.insert(candidate.id)
                                    } else {
                                        selectedPreferenceIds.remove(candidate.id)
                                    }
                                }
                            )) {
                                Text(candidate.summary)
                                    .font(.caption2)
                                    .lineLimit(2)
                                    .truncationMode(.middle)
                            }
                        }
                    }
                }

                Section(header: Text(localized("audio.import.behaviorTitle"))) {
                    Text(localized("audio.import.playbackBehavior"))
                        .font(.caption)
                        .foregroundColor(.secondary)
                }
            }
            .navigationTitle(localized("audio.import.playbackTitle"))
            .ts3InlineNavigationTitle()
            .onAppear {
                if selectedPreferenceIds.isEmpty {
                    selectedPreferenceIds = Set(preview.candidates.map(\.id))
                }
            }
            .toolbar {
                ToolbarItem(placement: TS3PlatformSupport.toolbarLeadingPlacement) {
                    Button(NSLocalizedString("common.cancel", comment: "")) {
                        cancel()
                    }
                }
                ToolbarItem(placement: TS3PlatformSupport.toolbarTrailingPlacement) {
                    Button(localized("audio.import.action")) {
                        importPreferences(validSelectedPreferenceIds)
                    }
                    .disabled(!preview.hasPreferences || validSelectedPreferenceIds.isEmpty)
                }
            }
        }
    }

    private func userPlaybackImportImpactText(_ summary: TS3UserPlaybackImportImpactSummary) -> String {
        [
            localized("audio.import.playbackImpactMutedFormat", summary.mutedPreferenceCount),
            localized("audio.import.playbackImpactVolumeFormat", summary.boostedPreferenceCount, summary.loweredPreferenceCount),
            localized("audio.import.playbackImpactAdjustedFormat", summary.adjustedPreferenceCount, summary.skippedPreferenceCount)
        ].joined(separator: " | ")
    }
}

struct TS3BorderedButtonStyle: ButtonStyle {
    var isProminent = false

    func makeBody(configuration: Configuration) -> some View {
        let accent = Color.accentColor
        let fill = isProminent ? accent : .clear
        let text = isProminent ? Color.white : accent
        return configuration.label
            .padding(.vertical, 8)
            .padding(.horizontal, 12)
            .frame(minHeight: 36)
            .background(fill.opacity(configuration.isPressed ? 0.7 : 1.0))
            .foregroundColor(text)
            .overlay(
                RoundedRectangle(cornerRadius: 8)
                    .stroke(accent, lineWidth: isProminent ? 0 : 1)
            )
            .cornerRadius(8)
            .opacity(configuration.isPressed ? 0.85 : 1.0)
    }
}

enum TS3PlatformSupport {
    static var defaultNickname: String {
        #if targetEnvironment(macCatalyst)
        return "Mac"
        #elseif os(macOS)
        return Host.current().localizedName ?? "Mac"
        #else
        return "iOS"
        #endif
    }

    static var toolbarLeadingPlacement: ToolbarItemPlacement {
        #if targetEnvironment(macCatalyst)
        return .automatic
        #elseif os(macOS)
        return .automatic
        #else
        return .navigationBarLeading
        #endif
    }

    static var toolbarTrailingPlacement: ToolbarItemPlacement {
        #if targetEnvironment(macCatalyst)
        return .automatic
        #elseif os(macOS)
        return .automatic
        #else
        return .navigationBarTrailing
        #endif
    }

    static func copyToPasteboard(_ string: String) {
        #if os(macOS)
        let pasteboard = NSPasteboard.general
        pasteboard.clearContents()
        pasteboard.setString(string, forType: .string)
        #elseif canImport(UIKit)
        UIPasteboard.general.string = string
        #endif
    }

    static func openURL(_ url: URL) {
        #if targetEnvironment(macCatalyst)
        UIApplication.shared.open(url)
        #elseif os(macOS)
        NSWorkspace.shared.open(url)
        #elseif canImport(UIKit)
        UIApplication.shared.open(url)
        #endif
    }

    static func openMicrophoneSettings() {
        #if targetEnvironment(macCatalyst)
        if let url = URL(string: "x-apple.systempreferences:com.apple.preference.security?Privacy_Microphone") {
            UIApplication.shared.open(url)
        }
        #elseif os(macOS)
        if let url = URL(string: "x-apple.systempreferences:com.apple.preference.security?Privacy_Microphone") {
            NSWorkspace.shared.open(url)
        }
        #elseif canImport(UIKit)
        if let url = URL(string: UIApplication.openSettingsURLString) {
            UIApplication.shared.open(url)
        }
        #endif
    }
}

extension View {
    @ViewBuilder
    func ts3InlineNavigationTitle() -> some View {
        #if os(macOS)
        self
        #else
        self.navigationBarTitleDisplayMode(.inline)
        #endif
    }

    @ViewBuilder
    func ts3URLTextField() -> some View {
        #if os(iOS)
        self
            .textContentType(.URL)
            .autocapitalization(.none)
            .disableAutocorrection(true)
        #else
        self
        #endif
    }

    @ViewBuilder
    func ts3PlainTextField() -> some View {
        #if os(iOS)
        self
            .autocapitalization(.none)
            .disableAutocorrection(true)
        #else
        self
        #endif
    }

    @ViewBuilder
    func ts3NumericKeyboard() -> some View {
        #if os(iOS)
        self.keyboardType(.numberPad)
        #else
        self
        #endif
    }

    @ViewBuilder
    func ts3ChannelListStyle() -> some View {
        #if os(macOS)
        self.listStyle(.inset)
        #else
        self.listStyle(.insetGrouped)
        #endif
    }
}
